    /**
     * Helper to set input/textarea value while preserving undo/redo history.
     * Uses document.execCommand('insertText') which is the standard way to 
     * hook into the browser's native undo stack for programmatic changes.
     */
    function setInputValueWithUndo(element, value, replaceEntireContent = true) {
      if (!element) return;

      element.focus();
      if (replaceEntireContent) {
        // Select the entire content to replace it
        element.setSelectionRange(0, element.value.length);
      }

      // Attempt to use execCommand for undo support
      const success = document.execCommand('insertText', false, value);

      // If execCommand fails, fall back to direct value setting
      if (!success) {
        if (replaceEntireContent) {
          element.value = value;
        } else {
          const start = element.selectionStart;
          const end = element.selectionEnd;
          const text = element.value;
          element.value = text.substring(0, start) + value + text.substring(end);
          element.selectionStart = element.selectionEnd = start + value.length;
        }
      }

      // Always trigger input event to ensure UI updates (like auto-resize)
      element.dispatchEvent(new Event('input', { bubbles: true }));
    }

    function generateAttachmentId(prefix = 'att') {
      return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    }

    function createImageAttachment(item) {
      return {
        id: generateAttachmentId('img'),
        kind: 'image',
        name: item.name || `image-${Date.now()}.png`,
        data: item.data
      };
    }

    function createCodeAttachment(type, content, meta = {}) {
      const normalized = String(type || 'TEXT').toUpperCase();
      const lang = normalized === 'CSS' ? 'css' : normalized === 'SVG' ? 'svg' : 'text';
      const name = normalized === 'CSS' ? 'CSS export' : normalized === 'SVG' ? 'SVG export' : 'Text export';
      return {
        id: generateAttachmentId('code'),
        kind: 'code',
        exportType: normalized,
        lang,
        name,
        content: String(content || ''),
        ...meta
      };
    }

    function getStagedImageAttachments() {
      return stagedAttachments.filter(item => item.kind === 'image');
    }

    function getStagedCodeAttachments() {
      return stagedAttachments.filter(item => item.kind === 'code');
    }

    function buildCodeAttachmentText(item) {
      const label = item.exportType || 'TEXT';
      const lang = item.lang || 'text';
      return `Attached ${label}:\n\`\`\`${lang}\n${item.content || ''}\n\`\`\``;
    }

    function getSerializedCodeAttachmentTexts(items = getStagedCodeAttachments()) {
      return items.map(buildCodeAttachmentText);
    }

    function optimizeExportedSvgMarkup(input) {
      const text = String(input || '').trim();
      if (!text) return text;

      const svgOptimizationConfig = {
        multipass: true,
        js2svg: { pretty: false },
        plugins: [
          {
            name: 'preset-default',
            params: {
              overrides: {
                cleanupIds: false
              }
            }
          }
        ]
      };

      const svgBlockRegex = /(?:<!--[\s\S]*?-->\s*)?<svg[\s\S]*?<\/svg>/gi;
      const matches = text.match(svgBlockRegex);

      const optimizeSingle = (block) => {
        const blockMatch = block.match(/^(\s*<!--[\s\S]*?-->\s*)?(<svg[\s\S]*<\/svg>)\s*$/i);
        const comment = blockMatch?.[1]?.trim() || '';
        const svg = blockMatch?.[2] || block;

        try {
          const optimized = optimizeSvg(svg, svgOptimizationConfig);
          const optimizedSvg = 'data' in optimized ? optimized.data : svg;
          return comment ? `${comment}\n${optimizedSvg}` : optimizedSvg;
        } catch (error) {
          console.warn('SVGO optimization failed, using original SVG block:', error);
          return block.trim();
        }
      };

      if (matches && matches.length > 0) {
        return matches.map(optimizeSingle).join('\n\n');
      }

      try {
        const optimized = optimizeSvg(text, svgOptimizationConfig);
        return 'data' in optimized ? optimized.data : text;
      } catch (error) {
        console.warn('SVGO optimization failed, using original SVG text:', error);
        return text;
      }
    }

    function normalizeSvgExportPayload(input) {
      if (Array.isArray(input)) {
        const blocks = input.filter(Boolean).map((item) => {
          const name = item?.name ? String(item.name) : '';
          const svg = item?.svg ? String(item.svg) : '';
          const layerNames = Array.isArray(item?.layerNames) ? item.layerNames.map((entry) => String(entry || '')).filter(Boolean) : [];
          const content = name ? `<!-- ${name} -->\n${svg}` : svg;
          return {
            content: optimizeExportedSvgMarkup(content),
            layerNames
          };
        }).filter((block) => block.content);

        return {
          content: blocks.map((block) => block.content).join('\n\n'),
          svgLayerNameHints: blocks.length === 1 ? blocks[0].layerNames : []
        };
      }

      return {
        content: optimizeExportedSvgMarkup(input),
        svgLayerNameHints: []
      };
    }

    function buildUserTextWithCodeAttachments(message, codeTexts = []) {
      const segments = [];
      if (message && message.trim()) segments.push(message.trim());
      if (codeTexts.length > 0) segments.push(codeTexts.join('\n\n'));
      return segments.join('\n\n').trim();
    }

    function createUserHistoryParts(message, imageDataUrls = [], codeTexts = []) {
      const parts = [];

      imageDataUrls.forEach((dataUrl) => {
        const base64Data = dataUrl.split(',')[1];
        const mimeType = dataUrl.split(',')[0].split(':')[1].split(';')[0] || 'image/png';
        parts.push({
          inline_data: {
            mime_type: mimeType,
            data: base64Data
          }
        });
      });

      if (message && message.trim()) {
        parts.push({ text: message.trim() });
      }

      codeTexts.forEach((text) => {
        parts.push({ text });
      });

      if (parts.length === 0) {
        parts.push({ text: 'What can you tell me about these attachments?' });
      }

      return parts;
    }

    function formatBytes(bytes, decimals = 1) {
      if (!bytes || bytes === 0) return '0 B';
      const k = 1024;
      const dm = decimals < 0 ? 0 : decimals;
      const sizes = ['B', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
    }

