    let HEX_TO_NAME = null;
    function getHexToNameMap() {
      if (HEX_TO_NAME) return HEX_TO_NAME;
      HEX_TO_NAME = {};
      CSS_COLOR_NAMES.forEach(name => {
        const hex = colorToHex(name);
        if (!HEX_TO_NAME[hex]) {
          HEX_TO_NAME[hex] = name.charAt(0).toUpperCase() + name.slice(1);
        }
      });
      return HEX_TO_NAME;
    }

    const colorCache = new Map();
    function colorToHex(color) {
      if (!color) return "#000000";
      if (colorCache.has(color)) return colorCache.get(color);

      // Handle "RGB 255,255,255" format
      let normalized = color;
      if (typeof color === 'string' && color.toUpperCase().startsWith('RGB ')) {
        normalized = color.toUpperCase().replace('RGB ', 'rgb(') + ')';
      }

      if (normalized.startsWith('#')) {
        let res;
        if (normalized.length === 4) {
          res = '#' + normalized[1] + normalized[1] + normalized[2] + normalized[2] + normalized[3] + normalized[3];
        } else {
          res = normalized.toUpperCase();
        }
        colorCache.set(color, res);
        return res;
      }

      const temp = document.createElement('div');
      temp.style.color = normalized;
      document.body.appendChild(temp);
      const style = window.getComputedStyle(temp);
      const rgb = style.color;
      document.body.removeChild(temp);

      const parts = rgb.match(/\d+/g);
      if (!parts || parts.length < 3) return "#000000";

      const hex = '#' + parts.slice(0, 3).map(x => {
        const h = parseInt(x).toString(16);
        return h.length === 1 ? '0' + h : h;
      }).join('').toUpperCase();

      colorCache.set(color, hex);
      return hex;
    }

    // Floating popover for editing placeholders
    function openPlaceholderPopover(anchorEl, type, initialValue, onUpdate, images) {
      // Remove any existing popover
      const existing = document.querySelector('.placeholder-popover');
      if (existing) existing.remove();

      const popover = document.createElement('div');
      popover.className = 'placeholder-popover';

      const label = document.createElement('div');
      label.className = 'popover-title';
      label.textContent = `Edit ${type === 'brace' ? '{...}' : '[...]'}`;
      label.style.marginLeft = '0';
      popover.appendChild(label);

      const input = document.createElement('input');
      input.type = 'text';
      input.value = initialValue;
      popover.appendChild(input);

      const actions = document.createElement('div');
      actions.className = 'placeholder-popover-actions';

      const cancelBtn = document.createElement('button');
      cancelBtn.className = 'placeholder-popover-btn cancel';
      cancelBtn.textContent = 'Cancel';
      cancelBtn.onclick = () => popover.remove();

      const updateBtn = document.createElement('button');
      updateBtn.className = 'placeholder-popover-btn submit';
      updateBtn.textContent = 'Update';

      const submit = () => {
        const newValue = input.value.trim();
        if (newValue) {
          onUpdate(newValue);
          popover.remove();
        }
      };

      updateBtn.onclick = submit;
      input.onkeydown = (e) => {
        if (e.key === 'Enter' && !e.isComposing) submit();
        if (e.key === 'Escape') popover.remove();
      };

      // Determine which images to show (passed images or staged image attachments fallback)
      const stagedImageAttachments = getStagedImageAttachments();
      const imagesToShow = images || (stagedImageAttachments.length > 0 ? stagedImageAttachments.map((img, i) => ({
        ref: `image${i + 1}`,
        src: typeof img === 'string' ? img : `data:image/png;base64,${arrayBufferToBase64(img.data)}`
      })) : []);

      // Add image chips if there are images
      if (imagesToShow && imagesToShow.length > 0) {
        const imageHeader = document.createElement('div');
        imageHeader.className = 'popover-title';
        imageHeader.textContent = 'Reference image:';
        imageHeader.style.marginTop = '4px';
        imageHeader.style.fontSize = '10px';
        imageHeader.style.opacity = '0.7';
        popover.appendChild(imageHeader);

        const chipsContainer = document.createElement('div');
        chipsContainer.className = 'placeholder-popover-image-chips';

        imagesToShow.forEach((img) => {
          const chip = document.createElement('button');
          chip.className = 'placeholder-popover-chip';
          const imgRef = img.ref;
          chip.innerHTML = `<img src="${img.src}" style="width:14px;height:14px;border-radius:2px;object-fit:cover;"> <span>${imgRef}</span>`;
          chip.title = `Add ${imgRef} reference`;
          chip.onclick = () => {
            const start = input.selectionStart;
            const end = input.selectionEnd;
            const text = input.value;
            const before = text.substring(0, start);
            const after = text.substring(end);
            input.value = before + imgRef + after;
            input.focus();
            const newPos = start + imgRef.length;
            input.setSelectionRange(newPos, newPos);
          };
          chipsContainer.appendChild(chip);
        });

        popover.appendChild(chipsContainer);
      }

      actions.appendChild(cancelBtn);
      actions.appendChild(updateBtn);
      popover.appendChild(actions);

      // Stop propagation so clicking inside doesn't trigger "click outside" handlers
      popover.addEventListener('click', (e) => e.stopPropagation());
      popover.addEventListener('mousedown', (e) => e.stopPropagation());

      document.body.appendChild(popover);

      // Position the popover
      const rect = anchorEl.getBoundingClientRect();
      const popoverRect = popover.getBoundingClientRect();

      let top = rect.bottom + 8;
      let left = rect.left;

      // Adjust if it goes off screen
      if (left + popoverRect.width > window.innerWidth) {
        left = window.innerWidth - popoverRect.width - 16;
      }
      if (top + popoverRect.height > window.innerHeight) {
        top = rect.top - popoverRect.height - 8;
      }

      popover.style.top = `${top}px`;
      popover.style.left = `${left}px`;

      input.focus();
      input.select();

      // Close on click outside
      const clickOutside = (e) => {
        if (!popover.contains(e.target) && !anchorEl.contains(e.target)) {
          popover.remove();
          document.removeEventListener('mousedown', clickOutside);
        }
      };
      document.addEventListener('mousedown', clickOutside);
    }

    // Color picker popover
    function openColorPickerPopover(anchorEl, initialColor, onUpdate) {
      // Remove any existing popover
      const existing = document.querySelector('.color-picker-popover');
      if (existing) existing.remove();

      const popover = document.createElement('div');
      popover.className = 'color-picker-popover';

      const label = document.createElement('div');
      label.className = 'popover-title';
      label.textContent = 'Pick a color';
      popover.appendChild(label);

      const previewRow = document.createElement('div');
      previewRow.className = 'color-preview-row';

      const colorWrapper = document.createElement('div');
      colorWrapper.className = 'color-input-wrapper';

      const colorInput = document.createElement('input');
      colorInput.type = 'color';
      colorInput.value = initialColor;
      colorWrapper.appendChild(colorInput);

      const hexInput = document.createElement('input');
      hexInput.type = 'text';
      hexInput.className = 'hex-input';
      hexInput.value = initialColor;
      hexInput.maxLength = 7;

      previewRow.appendChild(colorWrapper);
      previewRow.appendChild(hexInput);
      popover.appendChild(previewRow);

      // Sync color input and hex input
      colorInput.oninput = () => {
        hexInput.value = colorInput.value.toUpperCase();
      };

      hexInput.oninput = () => {
        let val = hexInput.value.trim();
        if (!val.startsWith('#')) val = '#' + val;
        if (/^#[0-9A-Fa-f]{6}$/.test(val)) {
          colorInput.value = val;
        }
      };

      const actions = document.createElement('div');
      actions.className = 'color-picker-actions';

      const cancelBtn = document.createElement('button');
      cancelBtn.className = 'placeholder-popover-btn cancel';
      cancelBtn.textContent = 'Cancel';
      cancelBtn.onclick = () => {
        popover.remove();
        document.removeEventListener('mousedown', clickOutside);
      };

      const applyBtn = document.createElement('button');
      applyBtn.className = 'placeholder-popover-btn submit';
      applyBtn.textContent = 'Apply';

      const submit = () => {
        let finalColor = hexInput.value.trim().toUpperCase();
        if (!finalColor.startsWith('#')) finalColor = '#' + finalColor;
        if (/^#[0-9A-Fa-f]{6}$/.test(finalColor)) {
          onUpdate(finalColor);
          popover.remove();
          document.removeEventListener('mousedown', clickOutside);
        }
      };

      applyBtn.onclick = submit;
      hexInput.onkeydown = (e) => {
        if (e.key === 'Enter') submit();
        if (e.key === 'Escape') {
          popover.remove();
          document.removeEventListener('mousedown', clickOutside);
        }
      };

      actions.appendChild(cancelBtn);
      actions.appendChild(applyBtn);
      popover.appendChild(actions);

      // Stop propagation so clicking inside doesn't trigger "click outside" handlers
      popover.addEventListener('click', (e) => e.stopPropagation());
      popover.addEventListener('mousedown', (e) => e.stopPropagation());

      document.body.appendChild(popover);

      // Position the popover
      const rect = anchorEl.getBoundingClientRect();
      const popoverRect = popover.getBoundingClientRect();

      let top = rect.bottom + 8;
      let left = rect.left;

      // Adjust if it goes off screen
      if (left + popoverRect.width > window.innerWidth) {
        left = window.innerWidth - popoverRect.width - 16;
      }
      if (top + popoverRect.height > window.innerHeight) {
        top = rect.top - popoverRect.height - 8;
      }
      if (left < 8) left = 8;
      if (top < 8) top = 8;

      popover.style.top = `${top}px`;
      popover.style.left = `${left}px`;

      hexInput.focus();
      hexInput.select();

      // Close on click outside
      const clickOutside = (e) => {
        if (!popover.contains(e.target) && !anchorEl.contains(e.target)) {
          popover.remove();
          document.removeEventListener('mousedown', clickOutside);
        }
      };
      document.addEventListener('mousedown', clickOutside);
    }

