    let isSidebarOpen = false; // Sidebar visibility state
    function getDimensions(ratio, resolution) {
      let factor = 1;
      if (resolution === '4K') factor = 4;
      else if (resolution === '2K') factor = 2;
      else if (resolution === '0.5K') factor = 0.5;

      const dim = baseImageDimensions[ratio] || baseImageDimensions['1:1'];

      let width = dim.w * factor;
      let height = dim.h * factor;

      if (width > FIGMA_MAX_IMAGE_DIMENSION || height > FIGMA_MAX_IMAGE_DIMENSION) {
        const cap = FIGMA_MAX_IMAGE_DIMENSION;
        if (width > height) {
          height = Math.round(height * (cap / width));
          width = cap;
        } else {
          width = Math.round(width * (cap / height));
          height = cap;
        }
      }

      return {
        width: Math.round(width / 8) * 8,
        height: Math.round(height / 8) * 8
      };
    }

    // Get dimensions for OpenAI Images API (fixed sizes, no resolution scaling)
    // GPT Image models support: 1:1 (1024x1024), 3:2 (1536x1024), 2:3 (1024x1536)
    // DALL-E 3 supports: 1:1 (1024x1024), 16:9 (1792x1024), 9:16 (1024x1792)
    // DALL-E 2 supports: 1:1 (1024x1024)
    function getOpenAIDimensions(ratio, model) {
      const modelLower = (model || '').toLowerCase();

      // DALL-E 3 high-end models
      if (modelLower.includes('dall-e-3') || modelLower.includes('dalle-3')) {
        if (ratio === '16:9') return { width: 1792, height: 1024 };
        if (ratio === '9:16') return { width: 1024, height: 1792 };
        return { width: 1024, height: 1024 };
      }

      // GPT Image models / chatgpt-image models (1.5, 1-mini, etc.)
      if (modelLower.includes('gpt-image') || modelLower.includes('chatgpt-image')) {
        if (ratio === '3:2') return { width: 1536, height: 1024 };
        if (ratio === '2:3') return { width: 1024, height: 1536 };
        return { width: 1024, height: 1024 };
      }

      // Default / DALL-E 2 / other models
      return { width: 1024, height: 1024 };
    }

    function getOpenAISupportedRatios(model) {
      const modelLower = (model || '').toLowerCase();
      if (modelLower.includes('dall-e-3') || modelLower.includes('dalle-3')) {
        return ['1:1', '16:9', '9:16'];
      }
      if (modelLower.includes('gpt-image') || modelLower.includes('chatgpt-image')) {
        return ['1:1', '3:2', '2:3'];
      }
      return ['1:1'];
    }

    function normalizeOpenAIModelAndRatio(model, ratio) {
      let normalizedModel = model;
      let normalizedRatio = ratio || '1:1';
      let changed = false;

      const supports = getOpenAISupportedRatios(normalizedModel);
      if (!supports.includes(normalizedRatio)) {
        changed = true;
        if (normalizedRatio === '16:9' || normalizedRatio === '9:16') {
          normalizedModel = 'dall-e-3';
        } else if (normalizedRatio === '3:2' || normalizedRatio === '2:3') {
          const lower = (normalizedModel || '').toLowerCase();
          if (!lower.includes('gpt-image') && !lower.includes('chatgpt-image')) {
            normalizedModel = 'gpt-image-1.5';
          }
        }
        const updatedSupports = getOpenAISupportedRatios(normalizedModel);
        if (!updatedSupports.includes(normalizedRatio)) {
          normalizedRatio = updatedSupports[0] || '1:1';
        }
      }

      return { model: normalizedModel, ratio: normalizedRatio, changed };
    }

    // Check if model is an OpenAI image model
    function isOpenAIImageModelName(modelName) {
      if (!modelName) return false;
      const lower = modelName.toLowerCase();
      return lower.includes('gpt-image') || lower.includes('chatgpt-image') || lower.includes('dall-e') || lower.includes('dalle') || lower.includes('image-1') || lower.includes('image-latest');
    }

    function getBestAspectRatio(width, height) {
      if (!width || !height) return '1:1';
      const targetRatio = width / height;
      const ratios = {
        '1:1': 1,
        '16:9': 16 / 9,
        '9:16': 9 / 16,
        '4:3': 4 / 3,
        '3:4': 3 / 4,
        '2:3': 2 / 3,
        '3:2': 3 / 2,
        '4:5': 4 / 5,
        '5:4': 5 / 4,
        '21:9': 21 / 9
      };

      let bestMatch = '1:1';
      let minDiff = Infinity;

      for (const [key, val] of Object.entries(ratios)) {
        const diff = Math.abs(targetRatio - val);
        if (diff < minDiff) {
          minDiff = diff;
          bestMatch = key;
        }
      }
      return bestMatch;
    }

    // Helper to get current API key based on provider
    function getCurrentApiKey() {
      switch (selectedProvider) {
        case 'gemini': return geminiApiKey;
        case 'openai': return openaiApiKey;
        case 'ollama': return ollamaApiKey;
        case 'anthropic': return anthropicApiKey;
        default: return '';
      }
    }

    const DEFAULT_OPENAI_API_BASE = 'https://api.openai.com/v1';

    function normalizeOpenAICompatBaseUrl(raw, defaultBase) {
      const fallback = defaultBase || DEFAULT_OPENAI_API_BASE;
      let s = String(raw || '').trim();
      if (!s) return fallback;
      s = s.replace(/\/+$/, '');
      try {
        const u = new URL(s);
        const pathRaw = u.pathname.replace(/\/+$/, '');
        if (!pathRaw || pathRaw === '/') {
          u.pathname = '/v1';
        }
        return `${u.origin}${u.pathname.replace(/\/+$/, '')}`;
      } catch {
        return fallback;
      }
    }

    function getOllamaBaseUrl() {
      const el = document.getElementById('ollamaBaseUrlInput');
      const fromInput = el && el.value != null ? String(el.value).trim() : '';
      return normalizeOpenAICompatBaseUrl(fromInput || ollamaBaseUrl, DEFAULT_OLLAMA_API_BASE);
    }

    function getCompatChatBaseUrl() {
      return selectedProvider === 'ollama' ? getOllamaBaseUrl() : DEFAULT_OPENAI_API_BASE;
    }

    function openAICompatUrl(path) {
      const base = getCompatChatBaseUrl();
      const p = String(path || '').replace(/^\//, '');
      return `${base}/${p}`;
    }

    /** Pending Ollama proxy replies from plugin main (bypass UI iframe CORS to localhost). */
    const ollamaProxyPending = new Map();

    function isOllamaPluginProxyUrl(url) {
      try {
        const u = new URL(url);
        if (u.protocol !== 'http:') return false;
        const host = u.hostname.toLowerCase();
        if (host !== 'localhost' && host !== 'host.docker.internal') return false;
        if (!u.port) return false;
        return Number(u.port) === 11434;
      } catch {
        return false;
      }
    }

    function fetchOllamaViaPlugin(url, init = {}) {
      return new Promise((resolve, reject) => {
        const requestId = `ollama-${Date.now()}-${Math.random().toString(36).slice(2)}`;
        const timeoutId = setTimeout(() => {
          if (ollamaProxyPending.has(requestId)) {
            ollamaProxyPending.delete(requestId);
            reject(new Error('Ollama request timed out'));
          }
        }, 120000);
        ollamaProxyPending.set(requestId, {
          settle(resultMsg) {
            if (resultMsg.error != null && resultMsg.status === undefined) {
              reject(new Error(resultMsg.error));
              return;
            }
            resolve(new Response(resultMsg.body ?? '', {
              status: resultMsg.status != null ? resultMsg.status : 502,
              statusText: resultMsg.ok ? 'OK' : 'Error'
            }));
          },
          reject,
          timeoutId
        });
        const headers = {};
        const h = init && init.headers;
        if (h) {
          if (typeof Headers !== 'undefined' && h instanceof Headers) {
            h.forEach((v, k) => { headers[k] = v; });
          } else if (typeof h === 'object') {
            Object.assign(headers, h);
          }
        }
        const method = (init && init.method) || 'GET';
        let body = init && init.body;
        if (body !== undefined && body !== null && typeof body !== 'string') {
          body = String(body);
        }
        parent.postMessage({
          pluginMessage: {
            type: 'ollama-proxy-fetch',
            requestId,
            url,
            method,
            headers,
            body: body !== undefined ? body : undefined
          }
        }, '*');
      });
    }

    function compatHttpFetch(url, init) {
      if (isOllamaPluginProxyUrl(url)) {
        return fetchOllamaViaPlugin(url, init);
      }
      return fetch(url, init);
    }

    function openAICompatFetch(path, init) {
      return compatHttpFetch(openAICompatUrl(path), init);
    }

    /** Headers for OpenAI-compatible chat (OpenAI key or optional Ollama Bearer). */
    function openAIAuthHeaders() {
      const keyEl = document.getElementById('openaiApiKeyInput');
      const key = ((keyEl && keyEl.value != null ? String(keyEl.value) : '') || openaiApiKey).trim();
      const headers = {};
      if (key) headers.Authorization = `Bearer ${key}`;
      return headers;
    }

    function ollamaAuthHeaders() {
      const keyEl = document.getElementById('ollamaApiKeyInput');
      const key = ((keyEl && keyEl.value != null ? String(keyEl.value) : '') || ollamaApiKey).trim();
      const headers = {};
      if (key) headers.Authorization = `Bearer ${key}`;
      return headers;
    }

    function openAICompatAuthHeaders() {
      return selectedProvider === 'ollama' ? ollamaAuthHeaders() : openAIAuthHeaders();
    }

    function hasOpenAiCredentialsForChat() {
      const keyEl = document.getElementById('openaiApiKeyInput');
      const key = ((keyEl && keyEl.value != null ? String(keyEl.value) : '') || openaiApiKey).trim();
      return !!key;
    }

    function hasOllamaCredentialsForChat() {
      return true;
    }

    function getOpenAICompatChatModelId() {
      return selectedProvider === 'ollama' ? ollamaModel : openaiModel;
    }

    function isAiProviderReady() {
      if (isAiOffModeEnabled()) return false;
      switch (selectedProvider) {
        case 'gemini': return !!geminiApiKey;
        case 'openai': return hasOpenAiCredentialsForChat();
        case 'ollama': return hasOllamaCredentialsForChat();
        case 'anthropic': return !!anthropicApiKey;
        default: return false;
      }
    }

    function isAiOffModeEnabled() {
      return aiOffMode === true;
    }

    function getAiOffBlockedMessage(actionLabel = 'This action') {
      const label = (actionLabel || '').trim() || 'This action';
      return `${label} is unavailable while No AI mode is selected. Choose an AI provider in Settings > Models.`;
    }

    function guardAiAction(actionLabel = 'This action') {
      if (!isAiOffModeEnabled()) return true;
      showToast(getAiOffBlockedMessage(actionLabel), 'error');
      return false;
    }

    function canUseSemanticFontSearch() {
      return isAiProviderReady();
    }

    function extractJsonObjectFromText(text) {
      const src = String(text || '').trim();
      if (!src) return null;
      try {
        return JSON.parse(src);
      } catch {
        const start = src.indexOf('{');
        const end = src.lastIndexOf('}');
        if (start === -1 || end === -1 || end <= start) return null;
        try {
          return JSON.parse(src.slice(start, end + 1));
        } catch {
          return null;
        }
      }
    }

    function isDirectActionAllowedInAiOff(actionKey) {
      return NON_AI_DIRECT_ACTIONS.has(actionKey);
    }

    function isLocalTaskAllowedInAiOff(taskOrName) {
      const name = typeof taskOrName === 'string'
        ? taskOrName
        : (taskOrName && typeof taskOrName.name === 'string' ? taskOrName.name : '');
      return NON_AI_LOCAL_TASKS.has(name);
    }

    function isTaskAvailableInAiOff(task, fallbackName = '') {
      if (!isAiOffModeEnabled()) return true;
      const name = fallbackName || task?.name || '';
      if (name === 'Translate text' || name === 'Translate naming') {
        return true;
      }
      if (isQuickActionAllowedInAiOff(task)) {
        return true;
      }
      return isLocalTaskAllowedInAiOff(name);
    }

    function isQuickActionAllowedInAiOff(task) {
      if (!isAiOffModeEnabled()) return true;
      if (!task) return false;
      if (isLocalTaskAllowedInAiOff(task)) {
        return true;
      }
      if (task.directAction) {
        return isDirectActionAllowedInAiOff(task.directAction);
      }
      return false;
    }

    function updateAiOffUiState() {
      const aiBtn = document.getElementById('chatInputAiBtn');
      if (!aiBtn) return;
      if (isAiOffModeEnabled()) {
        aiBtn.classList.remove('visible', 'loading');
        aiBtn.disabled = true;
        aiBtn.title = 'No AI mode is selected';
      } else {
        aiBtn.disabled = false;
        aiBtn.title = 'Improve prompt with AI';
      }
    }

    function updateAiOffLayoutState() {
      const isOff = isAiOffModeEnabled();
      document.body.classList.toggle('ai-off-mode', isOff);
      if (chatContainer) {
        chatContainer.classList.toggle('hidden', isOff);
      }
      if (isOff) {
        openCommandsDrawer({ keepSelection: true });
      } else if (commandsDrawer.classList.contains('show')) {
        closeCommandsDrawer();
      }
      if (!isOff) {
        noAiOverlayVisible = false;
      }
      renderNoAiOverlayCards();
    }

    function normalizeGeminiModelName(name) {
      if (!name) return '';
      // Handle "models/gemini-pro" -> "gemini-pro"
      // Handle "publishers/google/models/gemini-pro" -> "gemini-pro"
      if (name.includes('/')) {
        return name.split('/').pop().trim();
      }
      return name.replace(/^models\//i, '').trim();
    }

    function buildGeminiImageGenerationConfig(modelName, options = {}) {
      const lower = normalizeGeminiModelName(modelName).toLowerCase();
      const selectedRatio = options.aspectRatio || '1:1';
      const selectedRes = options.imageSize || '1K';
      const thinkingLevel = options.thinkingLevel || 'minimal';
      const config = {};
      const imageConfig = {};

      if (selectedRatio) {
        imageConfig.aspectRatio = selectedRatio;
      }

      if (selectedRes) {
        imageConfig.imageSize = selectedRes;
      }

      if (Object.keys(imageConfig).length > 0) {
        config.imageConfig = imageConfig;
      }

      const isNanoBanana2 = lower.includes('gemini-3.1-flash-image-preview');
      const isGemini3ProPreview = lower.includes('gemini-3-pro-image-preview') || lower.includes('gemini-3.0-pro');
      const supportsThinking = isNanoBanana2 || isGemini3ProPreview;

      // `gemini-3.1-flash-image-preview` is stricter than the older image-preview models.
      // Keep its request body aligned with the current Google docs and omit extra knobs
      // that can trigger `INVALID_ARGUMENT` in Generate image quick actions.
      if (!isNanoBanana2) {
        config.responseModalities = ['TEXT', 'IMAGE'];
      }

      if (supportsThinking && thinkingLevel !== 'minimal') {
        const normalizedThinkingLevel = thinkingLevel.toLowerCase() === 'high' ? 'HIGH' : 'LOW';
        config.thinkingConfig = {
          thinkingLevel: normalizedThinkingLevel,
          includeThoughts: true
        };
      }

      return Object.keys(config).length > 0 ? config : undefined;
    }

    async function requestGeminiImageGeneration(modelUrl, modelName, parts, options = {}) {
      const selectedRes = options.imageSize || '1K';
      const requestBody = {
        contents: [{ parts }],
        generationConfig: buildGeminiImageGenerationConfig(modelName, options)
      };

      let response = await fetch(modelUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestBody)
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        const errorMessage = errorData?.error?.message || '';
        const errorStatus = errorData?.error?.status || '';
        const isNanoBanana2 = normalizeGeminiModelName(modelName).toLowerCase() === 'gemini-3.1-flash-image-preview';
        const isKnownHalfKIssue = isNanoBanana2 &&
          selectedRes === '0.5K' &&
          errorStatus === 'INVALID_ARGUMENT';

        // The Nano Banana 2 model page documents 0.5K support, but the public
        // generateContent API schema still lists only 1K/2K/4K. When the backend
        // rejects 0.5K, retry at 1K so the action still completes instead of hard-failing.
        if (isKnownHalfKIssue) {
          console.warn('Gemini 3.1 Flash rejected 0.5K imageSize, retrying at 1K:', errorData);
          showToast('Nano Banana 2 rejected 0.5K in the API. Retrying with 1K.', 'warning');

          const retryBody = {
            contents: [{ parts }],
            generationConfig: buildGeminiImageGenerationConfig(modelName, {
              ...options,
              imageSize: '1K'
            })
          };

          response = await fetch(modelUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(retryBody)
          });

          if (!response.ok) {
            const retryErrorData = await response.json().catch(() => ({}));
            const retryErr = new Error(retryErrorData.error?.message || `Gemini API failed with status ${response.status}`);
            retryErr.rawData = retryErrorData;
            throw retryErr;
          }
        } else {
          const err = new Error(errorMessage || `Gemini API failed with status ${response.status}`);
          err.rawData = errorData;
          throw err;
        }
      }

      return response.json();
    }

    // List available Gemini models for a given key
    async function listGeminiModels(apiKey) {
      if (cachedChatModelsByProvider.gemini) return cachedChatModelsByProvider.gemini;
      if (chatModelsPromisesByProvider.gemini) return chatModelsPromisesByProvider.gemini;

      chatModelsPromisesByProvider.gemini = (async () => {
        const resp = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${apiKey}`);
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({}));
          throw new Error(err.error?.message || 'Failed to list models');
        }
        const data = await resp.json();

        // Store metadata and return model objects
        const modelMap = new Map();
        (data.models || []).forEach(m => {
          const modelId = normalizeGeminiModelName(m.name || m.id);
          if (!modelId) return;

          const methods = m.supportedGenerationMethods || [];
          const canGenerateContent = methods.some(method =>
            method.toLowerCase().includes('generatecontent')
          );

          // Skip models that can't generate content (like pure Imagen models) for the chat brain
          if (!canGenerateContent) return;

          // Store metadata
          modelMetadata.gemini[modelId] = {
            id: modelId,
            displayName: modelId.toLowerCase().includes('nano-banana') ? modelId : (m.displayName || modelId),
            description: m.description || '',
            inputTokenLimit: m.inputTokenLimit || null,
            outputTokenLimit: m.outputTokenLimit || null,
            supportedGenerationMethods: methods,
            version: m.version || ''
          };

          // Store in map to avoid duplicates
          if (!modelMap.has(modelId)) {
            modelMap.set(modelId, modelMetadata.gemini[modelId]);
          }
        });

        const sortedModels = Array.from(modelMap.values()).sort((a, b) => {
          // Sort by version descending (e.g. 2.0 > 1.5)
          const versionA = parseFloat(a.version) || (a.id.match(/(\d+\.\d+)/) || [0, 0])[1];
          const versionB = parseFloat(b.version) || (b.id.match(/(\d+\.\d+)/) || [0, 0])[1];
          if (versionA !== versionB) return versionB - versionA;
          return b.id.localeCompare(a.id); // Tie-break with ID
        });

        cachedChatModelsByProvider.gemini = sortedModels;
        return sortedModels;
      })().catch(err => {
        chatModelsPromisesByProvider.gemini = null;
        throw err;
      });
      return chatModelsPromisesByProvider.gemini;
    }

    // List available image generation models from Gemini/OpenAI API
    // Filters models by supportedGenerationMethods, description, and displayName for image-related keywords
    let cachedImageModelsByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
    let imageModelsPromisesByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
    let cachedChatModelsByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
    let chatModelsPromisesByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
    let openaiChatModelsListKey = '';
    let ollamaChatModelsListKey = '';

    async function listOpenAIImageModels(apiKey) {
      if (!apiKey) return [];

      try {
        const resp = await fetch('https://api.openai.com/v1/models', {
          headers: { 'Authorization': `Bearer ${apiKey}` }
        });
        if (!resp.ok) throw new Error('Failed to fetch models');
        const data = await resp.json();

        // Keywords to identify image generation models
        const imageKeywords = ['image', 'dall-e', 'dalle'];

        const models = (data.data || []).filter(m => {
          const id = m.id.toLowerCase();
          return imageKeywords.some(kw => id.includes(kw));
        }).map(m => ({
          id: m.id,
          displayName: m.id,
          description: getOpenAIDescription(m.id),
          created: m.created || 0
        })).sort((a, b) => b.created - a.created);

        // Filter out specific non-generation models if they mistakenly match
        const filtered = models.filter(m => {
          const id = m.id.toLowerCase();
          return !id.includes('vision') && !id.includes('edit') && !id.includes('search');
        });

        return filtered;
      } catch (e) {
        console.error('Failed to list OpenAI image models:', e);
        return [];
      }
    }

    function base64ToBlob(base64, mimeType = 'image/png') {
      try {
        const byteString = atob(base64.split(',')[1] || base64);
        const ab = new ArrayBuffer(byteString.length);
        const ia = new Uint8Array(ab);
        for (let i = 0; i < byteString.length; i++) {
          ia[i] = byteString.charCodeAt(i);
        }
        return new Blob([ab], { type: mimeType });
      } catch (e) {
        console.error('Failed to convert base64 to blob:', e);
        return null;
      }
    }

    async function getImageFromOpenAIResponse(data) {
      if (!data || !data.data || !data.data[0]) {
        throw new Error('Invalid response from image API');
      }
      const item = data.data[0];
      if (item.b64_json) return item.b64_json;
      if (item.url) {
        try {
          const resp = await fetch(item.url);
          if (!resp.ok) throw new Error('Failed to fetch image from URL');
          const blob = await resp.blob();
          return await new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onloadend = () => {
              const base64 = reader.result.split(',')[1];
              resolve(base64);
            };
            reader.onerror = reject;
            reader.readAsDataURL(blob);
          });
        } catch (e) {
          throw new Error('Failed to download image: ' + e.message);
        }
      }
      throw new Error('No image data or URL in response');
    }

    async function listImageGenerationModels(apiKey) {
      const provider = selectedProvider;
      if (!apiKey) return DEFAULT_IMAGE_MODELS;

      // Return cached if available
      if (cachedImageModelsByProvider[provider]) return cachedImageModelsByProvider[provider];

      // Return existing promise if already fetching
      if (imageModelsPromisesByProvider[provider]) return imageModelsPromisesByProvider[provider];

      imageModelsPromisesByProvider[provider] = (async () => {
        try {
          if (provider === 'openai') {
            const models = await listOpenAIImageModels(apiKey);
            cachedImageModelsByProvider.openai = models;
            return models;
          }

          if (provider === 'ollama') {
            cachedImageModelsByProvider.ollama = [];
            return [];
          }

          const resp = await fetch(`https://generativelanguage.googleapis.com/v1beta/models?key=${apiKey}`);
          if (!resp.ok) {
            const err = await resp.json().catch(() => ({}));
            throw new Error(err.error?.message || 'Failed to list models');
          }
          const data = await resp.json();

          // Keywords to identify image generation models
          const imageKeywords = ['image', 'imagen', 'picture', 'photo', 'visual', 'graphic', 'generate image', 'image generation'];

          const imageModels = [];
          (data.models || []).forEach(m => {
            const modelId = normalizeGeminiModelName(m.name || m.id);
            if (!modelId) return;

            const displayName = (m.displayName || '').toLowerCase();
            const description = (m.description || '').toLowerCase();
            const methods = m.supportedGenerationMethods || [];

            // Check if model supports image generation
            const hasImageMethod = methods.some(method =>
              method.toLowerCase().includes('image') ||
              method.toLowerCase().includes('generateimage')
            );

            // Check keywords in displayName or description
            const hasImageKeyword = imageKeywords.some(keyword =>
              displayName.includes(keyword) ||
              description.includes(keyword) ||
              modelId.toLowerCase().includes(keyword)
            );

            if (hasImageMethod || hasImageKeyword) {
              imageModels.push({
                id: modelId,
                name: m.name || m.id, // Store the full model name/path
                displayName: modelId.toLowerCase().includes('nano-banana') ? modelId : (m.displayName || modelId),
                description: m.description || '',
                supportedGenerationMethods: methods
              });
            }
          });

          // Sort: prefer models with 'imagen' in the name first
          imageModels.sort((a, b) => {
            const aIsImagen = a.id.toLowerCase().includes('imagen');
            const bIsImagen = b.id.toLowerCase().includes('imagen');
            if (aIsImagen && !bIsImagen) return -1;
            if (!aIsImagen && bIsImagen) return 1;
            return a.displayName.localeCompare(b.displayName);
          });

          // Filter out gemini-2.0-flash-exp-image-generation model
          const filteredModels = imageModels.filter(m =>
            m.id.toLowerCase() !== 'gemini-2.0-flash-exp-image-generation'
          );

          cachedImageModelsByProvider.gemini = filteredModels;
          return filteredModels;
        } catch (error) {
          console.error('Failed to list image generation models:', error);
          // Return default fallback models
          return provider === 'gemini' ? DEFAULT_IMAGE_MODELS : [];
        } finally {
          imageModelsPromisesByProvider[provider] = null;
        }
      })();

      return imageModelsPromisesByProvider[provider];
    }

    // List all image generation models from all available providers
    async function listAllImageGenerationModels() {
      const allModels = [];
      const providers = [];

      // Check which providers have API keys set
      if (geminiApiKey) providers.push({ name: 'gemini', apiKey: geminiApiKey, label: 'Gemini' });
      if (openaiApiKey) providers.push({ name: 'openai', apiKey: openaiApiKey, label: 'OpenAI' });

      // Fetch models from each provider in parallel
      const fetchPromises = providers.map(async (provider) => {
        try {
          // Save and restore selectedProvider to avoid side effects
          const originalProvider = selectedProvider;
          selectedProvider = provider.name;
          const models = await listImageGenerationModels(provider.apiKey);
          selectedProvider = originalProvider;

          return models.map(m => ({
            ...m,
            provider: provider.name,
            providerLabel: provider.label,
            // Add provider prefix to display name for clarity
            displayNameWithProvider: `${m.displayName || m.id}`
          }));
        } catch (err) {
          console.warn(`Failed to fetch image models from ${provider.name}:`, err);
          return [];
        }
      });

      const results = await Promise.all(fetchPromises);

      // Flatten and combine all models, grouped by provider
      results.forEach((providerModels, index) => {
        if (providerModels.length > 0) {
          // Add a provider separator object
          allModels.push({
            id: `__provider_header_${providers[index].name}__`,
            isProviderHeader: true,
            provider: providers[index].name,
            providerLabel: providers[index].label
          });
          allModels.push(...providerModels);
        }
      });

      return allModels;
    }

    function getOpenAIDescription(modelId) {
      const id = modelId.toLowerCase();

      // GPT-5 series (Next-gen)
      if (id.includes('gpt-5.2')) {
        if (id.includes('codex')) return 'Next-gen technical model optimized for elite coding and logic.';
        if (id.includes('chat')) return 'Flagship conversational model with human-level reasoning.';
        if (id.includes('pro')) return 'The most advanced and high-intelligence model available.';
        return 'Next-generation flagship model with massive context and intelligence.';
      }
      if (id.includes('gpt-5.1')) {
        if (id.includes('codex')) return 'Advanced technical model for complex software engineering.';
        return 'High-performance next-gen model.';
      }

      // Imaging
      if (id.includes('gpt-image')) return 'Specialized model for high-fidelity image understanding and generation.';

      // Existing models
      if (id.includes('gpt-5-mini')) return 'Fast, affordable next-gen model for small-scale tasks.';
      if (id.includes('gpt-5')) return "OpenAI's high-intelligence flagship model for complex tasks.";
      if (id.includes('o1-preview')) return 'Advanced reasoning model for complex logical problems.';
      if (id.includes('o1-mini')) return 'Fast reasoning model optimized for coding and STEM.';
      if (id.includes('gpt-4')) return 'Standard GPT-4 model.';
      if (id.includes('gpt-3.5-turbo')) return 'Capable and cost-effective model for simpler tasks.';

      return '';
    }

    async function listOpenAIModels(apiKey) {
      const listKey = `${DEFAULT_OPENAI_API_BASE}|${apiKey || ''}`;
      if (cachedChatModelsByProvider.openai != null && openaiChatModelsListKey === listKey) {
        return cachedChatModelsByProvider.openai;
      }
      if (chatModelsPromisesByProvider.openai && openaiChatModelsListKey === listKey) {
        return chatModelsPromisesByProvider.openai;
      }
      cachedChatModelsByProvider.openai = null;
      chatModelsPromisesByProvider.openai = null;
      openaiChatModelsListKey = listKey;

      const fetchKey = listKey;
      chatModelsPromisesByProvider.openai = (async () => {
        const resp = await fetch(`${DEFAULT_OPENAI_API_BASE}/models`, {
          headers: { Authorization: `Bearer ${apiKey}` }
        });
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({}));
          throw new Error(err.error?.message || 'Failed to list OpenAI models');
        }
        const data = await resp.json();
        const nonChatSubstrings = [
          'realtime', 'audio', 'whisper', 'tts', 'embedding', 'embed', 'moderation',
          'instruct'
        ];
        let models = (data.data || []).map(m => ({
          id: m.id,
          displayName: m.id,
          description: getOpenAIDescription(m.id),
          created: m.created || 0
        }));

        models = models.filter(m => {
          const id = m.id.toLowerCase();
          if (!id.startsWith('gpt') && !id.startsWith('o1') && !id.startsWith('dall-e')) return false;
          if (nonChatSubstrings.some(sub => id.includes(sub))) return false;
          if (id === 'gpt-3.5-turbo-instruct') return false;
          if (id.includes('preview') && id.includes('vision') && !id.startsWith('o1')) return false;
          return true;
        });

        const sortedModels = models.sort((a, b) => b.created - a.created);
        if (openaiChatModelsListKey === fetchKey) {
          cachedChatModelsByProvider.openai = sortedModels;
        }
        return sortedModels;
      })().catch(err => {
        chatModelsPromisesByProvider.openai = null;
        if (openaiChatModelsListKey === fetchKey) openaiChatModelsListKey = '';
        throw err;
      });
      return chatModelsPromisesByProvider.openai;
    }

    async function listOllamaModels() {
      const baseUrl = getOllamaBaseUrl();
      const key = String(ollamaApiKeyInput?.value != null ? ollamaApiKeyInput.value : ollamaApiKey || '').trim();
      const listKey = `${baseUrl}|${key}`;
      if (cachedChatModelsByProvider.ollama != null && ollamaChatModelsListKey === listKey) {
        return cachedChatModelsByProvider.ollama;
      }
      if (chatModelsPromisesByProvider.ollama && ollamaChatModelsListKey === listKey) {
        return chatModelsPromisesByProvider.ollama;
      }
      cachedChatModelsByProvider.ollama = null;
      chatModelsPromisesByProvider.ollama = null;
      ollamaChatModelsListKey = listKey;
      const fetchKey = listKey;

      const headers = {};
      if (key) headers.Authorization = `Bearer ${key}`;

      chatModelsPromisesByProvider.ollama = (async () => {
        const url = `${baseUrl}/models`;
        const resp = await compatHttpFetch(url, { headers });
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({}));
          throw new Error(err.error?.message || 'Failed to list Ollama models');
        }
        const data = await resp.json();
        const nonChatSubstrings = [
          'realtime', 'audio', 'whisper', 'tts', 'embedding', 'embed', 'moderation',
          'instruct'
        ];
        const models = (data.data || []).map(m => ({
          id: m.id,
          displayName: m.id,
          description: '',
          created: m.created || 0
        })).filter(m => {
          const id = m.id.toLowerCase();
          if (nonChatSubstrings.some(sub => id.includes(sub))) return false;
          return true;
        });
        const sortedModels = models.sort((a, b) => b.created - a.created);
        if (ollamaChatModelsListKey === fetchKey) {
          cachedChatModelsByProvider.ollama = sortedModels;
        }
        return sortedModels;
      })().catch(err => {
        chatModelsPromisesByProvider.ollama = null;
        if (ollamaChatModelsListKey === fetchKey) ollamaChatModelsListKey = '';
        throw err;
      });
      return chatModelsPromisesByProvider.ollama;
    }

    // Helper to build OpenAI request body with compatibility fixes
    function buildOpenAIRequestBody(model, messages, options = {}) {
      const isNewModel = model.startsWith('o1') || model.startsWith('gpt-5') || model.includes('chat-latest');

      const body = {
        model: model,
        messages: messages,
        ...options
      };

      // Handle max_tokens vs max_completion_tokens
      if (isNewModel && body.max_tokens) {
        body.max_completion_tokens = body.max_tokens;
        delete body.max_tokens;
      }

      // o1, gpt-5 and chat-latest models often don't support temperature handling (must be 1 or omitted)
      if (isNewModel) {
        delete body.temperature;
      }

      // o1 models handle system messages as 'developer' role according to latest docs
      if (model.startsWith('o1')) {
        body.messages = body.messages.map(m => ({
          ...m,
          role: m.role === 'system' ? 'developer' : m.role
        }));
      }

      return body;
    }

    function getAnthropicDescription(modelId) {
      if (modelId.includes('claude-3-5-sonnet')) return 'Most intelligent Claude model with breakthrough speed.';
      if (modelId.includes('claude-3-5-haiku')) return 'Fastest Claude model for near-instant responses.';
      if (modelId.includes('claude-3-opus')) return 'Most powerful model for highly complex tasks.';
      if (modelId.includes('claude-3-sonnet')) return 'Balanced intelligence and speed model.';
      if (modelId.includes('claude-3-haiku')) return 'Fast, cost-effective model for high-volume tasks.';
      return '';
    }

    async function listAnthropicModels(apiKey) {
      if (cachedChatModelsByProvider.anthropic) return cachedChatModelsByProvider.anthropic;
      if (chatModelsPromisesByProvider.anthropic) return chatModelsPromisesByProvider.anthropic;

      chatModelsPromisesByProvider.anthropic = (async () => {
        const resp = await fetch('https://api.anthropic.com/v1/models', {
          headers: {
            'x-api-key': apiKey,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json'
          }
        });
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({}));
          throw new Error(err.error?.message || 'Failed to list Anthropic models');
        }
        const data = await resp.json();
        const models = (data.data || []).map(m => ({
          id: m.id,
          displayName: m.display_name || m.id,
          description: getAnthropicDescription(m.id),
          created_at: m.created_at || ''
        }));

        // Sort by created_at descending (ISO strings sort correctly lexicographically)
        const sortedModels = models.sort((a, b) => b.created_at.localeCompare(a.created_at));
        cachedChatModelsByProvider.anthropic = sortedModels;
        return sortedModels;
      })().catch(err => {
        chatModelsPromisesByProvider.anthropic = null;
        throw err;
      });
      return chatModelsPromisesByProvider.anthropic;
    }

    // Clear cached image models (call when API key changes)
    function clearImageModelCache(provider) {
      if (provider) {
        cachedImageModelsByProvider[provider] = null;
        imageModelsPromisesByProvider[provider] = null;
      } else {
        cachedImageModelsByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
        imageModelsPromisesByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
      }
    }

    // Clear cached chat models (call when API key changes)
    function clearChatModelCache(provider) {
      if (provider) {
        cachedChatModelsByProvider[provider] = null;
        chatModelsPromisesByProvider[provider] = null;
        if (provider === 'openai') openaiChatModelsListKey = '';
        if (provider === 'ollama') ollamaChatModelsListKey = '';
      } else {
        cachedChatModelsByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
        chatModelsPromisesByProvider = { gemini: null, openai: null, ollama: null, anthropic: null };
        openaiChatModelsListKey = '';
        ollamaChatModelsListKey = '';
      }
    }

    function buildGeminiModelList(models, preferredValue) {
      // Normalize models to objects with id property
      const normalizedModels = (models || []).map(m => {
        if (typeof m === 'string') {
          // If it's just an ID string, create a basic object
          return {
            id: normalizeGeminiModelName(m),
            displayName: m,
            description: ''
          };
        }
        // If it's already an object, ensure id is normalized
        return {
          ...m,
          id: normalizeGeminiModelName(m.id || m.name || m)
        };
      }).filter(m => m.id);

      // Remove duplicates by id
      const uniqueMap = new Map();
      normalizedModels.forEach(m => {
        if (!uniqueMap.has(m.id)) {
          uniqueMap.set(m.id, m);
        }
      });

      const uniqueModels = Array.from(uniqueMap.values());
      const normalizedPreferred = normalizeGeminiModelName(preferredValue);

      // Keep the previously selected/saved model if it's not returned (e.g., older model)
      // But only if it's not an Imagen model (those shouldn't be used for chat brain)
      if (normalizedPreferred && !uniqueMap.has(normalizedPreferred)) {
        const isImagen = normalizedPreferred.toLowerCase().includes('imagen');
        if (!isImagen) {
          // Create a basic object for the preferred model if not found
          const preferredModel = {
            id: normalizedPreferred,
            displayName: normalizedPreferred,
            description: ''
          };
          uniqueModels.unshift(preferredModel);
          uniqueMap.set(normalizedPreferred, preferredModel);
        }
      }

      // If no models, use defaults
      if (uniqueModels.length === 0) {
        return DEFAULT_GEMINI_MODELS.map(id => ({
          id: normalizeGeminiModelName(id),
          displayName: id,
          description: ''
        }));
      }

      return uniqueModels;
    }

    function buildOpenAIModelList(models, preferredValue) {
      const normalizedModels = (models || []).map(m => {
        if (typeof m === 'string') {
          return { id: m, displayName: m, description: getOpenAIDescription(m) };
        }
        return m;
      });

      const uniqueMap = new Map();
      normalizedModels.forEach(m => {
        if (m.id && !uniqueMap.has(m.id)) {
          uniqueMap.set(m.id, m);
        }
      });

      const uniqueModels = Array.from(uniqueMap.values());

      if (preferredValue && !uniqueMap.has(preferredValue)) {
        const preferredModel = {
          id: preferredValue,
          displayName: preferredValue,
          description: getOpenAIDescription(preferredValue)
        };
        uniqueModels.unshift(preferredModel);
        uniqueMap.set(preferredValue, preferredModel);
      }

      if (uniqueModels.length === 0) {
        return DEFAULT_OPENAI_MODELS;
      }

      return uniqueModels;
    }

    function buildAnthropicModelList(models, preferredValue) {
      const normalizedModels = (models || []).map(m => {
        if (typeof m === 'string') {
          return { id: m, displayName: m, description: getAnthropicDescription(m) };
        }
        return m;
      });

      const uniqueMap = new Map();
      normalizedModels.forEach(m => {
        if (m.id && !uniqueMap.has(m.id)) {
          uniqueMap.set(m.id, m);
        }
      });

      const uniqueModels = Array.from(uniqueMap.values());

      if (preferredValue && !uniqueMap.has(preferredValue)) {
        const preferredModel = {
          id: preferredValue,
          displayName: preferredValue,
          description: getAnthropicDescription(preferredValue)
        };
        uniqueModels.unshift(preferredModel);
        uniqueMap.set(preferredValue, preferredModel);
      }

      if (uniqueModels.length === 0) {
        return DEFAULT_ANTHROPIC_MODELS;
      }

      return uniqueModels;
    }

    function populateGeminiModelSelect(models, preferredValue) {
      if (!geminiModelSelect) return;

      const modelList = buildGeminiModelList(models, preferredValue);
      geminiModelSelect.innerHTML = '';

      // Store metadata for all models
      modelList.forEach(model => {
        // Update metadata if we have more info
        if (model.description || model.displayName) {
          modelMetadata.gemini[model.id] = {
            ...modelMetadata.gemini[model.id],
            ...model
          };
        }

        const option = document.createElement('option');
        option.value = model.id;
        option.textContent = model.displayName || model.id;
        geminiModelSelect.appendChild(option);
      });

      const normalizedPreferred = normalizeGeminiModelName(preferredValue);
      const modelIds = modelList.map(m => m.id);
      const targetValue = normalizedPreferred && modelIds.includes(normalizedPreferred)
        ? normalizedPreferred
        : (modelIds[0] || '');

      geminiModelSelect.value = targetValue;
      geminiModel = geminiModelSelect.value;

      // Also update checklist with full model objects
      const enabledList = enabledModels.gemini.length > 0 ? enabledModels.gemini : modelIds;
      populateModelChecklist('gemini', modelList, enabledList);
    }

    async function refreshGeminiModelList({ apiKey, preferredModel, silent = false } = {}) {
      if (!geminiModelSelect) return;

      const fallbackValue = normalizeGeminiModelName(preferredModel || geminiModelSelect.value || geminiModel);

      if (!apiKey) {
        populateGeminiModelSelect(DEFAULT_GEMINI_MODELS, fallbackValue);
        return;
      }

      const loadingOption = document.createElement('option');
      loadingOption.value = '';
      loadingOption.textContent = t('settings.models.loading');
      geminiModelSelect.innerHTML = '';
      geminiModelSelect.appendChild(loadingOption);
      geminiModelSelect.disabled = true;

      try {
        const models = await listGeminiModels(apiKey);
        if (!models.length && !silent) {
          showToast(t('settings.messages.noGeminiModels'), 'info');
        }
        populateGeminiModelSelect(models.length ? models : DEFAULT_GEMINI_MODELS, fallbackValue);
      } catch (error) {
        console.warn('Gemini model fetch failed:', error);
        populateGeminiModelSelect(DEFAULT_GEMINI_MODELS, fallbackValue);
        if (!silent) {
          showToast(t('settings.messages.refreshUsingDefaults', {
            provider: getLocalizedProviderName('gemini')
          }), 'info');
        }
      } finally {
        geminiModelSelect.disabled = false;
        // Update chat dropdown if Gemini is current provider
        if (selectedProvider === 'gemini') {
          populateChatModelDropdown();
        }
      }
    }

    async function refreshOpenAIModelList({ apiKey, preferredModel, silent = false } = {}) {
      if (!openaiModelSelect) return;
      const fallbackValue = preferredModel || openaiModelSelect.value || openaiModel;
      if (!hasOpenAiCredentialsForChat()) {
        populateOpenAIModelSelect(DEFAULT_OPENAI_MODELS, fallbackValue);
        return;
      }
      openaiModelSelect.disabled = true;
      try {
        const models = await listOpenAIModels(apiKey);
        populateOpenAIModelSelect(models.length ? models : DEFAULT_OPENAI_MODELS, fallbackValue);
      } catch (error) {
        console.warn('OpenAI model fetch failed:', error);
        populateOpenAIModelSelect(DEFAULT_OPENAI_MODELS, fallbackValue);
        if (!silent) showToast(t('settings.messages.refreshUsingDefaults', {
          provider: getLocalizedProviderName('openai')
        }), 'info');
      } finally {
        openaiModelSelect.disabled = false;
        if (selectedProvider === 'openai') populateChatModelDropdown();
      }
    }

    async function refreshOllamaModelList({ preferredModel, silent = false } = {}) {
      if (!ollamaModelSelect) return;
      const fallbackValue = preferredModel || ollamaModelSelect.value || ollamaModel;
      ollamaModelSelect.disabled = true;
      try {
        const models = await listOllamaModels();
        populateOllamaModelSelect(models.length ? models : DEFAULT_OLLAMA_MODELS, fallbackValue);
      } catch (error) {
        console.warn('Ollama model fetch failed:', error);
        populateOllamaModelSelect(DEFAULT_OLLAMA_MODELS, fallbackValue);
        if (!silent) showToast(t('settings.messages.refreshUsingDefaults', {
          provider: getLocalizedProviderName('ollama')
        }), 'info');
      } finally {
        ollamaModelSelect.disabled = false;
        if (selectedProvider === 'ollama') populateChatModelDropdown();
      }
    }

    async function refreshAnthropicModelList({ apiKey, preferredModel, silent = false } = {}) {
      if (!anthropicModelSelect) return;
      const fallbackValue = preferredModel || anthropicModelSelect.value || anthropicModel;
      if (!apiKey) {
        populateAnthropicModelSelect(DEFAULT_ANTHROPIC_MODELS, fallbackValue);
        return;
      }
      anthropicModelSelect.disabled = true;
      try {
        const models = await listAnthropicModels(apiKey);
        populateAnthropicModelSelect(models.length ? models : DEFAULT_ANTHROPIC_MODELS, fallbackValue);
      } catch (error) {
        console.warn('Anthropic model fetch failed:', error);
        populateAnthropicModelSelect(DEFAULT_ANTHROPIC_MODELS, fallbackValue);
        if (!silent) showToast(t('settings.messages.refreshUsingDefaults', {
          provider: getLocalizedProviderName('anthropic')
        }), 'info');
      } finally {
        anthropicModelSelect.disabled = false;
        if (selectedProvider === 'anthropic') populateChatModelDropdown();
      }
    }

    function populateOpenAIModelSelect(models, preferredValue) {
      if (!openaiModelSelect) return;

      const modelList = buildOpenAIModelList(models, preferredValue);
      openaiModelSelect.innerHTML = '';

      modelList.forEach(model => {
        modelMetadata.openai[model.id] = { ...modelMetadata.openai[model.id], ...model };
        const option = document.createElement('option');
        option.value = model.id;
        option.textContent = model.displayName || model.id;
        openaiModelSelect.appendChild(option);
      });

      const modelIds = modelList.map(m => m.id);
      openaiModelSelect.value = preferredValue && modelIds.includes(preferredValue) ? preferredValue : (modelIds[0] || '');
      openaiModel = openaiModelSelect.value;

      const enabledList = enabledModels.openai.length > 0 ? enabledModels.openai : [];
      populateModelChecklist('openai', modelList, enabledList);
    }

    function populateOllamaModelSelect(models, preferredValue) {
      if (!ollamaModelSelect) return;

      const modelList = buildOpenAIModelList(models, preferredValue);
      ollamaModelSelect.innerHTML = '';

      modelList.forEach(model => {
        modelMetadata.ollama[model.id] = { ...modelMetadata.ollama[model.id], ...model };
        const option = document.createElement('option');
        option.value = model.id;
        option.textContent = model.displayName || model.id;
        ollamaModelSelect.appendChild(option);
      });

      const modelIds = modelList.map(m => m.id);
      ollamaModelSelect.value = preferredValue && modelIds.includes(preferredValue) ? preferredValue : (modelIds[0] || '');
      ollamaModel = ollamaModelSelect.value;

      const enabledList = enabledModels.ollama.length > 0 ? enabledModels.ollama : [];
      populateModelChecklist('ollama', modelList, enabledList);
    }

    function populateAnthropicModelSelect(models, preferredValue) {
      if (!anthropicModelSelect) return;

      const modelList = buildAnthropicModelList(models, preferredValue);
      anthropicModelSelect.innerHTML = '';

      modelList.forEach(model => {
        modelMetadata.anthropic[model.id] = { ...modelMetadata.anthropic[model.id], ...model };
        const option = document.createElement('option');
        option.value = model.id;
        option.textContent = model.displayName || model.id;
        anthropicModelSelect.appendChild(option);
      });

      const modelIds = modelList.map(m => m.id);
      anthropicModelSelect.value = preferredValue && modelIds.includes(preferredValue) ? preferredValue : (modelIds[0] || '');
      anthropicModel = anthropicModelSelect.value;

      const enabledList = enabledModels.anthropic.length > 0 ? enabledModels.anthropic : [];
      populateModelChecklist('anthropic', modelList, enabledList);
    }

    // Normalize and deduplicate model IDs for a provider
    function deduplicateModelIds(modelIds, provider) {
      if (!modelIds || !Array.isArray(modelIds)) return [];

      const normalizedMap = new Map();
      modelIds.forEach(id => {
        if (!id) return;
        const normalizedId = provider === 'gemini'
          ? normalizeGeminiModelName(id)
          : id;
        if (normalizedId && !normalizedMap.has(normalizedId)) {
          normalizedMap.set(normalizedId, normalizedId);
        }
      });

      return Array.from(normalizedMap.values());
    }

    // Populate model checklist for a provider
    // Define commonly used models for each provider
    function getCommonModels(provider) {
      const commonModels = {
        gemini: [
          DEFAULT_GEMINI_TITLE_MODEL,
          DEFAULT_GEMINI_CHAT_MODEL,
          'imagen-4.0-fast-generate-001',
          'imagen-4.0-generate-001'
        ],
        openai: [
          'gpt-5-nano',
          DEFAULT_OPENAI_CHAT_MODEL
        ],
        ollama: [
          DEFAULT_OLLAMA_CHAT_MODEL
        ],
        anthropic: [
          'claude-sonnet-4-20250514',
          'claude-3-5-sonnet-20241022'
        ]
      };
      return commonModels[provider] || [];
    }

    function populateModelChecklist(provider, models, enabledModelsList = []) {
      const checklistId = `${provider}ModelChecklist`;
      const checklist = document.getElementById(checklistId);
      if (!checklist) return;

      checklist.innerHTML = '';

      if (!models || models.length === 0) {
        checklist.innerHTML = '<div style="padding: var(--space-sm); color: var(--text-muted); text-align: center; font-style: italic;">No models available</div>';
        return;
      }

      const commonModels = getCommonModels(provider);

      // Normalize and deduplicate models by ID
      const normalizedModelsMap = new Map();
      models.forEach(model => {
        // Handle both object and string formats
        const modelObj = typeof model === 'string' ? { id: model, displayName: model, description: '' } : model;
        let modelId = modelObj.id || modelObj.name || model;

        // Normalize model ID (especially for Gemini models)
        if (provider === 'gemini') {
          modelId = normalizeGeminiModelName(modelId);
        }

        // Skip if already processed (deduplication)
        if (normalizedModelsMap.has(modelId)) {
          return;
        }

        // Get metadata if available
        const metadata = modelMetadata[provider]?.[modelId] || {};
        const displayName = metadata.displayName || modelObj.displayName || modelId;
        const description = metadata.description || modelObj.description || '';

        normalizedModelsMap.set(modelId, {
          id: modelId,
          displayName,
          description
        });
      });

      // Normalize common models for comparison (especially for Gemini)
      const normalizedCommonModels = provider === 'gemini'
        ? commonModels.map(id => normalizeGeminiModelName(id))
        : commonModels;

      // Normalize enabledModelsList for comparison
      const normalizedEnabledList = provider === 'gemini' && enabledModelsList.length > 0
        ? enabledModelsList.map(id => normalizeGeminiModelName(id))
        : enabledModelsList;

      // Process deduplicated models
      Array.from(normalizedModelsMap.values()).forEach(({ id: modelId, displayName, description }) => {

        // If enabledModelsList is empty (first time), default to common models only
        // Otherwise use the user's saved preferences
        const isEnabled = normalizedEnabledList.length === 0
          ? normalizedCommonModels.includes(modelId)
          : normalizedEnabledList.includes(modelId);

        // Check if this model should be hidden by default
        // Patterns to match (only checking displayName):
        // - "00n": numbers with leading zeros (e.g., 001, 004)
        // - "MM-YYYY": month-year format (e.g., 12-2025)
        // - "DD-MM": day-month format (e.g., 03-07)
        // - "(Preview)": literal string
        // - "Gemma": literal string
        const shouldHide = (() => {
          const text = displayName.toLowerCase();

          // Match "00n" pattern: numbers starting with 0 followed by digits (e.g., 001, 004)
          if (/\b0\d+\b/.test(text)) return true;

          // Match "MM-YYYY" pattern: 1-2 digits, dash, 4 digits (e.g., 12-2025, 1-2025)
          if (/\b\d{1,2}-\d{4}\b/.test(text)) return true;

          // Match "DD-MM" pattern: 2 digits, dash, 2 digits (e.g., 03-07, 12-25)
          // But exclude if it matches MM-YYYY pattern (already caught above)
          if (/\b\d{2}-\d{2}\b/.test(text) && !/\b\d{2}-\d{4}\b/.test(text)) return true;

          // Match literal strings
          if (text.includes('(preview)') || text.includes('gemma')) return true;

          return false;
        })();

        const item = document.createElement('div');
        item.className = 'model-checklist-item' + (shouldHide ? ' hidden-by-default' : '');

        const checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.id = `model-${provider}-${modelId}`;
        checkbox.value = modelId;
        checkbox.checked = isEnabled;
        checkbox.addEventListener('change', () => {
          handleSettingsChanged();
          // Update enabled models and refresh chat dropdown if current provider
          enabledModels[provider] = getEnabledModels(provider);
          updateCheckAllToggle(provider);
          if (provider === selectedProvider) {
            populateChatModelDropdown();
          }
        });

        const labelContainer = document.createElement('label');
        labelContainer.htmlFor = `model-${provider}-${modelId}`;
        labelContainer.className = 'model-checklist-label';
        labelContainer.title = t('settings.models.modelIdTitle', { id: modelId });

        const labelName = document.createElement('div');
        labelName.className = 'model-checklist-name';
        labelName.textContent = displayName;

        // Append ID to name if it differs significantly
        if (displayName !== modelId && !displayName.includes(modelId)) {
          const idSpan = document.createElement('span');
          idSpan.style.opacity = '0.5';
          idSpan.style.marginLeft = '6px';
          idSpan.style.fontWeight = 'normal';
          idSpan.textContent = `(${modelId})`;
          labelName.appendChild(idSpan);
        }

        labelContainer.appendChild(labelName);

        // Add description if available
        if (description) {
          const labelDesc = document.createElement('div');
          labelDesc.className = 'model-checklist-description';
          labelDesc.textContent = description;
          labelContainer.appendChild(labelDesc);
        }

        item.appendChild(checkbox);
        item.appendChild(labelContainer);
        checklist.appendChild(item);
      });

      // Update check-all toggle text after populating
      updateCheckAllToggle(provider);

      // Reset "Show All" button text when checklist is repopulated
      updateShowAllButtonLabel(provider);
    }

    function updateShowAllButtonLabel(provider) {
      const showAllBtn = document.querySelector(`.model-show-all-btn[data-provider="${provider}"]`);
      if (!showAllBtn) return;

      const checklistId = `${provider}ModelChecklist`;
      const checklist = document.getElementById(checklistId);
      const hiddenItems = checklist ? checklist.querySelectorAll('.model-checklist-item.hidden-by-default') : [];
      const isShowingAll = Array.from(hiddenItems).some((item) => item.classList.contains('show-all'));
      const textKey = isShowingAll ? 'settings.models.hideFiltered' : 'settings.models.showAll';
      const titleKey = isShowingAll ? 'settings.models.hideFilteredTitle' : 'settings.models.showAllTitle';
      showAllBtn.textContent = t(textKey);
      showAllBtn.title = t(titleKey);
    }

    // Get enabled models for a provider from checklist
    function getEnabledModels(provider) {
      const checklistId = `${provider}ModelChecklist`;
      const checklist = document.getElementById(checklistId);
      if (!checklist) return [];

      const checkboxes = checklist.querySelectorAll('input[type="checkbox"]:checked');
      return Array.from(checkboxes).map(cb => cb.value);
    }

    // Get all available models for a provider (from select or checklist)
    function getAvailableModels(provider) {
      const selectId = `${provider}ModelSelect`;
      const select = document.getElementById(selectId);
      if (!select) return [];

      const models = [];
      for (const option of select.options) {
        if (option.value) {
          models.push(option.value);
        }
      }
      return models;
    }

    // Update check-all toggle text based on current checkbox state
    function updateCheckAllToggle(provider) {
      const toggle = document.querySelector(`.check-all-toggle[data-provider="${provider}"]`);
      if (!toggle) return;

      const checklistId = `${provider}ModelChecklist`;
      const checklist = document.getElementById(checklistId);
      if (!checklist) return;

      const checkboxes = checklist.querySelectorAll('input[type="checkbox"]');
      if (checkboxes.length === 0) {
        toggle.querySelector('.check-all-text').textContent = t('settings.models.checkAll');
        return;
      }

      const checkedCount = checklist.querySelectorAll('input[type="checkbox"]:checked').length;
      const totalCount = checkboxes.length;

      if (checkedCount === 0) {
        toggle.querySelector('.check-all-text').textContent = t('settings.models.checkAll');
      } else if (checkedCount === totalCount) {
        toggle.querySelector('.check-all-text').textContent = t('settings.models.uncheckAll');
      } else {
        toggle.querySelector('.check-all-text').textContent = t('settings.models.checkAllProgress', {
          checked: checkedCount,
          total: totalCount
        });
      }
      toggle.title = t('settings.models.checkAllTitle');
    }

    // Toggle all checkboxes for a provider
    function toggleAllModels(provider) {
      const checklistId = `${provider}ModelChecklist`;
      const checklist = document.getElementById(checklistId);
      if (!checklist) return;

      const checkboxes = checklist.querySelectorAll('input[type="checkbox"]');
      if (checkboxes.length === 0) return;

      const checkedCount = checklist.querySelectorAll('input[type="checkbox"]:checked').length;
      const shouldCheckAll = checkedCount < checkboxes.length;

      checkboxes.forEach(checkbox => {
        checkbox.checked = shouldCheckAll;
      });

      handleSettingsChanged();
      enabledModels[provider] = getEnabledModels(provider);
      updateCheckAllToggle(provider);

      if (provider === selectedProvider) {
        populateChatModelDropdown();
      }
    }

    // Get list of available providers (those with API keys set)
    function getAvailableProviders() {
      const providers = [];
      if (geminiApiKey) providers.push('gemini');
      if (openaiApiKey) providers.push('openai');
      if (ollamaApiKey || ollamaShowLocalModelsInAssistantMenu !== false) providers.push('ollama');
      if (anthropicApiKey) providers.push('anthropic');
      return providers;
    }

    // Get provider display name
    function getProviderDisplayName(provider) {
      switch (provider) {
        case 'gemini': return 'Google Gemini';
        case 'openai': return 'OpenAI';
        case 'ollama': return 'Ollama';
        case 'anthropic': return 'Anthropic';
        default: return provider;
      }
    }

    // Get provider icon SVG
    function getProviderIcon(provider) {
      switch (provider) {
        case 'gemini':
          return '<svg class="provider-icon" viewBox="0 0 24 24" fill="currentColor"><path d="M24 12.024c-6.437.388-11.59 5.539-11.977 11.976h-.047C11.588 17.563 6.436 12.412 0 12.024v-.047C6.437 11.588 11.588 6.437 11.976 0h.047c.388 6.437 5.54 11.588 11.977 11.977v.047Z"/></svg>';
        case 'openai':
          return '<svg class="provider-icon" viewBox="0 0 24 24" fill="currentColor"><path d="M9.195 2.282a5.276 5.276 0 0 1 4.003.525 5.3 5.3 0 0 1 .752.531 5.277 5.277 0 0 1 6.611 5.104c0 .309-.03.616-.085.919a5.274 5.274 0 0 1 .434 6.92c-.894 1.164-1.654 1.475-2.386 1.741a5.27 5.27 0 0 1-3.72 3.7 5.276 5.276 0 0 1-4.002-.526 5.296 5.296 0 0 1-.756-.533A5.275 5.275 0 0 1 3.44 15.56c0-.31.029-.617.082-.92a5.284 5.284 0 0 1-1.475-3.017 5.274 5.274 0 0 1 3.427-5.645 5.275 5.275 0 0 1 3.72-3.696Zm6.36 14.9a.752.752 0 0 1-.375.65v-.001l-3.601 2.079a3.773 3.773 0 0 0 5.561-2.555v-4.709l-1.585-.914v5.45Zm-6.22.516a.752.752 0 0 1-.75 0l-3.646-2.106a3.776 3.776 0 0 0 3.775 3.743c.411 0 .82-.07 1.21-.202l4.131-2.386v-1.775l-4.72 2.726ZM13.94 8.56l-.44.253 5.141 2.969v4.538a3.777 3.777 0 0 0 1.352-5.14 3.746 3.746 0 0 0-.787-.955l-4.077-2.352-1.189.687Zm-8.58-.878a3.774 3.774 0 0 0-1.826 3.745 3.8 3.8 0 0 0 1.258 2.347L8.96 16.18l1.538-.887-4.765-2.752a.752.752 0 0 1-.374-.65V7.682Zm4.585 3.185v2.372L12 14.426l2.055-1.187v-2.372L12 9.679l-2.055 1.188Zm2.473-6.777A3.775 3.775 0 0 0 6.86 6.644v4.813l1.585.915V6.819a.753.753 0 0 1 .375-.65l3.598-2.079Zm2.868.577a3.8 3.8 0 0 0-1.222.204L9.945 7.25v1.882l5.186-2.992 3.93 2.267a3.775 3.775 0 0 0-3.775-3.741Z" clip-rule="evenodd"/></svg>';
        case 'ollama':
          return '<svg class="provider-icon" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8V7h2c.55 0 1-.45 1-1V5h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>';
        case 'anthropic':
          return '<svg class="provider-icon" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L2 7v10l10 5 10-5V7L12 2zm0 2.5L19 8l-7 3.5L5 8l7-3.5zM4 9.5l7 3.5v7l-7-3.5v-7zm16 0v7l-7 3.5v-7l7-3.5z"/></svg>';
        default:
          return '';
      }
    }

    // Populate chat dropdown from enabled models across all available providers
    function populateChatModelDropdown() {
      const dropdown = document.getElementById('modelSelectDropdown');
      const menu = document.getElementById('modelSelectMenu');
      const label = document.getElementById('modelSelectLabel');
      populateAssistantModelDropdown(dropdown, menu, label);
    }

    function populateAssistantModelDropdown(dropdown, menu, label) {
      if (!dropdown || !menu || !label) return;

      // Get available providers (those with API keys)
      const availableProviders = getAvailableProviders();

      // Always include current provider even if no API key (for display purposes)
      if (!availableProviders.includes(selectedProvider)) {
        availableProviders.unshift(selectedProvider);
      }

      // Sort providers in a consistent order: Gemini, OpenAI, Anthropic
      const providerOrder = { 'gemini': 0, 'openai': 1, 'ollama': 2, 'anthropic': 3 };
      availableProviders.sort((a, b) => {
        return (providerOrder[a] ?? 99) - (providerOrder[b] ?? 99);
      });

      menu.innerHTML = '';
      const currentModel = getCurrentModel();
      let hasAnyModels = false;

      availableProviders.forEach((provider, providerIndex) => {
        // Get enabled models for this provider
        const providerEnabledModels = enabledModels[provider] || [];
        const allModels = getAvailableModels(provider);

        // If no enabled models, show all models
        let modelsToShow = providerEnabledModels.length > 0
          ? allModels.filter(m => providerEnabledModels.includes(m))
          : allModels;

        if (provider === 'ollama' && ollamaShowLocalModelsInAssistantMenu === false) {
          modelsToShow = modelsToShow.filter(m => m !== OLLAMA_GEMMA4_MODEL_ID);
        }

        if (modelsToShow.length === 0) return;

        // Add divider between providers (except before the first one)
        if (hasAnyModels) {
          const divider = document.createElement('div');
          divider.className = 'model-select-divider';
          menu.appendChild(divider);
        }

        hasAnyModels = true;

        // Add provider header
        const header = document.createElement('div');
        header.className = 'model-select-provider-header';
        header.innerHTML = getProviderIcon(provider) + '<span>' + getProviderDisplayName(provider) + '</span>';
        menu.appendChild(header);

        // Add models for this provider
        modelsToShow.forEach(modelId => {
          const metadata = modelMetadata[provider]?.[modelId] || {};
          const displayName = metadata.displayName || modelId;

          const option = document.createElement('div');
          const isSelected = provider === selectedProvider && modelId === currentModel;
          option.className = `model-select-option ${isSelected ? 'selected' : ''}`;
          option.dataset.model = modelId;
          option.dataset.provider = provider;

          const nameSpan = document.createElement('span');
          nameSpan.className = 'model-name';
          nameSpan.textContent = displayName;

          option.appendChild(nameSpan);

          if (provider === 'ollama' && OLLAMA_LOCAL_BADGE_MODEL_IDS.has(modelId)) {
            const badge = document.createElement('span');
            badge.className = 'model-local-badge';
            badge.textContent = t('settings.models.localBadge');
            badge.title = t('settings.models.localBadgeTitle');
            option.appendChild(badge);
          }

          option.addEventListener('click', (e) => {
            e.stopPropagation();
            selectChatModel(provider, modelId);
            menu.classList.add('hidden');
            dropdown.classList.remove('open');
          });

          menu.appendChild(option);
        });
      });

      if (!hasAnyModels) {
        menu.innerHTML = '<div style="padding: var(--space-sm); color: var(--text-muted); text-align: center; font-style: italic;">No models available</div>';
        label.textContent = 'No Models';
        return;
      }

      // Update label with display name if available
      const currentMetadata = modelMetadata[selectedProvider]?.[currentModel];
      const currentDisplayName = currentMetadata?.displayName || currentModel;
      label.textContent = currentDisplayName || 'Model';
    }

    function migrateOllamaModelIfGemmaHiddenFromMenu() {
      if (ollamaShowLocalModelsInAssistantMenu !== false) return;
      if (ollamaModel !== OLLAMA_GEMMA4_MODEL_ID) return;
      const fallback = DEFAULT_OLLAMA_CHAT_MODEL;
      let next = fallback;
      if (ollamaModelSelect && ollamaModelSelect.options.length) {
        const ids = [...ollamaModelSelect.options].map(o => o.value);
        next = ids.includes(fallback) ? fallback : ids[0];
      }
      ollamaModel = next;
      if (ollamaModelSelect) ollamaModelSelect.value = next;
      if (lastSavedSettings) lastSavedSettings.ollamaModel = next;
      if (selectedProvider === 'ollama') {
        parent.postMessage({
          pluginMessage: { type: 'save-model-selection', provider: 'ollama', modelId: next }
        }, '*');
      }
    }

    function createModelSelectDropdownHTML(idPrefix) {
      return `
        <div class="model-select-dropdown" id="${idPrefix}ModelSelectDropdown">
          <button class="model-select-btn" id="${idPrefix}ModelSelectBtn" title="Select AI model">
            <span class="model-select-label" id="${idPrefix}ModelSelectLabel">Model</span>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12">
              <path d="M6 9l6 6 6-6" />
            </svg>
          </button>
          <div class="model-select-menu hidden" id="${idPrefix}ModelSelectMenu"></div>
        </div>
      `;
    }

    function setupModelSelectInPopup(popup, idPrefix, overlay = null) {
      const dropdown = popup.querySelector(`#${idPrefix}ModelSelectDropdown`);
      const menu = popup.querySelector(`#${idPrefix}ModelSelectMenu`);
      const label = popup.querySelector(`#${idPrefix}ModelSelectLabel`);
      const btn = popup.querySelector(`#${idPrefix}ModelSelectBtn`);

      if (!dropdown || !menu || !label || !btn) return;

      btn.onclick = (e) => {
        e.stopPropagation();
        const isOpen = !menu.classList.contains('hidden');
        if (isOpen) {
          menu.classList.add('hidden');
          dropdown.classList.remove('open');
        } else {
          populateAssistantModelDropdown(dropdown, menu, label);
          menu.classList.remove('hidden');
          dropdown.classList.add('open');
        }
      };

      if (overlay) {
        overlay.addEventListener('click', (e) => {
          if (dropdown && !dropdown.contains(e.target)) {
            menu.classList.add('hidden');
            dropdown.classList.remove('open');
          }
        });
      } else {
        document.addEventListener('click', (e) => {
          if (dropdown && !dropdown.contains(e.target)) {
            menu.classList.add('hidden');
            dropdown.classList.remove('open');
          }
        }, { once: true });
      }

      // Initial population
      const currentModel = getCurrentModel();
      const currentMetadata = modelMetadata[selectedProvider]?.[currentModel];
      label.textContent = currentMetadata?.displayName || currentModel || 'Model';
    }

    // Select a model from chat dropdown
    function selectChatModel(provider, modelId) {
      selectedProvider = provider;
      if (lastSavedSettings) {
        lastSavedSettings.provider = provider;
      }

      switch (provider) {
        case 'gemini':
          geminiModel = modelId;
          if (geminiModelSelect) geminiModelSelect.value = modelId;
          if (lastSavedSettings) lastSavedSettings.geminiModel = modelId;
          break;
        case 'openai':
          openaiModel = modelId;
          if (openaiModelSelect) openaiModelSelect.value = modelId;
          if (lastSavedSettings) lastSavedSettings.openaiModel = modelId;
          break;
        case 'ollama':
          ollamaModel = modelId;
          if (ollamaModelSelect) ollamaModelSelect.value = modelId;
          if (lastSavedSettings) lastSavedSettings.ollamaModel = modelId;
          break;
        case 'anthropic':
          anthropicModel = modelId;
          if (anthropicModelSelect) anthropicModelSelect.value = modelId;
          if (lastSavedSettings) lastSavedSettings.anthropicModel = modelId;
          break;
      }

      // Save model selection to client storage immediately
      parent.postMessage({
        pluginMessage: {
          type: 'save-model-selection',
          provider: provider,
          modelId: modelId
        }
      }, '*');

      // Update dropdown label with display name if available
      const metadata = modelMetadata[provider]?.[modelId];
      const displayName = metadata?.displayName || modelId;

      document.querySelectorAll('.model-select-label').forEach(lbl => {
        lbl.textContent = displayName;
      });

      // Update selected state in menu
      document.querySelectorAll('.model-select-menu').forEach(menu => {
        menu.querySelectorAll('.model-select-option').forEach(opt => {
          opt.classList.toggle('selected', opt.dataset.model === modelId && opt.dataset.provider === provider);
        });
      });

      updateChatStatus();
    }

    // Open/close model dropdown
    function toggleModelDropdown() {
      const dropdown = document.getElementById('modelSelectDropdown');
      const menu = document.getElementById('modelSelectMenu');
      if (!dropdown || !menu) return;

      const isOpen = !menu.classList.contains('hidden');
      if (isOpen) {
        closeModelDropdown();
      } else {
        openModelDropdown();
      }
    }

    function openModelDropdown() {
      const dropdown = document.getElementById('modelSelectDropdown');
      const menu = document.getElementById('modelSelectMenu');
      if (!dropdown || !menu) return;

      populateChatModelDropdown();
      menu.classList.remove('hidden');
      dropdown.classList.add('open');
    }

    function closeModelDropdown() {
      const dropdown = document.getElementById('modelSelectDropdown');
      const menu = document.getElementById('modelSelectMenu');
      if (!dropdown || !menu) return;

      menu.classList.add('hidden');
      dropdown.classList.remove('open');
    }

    function getSettingsFormState() {
      return {
        language: languageSelect?.value || DEFAULT_SETTINGS_LOCALE,
        provider: providerSelect.value || 'gemini',
        aiOffMode: noAiModeToggle?.checked === true,
        geminiApiKey: geminiApiKeyInput.value || '',
        geminiModel: geminiModelSelect.value || DEFAULT_GEMINI_CHAT_MODEL,
        openaiApiKey: openaiApiKeyInput.value || '',
        openaiModel: openaiModelSelect.value || DEFAULT_OPENAI_CHAT_MODEL,
        ollamaBaseUrl: (ollamaBaseUrlInput && ollamaBaseUrlInput.value) || DEFAULT_OLLAMA_API_BASE,
        ollamaApiKey: ollamaApiKeyInput.value || '',
        ollamaModel: ollamaModelSelect.value || DEFAULT_OLLAMA_CHAT_MODEL,
        ollamaShowLocalModelsInAssistantMenu: ollamaShowLocalModelsToggle?.checked !== false,
        anthropicApiKey: anthropicApiKeyInput.value || '',
        anthropicModel: anthropicModelSelect.value || 'claude-sonnet-4-20250514',
        cssFormat: cssFormatSelect.value || 'classes',
        quiverApiKey: quiverApiKeyInput.value || '',
        selectionSizeLimit: selectionSizeLimitSelect.value || '200',
        enabledModels: {
          gemini: deduplicateModelIds(getEnabledModels('gemini'), 'gemini'),
          openai: deduplicateModelIds(getEnabledModels('openai'), 'openai'),
          ollama: deduplicateModelIds(getEnabledModels('ollama'), 'ollama'),
          anthropic: deduplicateModelIds(getEnabledModels('anthropic'), 'anthropic')
        }
      };
    }

    function areSettingsEqual(a, b) {
      if (!a || !b) return false;
      return a.language === b.language &&
        a.provider === b.provider &&
        a.aiOffMode === b.aiOffMode &&
        a.geminiApiKey === b.geminiApiKey &&
        a.geminiModel === b.geminiModel &&
        a.openaiApiKey === b.openaiApiKey &&
        a.openaiModel === b.openaiModel &&
        a.ollamaBaseUrl === b.ollamaBaseUrl &&
        a.ollamaApiKey === b.ollamaApiKey &&
        a.ollamaModel === b.ollamaModel &&
        a.ollamaShowLocalModelsInAssistantMenu === b.ollamaShowLocalModelsInAssistantMenu &&
        a.anthropicApiKey === b.anthropicApiKey &&
        a.anthropicModel === b.anthropicModel &&
        a.cssFormat === b.cssFormat &&
        a.quiverApiKey === b.quiverApiKey &&
        String(a.selectionSizeLimit) === String(b.selectionSizeLimit);
    }

    function setSettingsDirty(isDirty) {
      settingsDirty = !!isDirty;
    }

    function refreshSettingsBaselineFromForm() {
      settingsBaseline = getSettingsFormState();
      setSettingsDirty(false);
    }

    function restoreSettingsFormFromSaved() {
      if (!lastSavedSettings) return;
      suppressSettingsDirty = true;
      if (languageSelect) {
        languageSelect.value = lastSavedSettings.language || DEFAULT_SETTINGS_LOCALE;
      }
      providerSelect.value = lastSavedSettings.provider || 'gemini';
      if (noAiModeToggle) {
        noAiModeToggle.checked = lastSavedSettings.aiOffMode === true;
      }
      geminiApiKeyInput.value = lastSavedSettings.geminiApiKey || '';
      populateGeminiModelSelect(DEFAULT_GEMINI_MODELS, lastSavedSettings.geminiModel || DEFAULT_GEMINI_CHAT_MODEL);
      openaiApiKeyInput.value = lastSavedSettings.openaiApiKey || '';
      populateOpenAIModelSelect(DEFAULT_OPENAI_MODELS, lastSavedSettings.openaiModel || DEFAULT_OPENAI_CHAT_MODEL);
      if (ollamaBaseUrlInput) ollamaBaseUrlInput.value = lastSavedSettings.ollamaBaseUrl || DEFAULT_OLLAMA_API_BASE;
      if (ollamaApiKeyInput) ollamaApiKeyInput.value = lastSavedSettings.ollamaApiKey || '';
      if (ollamaShowLocalModelsToggle) {
        ollamaShowLocalModelsToggle.checked = lastSavedSettings.ollamaShowLocalModelsInAssistantMenu !== false;
      }
      ollamaShowLocalModelsInAssistantMenu = lastSavedSettings.ollamaShowLocalModelsInAssistantMenu !== false;
      populateOllamaModelSelect(DEFAULT_OLLAMA_MODELS, lastSavedSettings.ollamaModel || DEFAULT_OLLAMA_CHAT_MODEL);
      migrateOllamaModelIfGemmaHiddenFromMenu();
      anthropicApiKeyInput.value = lastSavedSettings.anthropicApiKey || '';
      populateAnthropicModelSelect(DEFAULT_ANTHROPIC_MODELS, lastSavedSettings.anthropicModel || 'claude-sonnet-4-20250514');
      cssFormatSelect.value = lastSavedSettings.cssFormat || 'classes';
      quiverApiKeyInput.value = lastSavedSettings.quiverApiKey || '';
      selectionSizeLimitSelect.value = (lastSavedSettings.selectionSizeLimit ?? 200).toString();
      updateProviderSettingsVisibility();
      applySettingsLocale(languageSelect?.value || lastSavedSettings.language || DEFAULT_SETTINGS_LOCALE);
      suppressSettingsDirty = false;
      syncQuickSettingsMenusFromForm();
      refreshSettingsBaselineFromForm();

      // Populate checklists
      const geminiModels = getAvailableModels('gemini');
      const openaiModels = getAvailableModels('openai');
      const anthropicModels = getAvailableModels('anthropic');
      const savedEnabledModels = lastSavedSettings?.enabledModels || enabledModels;
      populateModelChecklist('gemini', geminiModels.length > 0 ? geminiModels : DEFAULT_GEMINI_MODELS, savedEnabledModels.gemini);
      populateModelChecklist('openai', openaiModels, savedEnabledModels.openai);
      const ollamaModels = getAvailableModels('ollama');
      populateModelChecklist('ollama', ollamaModels, savedEnabledModels.ollama);
      populateModelChecklist('anthropic', anthropicModels, savedEnabledModels.anthropic);

      refreshGeminiModelList({
        apiKey: geminiApiKeyInput.value,
        preferredModel: geminiModelSelect.value,
        silent: true
      }).then(refreshSettingsBaselineFromForm).catch(() => { });

      refreshOpenAIModelList({
        apiKey: openaiApiKeyInput.value,
        preferredModel: openaiModelSelect.value,
        silent: true
      }).then(refreshSettingsBaselineFromForm).catch(() => { });

      refreshOllamaModelList({
        preferredModel: ollamaModelSelect ? ollamaModelSelect.value : ollamaModel,
        silent: true
      }).then(refreshSettingsBaselineFromForm).catch(() => { });

      refreshAnthropicModelList({
        apiKey: anthropicApiKeyInput.value,
        preferredModel: anthropicModelSelect.value,
        silent: true
      }).then(refreshSettingsBaselineFromForm).catch(() => { });
    }

    function handleSettingsChanged() {
      if (suppressSettingsDirty) return;
      if (!settingsBaseline) {
        refreshSettingsBaselineFromForm();
        return;
      }
      setSettingsDirty(!areSettingsEqual(settingsBaseline, getSettingsFormState()));
    }

    // Helper to get current model based on provider
    function getCurrentModel() {
      switch (selectedProvider) {
        case 'gemini': return geminiModel;
        case 'openai': return openaiModel;
        case 'ollama': return ollamaModel;
        case 'anthropic': return anthropicModel;
        default: return '';
      }
    }

    // Default name detection for Smart rename suggestions
    function hasDefaultName(nodeName, nodeType) {
      if (!nodeName) return false;

      // Common default patterns in multiple languages
      const baseDefaultPatterns = [
        // English
        /^(Frame|Group|Rectangle|Ellipse|Polygon|Star|Line|Vector|Text|Component|Instance|Boolean|Section)\s+\d+$/i,
        // Japanese (フレーム, グループ, 矩形, 楕円, etc.)
        /^(フレーム|グループ|矩形|楕円|多角形|星|線|ベクター|テキスト|コンポーネント|インスタンス|セクション)\s*\d+$/i,
        // Chinese Simplified (框架, 组, 矩形, 椭圆, etc.)
        /^(框架|组|矩形|椭圆|多边形|星形|线条|矢量|文本|组件|实例|部分)\s*\d+$/i,
        // Chinese Traditional
        /^(框架|組|矩形|橢圓|多邊形|星形|線條|矢量|文本|組件|實例|部分)\s*\d+$/i,
        // Korean (프레임, 그룹, 사각형, 타원, etc.)
        /^(프레임|그룹|사각형|타원|다각형|별|선|벡터|텍스트|컴포넌트|인스턴스|섹션)\s*\d+$/i,
        // Spanish
        /^(Marco|Grupo|Rectángulo|Elipse|Polígono|Estrella|Línea|Vector|Texto|Componente|Instancia|Sección)\s+\d+$/i,
        // French
        /^(Cadre|Groupe|Rectangle|Ellipse|Polygone|Étoile|Ligne|Vecteur|Texte|Composant|Instance|Section)\s+\d+$/i,
        // German
        /^(Rahmen|Gruppe|Rechteck|Ellipse|Polygon|Stern|Linie|Vektor|Text|Komponente|Instanz|Abschnitt)\s+\d+$/i,
      ];

      // Check if it's a simple default name
      if (baseDefaultPatterns.some(pattern => pattern.test(nodeName.trim()))) return true;

      // Check if it's a variant name (Property 1=Frame 47695)
      // This pattern also matches the default property name "Property 1"
      if (nodeName.includes('=')) {
        const parts = nodeName.split('=');
        const valuePart = parts[1] ? parts[1].trim() : '';
        const propPart = parts[0] ? parts[0].trim() : '';

        // If it's "Property 1=Value" where "Property 1" is default
        if (/^Property\s+\d+$/i.test(propPart)) return true;

        // If it's "Prop=Frame 123" where value is default
        if (baseDefaultPatterns.some(pattern => pattern.test(valuePart))) return true;
      } else {
        // Direct property name check for component sets (e.g. "Property 1")
        if (/^Property\s+\d+$/i.test(nodeName.trim())) return true;
      }

      return false;
    }

    // DOM Elements
    const selectionInfo = byId('selectionInfo');
    const selectionCount = byId('selectionCount');
    const selectionNames = byId('selectionNames');
    const nodeActionsContainer = byId('nodeActionsContainer');
    const nodeActionsContent = query('.node-actions-content');
    const auditInputActions = byId('auditInputActions');

    // Update node actions content based on available actions
    function updateNodeActionsContent(items) {
      if (!nodeActionsContent || !items) return;

      const hasAnyDefault = items.some(item => hasDefaultName(item.name, item.type));
      const hasImageFill = items.some(item => item.hasImageFill === true);
      const isSingleImage = items.length === 1 && items[0].hasImageFill;

      let html = '';

      // Always include "New Chat" button when node actions are shown
      html += `
        <button class="node-action-btn" id="newChatNodeBtn" data-action="new-chat" data-action-label="New chat">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <path d="M12 5v14M5 12h14" />
          </svg>
          <span>${localizeActionString('New chat')}</span>
        </button>
      `;

      // Last used quick actions (most recent up to MAX_LAST_USED_ACTIONS)
      // Only show if we actually have last used actions or if usage has been loaded
      const lastUsed = (typeof getMostUsedQuickActions === 'function' && lastUsedQuickActions.length > 0)
        ? getMostUsedQuickActions(MAX_LAST_USED_ACTIONS)
        : [];
      lastUsed.forEach((action, idx) => {
        const isDisabled = !isTaskAvailableInAiOff(action.task, action.name);
        const disabledClass = isDisabled ? ' ai-disabled' : '';
        const disabledAttrs = isDisabled ? ' aria-disabled="true" tabindex="-1"' : '';
        const title = isDisabled
          ? getAiOffBlockedMessage(action.name || 'Quick action')
          : localizeActionString(action.desc || action.name);
        const customActions = action.isCustomQuickAction ? `
          <div class="command-item-custom-actions node-action-custom-actions">
            <button class="command-item-custom-trigger" data-custom-popover-trigger="${escapeHtml(action.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.moreActionsTitle'))}" aria-haspopup="menu" aria-expanded="false">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <circle cx="12" cy="5" r="1.5"/>
                <circle cx="12" cy="12" r="1.5"/>
                <circle cx="12" cy="19" r="1.5"/>
              </svg>
            </button>
            <div class="command-item-custom-popover" role="menu">
              <button class="dropdown-item" data-custom-action="edit" data-custom-action-id="${escapeHtml(action.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.editTitle'))}">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                  <path d="M12 20h9"/>
                  <path d="M16.5 3.5a2.121 2.121 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5Z"/>
                </svg>
                <span>${escapeHtml(tu('actions.option.edit'))}</span>
              </button>
              <button class="dropdown-item" data-custom-action="duplicate" data-custom-action-id="${escapeHtml(action.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.duplicateTitle'))}">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                  <rect x="9" y="9" width="13" height="13" rx="2"/>
                  <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/>
                </svg>
                <span>${escapeHtml(tu('actions.option.duplicate'))}</span>
              </button>
              <button class="dropdown-item dropdown-item-danger" data-custom-action="delete" data-custom-action-id="${escapeHtml(action.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.deleteTitle'))}">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                  <path d="M3 6h18"/>
                  <path d="M8 6V4a1 1 0 0 1 1-1h6a1 1 0 0 1 1 1v2"/>
                  <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
                  <path d="M10 11v6M14 11v6"/>
                </svg>
                <span>${escapeHtml(tu('actions.option.remove'))}</span>
              </button>
            </div>
          </div>
        ` : '';
        html += action.isCustomQuickAction ? `
          <div class="node-action-btn last-used-action-btn node-action-btn--custom${disabledClass}" data-last-used-index="${idx}" data-action-label="${escapeHtml(action.name || '')}" title="${escapeHtml(title)}" data-ai-disabled="${isDisabled ? 'true' : 'false'}" role="button"${disabledAttrs}>
              ${action.icon || defaultActionIcon}
              <span>${escapeHtml(localizeActionString(action.name || ''))}</span>
              ${customActions}
          </div>
        ` : `
          <button class="node-action-btn last-used-action-btn${disabledClass}" data-last-used-index="${idx}" data-action-label="${escapeHtml(action.name || '')}" title="${escapeHtml(title)}" data-ai-disabled="${isDisabled ? 'true' : 'false'}"${disabledAttrs}>
            ${action.icon || defaultActionIcon}
            <span>${escapeHtml(localizeActionString(action.name || ''))}</span>
          </button>
        `;
      });

      if (currentMode === 'ask') {
        // Always allow summarizing selection if something is selected
        html += `
          <button class="node-action-btn" id="summarizeSelectionBtn" data-action="summarize-selection" data-action-label="Summarize selection">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
              <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z" />
              <path d="M8 9h8M8 13h5" />
            </svg>
            <span>${localizeActionString('Summarize selection')}</span>
          </button>
        `;
        // In Ask mode, allow extracting prompt if it's an image
        if (isSingleImage) {
          html += `
            <button class="node-action-btn" id="extractPromptBtn" data-action="extract-prompt" data-action-label="Extract prompt">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2">
                <path d="M21 11.929V5a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h4.766"/>
                <path d="M14.5 10a1.5 1.5 0 1 0 0-3 1.5 1.5 0 0 0 0 3Z"/>
                <path d="m3 15 4.292-4.293a1 1 0 0 1 1.415 0l3.596 3.597"/>
                <path d="M13.309 19h8.666m0 0-4-4m4 4-4 4"/>
              </svg>
              <span>${localizeActionString('Extract prompt')}</span>
            </button>
          `;
        }
        // In Ask mode, allow editing image when selection contains image node(s)
        if (hasImageFill) {
          html += `
            <button class="node-action-btn" id="generateImageBtn" data-action="generate-image" data-action-label="Edit image">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M21 8.929V5a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h3.766"/>
                <path d="M14.5 10a1.5 1.5 0 1 0 0-3 1.5 1.5 0 0 0 0 3Z"/>
                <path d="m3 15 4.292-4.293a1 1 0 0 1 1.415 0l3.596 3.597"/>
                <path d="M19.253 12.488c.182-.182.31-.24.547-.338a1.956 1.956 0 0 1 2.13.421 1.946 1.946 0 0 1 .422 2.131 1.962 1.962 0 0 1-.425.635l-6.314 6.311a.906.906 0 0 1-.42.238l-1.975.495a.905.905 0 0 1-1.098-1.097l.495-1.976a.905.905 0 0 1 .238-.42l6.4-6.4Z"/>
              </svg>

              <span>${localizeActionString('Edit image')}</span>
            </button>
          `;
        }
      } else if (currentMode === 'agent') {
        if (hasAnyDefault) {
          html += `
            <button class="node-action-btn" id="smartRenameBtn" data-action="smart-rename" data-action-label="Smart rename">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <rect x="3" y="3" width="7" height="7" rx="1"/>
                <rect x="14" y="3" width="7" height="7" rx="1"/>
                <rect x="3" y="14" width="7" height="7" rx="1"/>
                <path d="M14 14h7M14 17h4M14 20h2"/>
                <path d="M10 6h4M6 10v4"/>
              </svg>
              <span>${localizeActionString('Smart rename')}</span>
            </button>
          `;
        }

        if (isSingleImage) {
          html += `
            <button class="node-action-btn" id="extractPromptBtn" data-action="extract-prompt" data-action-label="Extract prompt">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-linecap="round" stroke-linejoin="round" stroke-width="2">
                <path d="M21 11.929V5a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h4.766"/>
                <path d="M14.5 10a1.5 1.5 0 1 0 0-3 1.5 1.5 0 0 0 0 3Z"/>
                <path d="m3 15 4.292-4.293a1 1 0 0 1 1.415 0l3.596 3.597"/>
                <path d="M13.309 19h8.666m0 0-4-4m4 4-4 4"/>
              </svg>
              <span>${localizeActionString('Extract prompt')}</span>
            </button>
          `;
        }

        if (hasImageFill) {
          html += `
            <button class="node-action-btn" id="generateImageBtn" data-action="generate-image" data-action-label="Edit image">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M21 8.929V5a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h3.766"/>
                <path d="M14.5 10a1.5 1.5 0 1 0 0-3 1.5 1.5 0 0 0 0 3Z"/>
                <path d="m3 15 4.292-4.293a1 1 0 0 1 1.415 0l3.596 3.597"/>
                <path d="M19.253 12.488c.182-.182.31-.24.547-.338a1.956 1.956 0 0 1 2.13.421 1.946 1.946 0 0 1 .422 2.131 1.962 1.962 0 0 1-.425.635l-6.314 6.311a.906.906 0 0 1-.42.238l-1.975.495a.905.905 0 0 1-1.098-1.097l.495-1.976a.905.905 0 0 1 .238-.42l6.4-6.4Z"/>
              </svg>
              <span>${localizeActionString('Edit image')}</span>
            </button>
          `;
        }
      }

      nodeActionsContent.innerHTML = html;

      // Re-attach event listeners for last used actions
      const lastUsedActionBtns = nodeActionsContent.querySelectorAll('.last-used-action-btn');
      lastUsedActionBtns.forEach(btn => {
        btn.addEventListener('click', () => {
          if (btn.dataset.aiDisabled === 'true') {
            showToast(btn.title || getAiOffBlockedMessage('Quick action'), 'error');
            return;
          }
          const idx = parseInt(btn.dataset.lastUsedIndex);
          if (!Number.isNaN(idx) && lastUsed[idx]) {
            triggerSlashAction(lastUsed[idx]);
          }
        });
        btn.addEventListener('keydown', (event) => {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            btn.click();
          }
        });
      });

      nodeActionsContent.querySelectorAll('[data-custom-popover-trigger]').forEach((button) => {
        button.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          const actionId = button.dataset.customPopoverTrigger;
          const container = button.closest('.command-item-custom-actions');
          if (!actionId || !container) return;
          const shouldOpen = openCustomActionPopoverId !== actionId;
          closeCommandItemPopover();
          if (shouldOpen) {
            openCustomActionPopoverId = actionId;
            container.classList.add('is-open');
            nodeActionsContent.classList.add('has-open-custom-menu');
            button.setAttribute('aria-expanded', 'true');
          } else {
            button.setAttribute('aria-expanded', 'false');
          }
        });
      });

      nodeActionsContent.querySelectorAll('[data-custom-action]').forEach((button) => {
        button.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          closeCommandItemPopover();
          const { customAction, customActionId } = button.dataset;
          if (!customActionId) return;
          if (customAction === 'edit') {
            editCustomQuickAction(customActionId);
          } else if (customAction === 'duplicate') {
            duplicateCustomQuickAction(customActionId);
          } else if (customAction === 'delete') {
            deleteCustomQuickAction(customActionId);
          }
        });
      });

      // Re-attach event listeners
      const newChatNodeBtn = document.getElementById('newChatNodeBtn');
      if (newChatNodeBtn) {
        newChatNodeBtn.addEventListener('click', startNewChat);
      }

      const summarizeSelectionBtn = document.getElementById('summarizeSelectionBtn');
      if (summarizeSelectionBtn) {
        summarizeSelectionBtn.addEventListener('click', () => {
          chatInput.value = 'Summarize these selected elements';
          sendMessage();
        });
      }

      const smartRenameBtn = document.getElementById('smartRenameBtn');
      if (smartRenameBtn) {
        smartRenameBtn.addEventListener('click', () => {
          chatInput.value = '/smart-rename';
          sendMessage();
        });
      }

      const extractPromptBtn = document.getElementById('extractPromptBtn');
      if (extractPromptBtn) {
        extractPromptBtn.addEventListener('click', async () => {
          // Find the Extract prompt from image task
          let extractTask = null;
          for (const [category, tasks] of Object.entries(agentTasks)) {
            extractTask = tasks.find(task => task.name === 'Extract prompt from image');
            if (extractTask) break;
          }

          if (extractTask) {
            const icon = getActionIconForTask(extractTask, 'Accessibility & Quality') || '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg>';
            await handleExtractImagePrompt(extractTask.name, icon);
          } else {
            showToast('Extract prompt task not found', 'error');
          }
        });
      }

      const generateImageBtn = document.getElementById('generateImageBtn');
      if (generateImageBtn) {
        generateImageBtn.addEventListener('click', async () => {
          // Find the Generate image task
          let generateTask = null;
          for (const [category, tasks] of Object.entries(agentTasks)) {
            generateTask = tasks.find(task => task.name === 'Generate image');
            if (generateTask) break;
          }

          if (generateTask) {
            const icon = getActionIconForTask(generateTask, 'Content Creation') || '🖼️';
            await handleGenerateImageWithReference(generateTask.name, icon);
          } else {
            showToast('Generate image task not found', 'error');
          }
        });
      }

    }

    function refreshAuditInputActions() {
      if (!auditInputActions) return;
      const isAuditMode = currentMode === 'audit';
      auditInputActions.classList.toggle('hidden', !isAuditMode);
    }

    function openAuditSettingsModal() {
      if (auditModal) {
        auditModal.classList.add('show');
      }
    }

    function triggerAuditSelection() {
      if (isAIThinking) {
        showToast('Please wait for the current response to finish.', 'warning');
        return;
      }

      if (!lastKnownSelectionItems || lastKnownSelectionItems.length === 0) {
        showToast('Please select an element first', 'error');
        return;
      }

      setMode('audit');
      chatInput.value = 'Run audit on current selection';
      chatInput.style.height = 'auto';
      sendMessage();
    }

    function handleSelectionChange(items) {
      if (!items) return;
      lastKnownSelectionItems = items;
      selectionCount.textContent = items.length;
      const selectionSignature = items.map(i => i.id).join(',');
      if (selectionSignature !== lastSelectionSignature) {
        lastSelectionSignature = selectionSignature;
        selectionDescendantsById = new Map();
        selectionDescendantsTruncated = false;
        selectionTooLargeForDescendants = false;
        pendingSelectionDescendantsSignature = '';
      }

      if (lastFillFromOnlineParams) {
        lastFillFromOnlineParams = null;
      }

      // Update comments list if in selection scope
      if (currentCommentsScope === 'selection') {
        const container = document.getElementById('promptCommentsContainer');
        if (container && container.offsetParent !== null) { // only if visible
          const listContainer = document.getElementById('promptCommentsListContainer');
          if (listContainer) updateCommentsListOnly(); // Prefer updateCommentsListOnly for smoother update
          else renderCommentsInDrawer(container);
        }
        requestSelectionDescendantsIfNeeded(false);
      }

      // Update Create Graph selection size when drawer is open
      if (promptDrawer.classList.contains('open') && currentPromptAction && currentPromptAction.name === 'Create Graph') {
        if (chartSizeUpdateTimeout) clearTimeout(chartSizeUpdateTimeout);
        chartSizeUpdateTimeout = setTimeout(() => {
          parent.postMessage({ pluginMessage: { type: 'get-selection-bounding-box' } }, '*');
        }, 200);
      }

      if (promptDrawer.classList.contains('open') && currentPromptAction?.directAction === 'imageTo4PointVector') {
        if (imageTo4PointQuadPreviewTimeout) clearTimeout(imageTo4PointQuadPreviewTimeout);
        imageTo4PointQuadPreviewTimeout = setTimeout(() => {
          imageTo4PointQuadPreviewTimeout = null;
          refreshImageTo4PointQuadPreview();
        }, 120);
      }

      if (promptDrawer.classList.contains('open') && currentPromptAction?.name === 'Adjust length') {
        updateAdjustLengthDrawerMetrics();
      }

      // Trigger a background update of selection data size for the token counter
      // Caching: Only request if selection IDs have changed to avoid freezing on simple drags
      const currentIds = items.map(i => i.id).join(',');
      if (currentIds !== lastSelectionIdString && isTokenCounterEnabled) {
        lastSelectionIdString = currentIds;
        if (tokenUpdateTimeout) clearTimeout(tokenUpdateTimeout);
        if (items.length > 0) {
          // Longer debounce for data-heavy serialization
          tokenUpdateTimeout = setTimeout(() => {
            parent.postMessage({ pluginMessage: { type: 'get-selection-data', allowEmpty: true } }, '*');
          }, 1200);
        } else {
          currentSelectionDataSize = 0;
          updateTokenCount();
        }
      }

      // Check if any node has image fill
      const hasImageFill = items.some(item => item.hasImageFill === true);
      const hasAnyDefault = items.some(item => hasDefaultName(item.name, item.type));

      // Update all Figma buttons in image upload fields
      const containers = document.querySelectorAll('.prompt-image-upload-container');
      containers.forEach(container => {
        updateFigmaButtonsVisibility(container, items.length);
      });

      // Also update static ones if any
      const staticWrappers = document.querySelectorAll('.prompt-add-figma-wrapper');
      staticWrappers.forEach(wrapper => {
        if (items.length === 1) {
          wrapper.dataset.selectionCount = '1';
        } else if (items.length > 1) {
          wrapper.dataset.selectionCount = 'many';
        } else {
          wrapper.dataset.selectionCount = '0';
        }
      });

      if (items.length === 0) {
        selectionNames.textContent = t('settings.header.nothingSelected');
        // Always show node actions container even when nothing is selected
        // It will contain "New Chat" and "Last used" actions
        nodeActionsContainer.classList.remove('hidden');
        updateNodeActionsContent(items);
      } else {
        if (items.length === 1) {
          selectionNames.textContent = items[0].name;
        } else if (items.length > 12) {
          selectionNames.textContent = `${items.length} layers selected`;
        } else {
          selectionNames.textContent = items.map(i => i.name).join(', ');
        }

        // Toggle node actions container visibility - now always show if we have actions
        nodeActionsContainer.classList.remove('hidden');

        updateNodeActionsContent(items);

        // Toggle highlight on plus button and Copy Image menu item if any image is selected
        if (hasImageFill) {
          plusBtn.classList.add('highlight');
          const pngExportItem = exportMenu.querySelector('[data-export="png"]');
          if (pngExportItem) pngExportItem.classList.add('highlight');
        } else {
          plusBtn.classList.remove('highlight');
          const pngExportItem = exportMenu.querySelector('[data-export="png"]');
          if (pngExportItem) pngExportItem.classList.remove('highlight');
        }
      }

      if (promptDrawer.classList.contains('open')) {
        applyPromptFieldVisibility();
      }
    }

    function flattenSelectionNodes(items = []) {
      const out = [];
      const walk = (node) => {
        if (!node || typeof node !== 'object') return;
        out.push(node);
        if (Array.isArray(node.children)) {
          node.children.forEach(walk);
        }
      };
      items.forEach(walk);
      return out;
    }

    function getFirstSelectedTextNode(items = lastKnownSelectionItems || []) {
      const nodes = flattenSelectionNodes(items);
      return nodes.find((node) => node && node.type === 'TEXT' && typeof node.characters === 'string') || null;
    }

    function isAdjustLengthPromptOpen() {
      return promptDrawer.classList.contains('open') && currentPromptAction?.name === 'Adjust length';
    }

    function adjustLengthIsCjkChar(char) {
      if (!char) return false;
      const code = char.codePointAt(0) || 0;
      return (
        (code >= 0x4E00 && code <= 0x9FFF) ||
        (code >= 0x3400 && code <= 0x4DBF) ||
        (code >= 0x3040 && code <= 0x309F) ||
        (code >= 0x30A0 && code <= 0x30FF) ||
        (code >= 0xAC00 && code <= 0xD7AF) ||
        (code >= 0x1100 && code <= 0x11FF) ||
        (code >= 0x3130 && code <= 0x318F)
      );
    }

    function adjustLengthAnalyzeText(text) {
      const rawText = String(text || '').replace(/\r/g, '');
      const visibleChars = Array.from(rawText).filter((char) => !/\s/.test(char));

      let kanjiCount = 0;
      let hiraganaCount = 0;
      let katakanaCount = 0;
      let hangulCount = 0;
      let alphabetCount = 0;
      let numberCount = 0;

      visibleChars.forEach((char) => {
        const code = char.codePointAt(0) || 0;
        if ((code >= 0x4E00 && code <= 0x9FFF) || (code >= 0x3400 && code <= 0x4DBF)) {
          kanjiCount += 1;
          return;
        }
        if (code >= 0x3040 && code <= 0x309F) {
          hiraganaCount += 1;
          return;
        }
        if (code >= 0x30A0 && code <= 0x30FF) {
          katakanaCount += 1;
          return;
        }
        if ((code >= 0xAC00 && code <= 0xD7AF) || (code >= 0x1100 && code <= 0x11FF) || (code >= 0x3130 && code <= 0x318F)) {
          hangulCount += 1;
          return;
        }
        if (/[A-Za-z]/.test(char)) {
          alphabetCount += 1;
          return;
        }
        if (/[0-9０-９]/.test(char)) {
          numberCount += 1;
        }
      });

      const cjkCount = kanjiCount + hiraganaCount + katakanaCount + hangulCount;
      const normalizedWordCount = rawText.trim()
        ? rawText.trim().split(/\s+/).filter(Boolean).length
        : 0;
      const dominantCjk = cjkCount > 0 && cjkCount >= alphabetCount;

      const typeParts = [];
      if (kanjiCount > 0) typeParts.push('漢字');
      if (hiraganaCount > 0) typeParts.push('あぁ');
      if (katakanaCount > 0) typeParts.push('アァ');
      if (hangulCount > 0) typeParts.push('한글');
      if (alphabetCount > 0) typeParts.push('Aa');
      if (numberCount > 0) typeParts.push('0-9');

      return {
        rawText,
        visibleChars,
        kanjiCount,
        hiraganaCount,
        katakanaCount,
        hangulCount,
        alphabetCount,
        numberCount,
        cjkCount,
        normalizedWordCount,
        dominantCjk,
        countUnit: dominantCjk ? 'character' : 'word',
        currentCount: dominantCjk ? visibleChars.length : normalizedWordCount,
        typeLabel: typeParts.length ? typeParts.join('、') : 'Mixed'
      };
    }

    function adjustLengthParseLetterSpacingPx(textNode) {
      const value = textNode?.letterSpacing;
      const fontSize = typeof textNode?.fontSize === 'number' ? textNode.fontSize : 16;
      if (typeof value === 'number') return value;
      if (value && typeof value === 'object') {
        if (value.unit === 'PIXELS') return Number(value.value) || 0;
        if (value.unit === 'PERCENT') return fontSize * ((Number(value.value) || 0) / 100);
      }
      return 0;
    }

    function adjustLengthParseLineHeightPx(textNode) {
      const fontSize = typeof textNode?.fontSize === 'number' ? textNode.fontSize : 16;
      const value = textNode?.lineHeight;
      if (typeof value === 'number') return fontSize * value;
      if (value && typeof value === 'object') {
        if (value.unit === 'PIXELS') return Number(value.value) || fontSize * 1.2;
        if (value.unit === 'PERCENT') return fontSize * ((Number(value.value) || 120) / 100);
      }
      return fontSize * 1.2;
    }

    function adjustLengthCharWidth(textNode, char) {
      const fontSize = typeof textNode?.fontSize === 'number' ? textNode.fontSize : 16;
      const letterSpacing = adjustLengthParseLetterSpacingPx(textNode);
      if (!char || /\s/.test(char)) return Math.max(1, fontSize * 0.35);
      if (adjustLengthIsCjkChar(char) || (char.codePointAt(0) || 0) > 255) return fontSize + letterSpacing;
      if (/[A-Za-z0-9]/.test(char)) return fontSize * 0.5 + letterSpacing;
      return fontSize * 0.6 + letterSpacing;
    }

    function adjustLengthSimulateRenderedLines(textNode) {
      const text = String(textNode?.characters || '').replace(/\r/g, '');
      const paragraphs = text.split('\n');
      if (!paragraphs.length) return 1;
      if (textNode?.textAutoResize === 'WIDTH_AND_HEIGHT') return paragraphs.length;

      const availableWidth = Math.max(1, Number(textNode?.width) || 1);
      let renderedLines = 0;

      paragraphs.forEach((paragraph) => {
        if (!paragraph) {
          renderedLines += 1;
          return;
        }
        let currentWidth = 0;
        let currentLines = 1;
        let currentToken = '';
        let currentTokenWidth = 0;

        const flushToken = () => {
          if (!currentToken) return;
          if (currentWidth > 0 && currentWidth + currentTokenWidth > availableWidth) {
            currentLines += 1;
            currentWidth = 0;
          }
          currentWidth += currentTokenWidth;
          currentToken = '';
          currentTokenWidth = 0;
        };

        for (const char of Array.from(paragraph)) {
          if (/\s/.test(char)) {
            flushToken();
            continue;
          }

          const width = adjustLengthCharWidth(textNode, char);
          if (adjustLengthIsCjkChar(char)) {
            flushToken();
            if (currentWidth > 0 && currentWidth + width > availableWidth) {
              currentLines += 1;
              currentWidth = 0;
            }
            currentWidth += width;
            continue;
          }

          currentToken += char;
          currentTokenWidth += width;

          if (currentTokenWidth > availableWidth && currentToken.length > 1) {
            const lastChar = currentToken.slice(-1);
            const lastWidth = adjustLengthCharWidth(textNode, lastChar);
            currentToken = lastChar;
            currentTokenWidth = lastWidth;
            flushToken();
          }
        }

        flushToken();
        renderedLines += currentLines;
      });

      return Math.max(1, renderedLines);
    }

    function buildAdjustLengthMetrics(textNode) {
      if (!textNode) return null;
      const analysis = adjustLengthAnalyzeText(textNode.characters || '');
      const { visibleChars } = analysis;

      const renderedLines = adjustLengthSimulateRenderedLines(textNode);
      const explicitLines = String(textNode.characters || '').replace(/\r/g, '').split('\n').length;
      const fontSize = typeof textNode.fontSize === 'number' ? textNode.fontSize : 16;
      const lineHeightPx = adjustLengthParseLineHeightPx(textNode);
      const maxLines = textNode.textAutoResize === 'NONE'
        ? Math.max(1, Math.floor((Number(textNode.height) || lineHeightPx) / lineHeightPx))
        : renderedLines;

      const charsPerLineBase = analysis.dominantCjk
        ? Math.max(1, Math.floor((Number(textNode.width) || fontSize) / (fontSize + adjustLengthParseLetterSpacingPx(textNode))))
        : Math.max(1, Math.floor((Number(textNode.width) || fontSize) / (fontSize * 0.5 + adjustLengthParseLetterSpacingPx(textNode))));
      const estimatedMaxChars = Math.max(visibleChars.length, charsPerLineBase * Math.max(renderedLines, maxLines));

      return {
        types: analysis.typeLabel,
        charsPerLine: charsPerLineBase,
        totalChars: visibleChars.length,
        wordCount: analysis.normalizedWordCount,
        countUnit: analysis.countUnit,
        targetCountCurrent: analysis.currentCount,
        estimatedMaxChars,
        remainingChars: Math.max(0, estimatedMaxChars - visibleChars.length),
        currentLines: renderedLines,
        explicitLines,
        textAutoResize: textNode.textAutoResize || 'NONE'
      };
    }

    function buildAdjustLengthPromptContext(values, textNode = getFirstSelectedTextNode()) {
      if (!textNode) return { ...values };

      const metrics = buildAdjustLengthMetrics(textNode);
      if (!metrics) return { ...values };

      const countUnitPlural = metrics.countUnit === 'character' ? 'characters' : 'words';
      const currentCountSummary = `${metrics.targetCountCurrent} ${countUnitPlural}`;
      const currentLengthMetricsSummary = [
        `Measured node info: text kinds ${metrics.types}.`,
        `Current count: ${currentCountSummary}.`,
        `Current rendered lines: ${metrics.currentLines}.`,
        `Characters per line estimate: ${metrics.charsPerLine}.`,
        `Estimated max visible characters in this node: ${metrics.estimatedMaxChars}.`,
        `Remaining estimated visible characters before overflow: ${metrics.remainingChars}.`,
        `Explicit line breaks: ${metrics.explicitLines}.`,
        `Text auto resize: ${metrics.textAutoResize}.`
      ].join(' ');

      return {
        ...values,
        currentCountUnit: metrics.countUnit,
        currentCountUnitPlural: countUnitPlural,
        currentCountValue: metrics.targetCountCurrent,
        currentCountSummary,
        currentRenderedLines: metrics.currentLines,
        currentExplicitLines: metrics.explicitLines,
        currentCharsPerLine: metrics.charsPerLine,
        currentEstimatedMaxChars: metrics.estimatedMaxChars,
        currentRemainingChars: metrics.remainingChars,
        currentTextKinds: metrics.types,
        currentWordCount: metrics.wordCount,
        currentVisibleCharCount: metrics.totalChars,
        currentLengthMetricsSummary
      };
    }

    function ensureAdjustLengthMetricsContainer() {
      if (!isAdjustLengthPromptOpen()) return null;
      let el = document.getElementById('adjustLengthMetrics');
      if (el) return el;
      el = document.createElement('div');
      el.id = 'adjustLengthMetrics';
      el.className = 'adjust-length-metrics';
      promptDrawerFields.prepend(el);
      return el;
    }

    function updateAdjustLengthDrawerMetrics() {
      const container = ensureAdjustLengthMetricsContainer();
      if (!container) return;
      const textNode = getFirstSelectedTextNode();
      const metrics = buildAdjustLengthMetrics(textNode);

      if (!metrics) {
        container.innerHTML = `
          <div class="adjust-length-metrics-title">Live text metrics</div>
          <div class="adjust-length-metrics-subtitle">Select a text node to see real-time length guidance for this action.</div>
        `;
        return;
      }

      const subtitle = metrics.explicitLines !== metrics.currentLines
        ? `Rendered lines: ${metrics.currentLines} (explicit breaks: ${metrics.explicitLines}, auto resize: ${escapeHtml(String(metrics.textAutoResize))})`
        : `Auto resize: ${escapeHtml(String(metrics.textAutoResize))}`;

      container.innerHTML = `
        <div class="adjust-length-metrics-title">Live text metrics</div>
        <div class="adjust-length-metrics-subtitle">${subtitle}</div>
        <div class="adjust-length-metrics-grid">
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">文字の種類</span>
            <span class="adjust-length-metrics-value">${escapeHtml(metrics.types)}</span>
          </div>
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">1行あたりの文字数</span>
            <span class="adjust-length-metrics-value">${metrics.charsPerLine}</span>
          </div>
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">総文字数</span>
            <span class="adjust-length-metrics-value">${metrics.totalChars}</span>
          </div>
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">最大推定文字数</span>
            <span class="adjust-length-metrics-value">${metrics.estimatedMaxChars}</span>
          </div>
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">残り文字数</span>
            <span class="adjust-length-metrics-value">${metrics.remainingChars}</span>
          </div>
          <div class="adjust-length-metrics-row">
            <span class="adjust-length-metrics-label">現在の行数</span>
            <span class="adjust-length-metrics-value">${metrics.currentLines}</span>
          </div>
        </div>
      `;
    }

    function getSelectionDescendantsSignature(items = lastKnownSelectionItems || []) {
      if (!Array.isArray(items) || items.length === 0) return '';
      return items.map((node) => node?.id).filter(Boolean).join(',');
    }

    function addSelectionNodeAndDescendantIds(selectedIds, selectedNodes = lastKnownSelectionItems || []) {
      (selectedNodes || []).forEach((node) => {
        if (!node || !node.id) return;
        selectedIds.add(node.id);
        if (Array.isArray(node.descendantIds) && node.descendantIds.length > 0) {
          node.descendantIds.forEach((id) => selectedIds.add(id));
          return;
        }
        const cachedIds = selectionDescendantsById.get(node.id);
        if (Array.isArray(cachedIds)) {
          cachedIds.forEach((id) => selectedIds.add(id));
        }
      });
    }

    function requestSelectionDescendantsIfNeeded(force = false) {
      const needsDescendants =
        currentCommentsScope === 'selection' ||
        currentStickiesScope === 'selection' ||
        (currentPromptAction?.directAction === 'listAllComponents' && currentComponentsScope === 'selection') ||
        (currentPromptAction?.directAction === 'listAllStickies' && currentStickiesScope === 'selection');
      if (!needsDescendants) return;
      const signature = getSelectionDescendantsSignature();
      if (!signature) return;
      if (!force && (selectionTooLargeForDescendants || selectionDescendantsTruncated)) return;
      if (!force && pendingSelectionDescendantsSignature === signature) return;
      const hasAllDescendants = (lastKnownSelectionItems || []).every((node) =>
        Array.isArray(node?.descendantIds) || selectionDescendantsById.has(node?.id)
      );
      if (!force && hasAllDescendants) return;
      pendingSelectionDescendantsSignature = signature;
      parent.postMessage({ pluginMessage: { type: 'get-selection-descendants' } }, '*');
    }

    function applySelectionDescendantsPayload(items, signature, flags = {}) {
      const expectedSignature = getSelectionDescendantsSignature();
      if (!expectedSignature || !Array.isArray(items)) return false;
      if (signature && signature !== expectedSignature) return false;

      const nextMap = new Map();
      items.forEach((node) => {
        if (!node || !node.id) return;
        if (Array.isArray(node.descendantIds)) {
          nextMap.set(node.id, node.descendantIds);
        }
      });

      selectionDescendantsById = nextMap;
      selectionDescendantsTruncated = flags.descendantsTruncated === true;
      selectionTooLargeForDescendants = flags.selectionTooLarge === true;
      pendingSelectionDescendantsSignature = '';
      return true;
    }
