    // Color picker menu helpers
    let colorPickMenuEl = null;
    let colorPickMenuAnchor = null;
    let colorPickMenuOptions = [];
    let colorPickMenuActiveTab = 'all';
    let colorPickMenuViewMode = 'list';
    let colorPickMenuSearchQuery = '';
    let colorPickMenuSearchOpen = false;
    let colorPickMenuLibraryLoading = false;
    let colorPickMenuLibraryError = '';
    let colorPickMenuSelectedOptionId = '';
    let colorPickMenuSelectedTarget = null;
    let colorSwapLocalSourcesCache = null;
    let colorSwapLibrarySourcesCache = null;
    let colorSwapLocalSourcesPromise = null;
    let colorSwapLibrarySourcesPromise = null;

    function normalizeColorPreviewRgba(value) {
      if (!value || typeof value !== 'object') return null;
      if (!('r' in value) || !('g' in value) || !('b' in value)) return null;
      const r = Number(value.r);
      const g = Number(value.g);
      const b = Number(value.b);
      const a = Number.isFinite(Number(value.a)) ? Number(value.a) : 1;
      if (![r, g, b, a].every(Number.isFinite)) return null;
      return {
        r: Math.max(0, Math.min(1, r)),
        g: Math.max(0, Math.min(1, g)),
        b: Math.max(0, Math.min(1, b)),
        a: Math.max(0, Math.min(1, a))
      };
    }

    function rgbaToCssColor(value, fallbackHex = '#FFFFFF') {
      const rgba = normalizeColorPreviewRgba(value);
      if (!rgba) return normalizeSelectionHexColor(fallbackHex) || '#FFFFFF';
      return `rgba(${Math.round(rgba.r * 255)}, ${Math.round(rgba.g * 255)}, ${Math.round(rgba.b * 255)}, ${rgba.a})`;
    }

    function hexToRgbObject(hex) {
      const normalized = normalizeSelectionHexColor(hex);
      if (!normalized) return null;
      const raw = normalized.replace('#', '');
      return {
        r: parseInt(raw.slice(0, 2), 16) / 255,
        g: parseInt(raw.slice(2, 4), 16) / 255,
        b: parseInt(raw.slice(4, 6), 16) / 255
      };
    }

    function getPromptColorSourceBadgeLabel(selection) {
      if (!selection || selection.kind === 'custom') return '';
      return selection.kind === 'paintStyle' ? 'Style' : selection.kind === 'colorVariable' ? 'Variable' : '';
    }

    function getColorOptionPathPrefix(name) {
      if (!name || typeof name !== 'string') return '';
      const prefix = name.split('/').map(part => part.trim()).filter(Boolean)[0];
      return prefix && prefix !== name ? prefix : '';
    }

    function enhanceColorOption(option) {
      const normalized = normalizePromptColorSelection(option);
      normalized.name = option?.name || normalized.name || normalized.hex;
      normalized.subtitle = option?.subtitle || option?.label || normalized.subtitle || '';
      normalized.label = option?.label || normalized.label || '';
      normalized.count = option?.count || normalized.count || 0;
      normalized.tab = normalized.kind === 'custom' ? 'custom' : 'libraries';
      normalized.collectionName = option?.collectionName || normalized.collectionName || '';
      normalized.libraryName = option?.libraryName || normalized.libraryName || '';
      normalized.groupType = option?.groupType || normalized.kind || '';
      normalized.groupLibrary = option?.groupLibrary || normalized.libraryName || '';
      normalized.groupCollection = option?.groupCollection || normalized.collectionName || '';
      normalized.groupPathPrefix = option?.groupPathPrefix || getColorOptionPathPrefix(normalized.name);
      normalized.sourceType = option?.sourceType || normalized.sourceType || '';
      normalized.sourceBadgeLabel = option?.sourceBadgeLabel || normalized.sourceBadgeLabel || '';
      normalized.previewRgba = normalizeColorPreviewRgba(option?.previewRgba || option?.rgba || normalized.previewRgba);
      normalized.previewCss = option?.previewCss || rgbaToCssColor(normalized.previewRgba, normalized.hex);
      return normalized;
    }

    function normalizePromptColorSelection(value, fallbackHex = '#3B82F6') {
      const fallback = normalizeSelectionHexColor(fallbackHex) || '#3B82F6';
      if (!value) {
        return { kind: 'custom', scope: 'selection', hex: fallback, tab: 'custom' };
      }

      if (typeof value === 'string') {
        const normalized = normalizeSelectionHexColor(value);
        return {
          kind: 'custom',
          scope: 'selection',
          hex: normalized || fallback,
          tab: 'custom'
        };
      }

      if (typeof value === 'object') {
        const normalized = {
          ...value,
          kind: value.kind || 'custom',
          scope: value.scope || (value.kind === 'custom' ? 'selection' : 'local'),
          hex: normalizeSelectionHexColor(value.hex || fallback) || fallback,
        };
        normalized.tab = normalized.kind === 'custom' ? 'custom' : 'libraries';
        normalized.previewRgba = normalizeColorPreviewRgba(value.previewRgba || value.rgba || normalized.previewRgba);
        normalized.previewCss = value.previewCss || rgbaToCssColor(normalized.previewRgba, normalized.hex);
        return normalized;
      }

      return { kind: 'custom', scope: 'selection', hex: fallback, tab: 'custom' };
    }

    function serializeColorSelectionForDataset(selection) {
      try {
        return JSON.stringify(normalizePromptColorSelection(selection));
      } catch (error) {
        return '';
      }
    }

    function getColorOptionId(option) {
      if (!option) return '';
      if (option.kind === 'custom') return `custom:${option.hex}:${option.sourceType || 'any'}`;
      if (option.kind === 'paintStyle') return `paintStyle:${option.scope}:${option.id || option.key || option.name || option.hex}`;
      if (option.kind === 'colorVariable') return `colorVariable:${option.scope}:${option.id || option.key || option.name || option.hex}`;
      return `${option.kind || 'unknown'}:${option.hex || option.name || ''}`;
    }

    function closeColorPickMenu() {
      if (colorPickMenuEl && colorPickMenuEl.parentNode) {
        colorPickMenuEl.parentNode.removeChild(colorPickMenuEl);
      }
      colorPickMenuEl = null;
      colorPickMenuAnchor = null;
      colorPickMenuOptions = [];
      colorPickMenuActiveTab = 'all';
      colorPickMenuViewMode = 'list';
      colorPickMenuSearchQuery = '';
      colorPickMenuSearchOpen = false;
      colorPickMenuLibraryLoading = false;
      colorPickMenuLibraryError = '';
      colorPickMenuSelectedOptionId = '';
      colorPickMenuSelectedTarget = null;
      document.removeEventListener('mousedown', handleColorMenuOutside);
      document.removeEventListener('keydown', handleColorMenuKeydown);
    }

    function isColorPickOptionSelected(option) {
      if (!option) return false;
      const optionId = getColorOptionId(option);
      if (optionId && optionId === colorPickMenuSelectedOptionId) return true;
      if (!colorPickMenuSelectedTarget) return false;
      const selectedHex = normalizeSelectionHexColor(colorPickMenuSelectedTarget.hex || '');
      const optionHex = normalizeSelectionHexColor(option.hex || '');
      if (selectedHex && optionHex && selectedHex === optionHex) return true;
      return false;
    }

    function handleColorMenuOutside(event) {
      if (!colorPickMenuEl) return;
      if (colorPickMenuEl.contains(event.target)) return;
      if (colorPickMenuAnchor && colorPickMenuAnchor.contains(event.target)) return;
      closeColorPickMenu();
    }

    function handleColorMenuKeydown(event) {
      if (event.key === 'Escape') {
        if (colorPickMenuSearchOpen && colorPickMenuSearchQuery) {
          colorPickMenuSearchQuery = '';
          if (colorPickMenuEl) renderColorPickMenu(colorPickMenuEl, colorPickMenuOptions);
          return;
        }
        closeColorPickMenu();
      }
    }

    function getVisibleColorPickOptions(options) {
      const activeTab = colorPickMenuActiveTab || 'all';
      const searchQuery = String(colorPickMenuSearchQuery || '').trim().toLowerCase();
      return options.filter((opt) => {
        const matchesTab =
          activeTab === 'custom' ? opt.tab === 'custom'
            : activeTab === 'libraries' ? opt.tab === 'libraries'
            : true;
        if (!matchesTab) return false;
        if (!searchQuery) return true;
        const haystack = [
          opt.name,
          opt.hex,
          opt.subtitle,
          opt.label,
          opt.collectionName,
          opt.libraryName,
          opt.groupPathPrefix
        ].filter(Boolean).join(' ').toLowerCase();
        return haystack.includes(searchQuery);
      });
    }

    function getColorGroupStructures(options) {
      const customOptions = [];
      const localStyleOptions = [];
      const localVariableOptions = [];
      const libraryBuckets = new Map();

      const getLibraryBucket = (libraryName, collectionName) => {
        const key = `${libraryName || 'Library'}::${collectionName || ''}`;
        if (!libraryBuckets.has(key)) {
          libraryBuckets.set(key, {
            title: collectionName ? `${libraryName || 'Library'} / ${collectionName}` : (libraryName || 'Library'),
            items: []
          });
        }
        return libraryBuckets.get(key);
      };

      options.forEach((option) => {
        if (option.tab === 'custom' || option.kind === 'custom') {
          customOptions.push(option);
          return;
        }
        if (option.scope === 'local' && option.kind === 'paintStyle') {
          localStyleOptions.push(option);
          return;
        }
        if (option.scope === 'local' && option.kind === 'colorVariable') {
          localVariableOptions.push(option);
          return;
        }
        getLibraryBucket(option.groupLibrary || option.libraryName, option.groupCollection || option.collectionName).items.push(option);
      });

      const buildSubgroups = (items) => {
        const withPrefix = new Map();
        const withoutPrefix = [];
        items.forEach((item) => {
          const prefix = item.groupPathPrefix || '';
          if (!prefix) {
            withoutPrefix.push(item);
            return;
          }
          if (!withPrefix.has(prefix)) withPrefix.set(prefix, []);
          withPrefix.get(prefix).push(item);
        });
        const groups = Array.from(withPrefix.entries())
          .sort((a, b) => a[0].localeCompare(b[0]))
          .map(([title, groupedItems]) => ({
            title,
            items: groupedItems.sort((a, b) => (a.name || '').localeCompare(b.name || ''))
          }));
        if (withoutPrefix.length > 0) {
          groups.unshift({
            title: '',
            items: withoutPrefix.sort((a, b) => (a.name || '').localeCompare(b.name || ''))
          });
        }
        return groups;
      };

      const sections = [];
      if (customOptions.length > 0) {
        sections.push({
          key: 'custom',
          title: '',
          subgroups: [{ title: '', items: customOptions }]
        });
      }
      if (localStyleOptions.length > 0) {
        sections.push({
          key: 'local-styles',
          title: 'Local Styles',
          subgroups: buildSubgroups(localStyleOptions)
        });
      }
      if (localVariableOptions.length > 0) {
        sections.push({
          key: 'local-variables',
          title: 'Local Variables',
          subgroups: buildSubgroups(localVariableOptions)
        });
      }
      Array.from(libraryBuckets.entries())
        .sort((a, b) => a[1].title.localeCompare(b[1].title))
        .forEach(([key, bucket]) => {
          sections.push({
            key: `library-${key}`,
            title: bucket.title,
            subgroups: buildSubgroups(bucket.items)
          });
        });
      return sections;
    }

    function renderColorPickOption(option, index) {
      const isSelected = isColorPickOptionSelected(option);
      const computedCustomBadge = option.kind === 'custom'
        ? (option.sourceBadgeLabel || (
          option.sourceType === 'styleLinked'
            ? 'Style-linked'
            : option.sourceType === 'variableLinked'
              ? 'Variable-linked'
              : option.sourceType === 'flat'
                ? 'Flat color'
                : ''
        ))
        : '';
      const computedCustomBadgeType = option.kind === 'custom'
        ? (option.sourceType === 'styleLinked'
          ? 'style-linked'
          : option.sourceType === 'variableLinked'
            ? 'variable-linked'
            : option.sourceType === 'flat'
              ? 'flat'
              : '')
        : '';
      return `
        <button type="button" class="color-pick-option${isSelected ? ' selected' : ''}" data-index="${index}" aria-pressed="${isSelected ? 'true' : 'false'}">
          <span class="color-swatch">
            <span class="color-swatch-fill" style="background:${escapeHtmlAttr(option.previewCss || option.hex || '#FFFFFF')};"></span>
          </span>
          <div class="color-pick-meta">
            <span class="color-pick-name-row">
              <span class="color-pick-name">${escapeHtml(option.name || option.hex || 'Unnamed color')}</span>
              ${computedCustomBadge ? `<span class="color-pick-link-indicator${computedCustomBadgeType ? ` color-pick-link-indicator--${computedCustomBadgeType}` : ''}">${escapeHtml(computedCustomBadge)}</span>` : ''}
            </span>
            <span class="color-pick-source">${escapeHtml(option.subtitle || option.label || '')}</span>
          </div>
          <span class="color-pick-hex">${escapeHtml(option.hex || '')}</span>
          <span class="color-pick-selected-check" aria-hidden="true">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
              <polyline points="20 6 9 17 4 12"></polyline>
            </svg>
          </span>
        </button>
      `;
    }

    function renderColorPickSubgroup(subgroup, filteredOptions) {
      const isGrid = colorPickMenuViewMode === 'grid';
      return `
        <div class="color-pick-subgroup">
          ${subgroup.title ? `<div class="color-pick-subgroup-title">${escapeHtml(subgroup.title)}</div>` : ''}
          <div class="color-pick-subgroup-items${isGrid ? ' color-pick-subgroup-items--grid' : ''}">
            ${subgroup.items.map((opt) => renderColorPickOption(opt, filteredOptions.indexOf(opt))).join('')}
          </div>
        </div>
      `;
    }

    function setColorPickMenuState(partial = {}) {
      if (partial.options) {
        colorPickMenuOptions = Array.isArray(partial.options) ? partial.options.slice() : [];
      }
      if (partial.libraryLoading !== undefined) {
        colorPickMenuLibraryLoading = partial.libraryLoading === true;
      }
      if (partial.libraryError !== undefined) {
        colorPickMenuLibraryError = partial.libraryError || '';
      }
      if (colorPickMenuEl) {
        renderColorPickMenu(colorPickMenuEl, colorPickMenuOptions);
      }
    }

    function renderColorPickMenu(menu, options) {
      const activeTab = colorPickMenuActiveTab || 'all';
      const filteredOptions = getVisibleColorPickOptions(options);
      const groupedSections = getColorGroupStructures(filteredOptions);
      const showLibraryLoader = colorPickMenuLibraryLoading && (activeTab === 'libraries' || activeTab === 'all');
      const showLibraryError = !colorPickMenuLibraryLoading && !!colorPickMenuLibraryError && (activeTab === 'libraries' || activeTab === 'all');

      const tabs = [
        { id: 'all', label: 'All' },
        { id: 'custom', label: 'Custom' },
        { id: 'libraries', label: 'Libraries' }
      ];
      const isGrid = colorPickMenuViewMode === 'grid';

      menu.innerHTML = `
        <div class="color-pick-tabs">
          ${tabs.map((tab) => `
            <button type="button" class="color-pick-tab${tab.id === activeTab ? ' active' : ''}" data-tab="${tab.id}">
              ${tab.label}
            </button>
          `).join('')}
          <button type="button" class="color-pick-view-toggle${isGrid ? ' active' : ''}" data-color-view-toggle="true" aria-label="${isGrid ? 'Show list view' : 'Show grid view'}" title="${isGrid ? 'Show list view' : 'Show grid view'}">
            ${isGrid ? `
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M8 6h13"></path>
                <path d="M8 12h13"></path>
                <path d="M8 18h13"></path>
                <path d="M3 6h.01"></path>
                <path d="M3 12h.01"></path>
                <path d="M3 18h.01"></path>
              </svg>
            ` : `
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <rect x="3" y="3" width="7" height="7" rx="1"></rect>
                <rect x="14" y="3" width="7" height="7" rx="1"></rect>
                <rect x="3" y="14" width="7" height="7" rx="1"></rect>
                <rect x="14" y="14" width="7" height="7" rx="1"></rect>
              </svg>
            `}
          </button>
          <button type="button" class="color-pick-search-toggle${colorPickMenuSearchOpen ? ' active' : ''}" data-color-search-toggle="true" aria-label="Search colors" title="Search colors">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
              <circle cx="11" cy="11" r="7"></circle>
              <path d="m20 20-3.5-3.5"></path>
            </svg>
          </button>
        </div>
        ${colorPickMenuSearchOpen ? `
          <div class="color-pick-search-row">
            <input
              type="text"
              class="color-pick-search-input"
              data-color-search-input="true"
              placeholder="Search colors"
              value="${escapeHtmlAttr(colorPickMenuSearchQuery)}"
            >
          </div>
        ` : ''}
        <div class="color-pick-options">
          ${filteredOptions.length > 0 ? groupedSections.map((section) => `
            <div class="color-pick-section" data-section-key="${escapeHtmlAttr(section.key)}">
              ${section.title ? `<div class="color-pick-section-title">${escapeHtml(section.title)}</div>` : ''}
              ${section.subgroups.map((subgroup) => renderColorPickSubgroup(subgroup, filteredOptions)).join('')}
            </div>
          `).join('') : (!showLibraryLoader && !showLibraryError ? '<div class="color-pick-empty">No colors in this tab</div>' : '')}
          ${showLibraryLoader ? `
            <div class="color-pick-status color-pick-status--loading">
              <span class="color-pick-status-spinner" aria-hidden="true"></span>
              <span>Loading libraries…</span>
            </div>
          ` : ''}
          ${showLibraryError ? `
            <div class="color-pick-status color-pick-status--error">
              <span>${escapeHtml(colorPickMenuLibraryError)}</span>
            </div>
          ` : ''}
        </div>
      `;

      menu.querySelectorAll('.color-pick-tab').forEach((tabBtn) => {
        tabBtn.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          colorPickMenuActiveTab = tabBtn.dataset.tab || 'all';
          renderColorPickMenu(menu, colorPickMenuOptions);
        });
      });

      const viewToggle = menu.querySelector('[data-color-view-toggle="true"]');
      if (viewToggle) {
        viewToggle.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          colorPickMenuViewMode = colorPickMenuViewMode === 'grid' ? 'list' : 'grid';
          renderColorPickMenu(menu, colorPickMenuOptions);
        });
      }

      const searchToggle = menu.querySelector('[data-color-search-toggle="true"]');
      if (searchToggle) {
        searchToggle.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          colorPickMenuSearchOpen = !colorPickMenuSearchOpen;
          if (!colorPickMenuSearchOpen) {
            colorPickMenuSearchQuery = '';
          }
          renderColorPickMenu(menu, colorPickMenuOptions);
          if (colorPickMenuSearchOpen) {
            requestAnimationFrame(() => {
              menu.querySelector('[data-color-search-input="true"]')?.focus();
            });
          }
        });
      }

      const searchInput = menu.querySelector('[data-color-search-input="true"]');
      if (searchInput) {
        searchInput.addEventListener('input', () => {
          const nextValue = searchInput.value || '';
          colorPickMenuSearchQuery = nextValue;
          renderColorPickMenu(menu, colorPickMenuOptions);
          requestAnimationFrame(() => {
            const nextInput = menu.querySelector('[data-color-search-input="true"]');
            if (nextInput) {
              nextInput.focus();
              const caretPos = nextValue.length;
              nextInput.setSelectionRange?.(caretPos, caretPos);
            }
          });
        });
      }
    }

    function openColorPickMenu(options, anchorEl, onSelect) {
      closeColorPickMenu();
      if (!options || options.length === 0) return;

      let selectedOptionId = '';
      let selectedTarget = null;
      try {
        const wrapper = anchorEl?.closest?.('.prompt-color-input-wrapper');
        const selectedSourceRaw = wrapper?.dataset?.selectedSource;
        const selectedSource = selectedSourceRaw ? JSON.parse(selectedSourceRaw) : null;
        if (selectedSource) {
          selectedTarget = enhanceColorOption(selectedSource);
          selectedOptionId = getColorOptionId(selectedTarget);
        }
      } catch (_error) {
        selectedOptionId = '';
        selectedTarget = null;
      }

      const menu = document.createElement('div');
      menu.className = 'color-pick-menu';
      colorPickMenuOptions = Array.isArray(options) ? options.slice() : [];
      colorPickMenuActiveTab = colorPickMenuOptions.some(opt => opt.tab === 'libraries') ? 'all' : 'custom';
      colorPickMenuViewMode = 'list';
      colorPickMenuLibraryLoading = false;
      colorPickMenuLibraryError = '';
      colorPickMenuSelectedOptionId = selectedOptionId;
      colorPickMenuSelectedTarget = selectedTarget;
      renderColorPickMenu(menu, colorPickMenuOptions);

      document.body.appendChild(menu);
      colorPickMenuEl = menu;
      colorPickMenuAnchor = anchorEl || null;

      const anchorRect = anchorEl?.getBoundingClientRect ? anchorEl.getBoundingClientRect() : null;
      const viewportWidth = window.innerWidth;
      const viewportHeight = window.innerHeight;
      const menuWidth = menu.offsetWidth;
      const menuHeight = menu.offsetHeight;

      let left = anchorRect ? anchorRect.left : (viewportWidth - menuWidth) / 2;
      let top = anchorRect ? anchorRect.bottom + 6 : 80;

      left = Math.max(8, Math.min(left, viewportWidth - menuWidth - 8));
      if (top + menuHeight > viewportHeight - 8) {
        top = Math.max(8, viewportHeight - menuHeight - 8);
      }

      menu.style.left = `${left}px`;
      menu.style.top = `${top}px`;

      menu.addEventListener('click', (e) => {
        const btn = e.target.closest('.color-pick-option');
        if (!btn) return;
        const idx = Number(btn.dataset.index);
        const filteredOptions = getVisibleColorPickOptions(colorPickMenuOptions);
        const choice = filteredOptions[idx];
        if (!choice) return;
        closeColorPickMenu();
        if (typeof onSelect === 'function') {
          onSelect(choice);
        }
      });

      setTimeout(() => {
        document.addEventListener('mousedown', handleColorMenuOutside);
        document.addEventListener('keydown', handleColorMenuKeydown);
      }, 0);
    }

    function normalizeSelectionHexColor(hex) {
      if (!hex) return null;
      let value = String(hex).trim();
      if (!value.startsWith('#')) value = '#' + value;
      if (!/^#[0-9A-Fa-f]{6}$/.test(value)) return null;
      return value.toUpperCase();
    }

    function collectSelectionColors(selection, options = {}) {
      if (!Array.isArray(selection)) return [];
      const includeSourceBadges = options?.includeSourceBadges === true;

      const colorMap = new Map();

      const resolveCustomSourceType = ({ styleLinked = false, variableLinked = false } = {}) => {
        if (!includeSourceBadges) return { sourceType: 'flat', sourceBadgeLabel: '' };
        if (styleLinked) return { sourceType: 'styleLinked', sourceBadgeLabel: 'Style-linked' };
        if (variableLinked) return { sourceType: 'variableLinked', sourceBadgeLabel: 'Variable-linked' };
        return { sourceType: 'flat', sourceBadgeLabel: 'Flat color' };
      };

      const addColor = (hex, sourceLabel, previewRgba = null, sourceMeta = null) => {
        const normalized = normalizeSelectionHexColor(hex);
        if (!normalized) return;
        const { sourceType = 'flat', sourceBadgeLabel = 'Flat color' } = sourceMeta || {};
        const mapKey = `${normalized}::${sourceType}`;
        const entry = colorMap.get(mapKey) || { hex: normalized, sourceType, sourceBadgeLabel, sources: [], count: 0, previewRgba: null };
        entry.count += 1;
        if (sourceLabel && entry.sources.length < 2) {
          entry.sources.push(sourceLabel);
        }
        if (!entry.previewRgba && previewRgba) {
          entry.previewRgba = normalizeColorPreviewRgba(previewRgba);
        }
        colorMap.set(mapKey, entry);
      };

      const processPaint = (paint, nodeLabel, kind, sourceMeta) => {
        if (!paint || paint.visible === false) return;
        const baseLabel = `${kind} • ${nodeLabel}`;

        if (paint.type === 'SOLID' && paint.color) {
          const baseColor = hexToRgbObject(paint.color);
          addColor(paint.color, baseLabel, baseColor ? { ...baseColor, a: paint.opacity ?? 1 } : null, sourceMeta);
          return;
        }

        if (paint.gradient && Array.isArray(paint.gradient.stops)) {
          paint.gradient.stops.forEach(stop => {
            if (!stop || !stop.color) return;
            if (typeof stop.opacity === 'number' && stop.opacity <= 0) return;
            const stopLabel = typeof stop.position === 'number'
              ? `${baseLabel} (stop ${Math.round(stop.position * 100)}%)`
              : baseLabel;
            const stopColor = hexToRgbObject(stop.color);
            const stopVariableLinked = includeSourceBadges && stop?.boundVariables?.color?.type === 'VARIABLE_ALIAS' && !!stop?.boundVariables?.color?.id;
            const stopSourceMeta = stopVariableLinked
              ? resolveCustomSourceType({ styleLinked: false, variableLinked: true })
              : sourceMeta;
            addColor(stop.color, stopLabel, stopColor ? { ...stopColor, a: stop.opacity ?? 1 } : null, stopSourceMeta);
          });
        }
      };

      const processEffect = (effect, nodeLabel) => {
        if (!effect || effect.visible === false) return;
        if (effect.type !== 'DROP_SHADOW' && effect.type !== 'INNER_SHADOW') return;
        if (!effect.color) return;
        const effectColor = effect.color;
        const effectHex = rgbToHex(effectColor.r, effectColor.g, effectColor.b);
        const shadowKind = effect.type === 'INNER_SHADOW' ? 'Inner shadow' : 'Drop shadow';
        const effectSourceMeta = resolveCustomSourceType({
          styleLinked: false,
          variableLinked: includeSourceBadges && effect?.boundVariables?.color?.type === 'VARIABLE_ALIAS' && !!effect?.boundVariables?.color?.id
        });
        addColor(effectHex, `${shadowKind} • ${nodeLabel}`, {
          r: effectColor.r,
          g: effectColor.g,
          b: effectColor.b,
          a: effectColor.a ?? 1
        }, effectSourceMeta);
      };

      const walk = (node, path = '') => {
        if (!node || node.visible === false) return;
        if (typeof node.opacity === 'number' && node.opacity <= 0) return;

        const label = node.name || node.type || 'Layer';
        const nodeLabel = path ? `${path} › ${label}` : label;

        if (Array.isArray(node.fillsDetailed) && node.fillsDetailed.length > 0) {
          const fillSourceMeta = resolveCustomSourceType({
            styleLinked: !!node.fillStyleId,
            variableLinked: false
          });
          node.fillsDetailed.forEach((fill) => {
            const variableLinked = includeSourceBadges && fill?.boundVariables?.color?.type === 'VARIABLE_ALIAS' && !!fill?.boundVariables?.color?.id;
            processPaint(fill, nodeLabel, 'Fill', variableLinked ? resolveCustomSourceType({ styleLinked: false, variableLinked: true }) : fillSourceMeta);
          });
        } else if (node.fills) {
          addColor(node.fills, `Fill • ${nodeLabel}`, null, resolveCustomSourceType({ styleLinked: !!node.fillStyleId, variableLinked: false }));
        }

        if (Array.isArray(node.strokesDetailed) && node.strokesDetailed.length > 0) {
          const strokeSourceMeta = resolveCustomSourceType({
            styleLinked: !!node.strokeStyleId,
            variableLinked: false
          });
          node.strokesDetailed.forEach((stroke) => {
            const variableLinked = includeSourceBadges && stroke?.boundVariables?.color?.type === 'VARIABLE_ALIAS' && !!stroke?.boundVariables?.color?.id;
            processPaint(stroke, nodeLabel, 'Stroke', variableLinked ? resolveCustomSourceType({ styleLinked: false, variableLinked: true }) : strokeSourceMeta);
          });
        } else if (node.strokes) {
          addColor(node.strokes, `Stroke • ${nodeLabel}`, null, resolveCustomSourceType({ styleLinked: !!node.strokeStyleId, variableLinked: false }));
        } else if (node.strokeColor) {
          addColor(node.strokeColor, `Stroke • ${nodeLabel}`, null, resolveCustomSourceType({ styleLinked: !!node.strokeStyleId, variableLinked: false }));
        }

        if (Array.isArray(node.effects) && node.effects.length > 0) {
          node.effects.forEach((effect) => processEffect(effect, nodeLabel));
        }

        if (Array.isArray(node.children)) {
          node.children.forEach(child => walk(child, nodeLabel));
        }
      };

      selection.forEach(node => walk(node));

      return Array.from(colorMap.values())
        .map(entry => {
          const firstLabel = entry.sources[0] || '';
          const extraCount = entry.count - entry.sources.length;
          const label = extraCount > 0 ? `${firstLabel} (+${extraCount} more)` : firstLabel;
          return enhanceColorOption({
            kind: 'custom',
            scope: 'selection',
            hex: entry.hex,
            name: entry.hex,
            label: label || '',
            subtitle: label || 'Selection color',
            count: entry.count,
            sourceType: entry.sourceType || 'flat',
            sourceBadgeLabel: entry.sourceBadgeLabel || '',
            previewRgba: entry.previewRgba,
            tab: 'custom'
          });
        })
        .sort((a, b) => (b.count - a.count) || a.hex.localeCompare(b.hex));
    }

    function mapLocalColorSourcesToOptions(payload) {
      const options = [];
      const paintStyles = Array.isArray(payload?.paintStyles) ? payload.paintStyles : [];
      paintStyles.forEach((style) => {
        const hex = normalizeSelectionHexColor(style?.paints?.[0]?.color ? rgbToHex(
          style.paints[0].color.r,
          style.paints[0].color.g,
          style.paints[0].color.b
        ) : null);
        if (!hex) return;
        const rgba = style?.paints?.[0]?.color || null;
        options.push(enhanceColorOption({
          kind: 'paintStyle',
          scope: 'local',
          id: style.id,
          hex,
          name: style.name || hex,
          subtitle: 'Local style',
          previewRgba: rgba,
          tab: 'libraries'
        }));
      });

      const variables = Array.isArray(payload?.variables) ? payload.variables : [];
      variables.forEach((variable) => {
        if (variable?.resolvedType !== 'COLOR') return;
        const hex = normalizeSelectionHexColor(variable.displayValue || variable.displayColor);
        if (!hex) return;
        options.push(enhanceColorOption({
          kind: 'colorVariable',
          scope: 'local',
          id: variable.id,
          hex,
          name: variable.name || hex,
          collectionName: variable.collectionName || '',
          subtitle: variable.collectionName ? `Local variable • ${variable.collectionName}` : 'Local variable',
          previewRgba: variable.displayColor || null,
          tab: 'libraries'
        }));
      });

      return options;
    }

    function mapLibraryColorSourcesToOptions(payload) {
      const options = [];
      const paintStyles = Array.isArray(payload?.paintStyles) ? payload.paintStyles : [];
      paintStyles.forEach((style) => {
        const hex = normalizeSelectionHexColor(style?.hex);
        if (!hex) return;
        options.push(enhanceColorOption({
          kind: 'paintStyle',
          scope: 'team',
          key: style.key,
          id: style.id,
          hex,
          name: style.name || hex,
          libraryName: style.libraryName || '',
          subtitle: style.libraryName ? `Library style • ${style.libraryName}` : 'Library style',
          previewRgba: style.rgba || null,
          tab: 'libraries'
        }));
      });

      const variables = Array.isArray(payload?.variables) ? payload.variables : [];
      variables.forEach((variable) => {
        const hex = normalizeSelectionHexColor(variable.hex);
        if (!hex) return;
        options.push(enhanceColorOption({
          kind: 'colorVariable',
          scope: 'team',
          key: variable.key,
          id: variable.id,
          hex,
          name: variable.name || hex,
          collectionName: variable.collectionName || '',
          libraryName: variable.libraryName || '',
          subtitle: variable.libraryName
            ? `Library variable • ${variable.libraryName}${variable.collectionName ? ` / ${variable.collectionName}` : ''}`
            : (variable.collectionName ? `Library variable • ${variable.collectionName}` : 'Library variable'),
          previewRgba: variable.rgba || null,
          tab: 'libraries'
        }));
      });

      return options;
    }

    async function loadLocalColorSwapSources() {
      if (Array.isArray(colorSwapLocalSourcesCache)) {
        return colorSwapLocalSourcesCache;
      }
      if (colorSwapLocalSourcesPromise) {
        return colorSwapLocalSourcesPromise;
      }

      colorSwapLocalSourcesPromise = runLocalActionRequest({
        requestType: 'get-color-picker-local-sources',
        resultType: 'color-picker-local-sources',
        payload: {},
        timeoutMs: 20000,
        errorPrefixes: ['Failed to load color picker local sources']
      }).then((result) => {
        colorSwapLocalSourcesCache = mapLocalColorSourcesToOptions(result);
        return colorSwapLocalSourcesCache;
      }).catch((error) => {
        console.warn('Failed to load local color swap sources', error);
        return [];
      }).finally(() => {
        colorSwapLocalSourcesPromise = null;
      });

      return colorSwapLocalSourcesPromise;
    }

    async function loadLibraryColorSwapSources() {
      if (Array.isArray(colorSwapLibrarySourcesCache)) {
        return colorSwapLibrarySourcesCache;
      }
      if (colorSwapLibrarySourcesPromise) {
        return colorSwapLibrarySourcesPromise;
      }

      colorSwapLibrarySourcesPromise = runLocalActionRequest({
        requestType: 'get-color-picker-library-sources',
        resultType: 'color-picker-library-sources',
        payload: {},
        timeoutMs: 30000,
        errorPrefixes: ['Failed to load color picker library sources']
      }).then((result) => {
        colorSwapLibrarySourcesCache = mapLibraryColorSourcesToOptions(result);
        return colorSwapLibrarySourcesCache;
      }).catch((error) => {
        console.warn('Failed to load library color swap sources', error);
        return [];
      }).finally(() => {
        colorSwapLibrarySourcesPromise = null;
      });

      return colorSwapLibrarySourcesPromise;
    }

    function prewarmColorSwapSourceCaches() {
      void loadLocalColorSwapSources();
      void loadLibraryColorSwapSources();
    }

    function mergeColorMenuOptions(...optionSets) {
      const optionMap = new Map();
      optionSets.flat().forEach((option) => {
        const normalized = enhanceColorOption(option);
        const key = getColorOptionId(normalized);
        if (!optionMap.has(key)) {
          optionMap.set(key, normalized);
        }
      });
      return Array.from(optionMap.values());
    }

    function collectSelectionTokenReferences(selection) {
      const refs = {
        styleIds: new Set(),
        variableIds: new Set(),
      };

      const addBoundPaintVariable = (paint) => {
        const colorBinding = paint?.boundVariables?.color;
        if (colorBinding?.type === 'VARIABLE_ALIAS' && colorBinding.id) {
          refs.variableIds.add(colorBinding.id);
        }
      };

      const walk = (node) => {
        if (!node) return;
        if (node.fillStyleId) refs.styleIds.add(node.fillStyleId);
        if (node.strokeStyleId) refs.styleIds.add(node.strokeStyleId);

        if (Array.isArray(node.fillsDetailed)) {
          node.fillsDetailed.forEach(addBoundPaintVariable);
        }
        if (Array.isArray(node.strokesDetailed)) {
          node.strokesDetailed.forEach(addBoundPaintVariable);
        }
        if (node.boundVariables && typeof node.boundVariables === 'object') {
          Object.values(node.boundVariables).forEach((value) => {
            if (value?.type === 'VARIABLE_ALIAS' && value.id) {
              refs.variableIds.add(value.id);
            } else if (Array.isArray(value)) {
              value.forEach((entry) => {
                if (entry?.type === 'VARIABLE_ALIAS' && entry.id) refs.variableIds.add(entry.id);
              });
            }
          });
        }

        if (Array.isArray(node.children)) {
          node.children.forEach(walk);
        }
      };

      (Array.isArray(selection) ? selection : []).forEach(walk);
      return refs;
    }

    function collectSelectionLibraryOptions(selection) {
      const optionMap = new Map();

      const addOption = (option) => {
        const normalized = enhanceColorOption(option);
        normalized.subtitle = option.subtitle || normalized.subtitle || 'Used on selection';
        normalized.tab = 'libraries';
        const key = getColorOptionId(normalized);
        if (!optionMap.has(key)) {
          optionMap.set(key, normalized);
        }
      };

      const getPaintHex = (paints) => {
        if (!Array.isArray(paints)) return null;
        for (const paint of paints) {
          if (paint?.type === 'SOLID' && paint.color) {
            return normalizeSelectionHexColor(paint.color);
          }
        }
        return null;
      };

      const walk = (node) => {
        if (!node) return;

        if (node.fillStyleId || node.fillTokenName) {
          addOption({
            kind: 'paintStyle',
            scope: 'team',
            id: node.fillStyleId,
            name: node.fillTokenName || 'Selection fill style',
            hex: getPaintHex(node.fillsDetailed) || node.fills || '#000000',
            previewRgba: null,
            subtitle: 'Used on selection'
          });
        }

        if (node.strokeStyleId || node.strokeTokenName) {
          addOption({
            kind: 'paintStyle',
            scope: 'team',
            id: node.strokeStyleId,
            name: node.strokeTokenName || 'Selection stroke style',
            hex: getPaintHex(node.strokesDetailed) || node.strokes || '#000000',
            previewRgba: null,
            subtitle: 'Used on selection'
          });
        }

        const addPaintVariableOption = (paint, fallbackHex) => {
          const colorBinding = paint?.boundVariables?.color;
          if (colorBinding?.type !== 'VARIABLE_ALIAS' || !colorBinding.id) return;
          addOption({
            kind: 'colorVariable',
            scope: 'team',
            id: colorBinding.id,
            name: colorBinding.name || 'Selection color variable',
            hex: normalizeSelectionHexColor(fallbackHex || paint.color) || '#000000',
            previewRgba: paint?.opacity !== undefined && paint.color
              ? { ...hexToRgbObject(paint.color), a: paint.opacity }
              : null,
            subtitle: 'Used on selection'
          });
        };

        if (Array.isArray(node.fillsDetailed)) {
          node.fillsDetailed.forEach((paint) => addPaintVariableOption(paint, paint.color));
        }
        if (Array.isArray(node.strokesDetailed)) {
          node.strokesDetailed.forEach((paint) => addPaintVariableOption(paint, paint.color));
        }

        if (Array.isArray(node.children)) {
          node.children.forEach(walk);
        }
      };

      (Array.isArray(selection) ? selection : []).forEach(walk);
      return Array.from(optionMap.values());
    }

    function filterLibraryOptionsForSelection(options, selection) {
      const refs = collectSelectionTokenReferences(selection);
      const matched = options.filter((option) => {
        if (option.kind === 'paintStyle') {
          return option.id && refs.styleIds.has(option.id);
        }
        if (option.kind === 'colorVariable') {
          return option.id && refs.variableIds.has(option.id);
        }
        return false;
      });
      return mergeColorMenuOptions(matched, collectSelectionLibraryOptions(selection));
    }

    function applyPromptColorSelection(wrapper, selection) {
      if (!wrapper) return;
      const picker = wrapper.querySelector('.prompt-color-picker');
      const hexInput = wrapper.querySelector('.prompt-color-hex');
      const badge = wrapper.querySelector('.prompt-color-source-badge');
      const normalized = normalizePromptColorSelection(selection, picker?.value || hexInput?.value || '#3B82F6');
      wrapper.dataset.selectedSource = serializeColorSelectionForDataset(normalized);
      wrapper.dataset.selectedKind = normalized.kind || 'custom';
      if (picker) picker.value = normalized.hex;
      if (hexInput) hexInput.value = normalized.hex;
      if (badge) {
        const badgeLabel = getPromptColorSourceBadgeLabel(normalized);
        badge.textContent = badgeLabel;
        badge.hidden = !badgeLabel;
      }
      if (picker) {
        picker.style.setProperty('--prompt-color-preview', normalized.previewCss || normalized.hex);
      }
    }

    // Pick color from selected element
    async function pickColorFromSelection(picker, hexInput, anchorEl) {
      try {
        const wrapper = picker?.closest('.prompt-color-input-wrapper');
        const fieldKey = picker?.dataset?.fieldKey || '';
        const { data: selectionData } = await requestSelectionData();
        if (!selectionData || selectionData.length === 0) {
          showToast('Please select an element first', 'error');
          return;
        }

        let customOptions = collectSelectionColors(selectionData, { includeSourceBadges: false });
        const colorOptions = mergeColorMenuOptions(customOptions);
        if (colorOptions.length === 0) {
          showToast('Selected element has no visible fill or stroke colors', 'error');
          return;
        }

        const applyColor = (selection) => {
          const normalized = normalizePromptColorSelection(selection, picker?.value || '#3B82F6');
          if (!normalized) {
            showToast('Color is not supported', 'error');
            return;
          }
          applyPromptColorSelection(wrapper, normalized);
          showToast(`Color set to ${normalized.hex}`);
        };

        openColorPickMenu(colorOptions, anchorEl, (choice) => {
          if (choice) {
            applyColor(choice);
          }
        });
        setColorPickMenuState({ libraryLoading: true, libraryError: '' });

        const rebuildColorPickOptions = (localOptions = null, libraryOptions = null) => {
          const resolvedLocalOptions = Array.isArray(localOptions) ? localOptions : (colorSwapLocalSourcesCache || []);
          const resolvedLibraryOptions = Array.isArray(libraryOptions) ? libraryOptions : (colorSwapLibrarySourcesCache || []);
          const filteredLibraryOptions = fieldKey === 'fromColor'
            ? filterLibraryOptionsForSelection(mergeColorMenuOptions(resolvedLocalOptions, resolvedLibraryOptions), selectionData)
            : mergeColorMenuOptions(resolvedLocalOptions, resolvedLibraryOptions);
          return mergeColorMenuOptions(customOptions, filteredLibraryOptions);
        };

        // Defer expensive linked-source badge detection until after initial paint.
        requestAnimationFrame(() => {
          requestAnimationFrame(() => {
            if (!colorPickMenuEl) return;
            try {
              customOptions = collectSelectionColors(selectionData, { includeSourceBadges: true });
              setColorPickMenuState({
                options: rebuildColorPickOptions(),
              });
            } catch (error) {
              console.warn('Failed to load custom color source badges', error);
            }
          });
        });

        Promise.all([loadLocalColorSwapSources(), loadLibraryColorSwapSources()])
          .then(([localOptions, libraryOptions]) => {
            setColorPickMenuState({
              options: rebuildColorPickOptions(localOptions, libraryOptions),
              libraryLoading: false,
              libraryError: ''
            });
          })
          .catch((error) => {
            console.warn('Failed to stream color library options', error);
            setColorPickMenuState({
              libraryLoading: false,
              libraryError: 'Could not load libraries'
            });
          });
      } catch (error) {
        showToast('Failed to get selection', 'error');
      }
    }

    // Map color targets to their inputs
    const colorInputMap = {
      'primary': { picker: auditColorPrimary, hex: auditColorPrimaryHex },
      'secondary': { picker: auditColorSecondary, hex: auditColorSecondaryHex },
      'error': { picker: auditColorError, hex: auditColorErrorHex },
      'warning': { picker: auditColorWarning, hex: auditColorWarningHex },
      'success': { picker: auditColorSuccess, hex: auditColorSuccessHex }
    };

    auditColorPickBtns.forEach(btn => {
      btn.addEventListener('click', () => {
        const target = btn.dataset.colorTarget;
        const inputs = colorInputMap[target];
        if (inputs) {
          pickColorFromSelection(inputs.picker, inputs.hex, btn);
        }
      });
    });

    // Color drag-and-drop swap functionality
    const auditColorItems = document.querySelectorAll('.audit-color-item[draggable="true"]');
    let draggedColorItem = null;

    auditColorItems.forEach(item => {
      item.addEventListener('dragstart', (e) => {
        draggedColorItem = item;
        item.classList.add('dragging');
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', item.dataset.colorRole);
      });

      item.addEventListener('dragend', () => {
        item.classList.remove('dragging');
        auditColorItems.forEach(i => i.classList.remove('drag-over'));
        draggedColorItem = null;
      });

      item.addEventListener('dragover', (e) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        if (draggedColorItem && draggedColorItem !== item) {
          item.classList.add('drag-over');
        }
      });

      item.addEventListener('dragleave', () => {
        item.classList.remove('drag-over');
      });

      item.addEventListener('drop', (e) => {
        e.preventDefault();
        item.classList.remove('drag-over');

        if (!draggedColorItem || draggedColorItem === item) return;

        // Get the color inputs for both items
        const sourceRole = draggedColorItem.dataset.colorRole;
        const targetRole = item.dataset.colorRole;

        const sourceInputs = colorInputMap[sourceRole];
        const targetInputs = colorInputMap[targetRole];

        if (sourceInputs && targetInputs) {
          // Swap the color values
          const sourceColor = sourceInputs.picker.value;
          const targetColor = targetInputs.picker.value;

          sourceInputs.picker.value = targetColor;
          sourceInputs.hex.value = targetColor;
          targetInputs.picker.value = sourceColor;
          targetInputs.hex.value = sourceColor;

          showToast(`Swapped ${sourceRole} ↔ ${targetRole} colors`);
        }
      });
    });

    // Load a preset into the form
    function updateAuditInstructionsModifiedState() {
      if (!auditInstructionsModifiedBadge || !auditInstructions) return;
      const baseline = (currentPresetBaselineInstructions || '').trim();
      const currentText = (auditInstructions.value || '').trim();
      const isModified = baseline && currentText !== baseline;
      auditInstructionsModifiedBadge.classList.toggle('hidden', !isModified);
      auditInstructionsModifiedBadge.title = isModified
        ? 'Instructions differ from the selected preset'
        : 'Instructions match the selected preset';
    }

    function loadAuditPreset(presetId) {
      const preset = defaultAuditPresets[presetId] || userAuditPresets[presetId];
      if (!preset) return;

      currentPresetId = presetId;
      currentPresetBaselineInstructions = (preset.instructions || '').trim();

      setInputValueWithUndo(auditInstructions, preset.instructions);
      if (preset.language) auditLanguageSelect.value = preset.language;
      if (auditContextModeSelect) auditContextModeSelect.value = preset.settings.contextMode || ContextMode.SMART;
      auditTargetWidth.value = preset.settings.targetWidth;
      auditTargetHeight.value = preset.settings.targetHeight;
      auditMinWidth.value = preset.settings.minWidth;
      auditMinHeight.value = preset.settings.minHeight;
      if (auditSizeToggle) auditSizeToggle.checked = preset.settings.auditSizeEnabled !== false;

      auditColorPrimary.value = preset.settings.colors.primary;
      auditColorPrimaryHex.value = preset.settings.colors.primary;
      auditColorSecondary.value = preset.settings.colors.secondary;
      auditColorSecondaryHex.value = preset.settings.colors.secondary;
      auditColorError.value = preset.settings.colors.error;
      auditColorErrorHex.value = preset.settings.colors.error;
      auditColorWarning.value = preset.settings.colors.warning;
      auditColorWarningHex.value = preset.settings.colors.warning;
      auditColorSuccess.value = preset.settings.colors.success;
      auditColorSuccessHex.value = preset.settings.colors.success;
      if (auditColorsToggle) auditColorsToggle.checked = preset.settings.auditColorsEnabled === true;
      if (document.getElementById('auditPostCommentsToggle')) {
        document.getElementById('auditPostCommentsToggle').checked = preset.settings.postComments === true;
      }

      updateAuditInstructionsModifiedState();
      applyAuditToggleUI();

      // Show update/delete/edit buttons only for user presets
      const isUserPreset = !!userAuditPresets[presetId];
      auditPresetUpdateBtn.style.display = isUserPreset ? 'flex' : 'none';
      auditPresetDeleteBtn.style.display = isUserPreset ? 'flex' : 'none';
      auditPresetEditBtn.style.display = isUserPreset ? 'flex' : 'none';
    }

    // Save current form values to state
    function saveCurrentAuditSettings() {
      currentAuditSettings = {
        instructions: auditInstructions.value,
        targetWidth: parseInt(auditTargetWidth.value) || 390,
        targetHeight: parseInt(auditTargetHeight.value) || 844,
        minWidth: parseInt(auditMinWidth.value) || 320,
        minHeight: parseInt(auditMinHeight.value) || 568,
        colors: {
          primary: auditColorPrimary.value,
          secondary: auditColorSecondary.value,
          error: auditColorError.value,
          warning: auditColorWarning.value,
          success: auditColorSuccess.value
        },
        auditSizeEnabled: auditSizeToggle ? auditSizeToggle.checked : true,
        auditColorsEnabled: auditColorsToggle ? auditColorsToggle.checked : true,
        postComments: document.getElementById('auditPostCommentsToggle') ? document.getElementById('auditPostCommentsToggle').checked : false,
        contextMode: auditContextModeSelect?.value || ContextMode.SMART,
        language: auditLanguageSelect?.value || 'auto'
      };

      // Save to Figma storage
      parent.postMessage({
        pluginMessage: {
          type: 'save-audit-settings',
          settings: currentAuditSettings
        }
      }, '*');
    }

    // Toggle to input mode for saving preset
    auditPresetSaveBtn.addEventListener('click', () => {
      isEditingPresetName = false;
      auditPresetSelectMode.classList.add('hidden');
      auditPresetInputMode.classList.remove('hidden');
      auditPresetNameInput.value = '';
      auditPresetNameInput.placeholder = tu('aux.audit.presetNamePlaceholder');
      auditPresetNameInput.focus();
    });

    // Toggle to input mode for editing preset name
    auditPresetEditBtn.addEventListener('click', () => {
      const presetId = auditPresetSelect.value;
      const preset = userAuditPresets[presetId];
      if (!preset) return;

      isEditingPresetName = true;
      auditPresetSelectMode.classList.add('hidden');
      auditPresetInputMode.classList.remove('hidden');
      auditPresetNameInput.value = preset.name;
      auditPresetNameInput.placeholder = tu('aux.audit.presetNameEditPlaceholder');
      auditPresetNameInput.select();
      auditPresetNameInput.focus();
    });

    // Cancel input mode
    auditPresetCancelBtn.addEventListener('click', () => {
      isEditingPresetName = false;
      auditPresetInputMode.classList.add('hidden');
      auditPresetSelectMode.classList.remove('hidden');
      auditPresetNameInput.value = '';
    });

    // Confirm save preset
    auditPresetConfirmBtn.addEventListener('click', () => {
      const name = auditPresetNameInput.value.trim();
      if (!name) {
        showToast(tu('aux.audit.presetNameRequired'), 'error');
        auditPresetNameInput.focus();
        return;
      }

      if (isEditingPresetName) {
        const presetId = auditPresetSelect.value;
        if (userAuditPresets[presetId]) {
          userAuditPresets[presetId].name = name;
          updatePresetDropdown();
          auditPresetSelect.value = presetId;

          // Save to Figma storage
          parent.postMessage({
            pluginMessage: {
              type: 'save-audit-presets',
              presets: userAuditPresets
            }
          }, '*');

          showToast(tu('aux.audit.presetRenamed', { name }));
        }
      } else {
        const presetId = 'user-' + Date.now();
        const newPreset = {
          name: name,
          language: auditLanguageSelect.value,
          instructions: auditInstructions.value,
          settings: {
            targetWidth: parseInt(auditTargetWidth.value) || 390,
            targetHeight: parseInt(auditTargetHeight.value) || 844,
            minWidth: parseInt(auditMinWidth.value) || 320,
            minHeight: parseInt(auditMinHeight.value) || 568,
            colors: {
              primary: auditColorPrimary.value,
              secondary: auditColorSecondary.value,
              error: auditColorError.value,
              warning: auditColorWarning.value,
              success: auditColorSuccess.value
            },
            auditSizeEnabled: auditSizeToggle ? auditSizeToggle.checked : true,
            auditColorsEnabled: auditColorsToggle ? auditColorsToggle.checked : true,
            postComments: document.getElementById('auditPostCommentsToggle') ? document.getElementById('auditPostCommentsToggle').checked : false,
            contextMode: document.getElementById('auditContextModeSelect')?.value || ContextMode.SMART
          }
        };

        userAuditPresets[presetId] = newPreset;
        updatePresetDropdown();
        auditPresetSelect.value = presetId;
        auditPresetUpdateBtn.style.display = 'flex';
        auditPresetDeleteBtn.style.display = 'flex';
        auditPresetEditBtn.style.display = 'flex';

        // Save to Figma storage
        parent.postMessage({
          pluginMessage: {
            type: 'save-audit-presets',
            presets: userAuditPresets
          }
        }, '*');

        showToast(tu('aux.audit.presetSaved', { name }));
      }

      // Switch back to select mode
      isEditingPresetName = false;
      auditPresetInputMode.classList.add('hidden');
      auditPresetSelectMode.classList.remove('hidden');
      auditPresetNameInput.value = '';
    });

    // Handle Enter key in preset name input
    auditPresetNameInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        auditPresetConfirmBtn.click();
      } else if (e.key === 'Escape') {
        auditPresetCancelBtn.click();
      }
    });

    // Update existing preset
    auditPresetUpdateBtn.addEventListener('click', () => {
      const presetId = auditPresetSelect.value;
      if (!userAuditPresets[presetId]) return;

      const presetName = userAuditPresets[presetId].name;
      userAuditPresets[presetId] = {
        name: presetName,
        language: auditLanguageSelect.value,
        instructions: auditInstructions.value,
        settings: {
          targetWidth: parseInt(auditTargetWidth.value) || 390,
          targetHeight: parseInt(auditTargetHeight.value) || 844,
          minWidth: parseInt(auditMinWidth.value) || 320,
          minHeight: parseInt(auditMinHeight.value) || 568,
          colors: {
            primary: auditColorPrimary.value,
            secondary: auditColorSecondary.value,
            error: auditColorError.value,
            warning: auditColorWarning.value,
            success: auditColorSuccess.value
          },
          auditSizeEnabled: auditSizeToggle ? auditSizeToggle.checked : true,
          auditColorsEnabled: auditColorsToggle ? auditColorsToggle.checked : true,
          postComments: document.getElementById('auditPostCommentsToggle') ? document.getElementById('auditPostCommentsToggle').checked : false,
          contextMode: document.getElementById('auditContextModeSelect')?.value || ContextMode.SMART
        }
      };

      // Save to Figma storage
      parent.postMessage({
        pluginMessage: {
          type: 'save-audit-presets',
          presets: userAuditPresets
        }
      }, '*');

      showToast(tu('aux.audit.presetUpdated', { name: presetName }));
    });

    // Delete preset
    auditPresetDeleteBtn.addEventListener('click', () => {
      const presetId = auditPresetSelect.value;
      if (!userAuditPresets[presetId]) return;

      const presetName = userAuditPresets[presetId].name;
      delete userAuditPresets[presetId];
      updatePresetDropdown();
      auditPresetSelect.value = 'general-figma-design-audit-auto';
      loadAuditPreset('general-figma-design-audit-auto');

      // Save to Figma storage
      parent.postMessage({
        pluginMessage: {
          type: 'save-audit-presets',
          presets: userAuditPresets
        }
      }, '*');

      showToast(tu('aux.audit.presetDeleted', { name: presetName }));
    });

    // Ensure initial toggle UI state
    applyAuditToggleUI();

    // Update preset dropdown with user presets
    function updatePresetDropdown() {
      const currentVal = auditPresetSelect.value;
      auditPresetSelect.innerHTML = '';

      // Add default presets
      Object.entries(defaultAuditPresets).forEach(([id, preset]) => {
        const option = document.createElement('option');
        option.value = id;
        option.textContent = preset.name;
        auditPresetSelect.appendChild(option);
      });

      // Add user presets
      Object.entries(userAuditPresets).forEach(([id, preset]) => {
        const option = document.createElement('option');
        option.value = id;
        option.textContent = preset.name;
        option.dataset.user = 'true';
        auditPresetSelect.appendChild(option);
      });

      // Restore selection if it still exists
      if (currentVal && auditPresetSelect.querySelector(`option[value="${currentVal}"]`)) {
        auditPresetSelect.value = currentVal;
      }
    }

    // Initialize dropdown
    updatePresetDropdown();

    // Enhance prompt using AI
    async function enhanceAuditPrompt(text, apiKey, presetName) {
      const contextNote = presetName ? `\n\nPreset context: "${presetName}". Tailor enhancements to this review type.` : '';
      const systemPrompt = `You are an expert at improving UI/UX audit prompts. Enhance the following audit instructions to be more specific, actionable, and comprehensive while preserving the original intent and language. Keep the same structure and format but add more detail and clarity. Respond with ONLY the improved prompt, no explanations.${contextNote}`;
      const result = await callAISimple({ systemPrompt, userContent: text, temperature: 0.7, maxTokens: 4096 });
      return result.text;
    }

    // Initialize audit modal with first preset
    loadAuditPreset('app-review');

    // Combined Auto-fill / Enhance System Instructions button
    auditAutoFillInstructions.addEventListener('click', async () => {
      const apiKey = getCurrentApiKey();
      if (!isAiProviderReady()) {
        showToast(tu('aux.audit.apiKeyRequired'), 'error');
        return;
      }

      const currentText = auditInstructions.value.trim();
      const selectedOption = auditPresetSelect.options[auditPresetSelect.selectedIndex];
      const presetName = selectedOption ? selectedOption.textContent : '';

      const contextInfo = presetName && presetName !== 'App Review'
        ? `Create a comprehensive UI/UX audit instruction for "${presetName}" type of design review.`
        : 'Create a comprehensive general UI/UX audit instruction for reviewing designs.';

      auditAutoFillInstructions.classList.add('loading');

      try {
        if (!currentText) {
          const systemPrompt = `You are an expert Senior UI/UX Designer. Generate detailed audit instructions in Japanese following this structure:

役割と目標 (Role and Goals):
- Define the target environment
- Specify the reviewer role
- List key focus areas

レビュープロセス (Review Process):
1. 🧩 UI統一性・整合性チェック
2. 🔍 デザインシステム適合チェック
3. 📐 レイアウト & UX
4. 💡 状態変化・網羅性チェック
5. 🚀 改善提案

Include specific checkpoints and [OK/NG] evaluation format. Keep professional tone with appropriate design terminology.`;

          const instructions = await generateAuditContent(systemPrompt, contextInfo, apiKey);
          setInputValueWithUndo(auditInstructions, instructions);
          showToast(tu('aux.audit.instructionsAutofilled'));
        } else {
          const enhancedText = await enhanceAuditPrompt(currentText, apiKey, presetName);
          setInputValueWithUndo(auditInstructions, enhancedText);
          showToast(tu('aux.audit.instructionsEnhanced'));
        }
        updateAuditInstructionsModifiedState();
      } catch (error) {
        console.error('Auto-fill/Enhance instructions error:', error);
        showToast(tu('aux.audit.instructionsFailed', { message: error.message }), 'error');
      } finally {
        auditAutoFillInstructions.classList.remove('loading');
      }
    });

    // Auto-fill Viewport Settings from instructions or selection
    auditAutoFillViewport.addEventListener('click', async () => {
      const apiKey = getCurrentApiKey();
      if (!isAiProviderReady()) {
        showToast(tu('aux.audit.apiKeyRequired'), 'error');
        return;
      }

      auditAutoFillViewport.classList.add('loading');

      try {
        const instructions = auditInstructions.value.trim();

        // First try to extract from instructions
        if (instructions) {
          const systemPrompt = `Extract viewport/screen dimensions from these UI/UX audit instructions. Return JSON only: {"targetWidth": number, "targetHeight": number, "minWidth": number, "minHeight": number}. If not found, return null values.`;

          const result = await generateAuditContent(systemPrompt, instructions, apiKey);
          try {
            const jsonMatch = result.match(/\{[\s\S]*?\}/);
            if (jsonMatch) {
              const dimensions = JSON.parse(jsonMatch[0]);
              if (dimensions.targetWidth && dimensions.targetHeight) {
                auditTargetWidth.value = dimensions.targetWidth;
                auditTargetHeight.value = dimensions.targetHeight;
                if (dimensions.minWidth) auditMinWidth.value = dimensions.minWidth;
                if (dimensions.minHeight) auditMinHeight.value = dimensions.minHeight;
                showToast(tu('aux.audit.viewportExtracted'));
                return;
              }
            }
          } catch (e) {
            // JSON parse failed, continue to selection
          }
        }

        // Fallback: try to get from selection
        parent.postMessage({ pluginMessage: { type: 'get-selection-data' } }, '*');
        showToast(tu('aux.audit.gettingDimensions'), 'info');
      } catch (error) {
        console.error('Auto-fill viewport error:', error);
        showToast(tu('aux.audit.autofillFailed', { message: error.message }), 'error');
      } finally {
        auditAutoFillViewport.classList.remove('loading');
      }
    });

    // Auto-fill Colors from instructions or selection
    auditAutoFillColors.addEventListener('click', async () => {
      const apiKey = getCurrentApiKey();
      if (!isAiProviderReady()) {
        showToast(tu('aux.audit.apiKeyRequired'), 'error');
        return;
      }

      auditAutoFillColors.classList.add('loading');

      try {
        const instructions = auditInstructions.value.trim();

        // First try to extract from instructions
        if (instructions) {
          const systemPrompt = `Extract design system colors from these UI/UX audit instructions. Return JSON only: {"primary": "#hex", "secondary": "#hex", "error": "#hex", "warning": "#hex", "success": "#hex"}. Use standard hex color codes. If not found, return null.`;

          const result = await generateAuditContent(systemPrompt, instructions, apiKey);
          try {
            const jsonMatch = result.match(/\{[\s\S]*?\}/);
            if (jsonMatch) {
              const colors = JSON.parse(jsonMatch[0]);
              let colorsFound = false;

              if (colors.primary) {
                auditColorPrimary.value = colors.primary;
                auditColorPrimaryHex.value = colors.primary;
                colorsFound = true;
              }
              if (colors.secondary) {
                auditColorSecondary.value = colors.secondary;
                auditColorSecondaryHex.value = colors.secondary;
                colorsFound = true;
              }
              if (colors.error) {
                auditColorError.value = colors.error;
                auditColorErrorHex.value = colors.error;
                colorsFound = true;
              }
              if (colors.warning) {
                auditColorWarning.value = colors.warning;
                auditColorWarningHex.value = colors.warning;
                colorsFound = true;
              }
              if (colors.success) {
                auditColorSuccess.value = colors.success;
                auditColorSuccessHex.value = colors.success;
                colorsFound = true;
              }

              if (colorsFound) {
                showToast(tu('aux.audit.colorsExtracted'));
                return;
              }
              // No colors found in instructions, fall through to selection-based extraction
            }
          } catch (e) {
            // JSON parse failed, continue to selection
          }
        }

        // Fallback: try to get colors from selection
        parent.postMessage({ pluginMessage: { type: 'get-selection-colors' } }, '*');
        showToast(tu('aux.audit.gettingColors'), 'info');
      } catch (error) {
        console.error('Auto-fill colors error:', error);
        showToast(tu('aux.audit.autofillFailed', { message: error.message }), 'error');
      } finally {
        auditAutoFillColors.classList.remove('loading');
      }
    });

    // ============================================
    // Unified AI simple call helper (non-streaming, single turn)
    // Replaces duplicated 3-branch provider patterns across the codebase.
    // ============================================
    async function callAISimple({ systemPrompt, userContent, images, temperature = 0.7, maxTokens = 4096, jsonMode = false }) {
      const apiKey = getCurrentApiKey();
      if (selectedProvider === 'openai') {
        if (!hasOpenAiCredentialsForChat()) throw new Error('No API key configured');
      } else if (selectedProvider === 'ollama') {
        if (!hasOllamaCredentialsForChat()) throw new Error('Ollama is not configured');
      } else if (!apiKey) {
        throw new Error('No API key configured');
      }

      // Build image parts per provider
      const imageDataUrls = images || [];

      switch (selectedProvider) {
        case 'gemini': {
          const userParts = [];
          // Add images first (Gemini inline_data format)
          for (const imgUrl of imageDataUrls) {
            const base64Data = typeof imgUrl === 'string' && imgUrl.startsWith('data:')
              ? imgUrl.split(',')[1] : imgUrl;
            const mimeMatch = typeof imgUrl === 'string' && imgUrl.match(/^data:(image\/[^;]+);/);
            const mimeType = mimeMatch ? mimeMatch[1] : 'image/png';
            if (base64Data) {
              userParts.push({ inline_data: { mime_type: mimeType, data: base64Data } });
            }
          }
          userParts.push({ text: userContent });

          const geminiBody = {
            contents: [{ role: 'user', parts: userParts }],
            generationConfig: { temperature, maxOutputTokens: maxTokens }
          };
          if (systemPrompt) {
            geminiBody.systemInstruction = { parts: [{ text: systemPrompt }] };
          }
          if (jsonMode) {
            geminiBody.generationConfig.responseMimeType = 'application/json';
          }

          const response = await fetch(
            `https://generativelanguage.googleapis.com/v1beta/models/${geminiModel || DEFAULT_GEMINI_CHAT_MODEL}:generateContent?key=${apiKey}`,
            { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(geminiBody) }
          );
          if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData?.error?.message || `Gemini API error: ${response.status}`);
          }
          const data = await response.json();
          const candidate = data.candidates?.[0];
          return {
            text: (candidate?.content?.parts || []).map(p => p.text || '').join(''),
            finishReason: candidate?.finishReason || ''
          };
        }

        case 'openai':
        case 'ollama': {
          // Build user content parts for OpenAI-compatible vision format
          let userMsg;
          if (imageDataUrls.length > 0) {
            const contentParts = [];
            for (const imgUrl of imageDataUrls) {
              contentParts.push({ type: 'image_url', image_url: { url: imgUrl } });
            }
            contentParts.push({ type: 'text', text: userContent });
            userMsg = { role: 'user', content: contentParts };
          } else {
            userMsg = { role: 'user', content: userContent };
          }

          const messages = [];
          if (systemPrompt) messages.push({ role: 'system', content: systemPrompt });
          messages.push(userMsg);

          const openaiOptions = { max_tokens: maxTokens, temperature };
          if (jsonMode && selectedProvider === 'openai') openaiOptions.response_format = { type: 'json_object' };

          const compatModel = getOpenAICompatChatModelId() || (selectedProvider === 'ollama' ? DEFAULT_OLLAMA_CHAT_MODEL : 'gpt-5-mini');
          const response = await openAICompatFetch('chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', ...openAICompatAuthHeaders() },
            body: JSON.stringify(buildOpenAIRequestBody(compatModel, messages, openaiOptions))
          });
          if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData?.error?.message || `OpenAI API error: ${response.status}`);
          }
          const data = await response.json();
          return {
            text: data.choices?.[0]?.message?.content || '',
            finishReason: data.choices?.[0]?.finish_reason || ''
          };
        }

        case 'anthropic': {
          // Build user content parts for Anthropic format
          let userMsgContent;
          if (imageDataUrls.length > 0) {
            const contentParts = [];
            for (const imgUrl of imageDataUrls) {
              const base64Data = typeof imgUrl === 'string' && imgUrl.startsWith('data:')
                ? imgUrl.split(',')[1] : imgUrl;
              const mimeMatch = typeof imgUrl === 'string' && imgUrl.match(/^data:(image\/[^;]+);/);
              const mediaType = mimeMatch ? mimeMatch[1] : 'image/png';
              if (base64Data) {
                contentParts.push({ type: 'image', source: { type: 'base64', media_type: mediaType, data: base64Data } });
              }
            }
            contentParts.push({ type: 'text', text: userContent });
            userMsgContent = contentParts;
          } else {
            userMsgContent = userContent;
          }

          const anthropicBody = {
            model: anthropicModel || 'claude-3-5-sonnet-20240620',
            max_tokens: maxTokens,
            messages: [{ role: 'user', content: userMsgContent }]
          };
          if (systemPrompt) anthropicBody.system = systemPrompt;

          const response = await fetch('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'x-api-key': apiKey,
              'anthropic-version': '2023-06-01',
              'anthropic-dangerous-direct-browser-access': 'true'
            },
            body: JSON.stringify(anthropicBody)
          });
          if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData?.error?.message || `Anthropic API error: ${response.status}`);
          }
          const data = await response.json();
          return {
            text: data.content?.[0]?.text || '',
            finishReason: data.stop_reason || ''
          };
        }

        default:
          throw new Error('Unknown provider: ' + selectedProvider);
      }
    }

    // Utility: extract image data URLs from an imageInput field value (handles single, array, object with .data)
    function extractImageDataUrls(imageInputValue) {
      if (!imageInputValue) return [];
      const images = Array.isArray(imageInputValue) ? imageInputValue : [imageInputValue];
      return images.map(img => typeof img === 'object' && img.data ? img.data : img).filter(Boolean);
    }

    const ASCII_CHARSET_PRESETS = {
      standard: ' .:-=+*#%@',
      blocks: '　░▒▓█',
      codeStyle: ' *2/e+=',
      airy: '  .·°*+',
      symbols: '　・○◇□◆■',
      minimal: ' .oO#',
      dense: ' `^",:;Il!i~+_-?][}{1)(|\\/tfjrxnuvczXYUJCLQ0OZmwqpdbkhao*#MW&8%B@$'
    };
    const ASCII_EMOJI_TEXT_POOL = [
      '♥', '♦', '♣', '♠', '★', '☆', '☀', '☁', '☂', '☃', '☎', '☕', '☘', '☺', '☯',
      '☮', '☾', '☽', '♨', '✂', '✈', '✉', '✔', '✿', '❄', '⚡', '⚙', '⚽', '♪', '♫'
    ];
    const ASCII_EMOJI_COLOR_FAMILIES = {
      red: ['❤️', '♥️', '❣️', '🌹', '🍓', '🍒', '🌶️', '🐞', '🔴', '🟥'],
      orange: ['🧡', '🍊', '🍑', '🥕', '🦊', '🌅', '🔶', '🔸', '🟠', '🟧'],
      yellow: ['💛', '😀', '😃', '😄', '😊', '😉', '🤩', '🌟', '⭐️', '☀️', '🌼', '🌻', '🟡', '🟨'],
      green: ['💚', '🤢', '🤮', '🐸', '🍀', '🌿', '🍏', '🥝', '🥦', '🟢', '🟩'],
      blue: ['💙', '🥶', '🫐', '🐟', '🐬', '🌊', '🌀', '🧊', '🔵', '🟦'],
      purple: ['💜', '😈', '👾', '🍆', '☂️', '🪻', '🔮', '🟣', '🟪'],
      brown: ['🤎', '🐻', '🦉', '🥔', '🍪', '🌰', '🟤', '🟫'],
      white: ['🤍', '☁️', '🫧', '❄️', '🤍', '⚪', '⬜', '✨'],
      black: ['🖤', '🎱', '🕷️', '🌑', '♠️', '⚫', '⬛', '🕶️'],
    };
    const ASCII_EMOJI_COLOR_POOL = Object.values(ASCII_EMOJI_COLOR_FAMILIES).flat();
    const ASCII_EMOJI_CHARSET_DEFAULT_SIZE = 7;
    const ASCII_EMOJI_CHARSET_MIN_SIZE = 2;
    const ASCII_EMOJI_CHARSET_MAX_SIZE = 100;
    const ASCII_MIN_WIDTH = 16;
    const ASCII_MAX_WIDTH = 200;
    const ASCII_TEXT_FONT_STACK = '"Roboto Mono", "SF Mono", Menlo, Monaco, Consolas, "Liberation Mono", monospace';
    const ASCII_SYMBOL_FONT_STACK = '"Noto Sans Mono CJK JP", "Noto Sans Mono CJK SC", "Sarasa Mono J", "MS Gothic", "Osaka-Mono", "Hiragino Sans", monospace';
    const ASCII_EMOJI_TEXT_FONT_STACK = ASCII_SYMBOL_FONT_STACK;
    const ASCII_EMOJI_COLOR_FONT_STACK = ASCII_TEXT_FONT_STACK;
    /** advance/lineHeight (~0.55) for Latin mono at Figma 110% leading — tall cells. */
    const ASCII_CELL_ASPECT_MONOSPACE = 0.55;
    /** Block shades (░▒▓█) map to ~square terminal cells; using 0.55 undersamples rows → squat output. */
    const ASCII_CELL_ASPECT_BLOCK_ELEMENTS = 1;
    let asciiBrightnessOrderCache = new Map();
    const asciiGraphemeSegmenter = typeof Intl !== 'undefined' && typeof Intl.Segmenter === 'function'
      ? new Intl.Segmenter(undefined, { granularity: 'grapheme' })
      : null;

    function clampAsciiWidth(value) {
      const parsed = parseInt(String(value ?? ''), 10);
      if (!Number.isFinite(parsed)) return 80;
      return Math.max(ASCII_MIN_WIDTH, Math.min(ASCII_MAX_WIDTH, parsed));
    }

    function normalizeAsciiDensity(value) {
      const parsed = Number(value);
      if (!Number.isFinite(parsed)) return 0.7;
      return Math.max(0, Math.min(1, parsed / 100));
    }

    function isAsciiColorOutputEnabled(values) {
      return values?.colorOutput === true || values?.colorOutput === 'true';
    }

    function splitAsciiGlyphs(value) {
      const text = String(value || '');
      if (!text) return [];
      if (asciiGraphemeSegmenter) {
        return Array.from(asciiGraphemeSegmenter.segment(text), (entry) => entry.segment).filter(Boolean);
      }
      return Array.from(text);
    }

    function isAsciiEmojiPreset(values) {
      return String(values?.charsetPreset || '').toLowerCase() === 'emoji';
    }

    function getAsciiEmojiPool(values) {
      return isAsciiColorOutputEnabled(values) ? ASCII_EMOJI_COLOR_POOL : ASCII_EMOJI_TEXT_POOL;
    }

    function rgbToHsl(r, g, b) {
      const rn = Math.max(0, Math.min(1, r / 255));
      const gn = Math.max(0, Math.min(1, g / 255));
      const bn = Math.max(0, Math.min(1, b / 255));
      const max = Math.max(rn, gn, bn);
      const min = Math.min(rn, gn, bn);
      const delta = max - min;

      let h = 0;
      if (delta > 0) {
        if (max === rn) {
          h = ((gn - bn) / delta) % 6;
        } else if (max === gn) {
          h = (bn - rn) / delta + 2;
        } else {
          h = (rn - gn) / delta + 4;
        }
        h *= 60;
        if (h < 0) h += 360;
      }

      const l = (max + min) / 2;
      const s = delta === 0 ? 0 : delta / (1 - Math.abs(2 * l - 1));
      return { h, s, l };
    }

    function getAsciiEmojiColorFamily(r, g, b) {
      const { h, s, l } = rgbToHsl(r, g, b);

      if (l <= 0.16) return 'black';
      if (s <= 0.12 && l >= 0.82) return 'white';
      if (s <= 0.12) return l < 0.42 ? 'black' : 'white';

      if (h >= 15 && h < 45 && l < 0.5) return 'brown';
      if (h < 20 || h >= 345) return l > 0.72 ? 'white' : 'red';
      if (h < 45) return 'orange';
      if (h < 70) return 'yellow';
      if (h < 170) return 'green';
      if (h < 255) return 'blue';
      if (h < 345) return 'purple';
      return 'red';
    }

    function getColorMatchedEmojiGlyph(r, g, b, normalized, emojiGlyphs = null) {
      const familyName = getAsciiEmojiColorFamily(r, g, b);
      const fallbackFamily = ASCII_EMOJI_COLOR_FAMILIES[familyName] || ASCII_EMOJI_COLOR_FAMILIES.blue;
      const availableGlyphs = Array.isArray(emojiGlyphs) && emojiGlyphs.length > 0 ? emojiGlyphs : fallbackFamily;
      const familySet = new Set(fallbackFamily);
      const familyGlyphs = availableGlyphs.filter((glyph) => familySet.has(glyph));
      const pool = familyGlyphs.length > 0 ? familyGlyphs : availableGlyphs;
      const idx = Math.max(0, Math.min(pool.length - 1, Math.round(normalized * (pool.length - 1))));
      return pool[idx] || pool[pool.length - 1] || fallbackFamily[fallbackFamily.length - 1] || '🟦';
    }

    function getAsciiEmojiCharsetSize(values) {
      const parsed = Number(values?.emojiCharsetCount);
      if (!Number.isFinite(parsed)) return ASCII_EMOJI_CHARSET_DEFAULT_SIZE;
      return Math.max(
        ASCII_EMOJI_CHARSET_MIN_SIZE,
        Math.min(ASCII_EMOJI_CHARSET_MAX_SIZE, Math.round(parsed))
      );
    }

    function generateAsciiEmojiCharset(values, { randomize = true } = {}) {
      const sourcePool = getAsciiEmojiPool(values);
      if (!Array.isArray(sourcePool) || sourcePool.length === 0) return '';

      const picked = [];
      const targetSize = getAsciiEmojiCharsetSize(values);
      while (picked.length < targetSize) {
        const cyclePool = [...sourcePool];
        while (picked.length < targetSize && cyclePool.length > 0) {
          const index = randomize ? Math.floor(Math.random() * cyclePool.length) : 0;
          picked.push(cyclePool.splice(index, 1)[0]);
        }
      }
      return picked.join('');
    }

    function sortAsciiCharsetByBrightness(charset) {
      const chars = splitAsciiGlyphs(charset);
      const uniqueChars = [];
      const seen = new Set();
      chars.forEach((ch) => {
        if (!seen.has(ch)) {
          seen.add(ch);
          uniqueChars.push(ch);
        }
      });

      if (uniqueChars.length <= 1) {
        return uniqueChars.join('');
      }

      const cacheKey = uniqueChars.join('');
      if (asciiBrightnessOrderCache.has(cacheKey)) {
        return asciiBrightnessOrderCache.get(cacheKey);
      }

      const fontSize = 24;
      const pad = 6;
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (!ctx) {
        return uniqueChars.join('');
      }

      ctx.font = `${fontSize}px ${ASCII_TEXT_FONT_STACK}`;
      ctx.textBaseline = 'top';
      const metrics = uniqueChars.map((ch) => {
        const measure = ctx.measureText(ch || ' ');
        const width = Math.max(
          1,
          Math.ceil(
            Math.max(
              measure.width || 0,
              measure.actualBoundingBoxLeft + measure.actualBoundingBoxRight || 0,
              fontSize * 0.7
            )
          )
        );
        const height = Math.max(
          1,
          Math.ceil(
            Math.max(
              measure.actualBoundingBoxAscent + measure.actualBoundingBoxDescent || 0,
              fontSize * 1.2
            )
          )
        );
        canvas.width = width + pad * 2;
        canvas.height = height + pad * 2;
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.font = `${fontSize}px ${ASCII_TEXT_FONT_STACK}`;
        ctx.textBaseline = 'top';
        ctx.fillStyle = '#000000';
        ctx.fillText(ch, pad, pad);

        const image = ctx.getImageData(0, 0, canvas.width, canvas.height).data;
        let total = 0;
        for (let i = 0; i < image.length; i += 4) {
          total += image[i];
        }

        return {
          ch,
          brightness: total / (canvas.width * canvas.height)
        };
      });

      // Our mapper expects light → dark ordering.
      const ordered = metrics
        .sort((a, b) => b.brightness - a.brightness)
        .map((item) => item.ch)
        .join('');

      asciiBrightnessOrderCache.set(cacheKey, ordered);
      return ordered;
    }

    function resolveAsciiEmojiCharset(values, { fallbackToGenerated = true } = {}) {
      const custom = String(values?.customCharset || '');
      if (splitAsciiGlyphs(custom).length > 1) {
        return custom;
      }
      if (!fallbackToGenerated) {
        throw new Error('Emoji charset must contain at least 2 emoji.');
      }
      return generateAsciiEmojiCharset(values, { randomize: false });
    }

    function resolveAsciiCharset(values) {
      const preset = String(values.charsetPreset || 'standard').toLowerCase();
      if (preset === 'emoji') {
        return resolveAsciiEmojiCharset(values);
      }
      if (preset === 'custom') {
        const custom = String(values.customCharset || '');
        if (splitAsciiGlyphs(custom).length <= 1) {
          throw new Error('Custom charset must contain at least 2 characters.');
        }
        return sortAsciiCharsetByBrightness(custom);
      }
      const configured = ASCII_CHARSET_PRESETS[preset] || ASCII_CHARSET_PRESETS.standard;
      if (preset === 'blocks' || preset === 'codestyle' || preset === 'airy' || preset === 'symbols') {
        return configured;
      }
      return sortAsciiCharsetByBrightness(configured);
    }

    function resolveAsciiCharAspect(values) {
      const preset = String(values.charsetPreset || 'standard').toLowerCase();
      if (preset === 'blocks' || preset === 'symbols' || preset === 'emoji') {
        return ASCII_CELL_ASPECT_BLOCK_ELEMENTS;
      }
      return ASCII_CELL_ASPECT_MONOSPACE;
    }

    function resolveAsciiFontStack(preset, colorOutput = false) {
      if (preset === 'symbols') return ASCII_SYMBOL_FONT_STACK;
      if (preset === 'emoji') {
        return colorOutput ? ASCII_EMOJI_COLOR_FONT_STACK : ASCII_EMOJI_TEXT_FONT_STACK;
      }
      return ASCII_TEXT_FONT_STACK;
    }

    function bytesToDataUrl(data, mimeType = 'image/png') {
      return `data:${mimeType};base64,${arrayBufferToBase64(new Uint8Array(data))}`;
    }

    function loadImageFromDataUrl(dataUrl) {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => resolve(img);
        img.onerror = () => reject(new Error('Failed to load source image.'));
        img.src = dataUrl;
      });
    }

    function runPluginMessageRequest(requestMessage, resultType, { timeoutMs = 30000, errorMatcher = null } = {}) {
      return new Promise((resolve, reject) => {
        const timeout = setTimeout(() => {
          window.removeEventListener('message', handler);
          reject(new Error('Timed out while running local quick action.'));
        }, timeoutMs);

        const handler = (event) => {
          const msg = event.data?.pluginMessage;
          if (!msg) return;

          if (msg.type === resultType) {
            clearTimeout(timeout);
            window.removeEventListener('message', handler);
            resolve(msg);
            return;
          }

          if (msg.type === 'error' && (!errorMatcher || errorMatcher(msg))) {
            clearTimeout(timeout);
            window.removeEventListener('message', handler);
            reject(new Error(msg.message || 'Local quick action failed.'));
          }
        };

        window.addEventListener('message', handler);
        parent.postMessage({ pluginMessage: requestMessage }, '*');
      });
    }

    async function requestAsciiSourceImages() {
      const response = await runPluginMessageRequest(
        { type: 'get-ascii-source-images' },
        'ascii-source-images-result',
        {
          timeoutMs: 45000,
          errorMatcher: (msg) => typeof msg.message === 'string' && msg.message.includes('Failed to export ASCII source images')
        }
      );

      return Array.isArray(response.images) ? response.images : [];
    }

    async function createAsciiTextNodes(items, options = {}) {
      return runPluginMessageRequest(
        { type: 'create-ascii-text-nodes', items, ...options },
        'ascii-text-nodes-created',
        {
          timeoutMs: 45000,
          errorMatcher: (msg) => typeof msg.message === 'string' && msg.message.includes('ASCII text')
        }
      );
    }

    async function createAsciiFillNodes(items, options = {}) {
      return runPluginMessageRequest(
        { type: 'create-ascii-fill-nodes', items, ...options },
        'ascii-fill-nodes-created',
        {
          timeoutMs: 45000,
          errorMatcher: (msg) => typeof msg.message === 'string' && msg.message.includes('ASCII fill')
        }
      );
    }

    async function resolveAsciiSourceInputs(values) {
      const uploadedImages = extractImageDataUrls(values.imageInput);
      if (uploadedImages.length > 0) {
        return uploadedImages.map((dataUrl, index) => ({
          id: `upload-${index + 1}`,
          name: `Upload ${index + 1}`,
          dataUrl,
          width: null,
          height: null,
          x: null,
          y: null
        }));
      }

      const exportedImages = await requestAsciiSourceImages();
      return exportedImages.map((item, index) => ({
        id: item.id || `selection-${index + 1}`,
        name: item.name || `Selection ${index + 1}`,
        dataUrl: bytesToDataUrl(item.data || []),
        width: Number.isFinite(item.width) ? item.width : null,
        height: Number.isFinite(item.height) ? item.height : null,
        x: Number.isFinite(item.x) ? item.x : null,
        y: Number.isFinite(item.y) ? item.y : null
      }));
    }

    async function prefillImageToAsciiSourceImageFromSelection() {
      if (currentPromptAction?.directAction !== 'imageToAscii') return;
      const container = promptDrawerFields.querySelector('.prompt-image-upload-container[data-field-key="imageInput"]');
      if (!container) return;

      const currentValues = getPromptFieldValues();
      if (extractImageDataUrls(currentValues.imageInput).length > 0) return;

      const exportedImages = await requestAsciiSourceImages();
      if (!Array.isArray(exportedImages) || exportedImages.length === 0) return;

      populateImageFieldWithReference([exportedImages[0]], container);
      updatePromptDrawerImageChips();
      savePromptHistory();
      scheduleImageToAsciiPreviewRefresh();
    }

    /** Match `convertImageToAscii` geometry: columns × rows for the current source and width. */
    async function estimateImageToAsciiOutputCellCount(values) {
      const sources = await resolveAsciiSourceInputs(values);
      if (!sources.length) return 0;
      const width = clampAsciiWidth(values.width);
      const charAspect = resolveAsciiCharAspect(values);
      const image = await loadImageFromDataUrl(sources[0].dataUrl);
      const outputHeight = Math.max(
        1,
        Math.round((image.naturalHeight / Math.max(1, image.naturalWidth)) * width * charAspect)
      );
      return width * outputHeight;
    }

    /** Sobel gradients and magnitude (raw, before thinning), for Edges-only ASCII. */
    function buildAsciiSobelEdgeMap(pixels, width, height) {
      const n = width * height;
      const gray = new Float32Array(n);
      for (let i = 0, p = 0; i < n; i++, p += 4) {
        const a = pixels[p + 3] / 255;
        if (a <= 0.05) {
          gray[i] = -1;
        } else {
          gray[i] =
            (pixels[p] * 0.2126 + pixels[p + 1] * 0.7152 + pixels[p + 2] * 0.0722) / 255;
        }
      }
      const mag = new Float32Array(n);
      const gxArr = new Float32Array(n);
      const gyArr = new Float32Array(n);
      const sample = (yy, xx) => {
        const yi = Math.max(0, Math.min(height - 1, yy));
        const xi = Math.max(0, Math.min(width - 1, xx));
        const g = gray[yi * width + xi];
        return g < 0 ? 0 : g;
      };
      for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
          const idx = y * width + x;
          if (gray[idx] < 0) {
            mag[idx] = 0;
            gxArr[idx] = 0;
            gyArr[idx] = 0;
            continue;
          }
          const gx =
            -sample(y - 1, x - 1) +
            sample(y - 1, x + 1) -
            2 * sample(y, x - 1) +
            2 * sample(y, x + 1) -
            sample(y + 1, x - 1) +
            sample(y + 1, x + 1);
          const gy =
            -sample(y - 1, x - 1) -
            2 * sample(y - 1, x) -
            sample(y - 1, x + 1) +
            sample(y + 1, x - 1) +
            2 * sample(y + 1, x) +
            sample(y + 1, x + 1);
          gxArr[idx] = gx;
          gyArr[idx] = gy;
          mag[idx] = Math.hypot(gx, gy);
        }
      }
      return { mag, gx: gxArr, gy: gyArr };
    }

    /** Thin Sobel ridges to ~1 cell wide (Canny-style NMS) so thickness 1 is not a 2px band. */
    function nonMaxSuppressAsciiEdges(mag, gx, gy, width, height) {
      const out = new Float32Array(mag.length);
      for (let y = 1; y < height - 1; y++) {
        for (let x = 1; x < width - 1; x++) {
          const i = y * width + x;
          const m = mag[i];
          if (m <= 0) continue;
          const angle = (Math.atan2(gy[i], gx[i]) * 180) / Math.PI;
          const a = ((angle + 180) % 180);
          let n1;
          let n2;
          if (a < 22.5 || a >= 157.5) {
            n1 = mag[i - 1];
            n2 = mag[i + 1];
          } else if (a >= 22.5 && a < 67.5) {
            n1 = mag[i - width + 1];
            n2 = mag[i + width - 1];
          } else if (a >= 67.5 && a < 112.5) {
            n1 = mag[i - width];
            n2 = mag[i + width];
          } else {
            n1 = mag[i - width - 1];
            n2 = mag[i + width + 1];
          }
          if (m >= n1 && m >= n2) out[i] = m;
        }
      }
      return out;
    }

    function asciiEdgeMagInvMax(mag) {
      let maxM = 0;
      for (let i = 0; i < mag.length; i++) {
        if (mag[i] > maxM) maxM = mag[i];
      }
      return maxM > 1e-9 ? 1 / maxM : 0;
    }

    /** Expand strong edge responses by taking max magnitude in a square neighborhood (Chebyshev radius). */
    /** RGB quantization step from target palette size (~L³ colors, L levels per channel). */
    function asciiQuantStepFromMaxColors(raw) {
      const capped = Math.max(8, Math.min(512, Number(raw) || 120));
      const levels = Math.max(2, Math.min(32, Math.round(Math.cbrt(capped))));
      return Math.max(1, Math.floor(256 / levels));
    }

    function dilateAsciiEdgeMagBoxMax(mag, width, height, radius) {
      if (radius <= 0) return mag;
      const out = new Float32Array(mag.length);
      for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
          let m = 0;
          const y0 = Math.max(0, y - radius);
          const y1 = Math.min(height - 1, y + radius);
          const x0 = Math.max(0, x - radius);
          const x1 = Math.min(width - 1, x + radius);
          for (let yy = y0; yy <= y1; yy++) {
            const row = yy * width;
            for (let xx = x0; xx <= x1; xx++) {
              const v = mag[row + xx];
              if (v > m) m = v;
            }
          }
          out[y * width + x] = m;
        }
      }
      return out;
    }

    async function convertImageToAscii(source, values) {
      const preset = String(values.charsetPreset || 'standard').toLowerCase();
      const useColorMatchedEmoji = preset === 'emoji' && isAsciiColorOutputEnabled(values);
      const charset = splitAsciiGlyphs(resolveAsciiCharset(values));
      const emojiGlyphs = useColorMatchedEmoji ? charset.slice() : null;
      const width = clampAsciiWidth(values.width);
      const density = normalizeAsciiDensity(values.density);
      const invert = values.invert === true || values.invert === 'true';
      const edgesOnly = values.edgesOnly === true || values.edgesOnly === 'true';
      const colorOutput = isAsciiColorOutputEnabled(values);
      const image = await loadImageFromDataUrl(source.dataUrl);
      const charAspect = resolveAsciiCharAspect(values);
      const outputHeight = Math.max(1, Math.round((image.naturalHeight / Math.max(1, image.naturalWidth)) * width * charAspect));

      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = outputHeight;
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (!ctx) {
        throw new Error('Canvas is unavailable for ASCII conversion.');
      }

      ctx.imageSmoothingEnabled = density < 0.7;
      ctx.imageSmoothingQuality = density < 0.35 ? 'high' : (density < 0.7 ? 'medium' : 'low');
      ctx.drawImage(image, 0, 0, width, outputHeight);

      const pixels = ctx.getImageData(0, 0, width, outputHeight).data;
      const lines = [];
      const colorRows = colorOutput ? [] : null;
      const gamma = 1.25 - density * 0.55;
      const colorQuantStep = colorOutput ? asciiQuantStepFromMaxColors(values.colorMaxColors) : 0;
      const quantRgb = (v) => {
        const q = colorQuantStep;
        if (q <= 0) return v;
        return Math.min(255, Math.round(v / q) * q);
      };
      const edgeData = edgesOnly ? buildAsciiSobelEdgeMap(pixels, width, outputHeight) : null;
      let edgeMag = edgeData
        ? nonMaxSuppressAsciiEdges(edgeData.mag, edgeData.gx, edgeData.gy, width, outputHeight)
        : null;
      let edgeInvMax = edgeMag ? asciiEdgeMagInvMax(edgeMag) : 0;
      if (edgesOnly && edgeMag && edgeInvMax > 0) {
        const etRaw = Number(values.edgeThickness);
        const thickness = Number.isFinite(etRaw) ? Math.max(1, Math.min(12, Math.round(etRaw))) : 1;
        const dilateRadius = thickness - 1;
        if (dilateRadius > 0) {
          edgeMag = dilateAsciiEdgeMagBoxMax(edgeMag, width, outputHeight, dilateRadius);
          edgeInvMax = asciiEdgeMagInvMax(edgeMag);
        }
      }

      for (let y = 0; y < outputHeight; y++) {
        let line = '';
        const rowColors = colorOutput ? [] : null;
        for (let x = 0; x < width; x++) {
          const offset = (y * width + x) * 4;
          const alpha = pixels[offset + 3] / 255;
          if (alpha <= 0.05) {
            line += charset[0] || ' ';
            if (rowColors) rowColors.push(null);
            continue;
          }

          let normalized;
          if (edgesOnly && edgeMag && edgeInvMax > 0) {
            const rawEdge = edgeMag[y * width + x] * edgeInvMax;
            normalized = invert ? (1 - rawEdge) : rawEdge;
          } else {
            const luminance = (
              pixels[offset] * 0.2126 +
              pixels[offset + 1] * 0.7152 +
              pixels[offset + 2] * 0.0722
            ) / 255;
            normalized = invert ? luminance : (1 - luminance);
          }
          normalized = Math.max(0, Math.min(1, Math.pow(normalized, gamma)));
          const qR = quantRgb(pixels[offset]);
          const qG = quantRgb(pixels[offset + 1]);
          const qB = quantRgb(pixels[offset + 2]);
          const glyph = useColorMatchedEmoji
            ? getColorMatchedEmojiGlyph(
                qR,
                qG,
                qB,
                normalized,
                emojiGlyphs
              )
            : (() => {
                const index = Math.max(0, Math.min(charset.length - 1, Math.round(normalized * (charset.length - 1))));
                return charset[index] || charset[charset.length - 1] || ' ';
              })();
          line += glyph;
          if (rowColors) {
            rowColors.push({
              r: qR,
              g: qG,
              b: qB,
              a: alpha
            });
          }
        }
        lines.push(line);
        if (colorRows && rowColors) colorRows.push(rowColors);
      }

      return {
        name: source.name,
        sourceNodeId: source.id && !String(source.id).startsWith('upload-') ? source.id : null,
        x: source.x,
        y: source.y,
        width: source.width,
        height: source.height,
        asciiText: lines.join('\n'),
        columns: width,
        rows: outputHeight,
        invert,
        colorOutput,
        colorRows,
        colorQuantStep,
        charsetPreset: preset,
        sourceNaturalWidth: image.naturalWidth,
        sourceNaturalHeight: image.naturalHeight
      };
    }

    function buildAsciiColorRuns(asciiResult) {
      if (!asciiResult?.colorOutput || !Array.isArray(asciiResult?.colorRows)) return [];

      const lines = String(asciiResult.asciiText || '').split('\n');
      const colorRows = asciiResult.colorRows;
      const runs = [];
      let cursor = 0;
      let activeRun = null;

      /** Colors are quantized in convertImageToAscii via colorQuantStep; optionally re-round for safety. */
      const qRgb = Number(asciiResult.colorQuantStep) || 0;
      const roundRgb = (v) => (qRgb <= 0 ? v : Math.min(255, Math.round(v / qRgb) * qRgb));

      const flushRun = () => {
        if (!activeRun) return;
        runs.push(activeRun);
        activeRun = null;
      };

      for (let row = 0; row < lines.length; row++) {
        const line = lines[row];
        const glyphs = splitAsciiGlyphs(line);
        const rowColors = Array.isArray(colorRows[row]) ? colorRows[row] : [];
        let col = 0;
        for (const glyph of glyphs) {
          const color = col < rowColors.length ? rowColors[col] : undefined;
          col += 1;
          const nextColor = color && Number.isFinite(color.r) && Number.isFinite(color.g) && Number.isFinite(color.b)
            ? {
                r: roundRgb(color.r),
                g: roundRgb(color.g),
                b: roundRgb(color.b),
                a: Number.isFinite(color.a) ? color.a : 1,
              }
            : null;

          if (!nextColor) {
            flushRun();
            cursor += glyph.length;
            continue;
          }

          const sameAsActive = activeRun &&
            activeRun.color.r === nextColor.r &&
            activeRun.color.g === nextColor.g &&
            activeRun.color.b === nextColor.b &&
            activeRun.color.a === nextColor.a &&
            activeRun.end === cursor;

          if (sameAsActive) {
            activeRun.end += glyph.length;
          } else {
            flushRun();
            activeRun = { start: cursor, end: cursor + glyph.length, color: nextColor };
          }
          cursor += glyph.length;
        }

        flushRun();
        if (row < lines.length - 1) {
          cursor += 1;
        }
      }

      return runs;
    }

    function renderAsciiPreview(pre, asciiResult) {
      if (!pre) return;

      const preset = String(asciiResult?.charsetPreset || 'standard').toLowerCase();
      pre.style.fontFamily = resolveAsciiFontStack(preset, !!asciiResult?.colorOutput);
      pre.classList.toggle('ascii-preview-pre--symbols', preset === 'symbols');
      pre.classList.toggle('ascii-preview-pre--emoji', preset === 'emoji');
      if (preset === 'blocks' || preset === 'symbols' || preset === 'emoji') {
        pre.classList.add('ascii-preview-pre--grid');
        pre.innerHTML = '';
        const fragment = document.createDocumentFragment();
        const lines = String(asciiResult.asciiText || '').split('\n');
        const colorRows = Array.isArray(asciiResult?.colorRows) ? asciiResult.colorRows : null;

        lines.forEach((line, rowIndex) => {
          const chars = splitAsciiGlyphs(line);
          const rowColors = colorRows?.[rowIndex];
          chars.forEach((ch, colIndex) => {
            const span = document.createElement('span');
            span.className = 'ascii-preview-cell';
            span.textContent = ch === ' ' ? '\u00A0' : ch;

            const color = rowColors?.[colIndex];
            if (color && Number.isFinite(color.r) && Number.isFinite(color.g) && Number.isFinite(color.b)) {
              span.style.color = `rgba(${color.r}, ${color.g}, ${color.b}, ${Number.isFinite(color.a) ? color.a : 1})`;
            }

            fragment.appendChild(span);
          });

          if (rowIndex < lines.length - 1) {
            fragment.appendChild(document.createTextNode('\n'));
          }
        });

        pre.appendChild(fragment);
        return;
      }

      pre.classList.remove('ascii-preview-pre--grid');
      pre.classList.remove('ascii-preview-pre--symbols');
      pre.classList.remove('ascii-preview-pre--emoji');

      if (!asciiResult?.colorOutput || !Array.isArray(asciiResult?.colorRows)) {
        pre.textContent = asciiResult?.asciiText || '';
        return;
      }

      pre.innerHTML = '';
      const fragment = document.createDocumentFragment();
      const lines = String(asciiResult.asciiText || '').split('\n');
      const colorRows = asciiResult.colorRows;

      lines.forEach((line, rowIndex) => {
        const chars = splitAsciiGlyphs(line);
        const rowColors = Array.isArray(colorRows[rowIndex]) ? colorRows[rowIndex] : [];
        chars.forEach((ch, colIndex) => {
          const color = rowColors[colIndex];
          if (color && Number.isFinite(color.r) && Number.isFinite(color.g) && Number.isFinite(color.b)) {
            const span = document.createElement('span');
            span.textContent = ch === ' ' ? '\u00A0' : ch;
            span.style.color = `rgba(${color.r}, ${color.g}, ${color.b}, ${Number.isFinite(color.a) ? color.a : 1})`;
            fragment.appendChild(span);
          } else {
            fragment.appendChild(document.createTextNode(ch === ' ' ? '\u00A0' : ch));
          }
        });

        if (rowIndex < lines.length - 1) {
          fragment.appendChild(document.createTextNode('\n'));
        }
      });

      pre.appendChild(fragment);
    }

    let asciiPreviewResizeObserver = null;
    /** Latest Image→ASCII preview result for layout (source aspect ratio). */
    let lastAsciiPreviewLayoutResult = null;

    function resetAsciiPreviewViewport(panel) {
      const viewport = panel && panel.querySelector('.ascii-preview-viewport');
      const wrap = panel && panel.querySelector('.ascii-preview-scale-wrap');
      if (wrap) {
        wrap.style.transform = '';
        wrap.style.transformOrigin = '';
      }
      if (viewport) {
        viewport.style.height = '';
        viewport.style.width = '';
        viewport.style.margin = '';
        viewport.style.maxWidth = '';
      }
    }

    const ASCII_PREVIEW_MAX_HEIGHT_PX = 240;
    /** Warn / confirm before colored ASCII as Text when the grid is this large (columns × rows). */
    const ASCII_COLOR_TEXT_SLOW_CELL_THRESHOLD = 3000;

    function layoutAsciiPreviewInViewport(panel, asciiResult) {
      if (!panel) return;
      const viewport = panel.querySelector('.ascii-preview-viewport');
      const wrap = panel.querySelector('.ascii-preview-scale-wrap');
      const pre = panel.querySelector('.ascii-preview-pre');
      if (!viewport || !wrap || !pre) return;

      wrap.style.transform = '';
      wrap.style.transformOrigin = '';

      const contentW = pre.scrollWidth;
      const contentH = pre.scrollHeight;
      if (contentW < 1 || contentH < 1) {
        viewport.style.height = '';
        viewport.style.width = '';
        viewport.style.margin = '';
        viewport.style.maxWidth = '';
        return;
      }

      const cs = getComputedStyle(viewport);
      const padX = parseFloat(cs.paddingLeft) + parseFloat(cs.paddingRight) || 0;
      const padY = parseFloat(cs.paddingTop) + parseFloat(cs.paddingBottom) || 0;

      const sw = asciiResult && Number(asciiResult.sourceNaturalWidth);
      const sh = asciiResult && Number(asciiResult.sourceNaturalHeight);
      const ratio = Number.isFinite(sw) && Number.isFinite(sh) && sh > 0 ? sw / sh : null;

      const panelW = Math.max(1, panel.clientWidth || 0);
      const maxOuterH = ASCII_PREVIEW_MAX_HEIGHT_PX;
      const maxInnerW = Math.max(1, panelW - padX);
      const maxInnerH = Math.max(1, maxOuterH - padY);

      let innerW;
      let innerH;
      if (ratio && ratio > 0) {
        innerW = maxInnerW;
        innerH = innerW / ratio;
        if (innerH > maxInnerH) {
          innerH = maxInnerH;
          innerW = innerH * ratio;
        }
        viewport.style.width = `${Math.ceil(innerW + padX)}px`;
        viewport.style.maxWidth = '100%';
        viewport.style.margin = '0 auto';
        viewport.style.height = `${Math.ceil(innerH + padY)}px`;
      } else {
        viewport.style.width = '';
        viewport.style.maxWidth = '';
        viewport.style.margin = '';
        viewport.style.height = '';
        innerW = Math.max(1, viewport.clientWidth - padX);
        const maxH = parseFloat(cs.maxHeight);
        innerH = Math.max(1, (Number.isFinite(maxH) ? maxH : viewport.clientHeight) - padY);
      }

      const vpW = Math.max(1, innerW);
      const vpH = Math.max(1, innerH);

      const scale = Math.min(1, vpW / contentW, vpH / contentH);
      wrap.style.transformOrigin = '0 0';
      wrap.style.transform = `scale(${scale})`;
      if (!ratio) {
        viewport.style.height = `${Math.max(1, Math.ceil(contentH * scale + padY))}px`;
      }
    }

    function renderAsciiToBitmap(asciiResult) {
      const lines = String(asciiResult.asciiText || '').split('\n');
      const columns = lines.reduce((max, line) => Math.max(max, splitAsciiGlyphs(line).length), 1);
      const fontSize = 12;
      const padding = 12;
      const lineHeight = Math.ceil(fontSize * 1.2);
      const preset = String(asciiResult.charsetPreset || 'standard').toLowerCase();
      const useSquareCells = preset === 'blocks' || preset === 'symbols' || preset === 'emoji';
      const fontStack = resolveAsciiFontStack(preset, asciiResult.colorOutput);

      const measureCanvas = document.createElement('canvas');
      const measureCtx = measureCanvas.getContext('2d');
      if (!measureCtx) {
        throw new Error('Canvas is unavailable for ASCII rendering.');
      }
      measureCtx.font = `${fontSize}px ${fontStack}`;
      const charWidth = Math.max(7, Math.ceil(measureCtx.measureText('M').width));

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        throw new Error('Canvas is unavailable for ASCII rendering.');
      }

      const background = asciiResult.invert ? '#111111' : '#ffffff';
      const foreground = asciiResult.invert ? '#ffffff' : '#111111';
      const colorRows = Array.isArray(asciiResult.colorRows) ? asciiResult.colorRows : null;

      if (useSquareCells) {
        const cell = lineHeight;
        canvas.width = Math.max(1, padding * 2 + columns * cell);
        canvas.height = Math.max(1, padding * 2 + lines.length * cell);
        ctx.fillStyle = background;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.font = `${fontSize}px ${fontStack}`;
        ctx.textBaseline = 'middle';
        lines.forEach((line, row) => {
          const rowColors = colorRows?.[row];
          splitAsciiGlyphs(line).forEach((ch, col) => {
            const w = ctx.measureText(ch).width;
            const x = padding + col * cell + Math.max(0, (cell - w) / 2);
            const y = padding + row * cell + cell / 2;
            const color = rowColors?.[col];
            ctx.fillStyle = color
              ? `rgba(${color.r}, ${color.g}, ${color.b}, ${Number.isFinite(color.a) ? color.a : 1})`
              : foreground;
            ctx.fillText(ch, x, y);
          });
        });
      } else {
        canvas.width = Math.max(1, padding * 2 + charWidth * columns);
        canvas.height = Math.max(1, padding * 2 + lineHeight * lines.length);
        ctx.fillStyle = background;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.font = `${fontSize}px ${fontStack}`;
        ctx.textBaseline = 'top';
        lines.forEach((line, index) => {
          const chars = splitAsciiGlyphs(line);
          const rowColors = colorRows?.[index];
          chars.forEach((ch, col) => {
            const color = rowColors?.[col];
            ctx.fillStyle = color
              ? `rgba(${color.r}, ${color.g}, ${color.b}, ${Number.isFinite(color.a) ? color.a : 1})`
              : foreground;
            ctx.fillText(ch, padding + col * charWidth, padding + index * lineHeight);
          });
        });
      }

      return {
        base64: canvas.toDataURL('image/png').split(',')[1],
        width: canvas.width,
        height: canvas.height
      };
    }

    async function applyAsciiBitmapToSelection(renderedItems) {
      const targets = await getSelectionForFill();
      if (!targets || targets.length === 0) {
        throw new Error('Please select at least one node first.');
      }

      let commands;
      if (renderedItems.length === 1) {
        commands = targets.map(node => ({
          action: 'setImageFill',
          nodeId: node.id,
          imageData: base64ToBytes(renderedItems[0].base64),
          scaleMode: 'FILL',
          addAsNewLayer: false
        }));
      } else if (renderedItems.length === targets.length) {
        commands = targets.map((node, index) => ({
          action: 'setImageFill',
          nodeId: node.id,
          imageData: base64ToBytes(renderedItems[index].base64),
          scaleMode: 'FILL',
          addAsNewLayer: false
        }));
      } else {
        throw new Error('Replace selected fill supports either one source image or exactly one source per selected node.');
      }

      await new Promise((resolve, reject) => {
        const timeout = setTimeout(() => {
          window.removeEventListener('message', handler);
          reject(new Error('Timeout applying ASCII fill.'));
        }, 30000);

        const handler = (event) => {
          const msg = event.data?.pluginMessage;
          if (!msg) return;
          if (msg.type === 'commands-executed') {
            clearTimeout(timeout);
            window.removeEventListener('message', handler);
            if (msg.success > 0) {
              resolve(msg);
            } else {
              reject(new Error(msg.error || msg.message || 'Failed to apply ASCII fill.'));
            }
          }
        };

        window.addEventListener('message', handler);
        parent.postMessage({
          pluginMessage: {
            type: 'execute-commands',
            commands
          }
        }, '*');
      });
    }

    // Helper function to generate content using AI (thin wrapper around callAISimple)
    async function generateAuditContent(systemPrompt, userContent, apiKey) {
      const result = await callAISimple({ systemPrompt, userContent, temperature: 0.7, maxTokens: 4096 });
      return result.text;
    }

    async function runSemanticFontSearch({ query, candidates }) {
      if (!canUseSemanticFontSearch()) {
        const unavailableError = new Error('AI semantic font search is unavailable.');
        unavailableError.code = 'AI_UNAVAILABLE';
        throw unavailableError;
      }

      const normalizedQuery = String(query || '').trim();
      const candidateList = Array.isArray(candidates) ? candidates.slice(0, 250) : [];
      if (!normalizedQuery || candidateList.length === 0) {
        return { matches: [] };
      }

      const allowedMatches = new Map();
      const promptCandidates = candidateList.map((candidate, index) => {
        const family = String(candidate.family || '').trim();
        const source = candidate.source === 'local' ? 'local' : 'google';
        const key = `${source}::${family}`;
        allowedMatches.set(key, { family, source });
        return {
          index: index + 1,
          family,
          source,
          profile: String(candidate.semanticProfile || '').trim().slice(0, 320),
          localScore: Number.isFinite(candidate.localScore) ? Number(candidate.localScore) : 0,
        };
      }).filter(candidate => candidate.family);

      if (promptCandidates.length === 0) {
        return { matches: [] };
      }

      const systemPrompt = `You are a typography search expert. Rank candidate fonts by semantic fit to a user's description.

Rules:
- Use ONLY the provided candidates.
- Prefer semantic meaning over exact word overlap.
- Return no more than 60 matches.
- Every match MUST include "family" and "source" copied exactly from the candidates.
- "source" must be either "google" or "local".
- "reason" must be brief and concrete.
- "score" must be a number from 0 to 100.
- If nothing fits, return {"matches":[]}.
- Output JSON only.`;

      const userContent = JSON.stringify({
        query: normalizedQuery,
        maxMatches: 60,
        candidates: promptCandidates,
        outputSchema: {
          matches: [{ family: 'Font Family', source: 'google', reason: 'why it fits', score: 92 }]
        }
      });

      const response = await callAISimple({
        systemPrompt,
        userContent,
        temperature: 0.2,
        maxTokens: 4096,
        jsonMode: selectedProvider === 'gemini' || selectedProvider === 'openai' || selectedProvider === 'ollama',
      });

      const parsed = extractJsonObjectFromText(response.text);
      if (!parsed || !Array.isArray(parsed.matches)) {
        const parseError = new Error('Invalid semantic font search response.');
        parseError.code = 'INVALID_RESPONSE';
        throw parseError;
      }

      const seen = new Set();
      const matches = [];
      for (const rawMatch of parsed.matches) {
        const family = String(rawMatch?.family || '').trim();
        const source = rawMatch?.source === 'local' ? 'local' : rawMatch?.source === 'google' ? 'google' : '';
        if (!family || !source) continue;
        const key = `${source}::${family}`;
        if (!allowedMatches.has(key) || seen.has(key)) continue;
        seen.add(key);
        matches.push({
          family,
          source,
          reason: String(rawMatch?.reason || '').trim(),
          score: Number.isFinite(Number(rawMatch?.score)) ? Number(rawMatch.score) : null,
        });
        if (matches.length >= 60) break;
      }

      return { matches };
    }

    // ============================================
    // END AUDIT MODAL HANDLERS
    // ============================================

    // Custom tones for Change tone action
    let customTones = [];
    let customImagePresets = [];
    let customStyleCategories = [];
    let customReStylePresets = [];
    let customSmartRenamePresets = [];
