    function addTemplate() {
      const input = document.getElementById('newTemplateInput');
      if (!input) return;
      const text = input.value.trim();
      if (text) {
        replyTemplates.push(text);
        input.value = '';
        saveReplyTemplates();
        renderTemplateManagerList();
        refreshAllReplyTemplateContainers();
      }
    }

    function updateTemplate(index, value) {
      replyTemplates[index] = value;
      saveReplyTemplates();
      refreshAllReplyTemplateContainers();
    }

    function removeTemplate(index) {
      replyTemplates.splice(index, 1);
      saveReplyTemplates();
      renderTemplateManagerList();
      refreshAllReplyTemplateContainers();
    }

    function saveReplyTemplates() {
      parent.postMessage({ pluginMessage: { type: 'save-reply-templates', templates: replyTemplates } }, '*');
    }

    function refreshAllReplyTemplateContainers() {
      const batchReplyDropdown = document.getElementById('reply-dropdown-batchReplyTextarea');
      if (batchReplyDropdown && !batchReplyDropdown.classList.contains('hidden')) {
        batchReplyDropdown.innerHTML = renderBatchReplyTemplatesDropdownHtml('batchReplyTextarea');
      }
    }

    const baseAgentTasks = createAgentTasks({
      getCustomStyleCategories: () => customStyleCategories,
    });

    const builtInQuickActionNames = new Set(buildQuickActionsList(baseAgentTasks).map(action => action.name));
    const BUILT_IN_COMMAND_CATEGORIES = Object.keys(baseAgentTasks);
    const VALID_CUSTOM_QUICK_ACTION_CONTEXTS = new Set(PUBLIC_CONTEXT_MODES);
    const VALID_CUSTOM_QUICK_ACTION_INPUT_TYPES = new Set(['text', 'textarea', 'select', 'image']);

    function cloneAgentTaskMap(taskMap) {
      return Object.fromEntries(
        Object.entries(taskMap || {}).map(([category, tasks]) => [category, [...(tasks || [])]])
      );
    }

    function sanitizeCustomQuickActionInputKey(rawValue) {
      return typeof rawValue === 'string'
        ? rawValue.trim().replace(/[^a-zA-Z0-9_]/g, '_').replace(/_+/g, '_').replace(/^_+|_+$/g, '')
        : '';
    }

    function generateCustomQuickActionInputKey(baseLabel = '', existingInputs = [], fallbackIndex = null) {
      const base = sanitizeCustomQuickActionInputKey(baseLabel)
        || (fallbackIndex ? `input${fallbackIndex}` : 'input');
      const existingKeys = new Set((existingInputs || []).map((input) => String(input?.key || '').toLowerCase()).filter(Boolean));
      if (!existingKeys.has(base.toLowerCase())) return base;
      let counter = fallbackIndex || 1;
      let candidate = `${base}${counter}`;
      while (existingKeys.has(candidate.toLowerCase())) {
        counter += 1;
        candidate = `${base}${counter}`;
      }
      return candidate;
    }

    function generateCustomQuickActionInputId() {
      return `qai_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    }

    function generateCustomQuickActionInputOptionId() {
      return `qaio_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    }

    function sanitizeCustomQuickActionInputOptions(rawOptions) {
      if (!Array.isArray(rawOptions)) return [];

      const seenIds = new Set();
      const seenValues = new Set();
      return rawOptions.reduce((acc, item) => {
        if (!item || typeof item !== 'object') return acc;
        const id = typeof item.id === 'string' ? item.id.trim() : '';
        const label = typeof item.label === 'string' ? item.label.trim() : '';
        const value = typeof item.value === 'string' ? item.value.trim() : '';
        const normalizedValue = value.toLowerCase();
        if (!id || !label || !value) return acc;
        if (seenIds.has(id) || seenValues.has(normalizedValue)) return acc;
        seenIds.add(id);
        seenValues.add(normalizedValue);
        acc.push({ id, label, value });
        return acc;
      }, []);
    }

    function sanitizeCustomQuickActionInputs(rawInputs) {
      if (!Array.isArray(rawInputs)) return [];

      const seenIds = new Set();
      const seenKeys = new Set();
      return rawInputs.reduce((acc, item) => {
        if (!item || typeof item !== 'object') return acc;
        const id = typeof item.id === 'string' ? item.id.trim() : '';
        const label = typeof item.label === 'string' ? item.label.trim() : '';
        const key = sanitizeCustomQuickActionInputKey(item.key);
        const type = typeof item.type === 'string' && VALID_CUSTOM_QUICK_ACTION_INPUT_TYPES.has(item.type) ? item.type : null;
        const normalizedKey = key.toLowerCase();
        if (!id || !label || !key || !type) return acc;
        if (seenIds.has(id) || seenKeys.has(normalizedKey)) return acc;

        const multiple = type === 'select' ? item.multiple === true : false;
        const sanitizedInput = {
          id,
          key,
          label,
          type,
          required: item.required === true,
          multiple,
          options: type === 'select' ? sanitizeCustomQuickActionInputOptions(item.options) : [],
          allowCustomOption: type === 'select' ? item.allowCustomOption === true : false,
          placeholder: typeof item.placeholder === 'string' ? item.placeholder.trim() : '',
          defaultValue: null,
        };

        if (type === 'select' && multiple) {
          sanitizedInput.defaultValue = Array.isArray(item.defaultValue)
            ? item.defaultValue.map((entry) => typeof entry === 'string' ? entry.trim() : '').filter(Boolean)
            : [];
        } else if (typeof item.defaultValue === 'string') {
          sanitizedInput.defaultValue = item.defaultValue.trim();
        }

        seenIds.add(id);
        seenKeys.add(normalizedKey);
        acc.push(sanitizedInput);
        return acc;
      }, []);
    }

    function mapCustomQuickActionInputToField(input) {
      if (!input || !input.key || !input.label || !input.type) return null;
      const label = input.required ? `${input.label} *` : input.label;

      if (input.type === 'text') {
        return {
          key: input.key,
          type: 'text',
          label,
          placeholder: input.placeholder || '',
          default: typeof input.defaultValue === 'string' ? input.defaultValue : '',
        };
      }

      if (input.type === 'textarea') {
        return {
          key: input.key,
          type: 'textarea',
          label,
          placeholder: input.placeholder || '',
          default: typeof input.defaultValue === 'string' ? input.defaultValue : '',
        };
      }

      if (input.type === 'select') {
        const options = Array.isArray(input.options)
          ? input.options.map((option) => ({
            value: option.value,
            label: option.label,
          }))
          : [];
        if (input.allowCustomOption) {
          options.push({
            value: '__custom__',
            label: 'Custom option',
            inputKey: `${input.key}__custom`,
            inputDefault: '',
            inputType: 'text',
            inputPlaceholder: 'Enter custom option',
          });
        }
        return {
          key: input.key,
          type: 'select',
          label,
          multi: input.multiple === true,
          searchable: true,
          options,
          default: input.multiple === true
            ? (Array.isArray(input.defaultValue) ? input.defaultValue : [])
            : (typeof input.defaultValue === 'string' ? input.defaultValue : ''),
        };
      }

      if (input.type === 'image') {
        return {
          key: input.key,
          type: 'image',
          label,
          hint: input.placeholder || 'Add one or more images',
        };
      }

      return null;
    }

    function sanitizeCustomQuickActions(rawActions) {
      if (!Array.isArray(rawActions)) return [];

      const seenIds = new Set();
      const seenNames = new Set();

      return rawActions.reduce((acc, item) => {
        if (!item || typeof item !== 'object') return acc;

        const id = typeof item.id === 'string' ? item.id.trim() : '';
        const name = typeof item.name === 'string' ? item.name.trim() : '';
        const category = typeof item.category === 'string' ? item.category.trim() : '';
        const mode = item.mode === 'ask' ? 'ask' : item.mode === 'agent' ? 'agent' : null;
        const promptTemplate = typeof item.promptTemplate === 'string' ? item.promptTemplate.trim() : '';
        const normalizedName = name.toLowerCase();

        if (!id || !name || !category || !mode || !promptTemplate) return acc;
        if (!BUILT_IN_COMMAND_CATEGORIES.includes(category)) return acc;
        if (builtInQuickActionNames.has(name)) return acc;
        if (seenIds.has(id) || seenNames.has(normalizedName)) return acc;

        acc.push({
          id,
          name,
          category,
          mode,
          promptTemplate,
          inputs: sanitizeCustomQuickActionInputs(item.inputs),
          desc: typeof item.desc === 'string' ? item.desc.trim() : '',
          noSelection: item.noSelection === true,
          includeTokens: item.includeTokens === true,
          requiredContext: VALID_CUSTOM_QUICK_ACTION_CONTEXTS.has(item.requiredContext) ? item.requiredContext : ContextMode.SMART,
          createdAt: Number.isFinite(Number(item.createdAt)) ? Number(item.createdAt) : Date.now(),
          updatedAt: Number.isFinite(Number(item.updatedAt)) ? Number(item.updatedAt) : Date.now(),
        });

        seenIds.add(id);
        seenNames.add(normalizedName);
        return acc;
      }, []);
    }

    function mapCustomQuickActionToTask(action) {
      const mappedFields = Array.isArray(action.inputs)
        ? action.inputs.map(mapCustomQuickActionInputToField).filter(Boolean)
        : [];
      return {
        name: action.name,
        desc: action.desc || '',
        prompt: action.promptTemplate,
        promptTemplate: action.promptTemplate,
        fields: mappedFields,
        customQuickActionInputs: sanitizeCustomQuickActionInputs(action.inputs),
        noSelection: action.noSelection === true,
        includeTokens: action.includeTokens === true,
        requiredContext: VALID_CUSTOM_QUICK_ACTION_CONTEXTS.has(action.requiredContext) ? action.requiredContext : ContextMode.SMART,
        askMode: action.mode === 'ask',
        category: action.category,
        isCustomQuickAction: true,
        customQuickActionId: action.id,
      };
    }

    function pruneQuickActionUsageState() {
      const validNames = new Set(allQuickActions.map(action => action.name));
      const nextUsage = {};

      Object.entries(quickActionUsage || {}).forEach(([name, value]) => {
        if (validNames.has(name) && typeof value === 'number' && Number.isFinite(value) && value >= 0) {
          nextUsage[name] = value;
        }
      });

      quickActionUsage = nextUsage;
      lastUsedQuickActions = lastUsedQuickActions.filter(name => validNames.has(name)).slice(0, MAX_LAST_USED_ACTIONS);
      saveQuickActionUsageToLocal();
    }

    function rebuildAgentTasks(refreshUI = false) {
      const merged = cloneAgentTaskMap(baseAgentTasks);
      const sanitizedCustomActions = sanitizeCustomQuickActions(customQuickActions);
      customQuickActions = sanitizedCustomActions;

      sanitizedCustomActions.forEach((action) => {
        const category = action.category;
        if (!merged[category]) merged[category] = [];
        merged[category].unshift(mapCustomQuickActionToTask(action));
      });

      agentTasks = merged;
      allQuickActions = buildQuickActionsList(agentTasks);
      pruneQuickActionUsageState();

      if (refreshUI) {
        if (commandsDrawer?.classList.contains('show')) {
          renderDrawerContent(commandsSearch?.value || '');
        }
        if (slashMenuVisible || !lastSlashQuery) {
          handleSlashInput();
        }
        updateNodeActionsContent(lastKnownSelectionItems || []);
      }
    }

    let agentTasks = cloneAgentTaskMap(baseAgentTasks);

    const anyIconSetOption = {
      value: '',
      label: 'Any Iconify set',
      detail: 'Search across all Iconify collections',
      samples: ['home', 'search', 'settings'],
    };

    const defaultIconSetOption = {
      value: 'material-symbols',
      label: 'Material Symbols',
      detail: 'Iconify set',
      samples: ['home', 'search', 'settings'],
    };

    let iconCollectionsCache = null;
    let iconSetOptionsCache = [anyIconSetOption, defaultIconSetOption];
    let isLoadingIconSets = false;
    const iconifyCollectionSearchCache = new Map();
    const POPULAR_ICONIFY_LOCAL_SEARCH_PREFIXES = ['material-symbols', 'mdi', 'tabler', 'lucide', 'carbon', 'bi'];
    let createIconLazySearchRunId = 0;
    const CREATE_ICON_DRAWER_HISTORY_LIMIT = 8;
    let createIconDrawerHistoryTabs = [];
    let activeCreateIconDrawerHistoryTabId = null;

    const builtInIconSets = {
      'material-symbols': {
        name: 'Material Symbols',
        total: 15000,
        samples: ['home', 'search', 'settings'],
        category: 'Material',
        tags: ['Rounded', 'Outlined', 'Sharp']
      },
      'mdi': {
        name: 'Material Design Icons',
        total: 7000,
        samples: ['home', 'bell', 'account'],
        category: 'General',
        tags: ['UI', 'Filled', 'Outlined']
      },
      'tabler': {
        name: 'Tabler Icons',
        total: 4500,
        samples: ['star', 'calendar', 'check'],
        category: 'Outline',
        tags: ['Stroke', 'Outline']
      },
      'carbon': {
        name: 'Carbon',
        total: 1900,
        samples: ['add', 'subtract', 'user'],
        category: 'IBM',
        tags: ['IBM', 'UI']
      },
      'bi': {
        name: 'Bootstrap Icons',
        total: 2000,
        samples: ['alarm', 'archive', 'bag'],
        category: 'Bootstrap',
        tags: ['UI', 'Filled', 'Outline']
      }
    };

    function normalizeCollectionsPayload(data) {
      if (!data || typeof data !== 'object') return null;
      // Some endpoints return {collections:{...}}
      if (data.collections && typeof data.collections === 'object') return data.collections;
      return data;
    }

    async function fetchIconCollections() {
      const endpoints = [
        'https://api.iconify.design/collections?pretty=1',
        'https://api.iconify.design/collections',
        'https://icones.js.org/collections.json',
        'https://raw.githubusercontent.com/iconify/collections-json/master/collections.json',
        'https://unpkg.com/@iconify/collections/collections.json'
      ];

      for (const url of endpoints) {
        try {
          const res = await fetch(url, { cache: 'no-store' });
          if (!res.ok) {
            console.warn('Icon set fetch failed', url, res.status);
            continue;
          }
          const text = await res.text();
          // Handle responses that return plain "404" or other non-JSON bodies
          if (!text || text.trim() === '' || text.trim() === '404') {
            console.warn('Icon set fetch returned empty/404 body', url);
            continue;
          }
          let parsed = null;
          try {
            parsed = JSON.parse(text);
          } catch (err) {
            console.warn('Icon set parse failed (non-JSON body)', url, err, text.slice(0, 120));
            continue;
          }
          const data = normalizeCollectionsPayload(parsed);
          if (data && typeof data === 'object' && Object.keys(data).length > 0) {
            return data;
          }
          console.warn('Icon set payload missing/empty', url);
        } catch (err) {
          console.warn('Icon set fetch error', url, err);
        }
      }
      return null;
    }

    async function ensureIconCollectionsLoaded() {
      if (iconCollectionsCache) return iconSetOptionsCache;
      if (isLoadingIconSets) {
        // Wait until loading is finished to avoid returning empty options
        while (isLoadingIconSets) {
          await new Promise(resolve => setTimeout(resolve, 100));
        }
        return iconSetOptionsCache;
      }

      isLoadingIconSets = true;
      try {
        const data = await fetchIconCollections();
        if (data) {
          iconCollectionsCache = data || {};
          iconSetOptionsCache = buildIconSetOptions(iconCollectionsCache);
        }
      } catch (err) {
        console.error('Failed to load icon sets', err);
      } finally {
        isLoadingIconSets = false;
      }

      if (!iconCollectionsCache) {
        // fall back to built-in minimal list to keep UX unblocked
        iconCollectionsCache = builtInIconSets;
        iconSetOptionsCache = buildIconSetOptions(iconCollectionsCache);
        showToast('Using built-in icon sets (network fetch failed).', 'warning');
      }
      return iconSetOptionsCache;
    }

    function buildIconSetOptions(collections) {
      if (!collections || typeof collections !== 'object') return iconSetOptionsCache;
      const options = Object.entries(collections).map(([prefix, info]) => ({
        value: prefix,
        label: info?.name || prefix,
        detail: `${info?.total ? `${info.total} icons` : 'Iconify set'}${info?.category ? ` • ${info.category}` : ''}`,
        samples: Array.isArray(info?.samples) ? info.samples.slice(0, 3) : [],
        tags: Array.isArray(info?.tags) ? info.tags : [],
      }));
      const sorted = options.sort((a, b) => a.label.localeCompare(b.label));
      return [anyIconSetOption, ...sorted];
    }

    async function hydrateCreateIconFields(fields = [], excludeAnyIconifySet = false) {
      const fallbackOptions = Array.isArray(iconSetOptionsCache) && iconSetOptionsCache.length > 0
        ? iconSetOptionsCache
        : [anyIconSetOption, defaultIconSetOption];
      let iconOptions = fallbackOptions;
      try {
        // Don't block drawer opening on network; fall back quickly.
        iconOptions = await Promise.race([
          ensureIconCollectionsLoaded(),
          new Promise(resolve => setTimeout(() => resolve(fallbackOptions), 700))
        ]);
      } catch (_) {
        iconOptions = fallbackOptions;
      }
      let filteredOptions = iconOptions;
      if (excludeAnyIconifySet) {
        // Remove "Any Iconify set" option (value: '')
        filteredOptions = iconOptions.filter(option => option.value !== '');
      }
      const defaultPrefix = filteredOptions[0]?.value || '';
      return fields.map(field => {
        if (field.key === 'iconSet') {
          return { ...field, options: filteredOptions, default: defaultPrefix };
        }
        return field;
      });
    }

    async function hydratePaletteFields(fields = []) {
      // Load variable collections for the dropdown
      const collectionOptions = [{ value: '', label: 'Create new collection' }];

      // Request fresh collection data
      parent.postMessage({ pluginMessage: { type: 'get-variable-collections' } }, '*');

      // Use cached data if available, otherwise wait briefly
      if (window.variableCollectionsCache) {
        window.variableCollectionsCache.forEach(collection => {
          collectionOptions.push({
            value: collection.name,
            label: collection.name
          });
        });
      } else {
        // Wait briefly for response
        await new Promise(resolve => setTimeout(resolve, 100));
        if (window.variableCollectionsCache) {
          window.variableCollectionsCache.forEach(collection => {
            collectionOptions.push({
              value: collection.name,
              label: collection.name
            });
          });
        }
      }

      return fields.map(field => {
        if (field.key === 'collectionName') {
          return { ...field, options: collectionOptions };
        }
        return field;
      });
    }

    // Hydrate image generation model fields with dynamically fetched models from all available providers
    async function hydrateImageGenerationFields(fields = [], skipFetch = false) {
      const provider = selectedProvider;

      // Default fallback models with provider headers
      let modelOptions = [];

      // Add Gemini defaults if Gemini API key is set
      if (geminiApiKey) {
        modelOptions.push({ value: '__provider_header_gemini__', label: 'Gemini', isProviderHeader: true, provider: 'gemini' });
        modelOptions.push({ value: 'gemini-3.1-flash-image-preview', label: 'Gemini 3.1 Flash (Preview)', provider: 'gemini' });
        modelOptions.push({ value: 'gemini-3-pro-image-preview', label: 'Gemini 3 Pro (Preview)', provider: 'gemini' });
        modelOptions.push({ value: 'imagen-3.0-generate-002', label: 'Imagen 3 (Balanced)', provider: 'gemini' });
        modelOptions.push({ value: 'imagen-3.0-fast-generate-001', label: 'Imagen 3 Fast', provider: 'gemini' });
      }

      // Add OpenAI defaults if OpenAI API key is set
      if (openaiApiKey) {
        modelOptions.push({ value: '__provider_header_openai__', label: 'OpenAI', isProviderHeader: true, provider: 'openai' });
        modelOptions.push({ value: 'gpt-image-1.5', label: 'GPT Image 1.5', provider: 'openai' });
        modelOptions.push({ value: 'dall-e-3', label: 'DALL-E 3', provider: 'openai' });
      }

      // If no providers available, show defaults for current provider
      if (modelOptions.length === 0) {
        modelOptions = provider === 'openai' ? [
          { value: 'gpt-image-1.5', label: 'GPT Image 1.5', provider: 'openai' },
          { value: 'dall-e-3', label: 'DALL-E 3 (Latest)', provider: 'openai' }
        ] : [
          { value: 'imagen-3.0-generate-002', label: 'Imagen 3 (Balanced)', provider: 'gemini' },
          { value: 'imagen-3.0-fast-generate-001', label: 'Imagen 3 Fast', provider: 'gemini' }
        ];
      }

      // Try to fetch all available models if not skipping
      if (!skipFetch && (geminiApiKey || openaiApiKey)) {
        try {
          const allModels = await listAllImageGenerationModels();
          if (allModels && allModels.length > 0) {
            modelOptions = allModels.map(m => {
              if (m.isProviderHeader) {
                return {
                  value: `__provider_header_${m.provider}__`,
                  label: m.providerLabel,
                  isProviderHeader: true,
                  provider: m.provider
                };
              }
              return {
                value: m.id,
                label: m.displayName || m.id,
                provider: m.provider
              };
            });
          }
        } catch (error) {
          console.warn('Failed to fetch all image generation models, using defaults:', error);
        }
      }

      return fields.map(field => {
        if (field.key === 'imageModel' && field.dynamicOptions === 'imageGenModels') {
          // Determine default model based on selected provider
          let defaultValue = field.default;
          if (!defaultValue) {
            if (selectedProvider === 'openai' && openaiApiKey) {
              defaultValue = 'gpt-image-1.5';
            } else if (selectedProvider === 'ollama' && geminiApiKey) {
              defaultValue = 'gemini-3-pro-image-preview';
            } else if (geminiApiKey) {
              defaultValue = 'gemini-3-pro-image-preview';
            } else if (openaiApiKey) {
              defaultValue = 'gpt-image-1.5';
            } else {
              defaultValue = 'gemini-3-pro-image-preview';
            }
          }

          return { ...field, options: modelOptions, default: defaultValue };
        }
        if (field.key === 'imagePreset') {
          return {
            ...field,
            options: [
              { value: '', label: tu('actions.option.noneCustom') },
              ...Object.keys(IMAGE_GEN_PRESETS).map(name => ({
                value: name,
                label: name,
                thumbnail: IMAGE_GEN_PRESETS[name].thumbnail
              }))
            ]
          };
        }
        return field;
      });
    }

    async function hydrateCreateGraphFields(fields = []) {
      // Get all chart types from presets, split by " or " or " / " or ", "
      const chartOptionsSet = new Set();
      CHART_PRESETS.forEach(preset => {
        const types = [preset.bestChartType, ...preset.secondaryOptions];
        types.forEach(type => {
          if (type.includes('Horizontal or Vertical')) {
            chartOptionsSet.add('Bar Chart (Horizontal)');
            chartOptionsSet.add('Bar Chart (Vertical)');
            return;
          }

          // Split by various separators
          const splitTypes = type.split(/ or | \/ |, /);
          splitTypes.forEach(t => {
            const trimmed = t.trim();
            if (trimmed && !trimmed.toLowerCase().includes('(for flows)')) {
              chartOptionsSet.add(trimmed);
            } else if (trimmed && trimmed.toLowerCase().includes('(for flows)')) {
              chartOptionsSet.add(trimmed.replace(' (for flows)', ''));
            }
          });
        });
      });

      // Order by common usage (most used first); unlisted types go at end alphabetically
      const CHART_TYPE_USAGE_ORDER = [
        'Line Chart', 'Bar Chart (Horizontal)', 'Bar Chart (Vertical)', 'Column Chart',
        'Area Chart', 'Smooth Area', 'Pie Chart', 'Donut', 'Stacked Bar', 'Grouped Bar',
        'Scatter Plot', 'Bubble Chart', 'Heat Map', 'Treemap', 'Waterfall Chart',
        'Gauge Chart', 'Bullet Chart', 'Radar/Spider Chart', 'Candlestick Chart',
        'Box Plot', 'Funnel Chart', 'Sankey Diagram', 'Sunburst Chart', 'Waffle Chart',
        'Network Graph', 'Choropleth Map', 'Bubble Map', 'Word Cloud with Sentiment'
      ];
      const chartTypeOptions = Array.from(chartOptionsSet)
        .sort((a, b) => {
          const idxA = CHART_TYPE_USAGE_ORDER.indexOf(a);
          const idxB = CHART_TYPE_USAGE_ORDER.indexOf(b);
          if (idxA >= 0 && idxB >= 0) return idxA - idxB;
          if (idxA >= 0) return -1;
          if (idxB >= 0) return 1;
          return a.localeCompare(b);
        })
        .map(t => ({ value: t, label: t }));

      // Get current selection size for default
      let selectionSizeLabel = tu('actions.chart.autoSelection');
      let selectionSizeValue = '';
      try {
            const result = await requestSelectionData(true, false, ContextMode.LAYOUT_ONLY);
        if (result && result.data && result.data.length > 0) {
          // Calculate bounding box of all selected nodes
          let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
          result.data.forEach(node => {
            if (node.absX !== undefined && node.absY !== undefined && node.width !== undefined && node.height !== undefined) {
              minX = Math.min(minX, node.absX);
              minY = Math.min(minY, node.absY);
              maxX = Math.max(maxX, node.absX + node.width);
              maxY = Math.max(maxY, node.absY + node.height);
            }
          });

          if (minX !== Infinity) {
            const w = Math.round(maxX - minX);
            const h = Math.round(maxY - minY);
            selectionSizeValue = `${w}x${h}`;
            selectionSizeLabel = tu('actions.chart.selectionSize', { size: selectionSizeValue });
          }
        }
      } catch (e) {
        console.warn('Failed to get selection size for chart hydration', e);
      }

      return fields.map(field => {
        if (field.key === 'chartType') {
          return { ...field, options: chartTypeOptions };
        }
        if (field.key === 'chartSize') {
          const options = [
            { value: 'Auto', label: selectionSizeLabel },
            { value: '__custom__', label: tu('actions.option.custom'), inputKey: 'customChartSize', inputDefault: selectionSizeValue, inputType: 'text', inputPlaceholder: 'WxH' }
          ];
          return { ...field, options, default: 'Auto' };
        }
        return field;
      });
    }

    let verticalTextHydrationMeta = { sourceCharCount: 0, useVerticalColumns: false };
    let verticalTextLineHeightReloadEnabled = false;

    function fetchVerticalTextMetadata() {
      return new Promise((resolve) => {
        const timeout = setTimeout(() => {
          window.removeEventListener('message', handler);
          resolve(null);
        }, 5000);
        const handler = (event) => {
          const msg = event.data.pluginMessage;
          if (msg && msg.type === 'detect-vertical-text-metadata-result') {
            clearTimeout(timeout);
            window.removeEventListener('message', handler);
            resolve(msg.results);
          }
        };
        window.addEventListener('message', handler);
        parent.postMessage({ pluginMessage: { type: 'detect-vertical-text-metadata' } }, '*');
      });
    }

    function resolveVerticalTextReloadLineHeightPx(first) {
      if (!first || typeof first.fontSize !== 'number' || first.fontSize <= 0) return null;
      return Math.round(first.fontSize * 1.1 * 100) / 100;
    }

    /** Keep range slider in sync when a paired number input value is set in code (e.g. Vertical text linked fields). */
    function syncPromptSliderFromNumberInput(numberInput) {
      if (!numberInput || numberInput.type !== 'number') return;
      const container = numberInput.closest('.prompt-slider-container');
      if (!container) return;
      const slider = container.querySelector('input[type="range"]');
      if (!slider) return;
      const min = parseFloat(slider.min);
      const max = parseFloat(slider.max);
      if (!Number.isFinite(min) || !Number.isFinite(max)) return;
      let v = parseFloat(numberInput.value);
      if (!Number.isFinite(v)) v = min;
      const clamped = Math.max(min, Math.min(max, v));
      slider.value = String(clamped);
    }

    function attachVerticalTextLinkedFields() {
      const heightEl = promptDrawerFields.querySelector('input[data-field-key="heightPx"]');
      const colEl = promptDrawerFields.querySelector('input[data-field-key="columnTextCount"]');
      const useVerticalColumnsEl = promptDrawerFields.querySelector('input[data-field-key="useVerticalColumns"]');
      const verticalColsEl = promptDrawerFields.querySelector('input[data-field-key="verticalColumns"]');
      const lhEl = promptDrawerFields.querySelector('input[data-field-key="lineHeightPx"]');

      if (!heightEl || !colEl || !lhEl) return;

      let lastEdited = 'columnTextCount';

      const formatNumber = (value, decimals = 2) => {
        if (!Number.isFinite(value)) return '0';
        return Number(value.toFixed(decimals)).toString();
      };

      const updateComputedHeight = () => {
        const useVerticalColumns = useVerticalColumnsEl?.checked === true;
        const c = parseFloat(colEl.value) || 0;
        const lh = parseFloat(lhEl.value) || 0;
        const verticalCols = parseInt(verticalColsEl?.value || '0', 10) || 0;

        if (useVerticalColumns) {
          const sourceCharCount = verticalTextHydrationMeta.sourceCharCount || 0;
          const computedCount = (verticalCols > 0 && sourceCharCount > 0)
            ? Math.max(1, Math.ceil(sourceCharCount / verticalCols))
            : 0;
          colEl.value = computedCount > 0 ? String(computedCount) : '';
          heightEl.value = (computedCount > 0 && lh > 0) ? formatNumber(computedCount * lh) : '';
          syncPromptSliderFromNumberInput(colEl);
          syncPromptSliderFromNumberInput(heightEl);
          heightEl.dispatchEvent(new Event('change', { bubbles: true }));
          colEl.dispatchEvent(new Event('change', { bubbles: true }));
          return;
        }

        if (lastEdited === 'heightPx') {
          const h = parseFloat(heightEl.value) || 0;
          colEl.value = (h > 0 && lh > 0) ? String(Math.ceil(h / lh)) : '';
          syncPromptSliderFromNumberInput(colEl);
        } else {
          heightEl.value = (c > 0 && lh > 0) ? formatNumber(c * lh) : '';
          syncPromptSliderFromNumberInput(heightEl);
        }
        heightEl.dispatchEvent(new Event('change', { bubbles: true }));
      };

      heightEl.addEventListener('input', () => {
        lastEdited = 'heightPx';
        updateComputedHeight();
      });

      colEl.addEventListener('input', () => {
        lastEdited = 'columnTextCount';
        updateComputedHeight();
      });

      lhEl.addEventListener('input', updateComputedHeight);
      useVerticalColumnsEl?.addEventListener('input', updateComputedHeight);
      if (verticalColsEl) {
        verticalColsEl.addEventListener('input', updateComputedHeight);
      }

      const reloadLhBtn = promptDrawerFields.querySelector('button[data-reload-line-height]');
      if (reloadLhBtn) {
        reloadLhBtn.onclick = async () => {
          if (reloadLhBtn.disabled) return;
          try {
            const metadata = await fetchVerticalTextMetadata();
            const first = metadata && metadata[0];
            if (first && typeof first.fontSize === 'number' && first.fontSize > 0) {
              verticalTextHydrationMeta = {
                sourceCharCount: first.sourceCharCount || 0,
                useVerticalColumns: first.useVerticalColumns === true
              };
            }
            const px = resolveVerticalTextReloadLineHeightPx(first);
            if (px == null || !Number.isFinite(px)) return;
            lhEl.value = formatNumber(px);
            syncPromptSliderFromNumberInput(lhEl);
            lhEl.dispatchEvent(new Event('input', { bubbles: true }));
            lhEl.dispatchEvent(new Event('change', { bubbles: true }));
          } catch (e) {
            console.warn('Reload line height failed', e);
          }
        };
      }

      updateComputedHeight();
      syncPromptSliderFromNumberInput(heightEl);
      syncPromptSliderFromNumberInput(colEl);
      syncPromptSliderFromNumberInput(lhEl);
    }

    async function hydrateVerticalTextFields(fields = []) {
      verticalTextLineHeightReloadEnabled = false;
      try {
        const metadata = await fetchVerticalTextMetadata();

        if (metadata && Array.isArray(metadata) && metadata.length > 0) {
          const first = metadata[0];
          verticalTextLineHeightReloadEnabled = !!(first && typeof first.fontSize === 'number' && first.fontSize > 0);
          verticalTextHydrationMeta = {
            sourceCharCount: first.sourceCharCount || 0,
            useVerticalColumns: first.useVerticalColumns === true
          };
          if (first.isVertical) {
            const lhDefault = resolveVerticalTextReloadLineHeightPx(first);
            return fields.map(field => {
              if (field.key === 'heightPx' && first.heightPx > 0) return { ...field, default: first.heightPx };
              if (field.key === 'columnTextCount' && first.columnTextCount > 0) return { ...field, default: first.columnTextCount };
              if (field.key === 'verticalColumns' && first.verticalColumns > 0) return { ...field, default: first.verticalColumns };
              if (field.key === 'lineHeightPx' && lhDefault != null) return { ...field, default: lhDefault };
              if (field.key === 'useVerticalColumns') return { ...field, default: first.useVerticalColumns === true };
              if (field.key === 'keepManualLineBreaks') return { ...field, default: first.keepManualLineBreaks !== false };
              if (field.key === 'unicodeVerticalPunctuation') return { ...field, default: first.unicodeVerticalPunctuation === true };
              return field;
            });
          } else if (first.fontSize > 0) {
            const lhDefault = resolveVerticalTextReloadLineHeightPx(first);
            return fields.map(field => {
              if (field.key === 'lineHeightPx' && lhDefault != null) return { ...field, default: lhDefault };
              return field;
            });
          }
        }
      } catch (e) {
        console.warn('Failed to hydrate vertical text fields', e);
      }
      verticalTextHydrationMeta = { sourceCharCount: 0, useVerticalColumns: false };
      verticalTextLineHeightReloadEnabled = false;
      return fields;
    }

    // Refresh model list in background after drawer opens (fetches from all available providers)
    async function backgroundRefreshImageModels(originalActionName) {
      // Check if at least one provider has an API key
      if (!geminiApiKey && !openaiApiKey) return;

      try {
        // Fetch fresh list from all providers
        const allModels = await listAllImageGenerationModels();
        if (!allModels || allModels.length === 0) return;

        // Check if drawer is still open and showing the same action
        if (promptDrawer.classList.contains('open') && promptDrawerTitle.textContent === originalActionName) {
          const selectEl = promptDrawerFields.querySelector('.prompt-custom-select[data-field-key="imageModel"]');
          if (!selectEl) return;

          const optionsContainer = selectEl.querySelector('.prompt-custom-select-options');
          if (!optionsContainer) return;

          const isMulti = selectEl.dataset.multi === 'true';
          let currentSelected = selectEl.dataset.selected;
          if (!currentSelected && promptHistory[originalActionName] && promptHistory[originalActionName].imageModel) {
            currentSelected = promptHistory[originalActionName].imageModel;
          }
          const defaultValues = isMulti ? JSON.parse(currentSelected || '[]') : [currentSelected];

          // Re-generate options HTML with provider headers
          const optionsHtml = allModels.map(m => {
            if (m.isProviderHeader) {
              // Render provider header
              const providerIcon = getProviderIcon(m.provider);
              return `
                <div class="prompt-select-provider-header" data-provider="${escapeHtml(m.provider)}">
                  ${providerIcon}
                  <span>${escapeHtml(m.providerLabel)}</span>
                </div>
              `;
            }

            const isSelected = defaultValues.includes(String(m.id));
            const classes = `prompt-custom-select-option${isSelected ? ' selected' : ''}`;
            return `
              <div class="${classes}" data-value="${escapeHtml(m.id)}" data-provider="${escapeHtml(m.provider || '')}" data-label="${escapeHtml(String(m.displayName || m.id).toLowerCase())}" data-text="${escapeHtml(String(m.displayName || m.id))}" tabindex="0">
                ${escapeHtml(m.displayName || m.id)}
              </div>
            `;
          }).join('');

          optionsContainer.innerHTML = optionsHtml;

          // Re-attach click listeners to the new options (not headers)
          optionsContainer.querySelectorAll('.prompt-custom-select-option').forEach(optionEl => {
            optionEl.addEventListener('click', (e) => {
              if (isMulti) {
                optionEl.classList.toggle('selected');
              } else {
                selectEl.querySelectorAll('.prompt-custom-select-option').forEach(opt => opt.classList.remove('selected'));
                optionEl.classList.add('selected');
              }
              syncSelectState(selectEl);
              applyPromptFieldVisibility();
              optionEl.focus();
            });
          });

          // Sync initial state and update visibility for the restored model
          syncSelectState(selectEl);
          applyPromptFieldVisibility();
        }
      } catch (err) {
        console.warn('Background image model refresh failed:', err);
      }
    }

    // Quick action usage + flattened list for slash menu
    const QUICK_ACTION_USAGE_KEY = 'quickActionUsage';
    const LAST_USED_ACTION_KEY = 'lastUsedQuickAction';
    const HIDDEN_PROMPT_COMMENTS_KEY = 'hiddenPromptCommentsByFile';
    const BOOKMARKED_PROMPT_COMMENTS_KEY = 'bookmarkedPromptCommentsByFile';
    const MAX_LAST_USED_ACTIONS = 3;
    let quickActionUsage = sanitizeQuickActionUsageMap(loadQuickActionUsageFromLocal());
    let lastUsedQuickActions = loadLastUsedQuickActionsFromLocal();
    let quickActionUsageLoadedFromPlugin = false;
    let allQuickActions = buildQuickActionsList(agentTasks);

    function loadQuickActionUsageFromLocal() {
      try {
        const stored = localStorage.getItem(QUICK_ACTION_USAGE_KEY);
        return stored ? JSON.parse(stored) : {};
      } catch (e) {
        return {};
      }
    }

    function loadLastUsedQuickActionsFromLocal() {
      try {
        const stored = localStorage.getItem(LAST_USED_ACTION_KEY);
        if (!stored) return [];
        const parsed = JSON.parse(stored);
        // Handle backward compatibility: if it's a string, convert to array
        if (typeof parsed === 'string') {
          return [parsed];
        }
        // Ensure it's an array and limit to MAX_LAST_USED_ACTIONS
        if (Array.isArray(parsed)) {
          return parsed.slice(0, MAX_LAST_USED_ACTIONS).filter(Boolean);
        }
        return [];
      } catch (e) {
        return [];
      }
    }

    function saveQuickActionUsageToLocal() {
      try {
        localStorage.setItem(QUICK_ACTION_USAGE_KEY, JSON.stringify(quickActionUsage));
        if (lastUsedQuickActions && lastUsedQuickActions.length > 0) {
          localStorage.setItem(LAST_USED_ACTION_KEY, JSON.stringify(lastUsedQuickActions));
        }
      } catch (e) {
        // ignore
      }
    }

    function loadHiddenPromptCommentsByFileFromLocal() {
      try {
        const stored = localStorage.getItem(HIDDEN_PROMPT_COMMENTS_KEY);
        if (!stored) return {};
        const parsed = JSON.parse(stored);
        if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};

        const sanitized = {};
        Object.entries(parsed).forEach(([fileKey, commentMap]) => {
          if (!fileKey || !commentMap || typeof commentMap !== 'object' || Array.isArray(commentMap)) return;
          const sanitizedComments = {};
          Object.entries(commentMap).forEach(([commentId, hidden]) => {
            if (commentId && hidden === true) {
              sanitizedComments[commentId] = true;
            }
          });
          if (Object.keys(sanitizedComments).length > 0) {
            sanitized[fileKey] = sanitizedComments;
          }
        });

        return sanitized;
      } catch (e) {
        return {};
      }
    }

    function loadBookmarkedPromptCommentsByFileFromLocal() {
      try {
        const stored = localStorage.getItem(BOOKMARKED_PROMPT_COMMENTS_KEY);
        if (!stored) return {};
        const parsed = JSON.parse(stored);
        if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};

        const sanitized = {};
        Object.entries(parsed).forEach(([fileKey, commentMap]) => {
          if (!fileKey || !commentMap || typeof commentMap !== 'object' || Array.isArray(commentMap)) return;
          const sanitizedComments = {};
          Object.entries(commentMap).forEach(([commentId, marked]) => {
            if (commentId && marked === true) {
              sanitizedComments[commentId] = true;
            }
          });
          if (Object.keys(sanitizedComments).length > 0) {
            sanitized[fileKey] = sanitizedComments;
          }
        });

        return sanitized;
      } catch (e) {
        return {};
      }
    }

    let hiddenPromptCommentsByFile = loadHiddenPromptCommentsByFileFromLocal();
    let bookmarkedPromptCommentsByFile = loadBookmarkedPromptCommentsByFileFromLocal();

    function saveHiddenPromptCommentsByFileToLocal() {
      try {
        localStorage.setItem(HIDDEN_PROMPT_COMMENTS_KEY, JSON.stringify(hiddenPromptCommentsByFile));
      } catch (e) {
        // ignore
      }
    }

    function syncHiddenPromptCommentsToPluginStorage() {
      parent.postMessage({
        pluginMessage: {
          type: 'save-hidden-prompt-comments',
          hiddenPromptCommentsByFile,
        }
      }, '*');
    }

    function getPromptCommentsStorageFileKey() {
      return figmaFileKey || 'unknown-file';
    }

    function isPromptCommentHidden(commentId) {
      const fileKey = getPromptCommentsStorageFileKey();
      return !!hiddenPromptCommentsByFile[fileKey]?.[commentId];
    }

    function renderCommentsInDrawerPreservingScroll(container) {
      if (!container || container.offsetParent === null) {
        return;
      }

      const previousListContainer = document.getElementById('promptCommentsListContainer');
      const previousScrollTop = previousListContainer ? previousListContainer.scrollTop : 0;

      renderCommentsInDrawer(container);

      const nextListContainer = document.getElementById('promptCommentsListContainer');
      if (nextListContainer) {
        nextListContainer.scrollTop = previousScrollTop;
      }
    }

    function togglePromptCommentHidden(commentId) {
      const fileKey = getPromptCommentsStorageFileKey();
      const currentMap = { ...(hiddenPromptCommentsByFile[fileKey] || {}) };

      if (currentMap[commentId]) {
        delete currentMap[commentId];
      } else {
        currentMap[commentId] = true;
      }

      if (Object.keys(currentMap).length > 0) {
        hiddenPromptCommentsByFile = {
          ...hiddenPromptCommentsByFile,
          [fileKey]: currentMap,
        };
      } else {
        const nextState = { ...hiddenPromptCommentsByFile };
        delete nextState[fileKey];
        hiddenPromptCommentsByFile = nextState;
      }

      saveHiddenPromptCommentsByFileToLocal();
      syncHiddenPromptCommentsToPluginStorage();

      const container = document.getElementById('promptCommentsContainer');
      if (container && container.offsetParent !== null) {
        renderCommentsInDrawerPreservingScroll(container);
      }
    }

    function saveBookmarkedPromptCommentsByFileToLocal() {
      try {
        localStorage.setItem(BOOKMARKED_PROMPT_COMMENTS_KEY, JSON.stringify(bookmarkedPromptCommentsByFile));
      } catch (e) {
        // ignore
      }
    }

    function syncBookmarkedPromptCommentsToPluginStorage() {
      parent.postMessage({
        pluginMessage: {
          type: 'save-bookmarked-prompt-comments',
          bookmarkedPromptCommentsByFile,
        }
      }, '*');
    }

    function isPromptCommentBookmarked(commentId) {
      const fileKey = getPromptCommentsStorageFileKey();
      return !!bookmarkedPromptCommentsByFile[fileKey]?.[commentId];
    }

    function togglePromptCommentBookmarked(commentId) {
      const fileKey = getPromptCommentsStorageFileKey();
      const currentMap = { ...(bookmarkedPromptCommentsByFile[fileKey] || {}) };

      if (currentMap[commentId]) {
        delete currentMap[commentId];
      } else {
        currentMap[commentId] = true;
      }

      if (Object.keys(currentMap).length > 0) {
        bookmarkedPromptCommentsByFile = {
          ...bookmarkedPromptCommentsByFile,
          [fileKey]: currentMap,
        };
      } else {
        const nextState = { ...bookmarkedPromptCommentsByFile };
        delete nextState[fileKey];
        bookmarkedPromptCommentsByFile = nextState;
      }

      saveBookmarkedPromptCommentsByFileToLocal();
      syncBookmarkedPromptCommentsToPluginStorage();

      const container = document.getElementById('promptCommentsContainer');
      if (container && container.offsetParent !== null) {
        renderCommentsInDrawerPreservingScroll(container);
      }
    }

    function sanitizeQuickActionUsageMap(map) {
      const sanitized = {};
      Object.entries(map || {}).forEach(([name, value]) => {
        if (typeof value === 'number' && Number.isFinite(value) && value >= 0) {
          sanitized[name] = value;
        }
      });
      return sanitized;
    }

    function mergeQuickActionUsage(remoteUsage) {
      const localUsage = sanitizeQuickActionUsageMap(quickActionUsage);
      const incoming = sanitizeQuickActionUsageMap(remoteUsage);
      const merged = { ...localUsage };
      Object.entries(incoming).forEach(([name, value]) => {
        merged[name] = Math.max(merged[name] || 0, value);
      });
      quickActionUsage = merged;
      saveQuickActionUsageToLocal();
    }

    function mergeLastUsedQuickActions(remoteLastUsed) {
      if (!Array.isArray(remoteLastUsed)) return;

      // Combine local and remote, keeping most recent first
      // We'll prioritize remote if it's more recent, but since we don't have timestamps,
      // we'll just merge them and keep the top 3 unique ones.
      // Usually remote (clientStorage) is considered more "authoritative" for cross-device sync.
      const combined = [...remoteLastUsed, ...lastUsedQuickActions];
      const unique = [];
      const seen = new Set();

      for (const name of combined) {
        if (name && !seen.has(name)) {
          unique.push(name);
          seen.add(name);
        }
        if (unique.length >= MAX_LAST_USED_ACTIONS) break;
      }

      lastUsedQuickActions = unique;
      saveQuickActionUsageToLocal();
    }

    function saveQuickActionUsage() {
      const sanitized = sanitizeQuickActionUsageMap(quickActionUsage);
      quickActionUsage = sanitized;
      saveQuickActionUsageToLocal();
      parent.postMessage({
        pluginMessage: {
          type: 'save-quick-actions-usage',
          usage: sanitized,
          lastUsed: lastUsedQuickActions
        }
      }, '*');
    }

    function requestQuickActionUsageFromPlugin() {
      parent.postMessage({ pluginMessage: { type: 'load-quick-actions-usage' } }, '*');
    }

    function initQuickActionUsage() {
      requestQuickActionUsageFromPlugin();
    }

    function recordQuickActionUsage(name) {
      if (!name) return;
      quickActionUsage[name] = (quickActionUsage[name] || 0) + 1;

      // Update last used actions array (most recent first)
      // Remove the action if it already exists to avoid duplicates
      lastUsedQuickActions = lastUsedQuickActions.filter(a => a !== name);
      // Add the new action at the beginning
      lastUsedQuickActions.unshift(name);
      // Keep only the last MAX_LAST_USED_ACTIONS
      lastUsedQuickActions = lastUsedQuickActions.slice(0, MAX_LAST_USED_ACTIONS);

      saveQuickActionUsage();
    }

    function getMostUsedQuickActions(limit = 6) {
      // Find the last used actions (most recent first)
      const lastUsedActionsList = lastUsedQuickActions
        .map(name => allQuickActions.find(a => a.name === name))
        .filter(Boolean);

      // Create a set of last used action names for quick lookup
      const lastUsedActionNames = new Set(lastUsedQuickActions);

      // Sort all actions by usage count (excluding last used actions for now)
      const sorted = [...allQuickActions].sort((a, b) => {
        // Skip last used actions in sorting - they will be added first
        if (lastUsedActionNames.has(a.name)) return 1;
        if (lastUsedActionNames.has(b.name)) return -1;

        const diff = (quickActionUsage[b.name] || 0) - (quickActionUsage[a.name] || 0);
        if (diff !== 0) return diff;
        return (a.order || 0) - (b.order || 0);
      });

      // Build result list with last used actions first (in order: most recent first)
      const deduped = [];

      // Always add last used actions first if they exist (most recent first)
      for (const action of lastUsedActionsList) {
        if (!deduped.find(a => a.name === action.name)) {
          deduped.push(action);
        }
        if (deduped.length >= limit) break;
      }

      // Add remaining actions up to limit
      for (const action of sorted) {
        if (!deduped.find(a => a.name === action.name)) {
          deduped.push(action);
        }
        if (deduped.length >= limit) break;
      }

      // Fill remaining slots if needed
      if (deduped.length < limit) {
        for (const action of allQuickActions) {
          if (!deduped.find(a => a.name === action.name)) {
            deduped.push(action);
          }
          if (deduped.length >= limit) break;
        }
      }

      return deduped.slice(0, limit);
    }

    function scoreSlashQueryAgainstNameVariants(variants, qLower) {
      let best = 0;
      let matched = false;
      for (const raw of variants) {
        const nameLower = String(raw || '').toLowerCase();
        if (!nameLower) continue;
        if (nameLower === qLower) {
          matched = true;
          best = Math.max(best, 100);
        } else if (nameLower.startsWith(qLower)) {
          matched = true;
          best = Math.max(best, 95);
        } else {
          const words = nameLower.split(/[\s\-_]+/);
          if (words.includes(qLower)) {
            matched = true;
            best = Math.max(best, 85);
          } else if (nameLower.includes(qLower)) {
            matched = true;
            best = Math.max(best, 30);
          }
        }
      }
      return { score: best, matched };
    }

    function searchQuickActions(query, limit = 8) {
      const qLower = (query || '').toLowerCase().trim();
      if (!qLower) return getMostUsedQuickActions(limit);

      // Score and filter matches (English keys + all exact i18n strings, e.g. /縦書き /竖排文字)
      const scoredMatches = allQuickActions.map(action => {
        const task = action.task;
        const nameVariants = getExactTranslationVariantsForSearch(task.name || '');
        const descVariants = getExactTranslationVariantsForSearch(task.desc || '');
        const helpVariants = getExactTranslationVariantsForSearch(task.help || '');
        const keywordVariants = getExactTranslationVariantsForSearch(task.searchKeywords || '');
        const promptLower = (task.prompt || '').toLowerCase();

        let score = 0;
        let matched = false;

        const nameResult = scoreSlashQueryAgainstNameVariants(nameVariants, qLower);
        if (nameResult.matched) {
          score += nameResult.score;
          matched = true;
        }

        if (descVariants.some(v => String(v).toLowerCase().includes(qLower))) {
          score += 10;
          matched = true;
        }

        if (helpVariants.some(v => String(v).toLowerCase().includes(qLower))) {
          score += 5;
          matched = true;
        }

        if (keywordVariants.some(v => String(v).toLowerCase().includes(qLower))) {
          score += 5;
          matched = true;
        }

        if (promptLower.includes(qLower)) {
          score += 5;
          matched = true;
        }

        if (!matched) return null;

        return {
          ...action,
          matchScore: score
        };
      }).filter(Boolean);

      // Sort primarily by match score
      scoredMatches.sort((a, b) => {
        const scoreDiff = b.matchScore - a.matchScore;
        if (scoreDiff !== 0) return scoreDiff;

        // Tie-break with total usage count
        const usageDiff = (quickActionUsage[b.name] || 0) - (quickActionUsage[a.name] || 0);
        if (usageDiff !== 0) return usageDiff;

        // Finally by default order
        return (a.order || 0) - (b.order || 0);
      });

      return scoredMatches.slice(0, limit);
    }

    // Selected category state
    let selectedCategory = Object.keys(agentTasks)[0];
    let lastSelectedCategoryBeforePrompt = null;
    const commandsSidebar = document.getElementById('commandsSidebar');
    const commandsContent = document.getElementById('commandsContent');

    function filterCommandsForAiOffMode(tasks) {
      if (!isAiOffModeEnabled() || !tasks || tasks.length === 0) return tasks;
      return tasks.filter(t => isTaskAvailableInAiOff(t, t.name));
    }

    function getCommandsSidebarCategories() {
      const keys = Object.keys(agentTasks);
      if (!isAiOffModeEnabled()) return keys;
      return keys.filter(cat => {
        const tasks = agentTasks[cat] || [];
        return tasks.some(t => isTaskAvailableInAiOff(t, t.name));
      });
    }

    // Render sidebar with categories
    function renderSidebar() {
      const categories = getCommandsSidebarCategories();
      if (categories.length > 0 && !categories.includes(selectedCategory)) {
        selectedCategory = categories[0];
        parent.postMessage({ pluginMessage: { type: 'save-last-commands-category', category: selectedCategory } }, '*');
      }
      let html = '';

      categories.forEach(category => {
        const isActive = category === selectedCategory;
        const icon = categoryIcons[category] || defaultActionIcon;
        html += `
          <button class="commands-sidebar-item ${isActive ? 'active' : ''}" data-category="${category}">
            ${icon}
            <span>${localizeActionString(category)}</span>
          </button>
        `;
      });

      commandsSidebar.innerHTML = html;

      // Add click handlers
      commandsSidebar.querySelectorAll('.commands-sidebar-item').forEach(item => {
        item.addEventListener('click', () => {
          selectedCategory = item.dataset.category;
          renderSidebar();
          renderContent(commandsSearch.value);
          // Save last active category
          parent.postMessage({ pluginMessage: { type: 'save-last-commands-category', category: selectedCategory } }, '*');
        });
      });
    }

    // Render content area with action items
    function renderContent(filter = '') {
      const lowerFilter = filter.toLowerCase().trim();
      let filteredTasks = [];
      let headerText = '';

      if (lowerFilter) {
        // Global search - collect and score matches from all categories
        headerText = tu('actions.commands.results', { filter });

        const scoredMatches = [];
        Object.entries(agentTasks).forEach(([category, tasks]) => {
          tasks.forEach(task => {
            const localizedTask = getLocalizedTask(task);
            const nameLower = `${localizedTask.displayName || ''} ${task.name || ''}`.toLowerCase();
            const descLower = `${localizedTask.displayDesc || ''} ${task.desc || ''}`.toLowerCase();
            const promptLower = (task.prompt || '').toLowerCase();

            let score = 0;
            let matched = false;

            // Name matches (Primary)
            if (nameLower === lowerFilter) {
              score += 100;
              matched = true;
            } else if (nameLower.startsWith(lowerFilter)) {
              score += 95;
              matched = true;
            } else {
              const words = nameLower.split(/[\s\-_]+/);
              if (words.includes(lowerFilter)) {
                score += 85;
                matched = true;
              } else if (nameLower.includes(lowerFilter)) {
                score += 30;
                matched = true;
              }
            }

            // Secondary matches
            if (descLower.includes(lowerFilter)) {
              score += 10;
              matched = true;
            }
            if (promptLower.includes(lowerFilter)) {
              score += 5;
              matched = true;
            }

            if (matched) {
              scoredMatches.push({ ...task, category, matchScore: score });
            }
          });
        });

        // Sort by score, then frequency
        scoredMatches.sort((a, b) => {
          const scoreDiff = b.matchScore - a.matchScore;
          if (scoreDiff !== 0) return scoreDiff;
          const usageDiff = (quickActionUsage[b.name] || 0) - (quickActionUsage[a.name] || 0);
          if (usageDiff !== 0) return usageDiff;
          return 0; // Default order
        });

        filteredTasks = scoredMatches;
      } else {
        // Category view
        filteredTasks = agentTasks[selectedCategory] || [];
        headerText = localizeActionString(selectedCategory);
      }

      filteredTasks = filterCommandsForAiOffMode(filteredTasks);

      if (filteredTasks.length === 0) {
        const suffix = filter ? tu('actions.commands.emptySuffix', { filter }) : '';
        commandsContent.innerHTML = `
          <div class="commands-empty">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
              <circle cx="11" cy="11" r="8"/>
              <path d="M21 21l-4.35-4.35"/>
                </svg>
            <span>${tu('actions.commands.empty', { suffix })}</span>
            <div class="commands-empty-actions">
              <button class="commands-header-btn" id="addCustomQuickActionBtnEmpty">Add Custom Action</button>
            </div>
          </div>
        `;
        document.getElementById('addCustomQuickActionBtnEmpty')?.addEventListener('click', () => {
          openCustomQuickActionModal();
        });
        return;
      }

      let html = `
        <div class="commands-content-header">
          <div class="commands-content-title">${headerText}</div>
          <div class="commands-header-actions">
            <button class="commands-header-btn" id="addCustomQuickActionBtn">Add Custom Action</button>
          </div>
        </div>
      `;
      html += '<div class="commands-items-grid">';

      filteredTasks.forEach((task, taskIndex) => {
        const localizedTask = getLocalizedTask(task);
        const taskCategory = task.category || selectedCategory;
        const icon = getActionIconForTask(task, taskCategory);
        const commandBadges = buildQuickActionBadges(task);
        // Escape icon for data attribute (encode HTML)
        const iconEncoded = encodeURIComponent(icon);
        // Check if this action has fields (needs custom drawer)
        const hasFields = quickActionHasFields(task);
        const categoryLabel = lowerFilter && task.category ? `<div class="command-item-category">${localizeActionString(task.category)}</div>` : '';
        const itemTitle = localizedTask.displayDesc || localizedTask.displayName || task.name;
        const customTag = task.isCustomQuickAction ? `<div class="command-item-custom-tag">${task.askMode ? tu('actions.customQuickAction.mode.ask') : tu('actions.customQuickAction.mode.agent')}</div>` : '';
        const customActions = task.isCustomQuickAction ? `
          <div class="command-item-custom-actions">
            <button class="command-item-custom-trigger" data-custom-popover-trigger="${escapeHtml(task.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.moreActionsTitle'))}" aria-haspopup="menu" aria-expanded="false">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <circle cx="12" cy="5" r="1.5"/>
                <circle cx="12" cy="12" r="1.5"/>
                <circle cx="12" cy="19" r="1.5"/>
              </svg>
            </button>
            <div class="command-item-custom-popover" role="menu">
              <button class="dropdown-item" data-custom-action="edit" data-custom-action-id="${escapeHtml(task.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.editTitle'))}">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M12 20h9"/>
                <path d="M16.5 3.5a2.121 2.121 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5Z"/>
              </svg>
              <span>${escapeHtml(tu('actions.option.edit'))}</span>
              </button>
              <button class="dropdown-item" data-custom-action="duplicate" data-custom-action-id="${escapeHtml(task.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.duplicateTitle'))}">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <rect x="9" y="9" width="13" height="13" rx="2"/>
                <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/>
              </svg>
              <span>${escapeHtml(tu('actions.option.duplicate'))}</span>
              </button>
              <button class="dropdown-item dropdown-item-danger" data-custom-action="delete" data-custom-action-id="${escapeHtml(task.customQuickActionId)}" title="${escapeHtml(tu('actions.customQuickAction.deleteTitle'))}">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M3 6h18"/>
                <path d="M8 6V4a1 1 0 0 1 1-1h6a1 1 0 0 1 1 1v2"/>
                <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
                <path d="M10 11v6M14 11v6"/>
              </svg>
              <span>${escapeHtml(tu('actions.option.remove'))}</span>
              </button>
            </div>
          </div>
        ` : '';
        html += `
                <div class="command-item" role="button" tabindex="0" data-task-index="${taskIndex}" data-prompt="${(task.prompt || '').replace(/"/g, '&quot;')}" data-no-selection="${task.noSelection || false}" data-action-name="${task.name}" data-action-icon="${iconEncoded}" data-has-fields="${hasFields}" data-ai-disabled="false" title="${itemTitle}">
            <div class="command-item-main">
              <div class="command-item-icon">${icon}${commandBadges}</div>
              <div class="command-item-text">
                <div class="command-item-name">${localizedTask.displayName}</div>
                <div class="command-item-desc">${localizedTask.displayDesc}</div>
                ${categoryLabel}
                ${customTag}
              </div>
            </div>
            ${customActions}
          </div>
        `;
      });

      html += '</div>';
      commandsContent.innerHTML = html;

      document.getElementById('addCustomQuickActionBtn')?.addEventListener('click', () => {
        openCustomQuickActionModal();
      });

      commandsContent.querySelectorAll('[data-custom-popover-trigger]').forEach((button) => {
        button.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          const actionId = button.dataset.customPopoverTrigger;
          const container = button.closest('.command-item-custom-actions');
          if (!actionId || !container) return;
          const shouldOpen = openCustomActionPopoverId !== actionId;
          closeCommandItemPopover();
          if (shouldOpen) {
            openCustomActionPopoverId = actionId;
            container.classList.add('is-open');
            button.setAttribute('aria-expanded', 'true');
          } else {
            button.setAttribute('aria-expanded', 'false');
          }
        });
      });

      commandsContent.querySelectorAll('[data-custom-action]').forEach((button) => {
        button.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          closeCommandItemPopover();
          const { customAction, customActionId } = button.dataset;
          if (!customActionId) return;
          if (customAction === 'edit') {
            editCustomQuickAction(customActionId);
          } else if (customAction === 'duplicate') {
            duplicateCustomQuickAction(customActionId);
          } else if (customAction === 'delete') {
            deleteCustomQuickAction(customActionId);
          }
        });
      });

      // Add click handlers to command items
      commandsContent.querySelectorAll('.command-item').forEach(item => {
        item.addEventListener('keydown', (event) => {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            item.click();
          }
        });
        item.addEventListener('click', async () => {
          if (item.dataset.aiDisabled === 'true') {
            showToast(item.title || getAiOffBlockedMessage(item.dataset.actionName || 'Quick action'), 'error');
            return;
          }
          const taskIndex = parseInt(item.dataset.taskIndex);
          const hasFields = item.dataset.hasFields === 'true';
          const noSelection = item.dataset.noSelection === 'true';
          const actionName = item.dataset.actionName;
          const actionIcon = decodeURIComponent(item.dataset.actionIcon);

          // Get the full task object
          const task = filteredTasks[taskIndex];
          if (!isTaskAvailableInAiOff(task, actionName || task?.name || '')) {
            showToast(getAiOffBlockedMessage(actionName || task?.name || 'Quick action'), 'error');
            closeCommandsDrawer();
            return;
          }

          if (hasFields && task) {
            let hydratedFields = task.fields || [];
            if (task.directAction === 'browseIconSet') {
              const excludeAnyIconifySet = true;
              hydratedFields = await hydrateCreateIconFields(task.fields, excludeAnyIconifySet);
            }
            // Open custom prompt drawer for actions with fields
            await openPromptDrawer({
              ...task,
              fields: hydratedFields,
              icon: actionIcon
            });
          } else if (task && task.directAction === 'extractImagePrompt') {
            // Handle Extract prompt from image directly
            recordQuickActionUsage(actionName);
            closeCommandsDrawer();
            await handleExtractImagePrompt(actionName, actionIcon);
          } else if (task && (task.directAction === 'listAllComments' || task.directAction === 'listAllComponents' || task.directAction === 'listAllStickies' || task.directAction === 'browseStyles' || task.directAction === 'googleFontPreview' || task.directAction === 'hueShift' || task.directAction === 'fontMapping')) {
            // Handle actions that open in prompt drawer
            if (task.directAction === 'listAllComments') {
              ensureCommentsLoadedCached();
            } else if (task.directAction === 'listAllStickies') {
              ensureStickiesLoadedCached();
            }
            await openPromptDrawer({
              ...task,
              icon: actionIcon
            });
          } else if (task && task.directAction === 'summarizeComments') {
            // Handle Summarize Comments directly
            recordQuickActionUsage(actionName);
            closeCommandsDrawer();
            await handleSummarizeComments(actionName, actionIcon);
          } else {
            // Direct execution for simple actions

            // Local deterministic tasks bypass AI entirely
            if (NON_AI_LOCAL_TASKS.has(actionName) && actionName !== 'Smart rename') {
              closeCommandsDrawer();
              recordQuickActionUsage(actionName);
              await runLocalDeterministicQuickAction(actionName, {}, { name: actionName, icon: actionIcon });
              return;
            }

            // Handle askMode actions - they run in ask mode
            if (task && task.askMode) {
              recordQuickActionUsage(actionName);
              closeCommandsDrawer();
              // Handle direct actions for ask mode
              if (task.directAction === 'extractImagePrompt') {
                await handleExtractImagePrompt(actionName, actionIcon);
                return;
              }
              if (task.directAction === 'summarizeComments') {
                await handleSummarizeComments(actionName, actionIcon);
                return;
              }
              // For other askMode actions with fields, they should have been handled above
              // For simple askMode actions, send to ask mode
              const prompt = task.prompt || (typeof task.promptTemplate === 'string' ? task.promptTemplate : '');
              if (prompt) {
                await sendAskModeQuickAction(prompt, { name: actionName, icon: actionIcon });
              }
              return;
            }

            if (task && task.directAction && !task.askMode) {
              closeCommandsDrawer();
              recordQuickActionUsage(actionName);
              setMode('agent');
              await runDirectAction(task.directAction, {}, { ...task, icon: actionIcon });
              return;
            }

            closeCommandsDrawer();
            recordQuickActionUsage(actionName);
            setMode('agent');
            const includeTokens = task && task.includeTokens === true;
            const contextMode = (task && task.requiredContext) || ContextMode.SMART;

            // Auto-send the quick action message
            await sendQuickActionMessage(task.prompt, noSelection, { name: actionName, icon: actionIcon }, includeTokens, contextMode);
          }
        });
      });
    }

    // Send quick action message with custom display
    let currentQuickActionContext = null;

    // Handle askMode quick actions
    async function sendAskModeQuickAction(prompt, actionData) {
      if (!guardAiAction(actionData?.name || 'Ask mode quick action')) {
        return;
      }
      try {
        const result = await requestSelectionDataWithFallback(true);
        const { data: selectionData, fallbackImages, isFallback } = result;

        let finalPrompt = prompt;
        if (isFallback) {
          finalPrompt += "\n\n(Note: Selection was too large for full metadata. I'm using a snapshot and a lightweight node index instead, so you can still refer to elements by name.)";
        }

        // Show user message
        addMessage('user', finalPrompt, isFallback ? { type: 'PNG_DATA_URLS', data: fallbackImages } : null, actionData);

        // Add user message to chat history for archiving
        const userParts = [{ text: finalPrompt }];
        if (isFallback && fallbackImages) {
          fallbackImages.forEach(dataUrl => {
            const base64Data = dataUrl.split(',')[1];
            userParts.push({
              inline_data: {
                mime_type: 'image/png',
                data: base64Data
              }
            });
          });
        }
        chatHistory.push({ role: 'user', parts: userParts });

        // Send to AI in ask mode
        await sendToAI(finalPrompt, isFallback ? fallbackImages : null, selectionData || []);

      } catch (error) {
        if (error.name !== 'AbortError') {
          showToast('Failed to get selection: ' + error.message, 'error');
        }
      }
    }

    // Handle Extract prompt from image action
    async function handleExtractImagePrompt(actionName, actionIcon) {
      try {
        // Request PNG export (Copy Image function)
        parent.postMessage({
          pluginMessage: {
            type: 'get-png'
          }
        }, '*');

        // Wait for png-result message
        const imageData = await new Promise((resolve, reject) => {
          const timeout = setTimeout(() => {
            reject(new Error('Timeout waiting for image export'));
          }, 10000);

          const messageHandler = (event) => {
            const msg = event.data.pluginMessage;
            if (msg && msg.type === 'png-result') {
              clearTimeout(timeout);
              window.removeEventListener('message', messageHandler);
              resolve(msg.data);
            } else if (msg && msg.type === 'error' && msg.message) {
              clearTimeout(timeout);
              window.removeEventListener('message', messageHandler);
              reject(new Error(msg.message));
            }
          };

          window.addEventListener('message', messageHandler);
        });

        if (!imageData || imageData.length === 0) {
          showToast('Please select at least one element with an image', 'error');
          return;
        }

        // Stage the images
        stageImages(imageData);

        // Create prompt for AI
        const displayPrompt = 'Extract prompt from image';
        const aiPrompt = `Extract a high-quality, generation-ready descriptive prompt from the provided image(s).

Divide your response into exactly two sections:

Subject / Content:
- Describe the {primary subject(s)} first, followed by {secondary objects} and {background elements}
- Focus strictly on {visible, concrete details} such as appearance, pose, materials, environment, and relationships
- Avoid assumptions, emotions, or narrative context not directly visible

Artistic Style / Direction:
- Describe the {visual style}, {lighting}, {composition}, {camera perspective / lens}, and {overall aesthetic}
- Use concise, generator-friendly descriptors commonly used in image generation prompts

CRITICAL RULES:
- Describe strictly what is visible. Don't assume.
`;
        // Show user message with quick action display
        addMessage('user', displayPrompt, null, { name: actionName, icon: actionIcon });

        // Clear staged attachments immediately after sending
        clearStagedAttachments();

        // Send to AI with images
        await sendToAI(aiPrompt, imageData, null);

      } catch (error) {
        if (error.name !== 'AbortError') {
          showToast('Failed to extract image: ' + error.message, 'error');
        }
      }
    }

    // Populate comments in the prompt drawer
    async function populateCommentsInDrawer() {
      const container = document.getElementById('promptCommentsContainer');
      if (!container) return;

      // Show loading state
      container.innerHTML = `<div class="prompt-comments-loading">${tu('actions.comments.loading')}</div>`;

      try {
        const commentsLoaded = await ensureCommentsLoaded();

        if (!commentsLoaded) {
          container.innerHTML = `
          <div class="prompt-comments-error">
              <p>${tu('actions.comments.error')}</p>
              <p style="font-size: var(--text-xs); margin-top: 8px;">
                Please configure your Figma API token in Settings → Figma API
              </p>
            </div>
          `;
          return;
        }

        if (!figmaComments || figmaComments.length === 0) {
          container.innerHTML = `<div class="prompt-comments-empty">${tu('actions.comments.empty')}</div>`;
          return;
        }

        // Trigger page enrichment in background if needed
        if (currentCommentsScope === 'page' && commentNodePageMap.size === 0) {
          enrichCommentsWithPageInfo();
        }

        // Fetch node names for comments with node_ids (so layer names display in header)
        const nodeIds = [...new Set(figmaComments.map(c => c.client_meta?.node_id).filter(Boolean))];
        if (nodeIds.length > 0) {
          parent.postMessage({ pluginMessage: { type: 'get-viewport-and-node-positions', nodeIds } }, '*');
        }

        // Monitor context
        parent.postMessage({ pluginMessage: { type: 'get-current-context' } }, '*');

        renderCommentsInDrawer(container);
      } catch (error) {
        container.innerHTML = `<div class="prompt-comments-error">${tu('actions.comments.error')} ${escapeHtml(error.message)}</div>`;
      }
    }

    // Refresh comments in drawer (force reload)
    async function refreshCommentsInDrawer() {
      figmaCommentsLastLoaded = 0; // Invalidate cache
      await populateCommentsInDrawer();
      showToast('Comments refreshed', 'success');
    }

    // NEW: Refresh only a specific thread silently
    async function refreshCommentThread(threadId) {
      const token = figmaPersonalTokenInput?.value?.trim() || figmaPersonalToken;
      const fileKey = figmaFileKeyInput?.value?.trim() || figmaFileKey;

      if (!token || !fileKey) return;

      try {
        const response = await fetch(`https://api.figma.com/v1/files/${fileKey}/comments`, {
          headers: { 'X-Figma-Token': token }
        });

        if (response.ok) {
          const data = await response.json();
          figmaComments = data.comments || [];
          figmaCommentsLastLoaded = Date.now();

          // Group by thread
          const threads = new Map();
          figmaComments.forEach(c => {
            if (c.parent_id) {
              if (!threads.has(c.parent_id)) threads.set(c.parent_id, []);
              threads.get(c.parent_id).push(c);
            }
          });

          // 1. Refresh Prompt Drawer Thread
          const promptContainer = document.getElementById('promptCommentsContainer');
          if (promptContainer) {
            const threadEl = promptContainer.querySelector(`.prompt-comment-item[data-comment-id="${threadId}"]`);
            if (threadEl) {
              const comment = figmaComments.find(c => c.id === threadId);
              if (comment) {
                const newHtml = renderCommentItemHTML(comment, threads);
                const temp = document.createElement('div');
                temp.innerHTML = newHtml;
                if (temp.firstElementChild) threadEl.replaceWith(temp.firstElementChild);
              }
            }
          }

          // 2. Refresh Main Drawer
          if (typeof renderComments === 'function') {
            renderComments(); // Main drawer rendering is fast enough once data is loaded
          }

          // 3. Refresh Quick Modal (if open)
          const quickModal = document.getElementById('commentsQuickModal');
          if (quickModal && quickModal.parentElement.classList.contains('show')) {
            showCommentsModal();
          }
        }
      } catch (e) {
        console.error('Failed to refresh thread:', e);
      }
    }

