    // Get all known user handles from comments
    function getKnownUserHandles() {
      const handles = new Set();
      figmaComments.forEach(comment => {
        handles.add(comment.user.handle);
      });
      return handles;
    }

    // Get a map of user handles to user IDs for mention conversion
    function getUserHandleToIdMap() {
      const map = new Map();
      figmaComments.forEach(comment => {
        if (comment.user && comment.user.id && comment.user.handle) {
          map.set(comment.user.handle, comment.user.id);
        }
      });
      return map;
    }

    // Note: Figma's REST API does NOT support creating clickable mentions with notifications.
    // Mentions posted via API are plain text only. This function is kept for potential future use
    // but currently just returns the message unchanged, keeping @username as readable text.
    function convertMentionsToFigmaFormat(message) {
      // Return message as-is - @username will display as plain text
      return message;
    }

    // Extract @mentions from text using known user handles
    // This handles names with spaces like "@有住兼寿 (bravesoft)"
    function extractMentions(text, knownHandles = null) {
      const mentions = [];
      const handles = knownHandles || getKnownUserHandles();

      // Sort handles by length (longest first) to match longer names before shorter ones
      const sortedHandles = Array.from(handles).sort((a, b) => b.length - a.length);

      // Try to match known handles first
      let remainingText = text;
      for (const handle of sortedHandles) {
        const mentionPattern = new RegExp(`@${handle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`, 'g');
        if (mentionPattern.test(text)) {
          mentions.push(handle);
        }
      }

      // Also try to find any @mentions that don't match known handles (fallback)
      // Match @ followed by any non-whitespace characters until we hit common delimiters
      const regex = /@([^\s@]+)/g;
      let match;
      while ((match = regex.exec(text)) !== null) {
        const potentialMention = match[1];
        // Only add if not already found and looks like a valid mention
        if (!mentions.includes(potentialMention) && potentialMention.length > 0) {
          // Check if any known handle starts with this (partial match)
          const matchesKnown = sortedHandles.some(h => h.startsWith(potentialMention) || potentialMention.startsWith(h));
          if (!matchesKnown) {
            mentions.push(potentialMention);
          }
        }
      }

      return mentions;
    }

    // Extract all unique people from comments (authors and mentions)
    // Only extracts from the provided comments list (respects resolved filter)
    function extractPeopleFromComments(comments) {
      const people = new Map(); // name -> { isAuthor: bool, isMentioned: bool, img_url: string }

      // First pass: collect all authors
      comments.forEach(comment => {
        const authorName = comment.user.handle;
        if (!people.has(authorName)) {
          people.set(authorName, { isAuthor: false, isMentioned: false, img_url: comment.user.img_url });
        }
        people.get(authorName).isAuthor = true;
        // Ensure we keep the img_url if we find it later
        if (!people.get(authorName).img_url && comment.user.img_url) {
          people.get(authorName).img_url = comment.user.img_url;
        }
      });

      // Get known handles for mention extraction
      const knownHandles = new Set(people.keys());

      // Second pass: extract mentions using known handles
      comments.forEach(comment => {
        const mentions = extractMentions(comment.message, knownHandles);
        mentions.forEach(name => {
          if (!people.has(name)) {
            people.set(name, { isAuthor: false, isMentioned: false, img_url: null });
          }
          people.get(name).isMentioned = true;
        });
      });

      return people;
    }

    // Check if a comment matches the people filter
    // Also tracks if match is in replies for UI indicator
    function commentMatchesPeopleFilter(comment, threads, trackReplyMatches = false) {
      const hasAuthorFilter = selectedAuthorsFilter.size > 0;
      const hasMentionFilter = selectedMentionsFilter.size > 0;

      // No filter applied - show all
      if (!hasAuthorFilter && !hasMentionFilter) return true;

      const knownHandles = getKnownUserHandles();
      const replies = threads.get(comment.id) || [];

      let matchesAuthorFilter = true;
      let matchesMentionFilter = true;
      let matchInReplies = false;

      // Check author filter (OR within filter - any selected author matches)
      if (hasAuthorFilter) {
        // Check main comment first
        const mainCommentAuthorMatch = Array.from(selectedAuthorsFilter).some(name =>
          comment.user.handle === name
        );
        // Check replies (respecting From toggle)
        const replyAuthorMatch = peopleFilterIncludeRepliesFrom
          ? Array.from(selectedAuthorsFilter).some(name => replies.some(r => r.user.handle === name))
          : false;

        matchesAuthorFilter = mainCommentAuthorMatch || replyAuthorMatch;
        if (!mainCommentAuthorMatch && replyAuthorMatch) {
          matchInReplies = true;
        }
      }

      // Check mention filter (OR within filter - any selected mention matches)
      if (hasMentionFilter) {
        // Check main comment first
        const mainMentions = extractMentions(comment.message, knownHandles);
        const mainCommentMentionMatch = Array.from(selectedMentionsFilter).some(name =>
          mainMentions.includes(name)
        );
        // Check replies (respecting Mentions toggle)
        const replyMentionMatch = peopleFilterIncludeRepliesMentions
          ? Array.from(selectedMentionsFilter).some(name =>
            replies.some(r => {
              const mentions = extractMentions(r.message, knownHandles);
              return mentions.includes(name);
            })
          )
          : false;

        matchesMentionFilter = mainCommentMentionMatch || replyMentionMatch;
        if (!mainCommentMentionMatch && replyMentionMatch) {
          matchInReplies = true;
        }
      }

      const matches = matchesAuthorFilter && matchesMentionFilter;

      // Track reply matches for UI indicator
      if (trackReplyMatches && matches && matchInReplies) {
        commentsWithPeopleReplyMatches.add(comment.id);
      }

      return matches;
    }

    // Toggle people filter expansion
    function togglePeopleFilter() {
      peopleFilterExpanded = !peopleFilterExpanded;
      const section = document.getElementById('peopleFilterSection');
      const toggle = document.getElementById('peopleFilterToggle');
      if (section) section.classList.toggle('expanded', peopleFilterExpanded);
      if (toggle) toggle.classList.toggle('expanded', peopleFilterExpanded);
    }

    // Switch people filter tab
    function switchPeopleFilterTab(tab) {
      if (peopleFilterActiveTab === tab) return;
      peopleFilterActiveTab = tab;
      // Re-render to update toggle and chips
      const container = document.getElementById('promptCommentsContainer');
      if (container) renderCommentsInDrawer(container);
    }

    // Toggle include replies in people filter
    function togglePeopleIncludeReplies() {
      if (peopleFilterActiveTab === 'from') {
        peopleFilterIncludeRepliesFrom = !peopleFilterIncludeRepliesFrom;
      } else {
        peopleFilterIncludeRepliesMentions = !peopleFilterIncludeRepliesMentions;
      }
      updateCommentsListOnly();
      // Re-render header to update toggle state
      const container = document.getElementById('promptCommentsContainer');
      if (container) renderCommentsInDrawer(container);
    }

    // Toggle a person chip selection
    function togglePersonChip(name, filterType) {
      const filterSet = filterType === 'from' ? selectedAuthorsFilter : selectedMentionsFilter;

      if (filterSet.has(name)) {
        filterSet.delete(name);
      } else {
        filterSet.add(name);
        // Auto-expand the filter section when selecting
        if (!peopleFilterExpanded) {
          peopleFilterExpanded = true;
          const section = document.getElementById('peopleFilterSection');
          const toggle = document.getElementById('peopleFilterToggle');
          if (section) section.classList.add('expanded');
          if (toggle) toggle.classList.add('expanded');
        }
      }
      updateCommentsListOnly();
      // Update chip visual state
      const chip = document.querySelector(`.people-chip[data-name="${CSS.escape(name)}"][data-filter="${filterType}"]`);
      if (chip) chip.classList.toggle('selected', filterSet.has(name));
      // Update count display
      updatePeopleFilterCount();
    }

    // Clear people filter selections for current tab or all
    function clearPeopleFilter(which = 'current') {
      if (which === 'all' || which === 'from') {
        selectedAuthorsFilter.clear();
        document.querySelectorAll('.people-chip[data-filter="from"].selected').forEach(c => c.classList.remove('selected'));
      }
      if (which === 'all' || which === 'mentions') {
        selectedMentionsFilter.clear();
        document.querySelectorAll('.people-chip[data-filter="mentions"].selected').forEach(c => c.classList.remove('selected'));
      }
      if (which === 'current') {
        if (peopleFilterActiveTab === 'from') {
          selectedAuthorsFilter.clear();
          document.querySelectorAll('.people-chip[data-filter="from"].selected').forEach(c => c.classList.remove('selected'));
        } else {
          selectedMentionsFilter.clear();
          document.querySelectorAll('.people-chip[data-filter="mentions"].selected').forEach(c => c.classList.remove('selected'));
        }
      }
      updateCommentsListOnly();
      updatePeopleFilterCount();
    }

