    // Handle search input with debounce and IME support
    let commentsSearchTimer = null;
    let isComposingSearch = false;

    function handleCommentsSearchInput(value) {
      // Don't search during IME composition
      if (isComposingSearch) return;

      // Clear existing timer
      if (commentsSearchTimer) {
        clearTimeout(commentsSearchTimer);
      }
      // Debounce: wait 400ms after user stops typing
      commentsSearchTimer = setTimeout(() => {
        commentsSearchQuery = value.toLowerCase().trim();
        // Only update the comments list, not the toolbar
        updateCommentsListOnly();
      }, 400);
    }

    function handleCommentsSearchCompositionStart() {
      isComposingSearch = true;
    }

    function handleCommentsSearchCompositionEnd(e) {
      isComposingSearch = false;
      // Trigger search after composition ends with longer delay
      if (commentsSearchTimer) {
        clearTimeout(commentsSearchTimer);
      }
      commentsSearchTimer = setTimeout(() => {
        commentsSearchQuery = e.target.value.toLowerCase().trim();
        updateCommentsListOnly();
      }, 100);
    }

    // Helper function to check if a comment or its replies match a keyword
    // Returns: { matches: boolean, inReply: boolean }
    function commentMatchesKeyword(comment, keyword, threads) {
      const kw = keyword.toLowerCase();
      // Check main comment
      if (comment.message.toLowerCase().includes(kw) ||
        comment.user.handle.toLowerCase().includes(kw)) {
        return { matches: true, inReply: false };
      }
      // Check replies
      const replies = threads.get(comment.id) || [];
      const replyMatch = replies.some(reply =>
        reply.message.toLowerCase().includes(kw) ||
        reply.user.handle.toLowerCase().includes(kw)
      );
      return { matches: replyMatch, inReply: replyMatch };
    }

    // Track which comments have matches in replies (for UI indicator)
    let commentsWithReplyMatches = new Set();
    let commentsWithPeopleReplyMatches = new Set();

