    // Highlight matching keywords and linkify mentions
    function highlightAndLinkify(text, searchQuery) {
      if (!text) return '';

      // 1. Escape HTML first
      let result = escapeHtml(text);

      // 1.5 Parse emoji shortcodes
      result = parseEmojiShortcodes(result);

      // 2. Linkify mentions based on known user handles
      const handles = getKnownUserHandles();
      const sortedHandles = Array.from(handles).sort((a, b) => b.length - a.length);

      for (const handle of sortedHandles) {
        const escapedHandle = handle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        // Match @Handle but not if it's already part of a link (though at this point it shouldn't be)
        const mentionPattern = new RegExp(`@${escapedHandle}`, 'g');
        const linkHtml = `<span class="person-link" onclick="event.stopPropagation(); togglePersonChip('${escapeHtml(handle).replace(/'/g, "\\'")}', 'from')">@${handle}</span>`;
        result = result.replace(mentionPattern, linkHtml);
      }

      // 3. Highlight search keywords, skipping already added HTML tags
      if (searchQuery) {
        const keywords = searchQuery.split(/[\s,]+/).filter(k => k.length > 0);
        keywords.forEach(keyword => {
          const escapedKeyword = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
          // Match keywords only if they are not inside an HTML tag
          const regex = new RegExp(`(${escapedKeyword})(?![^<]*>)`, 'gi');
          result = result.replace(regex, '<mark class="search-highlight">$1</mark>');
        });
      }

      return result;
    }

    // Highlight matching keywords in text
    function highlightSearchMatches(text, searchQuery) {
      if (!searchQuery || !text) return escapeHtml(text);

      const keywords = searchQuery.split(/[\s,]+/).filter(k => k.length > 0);
      if (keywords.length === 0) return escapeHtml(text);

      // Escape HTML first
      let result = escapeHtml(text);

      // Create a regex pattern for all keywords (case insensitive)
      keywords.forEach(keyword => {
        const escapedKeyword = keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(`(${escapedKeyword})`, 'gi');
        result = result.replace(regex, '<mark class="search-highlight">$1</mark>');
      });

      return result;
    }

    // Filter and sort comments by search keywords (AND results first, then OR)
    function filterCommentsBySearch(comments, searchQuery, threads) {
      commentsWithReplyMatches.clear();

      if (!searchQuery) return comments;

      // Parse keywords (split by space or comma)
      const keywords = searchQuery.split(/[\s,]+/).filter(k => k.length > 0);
      if (keywords.length === 0) return comments;

      if (keywords.length === 1) {
        // Single keyword - simple filter
        return comments.filter(c => {
          const result = commentMatchesKeyword(c, keywords[0], threads);
          if (result.matches && result.inReply) {
            commentsWithReplyMatches.add(c.id);
          }
          return result.matches;
        });
      }

      // Multiple keywords - separate AND and OR matches
      const andMatches = [];
      const orMatches = [];

      comments.forEach(comment => {
        let matchCount = 0;
        let hasReplyMatch = false;

        keywords.forEach(kw => {
          const result = commentMatchesKeyword(comment, kw, threads);
          if (result.matches) {
            matchCount++;
            if (result.inReply) hasReplyMatch = true;
          }
        });

        if (matchCount > 0) {
          if (hasReplyMatch) {
            commentsWithReplyMatches.add(comment.id);
          }
          if (matchCount === keywords.length) {
            andMatches.push(comment);
          } else {
            orMatches.push({ comment, matchCount });
          }
        }
      });

      // Sort OR matches by match count (more matches first)
      orMatches.sort((a, b) => b.matchCount - a.matchCount);

      return [...andMatches, ...orMatches.map(m => m.comment)];
    }

    // Update only the comments list without touching the toolbar
    function updateCommentsListOnly() {
      const listContainer = document.getElementById('promptCommentsListContainer');
      const countSpan = document.getElementById('commentsCountDisplay');
      if (!listContainer || figmaComments.length === 0) return;

      // Group comments by thread
      const threads = new Map();
      const topLevelComments = [];

      figmaComments.forEach(comment => {
        if (comment.parent_id) {
          if (!threads.has(comment.parent_id)) {
            threads.set(comment.parent_id, []);
          }
          threads.get(comment.parent_id).push(comment);
        } else {
          topLevelComments.push(comment);
        }
      });

      // Filter by resolved state
      let filteredComments = showResolvedComments
        ? topLevelComments
        : topLevelComments.filter(c => !c.resolved_at);

      // Filter by scope
      if (currentCommentsScope === 'page') {
        filteredComments = filteredComments.filter(c => {
          const nodeId = c.client_meta?.node_id;
          if (!nodeId) return false;
          const pageId = commentNodePageMap.get(nodeId);
          return !pageId || pageId === figmaCurrentPageId;
        });
      } else if (currentCommentsScope === 'selection') {
        const selectedIds = new Set();
        addSelectionNodeAndDescendantIds(selectedIds, lastKnownSelectionItems || []);
        filteredComments = filteredComments.filter(c => {
          const nodeId = c.client_meta?.node_id;
          return nodeId && selectedIds.has(nodeId);
        });
      }

      // Filter by people (if any selected in either tab)
      commentsWithPeopleReplyMatches.clear();
      if (selectedAuthorsFilter.size > 0 || selectedMentionsFilter.size > 0) {
        filteredComments = filteredComments.filter(c => commentMatchesPeopleFilter(c, threads, true));
      }

      // Filter by search query (with AND/OR logic and reply search)
      filteredComments = filterCommentsBySearch(filteredComments, commentsSearchQuery, threads);

      // Filter by custom filter (e.g. pending reply)
      if (commentsFilterBy === 'pending') {
        filteredComments = filteredComments.filter(c => {
          const replies = threads.get(c.id) || [];
          if (replies.length > 0) {
            // Sort replies by date to find the last one
            const sortedReplies = [...replies].sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
            const lastReply = sortedReplies[sortedReplies.length - 1];
            return lastReply.user.id !== figmaCurrentUser?.id;
          } else {
            // No replies, check if the original comment is from someone else
            return c.user.id !== figmaCurrentUser?.id;
          }
        });
      }

      if (commentsFilterBy === 'bookmarked') {
        filteredComments = filteredComments.filter(c => isPromptCommentBookmarked(c.id));
      }

      // Sort comments
      const sortFn = {
        'activity': (a, b) => {
          const getLatest = (c) => {
            const replies = threads.get(c.id) || [];
            return replies.reduce((latest, r) => {
              const d = new Date(r.created_at);
              return d > latest ? d : latest;
            }, new Date(c.created_at));
          };
          return getLatest(b) - getLatest(a);
        },
        'newest': (a, b) => new Date(b.created_at) - new Date(a.created_at),
        'oldest': (a, b) => new Date(a.created_at) - new Date(b.created_at),
        'replies': (a, b) => (threads.get(b.id)?.length || 0) - (threads.get(a.id)?.length || 0),
        'people': (a, b) => a.user.handle.localeCompare(b.user.handle),
        'viewport': (a, b) => {
          if (!cachedViewportCenter) return 0;
          const vc = cachedViewportCenter;
          const posA = cachedNodePositions[a.client_meta?.node_id];
          const posB = cachedNodePositions[b.client_meta?.node_id];
          const distA = posA ? Math.sqrt((posA.x - vc.x) ** 2 + (posA.y - vc.y) ** 2) : Infinity;
          const distB = posB ? Math.sqrt((posB.x - vc.x) ** 2 + (posB.y - vc.y) ** 2) : Infinity;
          return distA - distB;
        },
        'burst': (a, b) => new Date(a.created_at) - new Date(b.created_at)
      };
      filteredComments.sort(sortFn[commentsSortBy] || sortFn['newest']);

      const total = topLevelComments.length;
      lastFilteredCount = filteredComments.length;
      lastTotalCount = total;

      // Update count display
      if (countSpan) {
        countSpan.textContent = `${multiSelectEnabled ? `${tu('actions.comments.drawer.selectedCount', { count: selectedCommentIds.size })} · ` : ''}${lastFilteredCount}/${lastTotalCount}`;
      }

      // Render comments list only
      listContainer.innerHTML = renderCommentsListHTML(filteredComments, threads);
      updateBatchActionsState();
    }

    // Toggle comments sort/filter dropdown
