    // Toggle comment selection
    function handleCommentItemClick(event, commentId) {
      if (!multiSelectEnabled) return;

      // If clicking on interactive elements, don't toggle checkbox
      const target = event.target;
      if (
        target.tagName === 'BUTTON' ||
        target.tagName === 'A' ||
        target.tagName === 'TEXTAREA' ||
        target.tagName === 'INPUT' ||
        target.closest('button') ||
        target.closest('.comment-actions') ||
        target.closest('.comment-reply-input') ||
        target.closest('.comment-rewrite-btn') ||
        target.closest('.comment-ai-gen-btn') ||
        target.closest('.comment-replies-toggle') ||
        target.closest('.comment-replies') ||
        target.closest('.reply-templates-row')
      ) {
        return;
      }

      const checkbox = event.currentTarget.querySelector('.comment-select-checkbox');
      if (checkbox) {
        checkbox.checked = !checkbox.checked;
        toggleCommentSelection(commentId, checkbox);
      }
    }

    function toggleCommentSelection(commentId, checkbox) {
      if (checkbox.checked) {
        selectedCommentIds.add(commentId);
      } else {
        selectedCommentIds.delete(commentId);
      }
      updateBatchActionsState();
    }

    // Update batch actions button state
    function updateBatchActionsState() {
      const summarizeBtn = document.getElementById('batchSummarizeBtn');
      const replyBtn = document.getElementById('batchReplyBtn');
      const replyChevronBtn = document.getElementById('batchReplyChevronBtn');
      const aiReplyBtn = document.getElementById('batchAiReplyBtn');
      const visibilityBtn = document.getElementById('batchVisibilityBtn');
      const visibilityBtnLabel = document.getElementById('batchVisibilityBtnLabel');
      const visibilityBtnIcon = document.getElementById('batchVisibilityBtnIcon');
      const selectAllBtn = document.getElementById('selectAllBtn');
      const count = selectedCommentIds.size;

      if (summarizeBtn) summarizeBtn.disabled = count === 0;
      if (replyBtn) replyBtn.disabled = count === 0;
      if (replyChevronBtn) replyChevronBtn.disabled = count === 0;
      if (visibilityBtn) visibilityBtn.disabled = count === 0;

      const csvBtn = document.getElementById('batchCsvBtn');
      if (csvBtn) {
        // If nothing is selected, the button downloads all currently filtered comments
        // If things are selected, it's always enabled to download those selections.
        // Actually, getFilteredCommentsForSummarize already handles this logic.
        // Let's enable it if there's anything visible or selected.
        const { filteredComments } = getFilteredCommentsForSummarize();
        csvBtn.disabled = filteredComments.length === 0;
      }

      if (selectAllBtn) {
        selectAllBtn.textContent = count > 0 ? tu('actions.comments.drawer.deselectAll') : tu('actions.comments.drawer.selectAll');
      }

      if (visibilityBtn && visibilityBtnLabel && visibilityBtnIcon) {
        const selectedIds = Array.from(selectedCommentIds);
        const allHidden = selectedIds.length > 0 && selectedIds.every(id => isPromptCommentHidden(id));
        visibilityBtnLabel.textContent = allHidden ? 'Show' : 'Hide';
        visibilityBtn.title = allHidden ? 'Show selected comments' : 'Hide selected comments';
        visibilityBtnIcon.innerHTML = allHidden
          ? '<path d="M2 12s3.5-6 10-6 10 6 10 6-3.5 6-10 6-10-6-10-6Z"></path><circle cx="12" cy="12" r="3"></circle><path d="M4 4l16 16"></path>'
          : '<path d="M2 12s3.5-6 10-6 10 6 10 6-3.5 6-10 6-10-6-10-6Z"></path><circle cx="12" cy="12" r="3"></circle>';
      }

      // Update count labels in input areas
      const replyLabel = document.getElementById('batchReplyCountLabel');
      if (replyLabel) replyLabel.textContent = count;
      const aiLabel = document.getElementById('batchAiReplyCountLabel');
      if (aiLabel) aiLabel.textContent = count;

      // Also update the "Summarize All" button in the footer
      updateSummarizeAllButtonState();

      // Update the main count display
      const countSpan = document.getElementById('commentsCountDisplay');
      if (countSpan) {
        countSpan.textContent = `${multiSelectEnabled ? `${tu('actions.comments.drawer.selectedCount', { count })} · ` : ''}${lastFilteredCount}/${lastTotalCount}`;
      }
    }



    // AI action menu logic
    function removeAiActionMenu() {
      const menu = document.querySelector('.ai-action-menu');
      if (menu) menu.remove();
    }

    function toggleAiActionMenu(event) {
      event.stopPropagation();
      let menu = document.querySelector('.ai-action-menu');
      if (menu) {
        menu.remove();
        return;
      }

      menu = document.createElement('div');
      menu.className = 'ai-action-menu';

      const isStyles = currentPromptAction && currentPromptAction.directAction === 'browseStyles';
      const actions = isStyles ? styleAiActions : commentAiActions;
      const currentActionKey = isStyles ? currentStyleAiAction : currentCommentAiAction;

      Object.keys(actions).forEach(key => {
        const action = isStyles ? actions[key] : getCommentAiActionMeta(key);
        const item = document.createElement('div');
        item.className = `ai-action-menu-item${currentActionKey === key ? ' active' : ''}`;
        item.innerHTML = `
          ${action.icon}
          <span>${action.label}</span>
        `;
        item.onclick = () => {
          if (isStyles) {
            selectAiStyleAction(key);
          } else {
            selectAiCommentAction(key);
          }
        };
        menu.appendChild(item);
      });

      document.body.appendChild(menu);
      menu.style.display = 'block';

      const toggleBtn = event.currentTarget;
      const rect = toggleBtn.getBoundingClientRect();
      menu.style.top = `${rect.top - menu.offsetHeight - 8}px`;
      menu.style.left = `${rect.right - menu.offsetWidth}px`;

      const closeMenu = (e) => {
        if (!menu.contains(e.target) && !toggleBtn.contains(e.target)) {
          menu.remove();
          document.removeEventListener('mousedown', closeMenu);
        }
      };
      document.addEventListener('mousedown', closeMenu);
    }

    function selectAiCommentAction(key) {
      currentCommentAiAction = key;
      const menu = document.querySelector('.ai-action-menu');
      if (menu) menu.remove();

      // Update button in footer
      const btn = document.querySelector('.prompt-action-main-btn');
      if (btn) {
        const action = getCommentAiActionMeta(key);
        btn.innerHTML = `
          ${action.icon}
          ${action.label}${key === 'summarize' ? ' <span class="summarize-count">()</span>' : ''}
        `;
        btn.title = action.title;
        updateSummarizeAllButtonState(); // to restore count
      }

      // Execute action
      const fnName = commentAiActions[key].fn;
      if (typeof window[fnName] === 'function') {
        window[fnName]();
      }
    }

    function selectAiStyleAction(key) {
      currentStyleAiAction = key;
      const menu = document.querySelector('.ai-action-menu');
      if (menu) menu.remove();

      // Update button in footer
      const btn = document.querySelector('.prompt-action-main-btn');
      if (btn) {
        const action = styleAiActions[key];
        btn.innerHTML = `
          ${action.icon}
          ${action.label}
        `;
        btn.title = action.title;
      }

      // Execute action
      const fnName = styleAiActions[key].fn;
      if (typeof window[fnName] === 'function') {
        window[fnName]();
      }
    }

    function executeCurrentAiAction() {
      if (currentPromptAction) {
        recordQuickActionUsage(currentPromptAction.name);
      }

      const isStyles = currentPromptAction && currentPromptAction.directAction === 'browseStyles';
      const actions = isStyles ? styleAiActions : commentAiActions;
      const currentKey = isStyles ? currentStyleAiAction : currentCommentAiAction;

      const fnName = actions[currentKey].fn;
      if (typeof window[fnName] === 'function') {
        window[fnName]();
      }
    }

    // New AI Comment functions
    async function generateTodoListFromDrawer() {
      const { filteredComments: selectedComments } = getFilteredCommentsForSummarize();
      if (selectedComments.length === 0) return;

      closePromptDrawer();
      setMode('ask');

      const commentsList = formatCommentsForAI(selectedComments);
      const prompt = `Based on these design comments, please generate a clear and actionable TODO list. Group them by page/section if applicable and prioritize critical feedback.

${commentsList}`;

      chatInput.value = prompt;
      await sendMessage();
    }

    function showAiAssistantDrawerPopup() {
      const { filteredComments: selectedComments } = getFilteredCommentsForSummarize();
      if (selectedComments.length === 0) return;

      const overlay = document.createElement('div');
      overlay.className = 'prompt-drawer-overlay open';
      overlay.style.zIndex = '10001';

      const popup = document.createElement('div');
      popup.className = 'ai-assistant-popup ai-assistant-popup--centered';
      popup.innerHTML = `
        <div class="ai-assistant-popup-header">
          <svg width="24" height="24" fill="none" viewBox="0 0 24 24" aria-hidden="true"><path fill="currentColor" d="M19 2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h4l3 3 3-3h4c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2m0 16h-4.83l-.59.59L12 20.17l-1.59-1.59-.58-.58H5V4h14zm-7-1 1.88-4.12L18 11l-4.12-1.88L12 5l-1.88 4.12L6 11l4.12 1.88z"/></svg>
          <span>${escapeHtml(tu('actions.comments.ai.assistantPopupTitle', { count: selectedComments.length }))}</span>
          ${createModelSelectDropdownHTML('drawerAssistant')}
        </div>
        <textarea class="ai-assistant-popup-input" id="aiAssistantPrompt" placeholder="${escapeHtml(tu('actions.comments.ai.assistantPlaceholder'))}" rows="3"></textarea>
        <div class="ai-assistant-popup-footer">
          <button class="ai-assistant-popup-cancel" id="aiAssistantDrawerCancel">${escapeHtml(tu('actions.comments.drawer.cancel'))}</button>
          <button class="ai-assistant-popup-submit" id="aiAssistantSubmit">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="12" height="12"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            ${escapeHtml(tu('actions.comments.ai.ask'))}
          </button>
        </div>
      `;

      overlay.appendChild(popup);
      document.body.appendChild(overlay);

      // Setup model selection in popup
      setupModelSelectInPopup(popup, 'drawerAssistant', overlay);

      const cancelBtn = popup.querySelector('#aiAssistantDrawerCancel');
      cancelBtn.onclick = () => overlay.remove();

      const ta = popup.querySelector('#aiAssistantPrompt');
      ta.focus();

      const submitBtn = popup.querySelector('#aiAssistantSubmit');
      submitBtn.onclick = async () => {
        const userPrompt = ta.value.trim();
        if (!userPrompt) return;

        overlay.remove();
        closePromptDrawer();
        setMode('ask');

        const { filteredComments: comments } = getFilteredCommentsForSummarize();
        const commentsList = formatCommentsForAI(comments);
        const fullPrompt = `${userPrompt}\n\nContext (Comments):\n${commentsList}`;

        chatInput.value = fullPrompt;
        await sendMessage();
      };
    }
    function formatCommentsForAI(comments) {
      const threads = new Map();
      figmaComments.forEach(c => {
        if (c.parent_id) {
          if (!threads.has(c.parent_id)) threads.set(c.parent_id, []);
          threads.get(c.parent_id).push(c);
        }
      });

      return comments.map((c, i) => {
        const replies = threads.get(c.id) || [];
        let text = `${i + 1}. ${c.user.handle}: "${c.message}"${c.resolved_at ? ' [RESOLVED]' : ''}`;
        if (replies.length > 0) {
          replies.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
          const repliesText = replies.map(r => `   - ${r.user.handle}: "${r.message}"`).join('\n');
          text += '\n' + repliesText;
        }
        return text;
      }).join('\n\n');
    }

    function batchSummarizeSelected() {
      summarizeCommentsFromDrawer();
    }

    function batchTogglePromptCommentHidden() {
      const ids = Array.from(selectedCommentIds);
      if (ids.length === 0) return;

      const shouldShow = ids.every(id => isPromptCommentHidden(id));
      const fileKey = getPromptCommentsStorageFileKey();
      const currentMap = { ...(hiddenPromptCommentsByFile[fileKey] || {}) };

      ids.forEach((commentId) => {
        if (shouldShow) delete currentMap[commentId];
        else currentMap[commentId] = true;
      });

      if (Object.keys(currentMap).length > 0) {
        hiddenPromptCommentsByFile = {
          ...hiddenPromptCommentsByFile,
          [fileKey]: currentMap,
        };
      } else {
        const nextState = { ...hiddenPromptCommentsByFile };
        delete nextState[fileKey];
        hiddenPromptCommentsByFile = nextState;
      }

      saveHiddenPromptCommentsByFileToLocal();
      syncHiddenPromptCommentsToPluginStorage();

      const container = document.getElementById('promptCommentsContainer');
      if (container && container.offsetParent !== null) {
        renderCommentsInDrawerPreservingScroll(container);
      }
    }


    // Select all visible comments
    function selectAllVisibleComments() {
      // Get currently visible top-level comments using the same filters
      const threads = new Map();
      const topLevelComments = [];
      figmaComments.forEach(c => {
        if (c.parent_id) {
          if (!threads.has(c.parent_id)) threads.set(c.parent_id, []);
          threads.get(c.parent_id).push(c);
        } else {
          topLevelComments.push(c);
        }
      });

      let visible = showResolvedComments
        ? topLevelComments
        : topLevelComments.filter(c => !c.resolved_at);

      // Filter by scope
      if (currentCommentsScope === 'page') {
        visible = visible.filter(c => {
          const nodeId = c.client_meta?.node_id;
          if (!nodeId) return false;
          const pageId = commentNodePageMap.get(nodeId);
          return !pageId || pageId === figmaCurrentPageId;
        });
      } else if (currentCommentsScope === 'selection') {
        const selectedIds = new Set();
        addSelectionNodeAndDescendantIds(selectedIds, lastKnownSelectionItems || []);
        visible = visible.filter(c => {
          const nodeId = c.client_meta?.node_id;
          return nodeId && selectedIds.has(nodeId);
        });
      }

      if (selectedAuthorsFilter.size > 0 || selectedMentionsFilter.size > 0) {
        visible = visible.filter(c => commentMatchesPeopleFilter(c, threads, true));
      }
      visible = filterCommentsBySearch(visible, commentsSearchQuery, threads);

      // If all visible are already selected, deselect them. Otherwise, select all visible.
      const allVisibleSelected = visible.length > 0 && visible.every(c => selectedCommentIds.has(c.id));

      if (allVisibleSelected) {
        visible.forEach(c => selectedCommentIds.delete(c.id));
      } else {
        visible.forEach(c => selectedCommentIds.add(c.id));
      }

      // Re-render only the list to update checkboxes
      updateCommentsListOnly();
    }

    // Toggle batch action inputs
    function toggleBatchReplyInput(defaultTab = 'manual') {
      const container = document.getElementById('batchActionInputContainer');
      const isCurrentlyOpen = container.style.display === 'block';

      if (isCurrentlyOpen) {
        container.style.display = 'none';
      } else {
        container.style.display = 'block';
        switchBatchActionTab(defaultTab);
        refreshAllReplyTemplateContainers();
      }
    }

    function switchBatchActionTab(tab) {
      const replyArea = document.getElementById('batchReplyInputArea');
      const aiArea = document.getElementById('batchAiReplyInputArea');
      const manualTabBtn = document.getElementById('batchTabManual');
      const aiTabBtn = document.getElementById('batchTabAi');

      if (tab === 'manual') {
        replyArea.style.display = 'block';
        aiArea.style.display = 'none';
        manualTabBtn.classList.add('active');
        aiTabBtn.classList.remove('active');
        document.getElementById('batchReplyTextarea').focus();
      } else {
        replyArea.style.display = 'none';
        aiArea.style.display = 'block';
        manualTabBtn.classList.remove('active');
        aiTabBtn.classList.add('active');
        document.getElementById('batchAiReplyInstruction').focus();
      }
    }

    function switchCommentScope(scope, btn) {
      if (currentCommentsScope === scope) return;
      currentCommentsScope = scope;

      // Update UI
      const container = btn.parentElement;
      container.querySelectorAll('.pill-tab').forEach(t => t.classList.remove('active'));
      btn.classList.add('active');

      if (scope === 'page' || scope === 'selection') {
        parent.postMessage({ pluginMessage: { type: 'get-current-context' } }, '*');
      }
      if (scope === 'selection') {
        requestSelectionDescendantsIfNeeded(true);
      }

      const promptContainer = document.getElementById('promptCommentsContainer');
      if (promptContainer) {
        renderCommentsInDrawer(promptContainer);
      }

      // If we switched to 'page' and don't have enough page info, trigger enrichment
      if (scope === 'page' && commentNodePageMap.size === 0 && figmaComments.length > 0) {
        enrichCommentsWithPageInfo();
      }
    }

    function enrichCommentsWithPageInfo() {
      const nodeIds = [...new Set(figmaComments.map(c => c.client_meta?.node_id).filter(id => id))];
      if (nodeIds.length === 0) return;
      parent.postMessage({ pluginMessage: { type: 'get-nodes-pages', nodeIds } }, '*');
    }



    function closeBatchInput() {
      document.getElementById('batchActionInputContainer').style.display = 'none';
      document.getElementById('batchReplyInputArea').style.display = 'none';
      document.getElementById('batchAiReplyInputArea').style.display = 'none';
    }

    // Handle keydown in batch reply inputs
    function handleBatchReplyKeydown(event, type) {
      if (event.key === 'Enter' && (event.metaKey || event.ctrlKey)) {
        event.preventDefault();
        event.stopPropagation();
        if (type === 'manual') {
          executeBatchReply();
        } else if (type === 'ai') {
          executeBatchAiReply();
        }
      }
    }

    // Execute batch manual reply
    async function executeBatchReply() {
      const textarea = document.getElementById('batchReplyTextarea');
      const rawMessage = textarea.value.trim();
      if (!rawMessage) return;

      const ids = Array.from(selectedCommentIds);
      if (ids.length === 0) return;

      showToast(`Posting reply to ${ids.length} comments...`, 'info');
      closeBatchInput();

      let successCount = 0;
      for (const id of ids) {
        try {
          await postFigmaCommentReplyHelper(id, rawMessage);
          successCount++;
        } catch (e) {
          console.error(`Failed to post reply to ${id}:`, e);
        }
      }

      showToast(`Successfully posted ${successCount}/${ids.length} replies`, 'success');
      textarea.value = '';
      selectedCommentIds.clear();
      await refreshCommentsInDrawer();
    }

    // Execute batch AI reply
    async function executeBatchAiReply() {
      const instruction = document.getElementById('batchAiReplyInstruction').value.trim();
      if (!instruction) {
        showToast('Please enter an instruction for AI', 'error');
        return;
      }

      const ids = Array.from(selectedCommentIds);
      if (ids.length === 0) return;

      const apiKey = geminiApiKeyInput?.value?.trim() || geminiApiKey;
      if (!apiKey) {
        showToast('Please configure Gemini API key in Settings', 'error');
        return;
      }

      const btn = document.getElementById('executeBatchAiReplyBtn');
      btn.disabled = true;
      const originalText = btn.innerHTML;
      btn.textContent = 'AI Thinking...';

      let successCount = 0;
      try {
        // Build threads map for context
        const threads = new Map();
        figmaComments.forEach(c => {
          if (c.parent_id) {
            if (!threads.has(c.parent_id)) threads.set(c.parent_id, []);
            threads.get(c.parent_id).push(c);
          }
        });

        for (const id of ids) {
          try {
            const comment = figmaComments.find(c => c.id === id);
            const replies = threads.get(id) || [];
            replies.sort((a, b) => new Date(a.created_at) - new Date(b.created_at));

            // Generate AI reply for this specific thread context
            let contextText = `Original comment by ${comment.user.handle}: "${comment.message}"\n`;
            if (replies.length > 0) {
              contextText += `Replies:\n` + replies.map(r => ` - ${r.user.handle}: "${r.message}"`).join('\n');
            }

            const prompt = `You are a helpful assistant responding to design feedback in Figma.
Instruction: ${instruction}

Context of the comment thread:
${contextText}

Generate a suitable, professional response. 
- Use the SAME LANGUAGE as the original comment.
- Output ONLY the response text.
- Be concise.`;

            const aiResponse = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${geminiModel || DEFAULT_GEMINI_CHAT_MODEL}:generateContent?key=${apiKey}`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                contents: [{ parts: [{ text: prompt }] }],
                generationConfig: { temperature: 0.7, maxOutputTokens: 256 }
              })
            });

            if (aiResponse.ok) {
              const data = await aiResponse.json();
              const aiText = data.candidates?.[0]?.content?.parts?.[0]?.text?.trim();
              if (aiText) {
                await postFigmaCommentReplyHelper(id, aiText);
                successCount++;
              }
            }
          } catch (e) {
            console.error(`Error in AI batch item ${id}:`, e);
          }
        }

        showToast(`AI posted ${successCount}/${ids.length} replies`, 'success');
        closeBatchInput();
        document.getElementById('batchAiReplyInstruction').value = '';
        selectedCommentIds.clear();
        await refreshCommentsInDrawer();
      } catch (err) {
        showToast(`Batch AI failed: ${err.message}`, 'error');
      } finally {
        btn.disabled = false;
        btn.innerHTML = originalText;
      }
    }

    // Internal helper for posting replies
    async function postFigmaCommentReplyHelper(commentId, rawMessage) {
      const token = figmaPersonalTokenInput?.value?.trim() || figmaPersonalToken;
      const fileKey = figmaFileKeyInput?.value?.trim() || figmaFileKey;
      if (!token || !fileKey) throw new Error('Missing token or file key');

      const message = convertMentionsToFigmaFormat(rawMessage);
      const response = await fetch(`https://api.figma.com/v1/files/${fileKey}/comments`, {
        method: 'POST',
        headers: {
          'X-Figma-Token': token,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          message,
          comment_id: commentId
        })
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({}));
        throw new Error(error.message || 'Failed to post reply');
      }
      return await response.json();
    }

    // Toggle replies visibility
    function toggleReplies(commentId) {
      const repliesEl = document.getElementById(`replies-${commentId}`);
      const toggleBtn = document.getElementById(`replies-toggle-${commentId}`);
      if (repliesEl && toggleBtn) {
        const isCollapsed = repliesEl.classList.contains('collapsed') || repliesEl.style.display === 'none';
        if (isCollapsed) {
          repliesEl.classList.remove('collapsed');
          animateCollapsibleOpen(repliesEl, 'block');
          toggleBtn.classList.add('expanded');
        } else {
          animateCollapsibleClose(repliesEl);
          toggleBtn.classList.remove('expanded');
        }
      }
    }

    // Get the currently filtered comments (respecting all active filters)
    function getFilteredCommentsForSummarize() {
      // Build threads map
      const threads = new Map();
      figmaComments.forEach(comment => {
        if (comment.parent_id) {
          if (!threads.has(comment.parent_id)) threads.set(comment.parent_id, []);
          threads.get(comment.parent_id).push(comment);
        }
      });

      // If anything is selected, use only those
      if (selectedCommentIds.size > 0) {
        const filteredComments = figmaComments.filter(c => selectedCommentIds.has(c.id));
        return { filteredComments, threads };
      }

      const topLevelComments = figmaComments.filter(c => !c.parent_id);

      // Filter by resolved state
      let filteredComments = showResolvedComments
        ? topLevelComments
        : topLevelComments.filter(c => !c.resolved_at);

      // Filter by people (if any selected in either tab)
      if (selectedAuthorsFilter.size > 0 || selectedMentionsFilter.size > 0) {
        filteredComments = filteredComments.filter(c => commentMatchesPeopleFilter(c, threads, true));
      }

      // Filter by search query (with AND/OR logic and reply search)
      filteredComments = filterCommentsBySearch(filteredComments, commentsSearchQuery, threads);

      if (commentsFilterBy === 'pending') {
        filteredComments = filteredComments.filter(c => {
          const replies = threads.get(c.id) || [];
          if (replies.length > 0) {
            const sortedReplies = [...replies].sort((a, b) => new Date(a.created_at) - new Date(b.created_at));
            const lastReply = sortedReplies[sortedReplies.length - 1];
            return lastReply.user.id !== figmaCurrentUser?.id;
          }
          return c.user.id !== figmaCurrentUser?.id;
        });
      }

      if (commentsFilterBy === 'bookmarked') {
        filteredComments = filteredComments.filter(c => isPromptCommentBookmarked(c.id));
      }

      return { filteredComments, threads };
    }

    // Download comments as CSV
    function downloadCommentsAsCSV() {
      const { filteredComments, threads } = getFilteredCommentsForSummarize();
      if (filteredComments.length === 0) {
        showToast('No comments to export', 'info');
        return;
      }

      // CSV Header
      let csvContent = 'Type,Author,Message,Date,Status,Node ID,ID,Parent ID\n';

      // Build CSV rows
      filteredComments.forEach(c => {
        const replies = threads.get(c.id) || [];
        const status = c.resolved_at ? 'Resolved' : 'Unresolved';
        const nodeId = c.client_meta?.node_id || '';
        const author = c.user.handle.replace(/"/g, '""');
        const message = c.message.replace(/"/g, '""');
        const date = formatCommentDate(c.created_at);

        // Main comment row
        csvContent += `"Comment","${author}","${message}","${date}","${status}","${nodeId}","${c.id}",""\n`;

        // Include replies if any
        replies.forEach(r => {
          const rAuthor = r.user.handle.replace(/"/g, '""');
          const rMessage = r.message.replace(/"/g, '""');
          const rDate = formatCommentDate(r.created_at);
          csvContent += `"  ↳Reply","${rAuthor}","${rMessage}","${rDate}","","","${r.id}","${c.id}"\n`;
        });
      });

      // Create blob and download link
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      const filename = `figma-comments-${new Date().toISOString().split('T')[0]}.csv`;

      link.setAttribute('href', url);
      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }

    // Update summarize all button state (count and disabled)
    function updateSummarizeAllButtonState() {
      const mainBtn = document.querySelector('.prompt-action-main-btn');
      if (!mainBtn) return;

      if (currentPromptAction?.directAction === 'listAllStickies') {
        const { filteredStickies } = getFilteredStickiesForSummarize();
        const count = filteredStickies.length;
        const countSpan = mainBtn.querySelector('.summarize-count');
        if (countSpan) {
          countSpan.textContent = `(${count})`;
        }
        mainBtn.disabled = count === 0;
        mainBtn.style.opacity = count === 0 ? '0.5' : '1';
        return;
      }

      const { filteredComments } = getFilteredCommentsForSummarize();
      const count = filteredComments.length;

      // Update count in button only if it's the summarize action
      if (currentCommentAiAction === 'summarize') {
        const countSpan = mainBtn.querySelector('.summarize-count');
        if (countSpan) {
          countSpan.textContent = `(${count})`;
        }
      }

      // Enable/disable whole group or main button
      const group = mainBtn.closest('.ai-action-group');
      if (group) {
        if (count === 0) {
          group.style.opacity = '0.5';
          group.style.pointerEvents = 'none';
        } else {
          group.style.opacity = '1';
          group.style.pointerEvents = 'auto';
        }
      }
      mainBtn.disabled = count === 0;
    }

