    const iconFontUnicodeCache = new Map();
    const iconFontAvailabilityState = {
      families: null,
      promise: null
    };

    function normalizeFontLookupKey(value) {
      return String(value || '')
        .trim()
        .replace(/\s+/g, ' ')
        .toLowerCase();
    }

    function getIconFontConfig(fontFamilyName) {
      return ICON_FONT_FAMILY_CONFIG[fontFamilyName] || null;
    }

    function getConfiguredIconFontFamilies() {
      return Object.entries(ICON_FONT_FAMILY_CONFIG)
        .sort(([, a], [, b]) => (a?.sortOrder ?? 99) - (b?.sortOrder ?? 99))
        .map(([familyName]) => familyName);
    }

    function buildIconFontAvailabilityMap(families) {
      const map = new Map();
      (Array.isArray(families) ? families : []).forEach(entry => {
        const family = typeof entry?.family === 'string' ? entry.family.trim() : '';
        if (!family) return;
        const styleOrder = (Array.isArray(entry?.styles) ? entry.styles : [])
          .map((style) => (typeof style === 'string' ? style.trim() : ''))
          .filter(Boolean);
        map.set(normalizeFontLookupKey(family), {
          family,
          styles: new Set(styleOrder.map((style) => normalizeFontLookupKey(style))),
          styleOrder
        });
      });
      return map;
    }

    function fuzzyMatchIconFontFamilyEntry(fontFamilyName, availabilityMap) {
      if (!(availabilityMap instanceof Map) || availabilityMap.size === 0) return null;
      const rows = [...availabilityMap.values()];
      const parts = (...needles) => (family) => {
        const n = normalizeFontLookupKey(family);
        return needles.every((k) => n.includes(k));
      };

      if (fontFamilyName === 'Material Symbols Outlined') {
        return rows.find((e) => parts('material', 'symbol', 'outlined')(e.family)) || null;
      }
      if (fontFamilyName === 'Material Symbols Rounded') {
        return rows.find((e) => parts('material', 'symbol', 'rounded')(e.family)) || null;
      }
      if (fontFamilyName === 'Material Symbols Sharp') {
        return rows.find((e) => parts('material', 'symbol', 'sharp')(e.family)) || null;
      }
      if (fontFamilyName === 'Lineicons Free') {
        const isLineicons = (e) => {
          const n = normalizeFontLookupKey(e.family);
          if (!n.includes('lineicon')) return false;
          if (n.includes('lineicons-pro') || n.includes('lineicon-pro')) return false;
          return true;
        };
        return rows.find(isLineicons) || rows.find((e) => normalizeFontLookupKey(e.family).includes('lineicon')) || null;
      }
      return null;
    }

    function findAvailableIconFontEntry(fontFamilyName, availabilityMap) {
      const config = getIconFontConfig(fontFamilyName);
      if (!config || !(availabilityMap instanceof Map)) return null;
      const aliases = Array.isArray(config.familyAliases) && config.familyAliases.length
        ? config.familyAliases
        : [fontFamilyName];
      for (const alias of aliases) {
        const entry = availabilityMap.get(normalizeFontLookupKey(alias));
        if (entry) return entry;
      }
      return fuzzyMatchIconFontFamilyEntry(fontFamilyName, availabilityMap);
    }

    /** Figma font picker / listAvailableFontsAsync use exact family + style strings; must not use config keys. */
    function resolveFigmaFontNameForIconFont(configKey, preferredStyle, availabilityMap) {
      const entry = findAvailableIconFontEntry(configKey, availabilityMap);
      if (!entry) return null;
      const styleOrder = Array.isArray(entry.styleOrder) && entry.styleOrder.length
        ? entry.styleOrder
        : [...entry.styles];
      const prefNorm = normalizeFontLookupKey(preferredStyle || 'Regular');
      const byPref = styleOrder.find((s) => normalizeFontLookupKey(s) === prefNorm);
      if (byPref) return { family: entry.family, style: byPref };
      const regular = styleOrder.find((s) => normalizeFontLookupKey(s) === 'regular');
      if (regular) return { family: entry.family, style: regular };
      if (styleOrder.length) {
        const sorted = [...styleOrder].sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));
        return { family: entry.family, style: sorted[0] };
      }
      return { family: entry.family, style: preferredStyle || 'Regular' };
    }

    function buildOrderedIconFontFamilies(configKey, resolvedFromMapFamily) {
      const cfg = getIconFontConfig(configKey);
      const list = [];
      if (Array.isArray(cfg?.canonicalLoadFamilies)) {
        list.push(...cfg.canonicalLoadFamilies);
      }
      if (resolvedFromMapFamily) list.push(resolvedFromMapFamily);
      if (cfg?.familyAliases) list.push(...cfg.familyAliases);
      if (configKey) list.push(configKey);
      const seen = new Set();
      return list.filter((f) => {
        const t = (f || '').trim();
        if (!t) return false;
        const k = normalizeFontLookupKey(t);
        if (seen.has(k)) return false;
        seen.add(k);
        return true;
      });
    }

    async function ensureIconFontAvailabilityMap() {
      if (iconFontAvailabilityState.families instanceof Map) {
        return iconFontAvailabilityState.families;
      }
      if (iconFontAvailabilityState.promise) {
        return iconFontAvailabilityState.promise;
      }

      iconFontAvailabilityState.promise = new Promise((resolve) => {
        const timeout = setTimeout(() => {
          window.removeEventListener('message', handler);
          const emptyMap = new Map();
          iconFontAvailabilityState.families = emptyMap;
          resolve(emptyMap);
        }, 8000);

        const handler = (event) => {
          const msg = event.data?.pluginMessage;
          if (!msg || msg.type !== 'font-preview-local-fonts-result') return;
          if (msg.requestId) return;
          clearTimeout(timeout);
          window.removeEventListener('message', handler);
          const availabilityMap = buildIconFontAvailabilityMap(msg.families);
          iconFontAvailabilityState.families = availabilityMap;
          resolve(availabilityMap);
        };

        window.addEventListener('message', handler);
        parent.postMessage({ pluginMessage: { type: 'list-font-preview-local-fonts' } }, '*');
      }).finally(() => {
        iconFontAvailabilityState.promise = null;
      });

      return iconFontAvailabilityState.promise;
    }

    function isIconFontFamilyAvailable(fontFamilyName, availabilityMap) {
      if (!fontFamilyName || !(availabilityMap instanceof Map)) return false;
      const familyEntry = findAvailableIconFontEntry(fontFamilyName, availabilityMap);
      if (!familyEntry) return false;
      const requiredStyles = getIconFontConfig(fontFamilyName)?.requiredStyles || [];
      if (!requiredStyles.length) return true;
      if (requiredStyles.some(style => familyEntry.styles.has(normalizeFontLookupKey(style)))) return true;
      const onlyRegular =
        requiredStyles.length === 1 && normalizeFontLookupKey(requiredStyles[0]) === 'regular';
      if (onlyRegular && familyEntry.styles.size > 0) return true;
      return false;
    }

    function getAvailableIconFontSearchConfigs(availabilityMap) {
      return getConfiguredIconFontFamilies()
        .filter(fontFamily => isIconFontFamilyAvailable(fontFamily, availabilityMap))
        .map(fontFamily => {
          const config = getIconFontConfig(fontFamily) || {};
          return {
            fontFamily,
            searchMode: config.searchMode || 'iconify',
            prefixes: Array.isArray(config.iconifyPrefixes) ? config.iconifyPrefixes : []
          };
        });
    }

    /** All configured icon sets (Iconify/API search). Inserts still use a glyph only when the font is active in Figma; otherwise SVG via Iconify. */
    function getAllIconFontSearchConfigs() {
      return getConfiguredIconFontFamilies().map(fontFamily => {
        const config = getIconFontConfig(fontFamily) || {};
        return {
          fontFamily,
          searchMode: config.searchMode || 'iconify',
          prefixes: Array.isArray(config.iconifyPrefixes) ? config.iconifyPrefixes : []
        };
      });
    }

    function formatIconFontAvailabilityMessage(availabilityMap) {
      const configuredFamilies = getConfiguredIconFontFamilies();
      const availableFamilies = configuredFamilies
        .filter(name => isIconFontFamilyAvailable(name, availabilityMap))
        .map(name => getIconFontConfig(name)?.displayName || name);
      if (availableFamilies.length > 0) {
        return `Available icon fonts in this Figma file: ${availableFamilies.join(', ')}.`;
      }
      return `None of the configured icon fonts are available in this Figma file. Install or enable one of: ${configuredFamilies.map(name => getIconFontConfig(name)?.displayName || name).join(', ')}.`;
    }

    function parseIconNameFromId(iconId) {
      if (typeof iconId !== 'string') return '';
      if (iconId.includes(':')) return iconId.split(':').slice(1).join(':');
      return iconId;
    }

    function parseIconPrefixFromId(iconId) {
      if (typeof iconId !== 'string') return '';
      if (!iconId.includes(':')) return '';
      return iconId.split(':')[0] || '';
    }

    function getIconFontStyleForIconId(iconId, fontFamilyName) {
      const prefix = parseIconPrefixFromId(iconId);
      if (fontFamilyName === 'Font Awesome 5 Free' || fontFamilyName === 'Font Awesome 6 Free') {
        if (prefix.includes('regular')) return 'Regular';
        if (prefix.includes('solid')) return 'Solid';
      }
      return getIconFontConfig(fontFamilyName)?.defaultStyle || 'Regular';
    }

    function getIconFontCssWeight(fontFamilyName, fontStyle) {
      if (fontFamilyName === 'Font Awesome 5 Free' || fontFamilyName === 'Font Awesome 6 Free') {
        return fontStyle === 'Solid' ? '900' : '400';
      }
      return '400';
    }

    function buildMaterialIconNameCandidates(iconName) {
      const normalized = (iconName || '').toLowerCase().trim();
      if (!normalized) return [];
      const set = new Set();
      const push = (v) => {
        const safe = (v || '').trim();
        if (safe) set.add(safe);
      };

      push(normalized);
      push(normalized.replace(/-/g, '_'));

      // Remove style/variant suffixes used in material-symbols ids.
      const withoutStyle = normalized.replace(/-(outline|rounded|sharp|fill|filled)$/i, '');
      push(withoutStyle);
      push(withoutStyle.replace(/-/g, '_'));

      // Remove numeric weights/variants like "-5", "-6", "-100", etc.
      const withoutNumbers = withoutStyle.replace(/-\d+$/i, '');
      push(withoutNumbers);
      push(withoutNumbers.replace(/-/g, '_'));

      // Base token fallback: first segment only (e.g., "book-6-rounded" -> "book")
      const firstToken = normalized.split('-')[0] || '';
      push(firstToken);

      return Array.from(set);
    }

    /** Map Iconify ids (hyphen + -outline/-rounded/-sharp) to Google codepoints file keys (underscore). */
    function normalizeMaterialSymbolIconifyNameToCodepointKey(iconNameHyphen) {
      let s = String(iconNameHyphen || '')
        .toLowerCase()
        .trim();
      for (let i = 0; i < 12; i++) {
        const before = s;
        s = s
          .replace(/-outline-rounded$/i, '')
          .replace(/-outline-sharp$/i, '')
          .replace(/-rounded-outline$/i, '')
          .replace(/-sharp-outline$/i, '')
          .replace(/-rounded$/i, '')
          .replace(/-sharp$/i, '')
          .replace(/-outline$/i, '')
          .replace(/-fill(?:ed)?$/i, '');
        if (s === before) break;
      }
      return s.replace(/-/g, '_');
    }

    const MATERIAL_SYMBOLS_GLYPHS_BUNDLED = {
      'Material Symbols Outlined': materialSymbolsOutlinedGlyphsJson,
      'Material Symbols Rounded': materialSymbolsRoundedGlyphsJson,
      'Material Symbols Sharp': materialSymbolsSharpGlyphsJson
    };

    function unicodeHexToChar(hexCode) {
      if (typeof hexCode !== 'string') return null;
      const normalized = hexCode.trim().replace(/^U\+/i, '').toLowerCase();
      if (!/^[0-9a-f]+$/i.test(normalized)) return null;
      const codePoint = Number.parseInt(normalized, 16);
      if (!Number.isFinite(codePoint)) return null;
      try {
        return String.fromCodePoint(codePoint);
      } catch (_) {
        return null;
      }
    }

    function parseIconFontCssContentMap(text, classPrefixes = []) {
      const unicodeMap = new Map();
      const regex = /\.([a-z0-9_-]+)::?before\s*\{\s*content:\s*["']\\([0-9a-fA-F]+)["'];?\s*\}/gi;
      let match;
      while ((match = regex.exec(text)) !== null) {
        const rawClassName = match[1];
        const hex = match[2];
        const char = unicodeHexToChar(hex);
        if (!char) continue;
        let key = rawClassName;
        for (const prefix of classPrefixes) {
          if (key.startsWith(prefix)) {
            key = key.slice(prefix.length);
            break;
          }
        }
        key = (key || '').toLowerCase();
        if (key) unicodeMap.set(key, char);
      }
      return unicodeMap;
    }

    function iconFontUnicodeCacheKey(fontFamilyName) {
      const config = getIconFontConfig(fontFamilyName);
      const url = config?.unicodeSource?.url;
      return url ? `${fontFamilyName}::${url}` : fontFamilyName;
    }

    async function loadIconFontUnicodeMap(fontFamilyName) {
      const cacheKey = iconFontUnicodeCacheKey(fontFamilyName);
      if (iconFontUnicodeCache.has(cacheKey)) {
        return iconFontUnicodeCache.get(cacheKey);
      }

      const config = getIconFontConfig(fontFamilyName);
      const unicodeMap = new Map();
      if (!config) {
        iconFontUnicodeCache.set(cacheKey, unicodeMap);
        return unicodeMap;
      }

      try {
        if (fontFamilyName === 'Lineicons Free' && lineiconsFreeGlyphsJson && lineiconsFreeGlyphsJson.glyphs) {
          Object.entries(lineiconsFreeGlyphsJson.glyphs).forEach(([name, hex]) => {
            const char = unicodeHexToChar(String(hex));
            if (char) unicodeMap.set(String(name).toLowerCase(), char);
          });
        }
        const msBundled = MATERIAL_SYMBOLS_GLYPHS_BUNDLED[fontFamilyName];
        if (msBundled && msBundled.glyphs) {
          Object.entries(msBundled.glyphs).forEach(([name, hex]) => {
            const char = unicodeHexToChar(String(hex));
            if (char) unicodeMap.set(String(name).toLowerCase(), char);
          });
        }
        const unicodeSource = config.unicodeSource;
        if (unicodeMap.size === 0 && unicodeSource?.url) {
          const res = await fetch(unicodeSource.url, { cache: 'no-store' });
          if (res.ok) {
            if (unicodeSource.type === 'json-metadata') {
              const metadata = await res.json();
              Object.entries(metadata || {}).forEach(([name, data]) => {
                const hex = data?.unicode;
                const char = unicodeHexToChar(hex);
                if (char) unicodeMap.set(name, char);
              });
            } else {
              const text = await res.text();
              if (unicodeSource.type === 'plain-codepoints') {
                text.split('\n').forEach(line => {
                  const trimmed = line.trim();
                  if (!trimmed) return;
                  const [name, hex] = trimmed.split(/\s+/);
                  if (!name || !hex) return;
                  const char = unicodeHexToChar(hex);
                  if (char) unicodeMap.set(name, char);
                });
              } else if (unicodeSource.type === 'css-map') {
                parseIconFontCssContentMap(text, unicodeSource.classPrefixes || []).forEach((char, name) => {
                  unicodeMap.set(name, char);
                });
              }
            }
          }
        }
      } catch (err) {
        console.warn('Failed to load icon font unicode map:', fontFamilyName, err);
      }

      iconFontUnicodeCache.set(cacheKey, unicodeMap);
      return unicodeMap;
    }

    async function resolveIconFontGlyph(iconId, fontFamilyName) {
      const iconName = parseIconNameFromId(iconId);
      if (!iconName) return null;

      const unicodeMap = await loadIconFontUnicodeMap(fontFamilyName);
      const normalizedName = iconName.toLowerCase();

      const candidates = [];
      if (fontFamilyName === 'Material Icons') {
        candidates.push(...buildMaterialIconNameCandidates(normalizedName));
      } else if (
        fontFamilyName === 'Material Symbols Outlined' ||
        fontFamilyName === 'Material Symbols Rounded' ||
        fontFamilyName === 'Material Symbols Sharp'
      ) {
        const codeKey = normalizeMaterialSymbolIconifyNameToCodepointKey(iconName);
        candidates.push(codeKey);
        candidates.push(normalizedName.replace(/-/g, '_'));
        const noTrailNum = normalizedName.replace(/-\d+$/i, '');
        if (noTrailNum !== normalizedName) {
          candidates.push(normalizeMaterialSymbolIconifyNameToCodepointKey(noTrailNum));
          candidates.push(noTrailNum.replace(/-/g, '_'));
        }
      } else if (fontFamilyName === 'Lineicons Free') {
        candidates.push(normalizedName);
        if (normalizedName.startsWith('lni-')) {
          candidates.push(normalizedName.replace(/^lni-/, ''));
        }
        candidates.push(normalizedName.replace(/-/g, '_'));
      } else {
        candidates.push(normalizedName);
        if (normalizedName.startsWith('fa-')) {
          candidates.push(normalizedName.replace(/^fa-/, ''));
        }
        candidates.push(normalizedName.replace(/-/g, '_'));
        candidates.push(normalizedName.replace(/-outline(?:-[a-z]+)?$/i, '').replace(/-/g, '_'));
        candidates.push(normalizedName.replace(/-(rounded|sharp|fill|filled)$/i, '').replace(/-/g, '_'));
      }

      const seen = new Set();
      for (const key of candidates) {
        if (!key || seen.has(key)) continue;
        seen.add(key);
        if (unicodeMap.has(key)) return unicodeMap.get(key);
      }

      return null;
    }

    function getIconFontLigatureText(iconId, fontFamilyName) {
      const iconName = parseIconNameFromId(iconId);
      if (!iconName) return null;

      const normalizedName = iconName.toLowerCase();
      const config = getIconFontConfig(fontFamilyName);
      if (!config?.useLigatureFallback) return null;

      if (config.ligatureFamily === 'material-icons') {
        const candidates = buildMaterialIconNameCandidates(normalizedName);
        return candidates[1] || candidates[0] || null;
      }

      if (config.ligatureFamily?.startsWith('material-symbols')) {
        return normalizeMaterialSymbolIconifyNameToCodepointKey(iconName);
      }

      return null;
    }

    async function resolveIconFontInsertText(iconId, fontFamilyName) {
      const glyph = await resolveIconFontGlyph(iconId, fontFamilyName);
      if (glyph) {
        return { text: glyph, mode: 'glyph' };
      }
      const ligature = getIconFontLigatureText(iconId, fontFamilyName);
      if (ligature) {
        return { text: ligature, mode: 'ligature' };
      }
      return { text: '?', mode: 'fallback' };
    }

    async function searchIconifyAcrossPrefixes(prefixes, query, limit = 20, fontFamily = null) {
      const allResults = [];
      for (const prefix of prefixes || []) {
        const url = new URL('https://api.iconify.design/search');
        url.searchParams.set('query', query);
        url.searchParams.set('prefix', prefix);
        url.searchParams.set('limit', String(limit));
        try {
          const res = await fetch(url.toString(), { cache: 'no-store' });
          if (!res.ok) continue;
          const data = await res.json();
          const icons = Array.isArray(data?.icons) ? data.icons : [];
          for (const id of icons) {
            if (typeof id === 'string' && id.includes(':')) {
              allResults.push({ id, label: id, source: 'iconfont', fontFamily });
            }
          }
        } catch (err) {
          console.warn('Iconify icon-font search failed for prefix', prefix, err);
        }
      }

      const unique = new Map();
      allResults.forEach(item => {
        if (item?.id && !unique.has(`${item.fontFamily || ''}:${item.id}`)) unique.set(`${item.fontFamily || ''}:${item.id}`, item);
      });
      return Array.from(unique.values());
    }

    function matchesMaterialSymbolVariant(iconId, fontFamilyName) {
      const iconName = parseIconNameFromId(iconId);
      if (!iconName) return false;
      const config = getIconFontConfig(fontFamilyName);
      const variant = config?.materialSymbolVariant;
      if (variant === 'rounded') return /-rounded$/i.test(iconName);
      if (variant === 'sharp') return /-sharp$/i.test(iconName);
      return !/-rounded$/i.test(iconName) && !/-sharp$/i.test(iconName);
    }

    function normalizeCreateIconSearchRaw(value) {
      return String(value || '')
        .toLowerCase()
        .replace(/["']/g, '')
        .replace(/\s+/g, ' ')
        .trim();
    }

    function tokenizeCreateIconSearch(value) {
      return normalizeCreateIconSearchRaw(value)
        .split(/[\s_-]+/)
        .map(token => token.trim())
        .filter(Boolean);
    }

    function normalizeCreateIconSearchCanonical(value) {
      return tokenizeCreateIconSearch(value).join(' ');
    }

    function normalizeCreateIconSearchJoined(value) {
      return tokenizeCreateIconSearch(value).join('');
    }

    function buildCreateIconPhraseVariants(...values) {
      const seen = new Set();
      const variants = [];
      const push = (candidate) => {
        const normalized = normalizeCreateIconSearchRaw(candidate);
        if (!normalized || seen.has(normalized)) return;
        seen.add(normalized);
        variants.push(normalized);
      };

      values.forEach(value => {
        const raw = normalizeCreateIconSearchRaw(value);
        if (!raw) return;
        push(raw);

        const words = tokenizeCreateIconSearch(raw);
        if (!words.length) return;

        push(words.join(' '));
        if (words.length > 1) {
          push(words.join(''));
          push(words.join('-'));
          push(words.join('_'));
        }
      });

      return variants;
    }

    function buildCreateIconSearchQueries(...values) {
      return buildCreateIconPhraseVariants(...values);
    }

    const CREATE_ICON_MATCH_TIER_CONFIG = {
      exact: { order: 0, label: 'Exact hit' },
      connector: { order: 1, label: 'Connector variant' },
      single: { order: 2, label: 'Single-word hit' },
      generate: { order: 3, label: 'Generate' }
    };

    function getCreateIconMatchTierLabel(tierKey) {
      return CREATE_ICON_MATCH_TIER_CONFIG[tierKey]?.label || 'Single-word hit';
    }

    function getCreateIconMatchTierOrder(tierKey) {
      return CREATE_ICON_MATCH_TIER_CONFIG[tierKey]?.order ?? 99;
    }

    function getCreateIconMatchInfo(iconName, query) {
      const queryRaw = normalizeCreateIconSearchRaw(query);
      const iconRaw = normalizeCreateIconSearchRaw(iconName);
      const queryWords = tokenizeCreateIconSearch(query);
      const iconWords = tokenizeCreateIconSearch(iconName);
      const queryJoined = normalizeCreateIconSearchJoined(query);
      const iconJoined = normalizeCreateIconSearchJoined(iconName);

      if (!queryWords.length || !iconWords.length) return null;

      if (iconRaw === queryRaw) {
        return {
          tier: 'exact',
          label: getCreateIconMatchTierLabel('exact'),
          order: getCreateIconMatchTierOrder('exact'),
          wordsMatched: queryWords.length,
          score: 3000 + queryWords.length * 20
        };
      }

      if (queryWords.length > 1 && queryJoined === iconJoined) {
        return {
          tier: 'connector',
          label: getCreateIconMatchTierLabel('connector'),
          order: getCreateIconMatchTierOrder('connector'),
          wordsMatched: queryWords.length,
          score: 2000 + queryWords.length * 20
        };
      }

      let wordsMatched = 0;
      let exactWordMatches = 0;
      queryWords.forEach(word => {
        if (!word) return;
        if (iconWords.includes(word)) {
          exactWordMatches += 1;
          wordsMatched += 1;
          return;
        }
        if (iconRaw.includes(word) || iconJoined.includes(word)) {
          wordsMatched += 1;
        }
      });

      if (queryWords.length === 1 && wordsMatched > 0) {
        return {
          tier: 'single',
          label: getCreateIconMatchTierLabel('single'),
          order: getCreateIconMatchTierOrder('single'),
          wordsMatched,
          score: 1000 + wordsMatched * 50 + exactWordMatches * 15 + (iconRaw.startsWith(queryWords[0]) ? 10 : 0)
        };
      }

      if (queryWords.length > 1 && wordsMatched === 1) {
        return {
          tier: 'single',
          label: getCreateIconMatchTierLabel('single'),
          order: getCreateIconMatchTierOrder('single'),
          wordsMatched,
          score: 1000 + wordsMatched * 50 + exactWordMatches * 15
        };
      }

      return null;
    }

    function getBestCreateIconMatchInfo(iconName, queries) {
      const list = Array.isArray(queries) ? queries : [queries];
      let best = null;
      list.forEach(query => {
        const info = getCreateIconMatchInfo(iconName, query);
        if (!info) return;
        if (!best || info.order < best.order || (info.order === best.order && info.score > best.score)) {
          best = { ...info, query };
        }
      });
      return best;
    }

    const ICON_FONT_SYNONYM_MAP = {
      add: ['plus', 'create', 'new'],
      alert: ['warning', 'error', 'notification'],
      archive: ['box', 'inbox'],
      arrow: ['chevron', 'caret'],
      attachment: ['paperclip', 'clip'],
      bell: ['notification', 'alert'],
      bin: ['trash', 'delete', 'remove'],
      calendar: ['date', 'event'],
      chat: ['message', 'comment', 'bubble'],
      check: ['done', 'confirm', 'success'],
      close: ['dismiss', 'cancel', 'x'],
      cog: ['gear', 'settings'],
      comment: ['message', 'chat', 'bubble'],
      create: ['add', 'plus', 'new'],
      date: ['calendar', 'event'],
      delete: ['trash', 'remove', 'bin'],
      dismiss: ['close', 'cancel', 'x'],
      download: ['arrow-down', 'import'],
      edit: ['pencil', 'pen', 'write'],
      email: ['mail', 'envelope', 'message'],
      error: ['alert', 'warning'],
      event: ['calendar', 'date'],
      find: ['search', 'magnifier', 'magnify'],
      gear: ['settings', 'cog'],
      home: ['house'],
      house: ['home'],
      import: ['download', 'arrow-down'],
      info: ['information', 'details'],
      mail: ['email', 'envelope', 'message'],
      menu: ['hamburger', 'bars', 'navigation'],
      message: ['chat', 'comment', 'bubble', 'mail'],
      new: ['add', 'plus', 'create'],
      notification: ['bell', 'alert'],
      password: ['lock', 'key', 'security'],
      pen: ['pencil', 'edit', 'write'],
      pencil: ['edit', 'pen', 'write'],
      person: ['user', 'profile', 'account'],
      photo: ['image', 'picture'],
      picture: ['image', 'photo'],
      plus: ['add', 'create', 'new'],
      profile: ['user', 'person', 'account'],
      remove: ['delete', 'trash', 'bin'],
      search: ['find', 'magnifier', 'magnify'],
      security: ['shield', 'lock', 'password'],
      settings: ['gear', 'cog'],
      shield: ['security', 'protect'],
      success: ['check', 'done', 'confirm'],
      trash: ['delete', 'remove', 'bin'],
      upload: ['arrow-up', 'export'],
      user: ['person', 'profile', 'account'],
      warning: ['alert', 'error'],
      write: ['edit', 'pencil', 'pen'],
      x: ['close', 'dismiss', 'cancel']
    };

    function expandIconFontSynonymTerms(...queries) {
      const seen = new Set();
      const terms = [];
      const push = (value) => {
        const normalized = String(value || '')
          .toLowerCase()
          .replace(/["']/g, '')
          .replace(/\s+/g, ' ')
          .trim();
        if (!normalized || seen.has(normalized)) return;
        seen.add(normalized);
        terms.push(normalized);
      };

      queries.filter(Boolean).forEach(push);

      queries.forEach(query => {
        const normalized = String(query || '')
          .toLowerCase()
          .replace(/["']/g, '')
          .replace(/[_-]+/g, ' ')
          .replace(/\s+/g, ' ')
          .trim();
        if (!normalized) return;

        const direct = ICON_FONT_SYNONYM_MAP[normalized] || [];
        direct.forEach(push);

        const tokens = normalized.split(' ').filter(Boolean);
        tokens.forEach((token, index) => {
          const synonyms = ICON_FONT_SYNONYM_MAP[token] || [];
          synonyms.forEach(push);
          synonyms.forEach(synonym => {
            const replaced = [...tokens];
            replaced[index] = synonym;
            push(replaced.join(' '));
          });
        });
      });

      return terms;
    }

    function scoreIconFontMatch(name, queries) {
      const info = getBestCreateIconMatchInfo(name, queries);
      return info ? info.score : 0;
    }

    function buildLocalIconFontId(fontFamily, name) {
      const config = getIconFontConfig(fontFamily) || {};
      const safeName = String(name || '').trim().toLowerCase().replace(/_/g, '-');
      if (!safeName) return null;

      if (fontFamily === 'Material Symbols Rounded') return `material-symbols:${safeName}-rounded`;
      if (fontFamily === 'Material Symbols Sharp') return `material-symbols:${safeName}-sharp`;
      if (fontFamily === 'Material Symbols Outlined' || fontFamily === 'Material Icons') return `material-symbols:${safeName}`;

      const prefixes = Array.isArray(config.iconifyPrefixes) ? config.iconifyPrefixes : [];
      if (!prefixes.length) return safeName;

      let preferredPrefix = prefixes[0];
      if (config.defaultStyle === 'Solid') {
        preferredPrefix = prefixes.find(prefix => String(prefix || '').includes('solid')) || preferredPrefix;
      } else if (config.defaultStyle === 'Regular') {
        preferredPrefix = prefixes.find(prefix => String(prefix || '').includes('regular')) || preferredPrefix;
      }
      return `${preferredPrefix}:${safeName}`;
    }

    async function searchLocalIconFontNames(queries, limit = 20, fontFamily = null) {
      const targetFamilies = fontFamily ? [fontFamily] : getConfiguredIconFontFamilies();
      const results = [];

      for (const family of targetFamilies) {
        const unicodeMap = await loadIconFontUnicodeMap(family);
        for (const [name] of unicodeMap.entries()) {
          const matchInfo = getBestCreateIconMatchInfo(name, queries);
          if (!matchInfo) continue;
          const id = buildLocalIconFontId(family, name);
          if (!id) continue;
          results.push({
            id,
            label: `${normalizeFontLookupKey(family).replace(/\s+/g, '-')}:${name}`,
            source: 'iconfont',
            fontFamily: family,
            score: matchInfo.score,
            matchTier: matchInfo.tier,
            matchTierLabel: matchInfo.label,
            matchTierOrder: matchInfo.order,
            matchWords: matchInfo.wordsMatched
          });
        }
      }

      results.sort((a, b) => {
        if ((a.matchTierOrder ?? 99) !== (b.matchTierOrder ?? 99)) return (a.matchTierOrder ?? 99) - (b.matchTierOrder ?? 99);
        const aFont = getIconFontConfig(a.fontFamily)?.sortOrder ?? 99;
        const bFont = getIconFontConfig(b.fontFamily)?.sortOrder ?? 99;
        if (aFont !== bFont) return aFont - bFont;
        return (b.score || 0) - (a.score || 0) || String(a.label || a.id || '').localeCompare(String(b.label || b.id || ''));
      });

      return results.slice(0, Math.max(1, limit));
    }

    async function searchMaterialIconsByCodepoints(query, limit = 20, fontFamily = 'Material Icons') {
      return searchLocalIconFontNames([query], limit, fontFamily);
    }

    async function searchMaterialSymbolsByVariant(query, limit = 20, fontFamily = 'Material Symbols Outlined') {
      return searchLocalIconFontNames([query], limit, fontFamily);
    }

    function collectIconifyCollectionIconNames(collectionData) {
      const iconsList = [];
      const seen = new Set();
      const push = (value) => {
        const safe = String(value || '').trim();
        if (!safe || seen.has(safe)) return;
        seen.add(safe);
        iconsList.push(safe);
      };

      if (collectionData?.uncategorized) {
        collectionData.uncategorized.forEach(push);
      }
      if (collectionData?.icons && typeof collectionData.icons === 'object') {
        Object.keys(collectionData.icons).forEach(push);
      }
      if (collectionData?.categories && typeof collectionData.categories === 'object') {
        Object.values(collectionData.categories).forEach(list => {
          (Array.isArray(list) ? list : []).forEach(push);
        });
      }

      return iconsList;
    }

    async function searchIconifyCollectionLocal(prefix, queries, limit = 20) {
      if (!prefix) return [];
      const data = await fetchIconifyCollection(prefix);
      if (!data) return [];

      const results = [];
      collectIconifyCollectionIconNames(data).forEach(name => {
        const matchInfo = getBestCreateIconMatchInfo(name, queries);
        if (!matchInfo) return;
        results.push({
          prefix,
          name,
          id: `${prefix}:${name}`,
          label: `${prefix}:${name}`,
          score: matchInfo.score,
          matchTier: matchInfo.tier,
          matchTierLabel: matchInfo.label,
          matchTierOrder: matchInfo.order,
          matchWords: matchInfo.wordsMatched
        });
      });

      results.sort((a, b) => {
        if ((a.matchTierOrder ?? 99) !== (b.matchTierOrder ?? 99)) return (a.matchTierOrder ?? 99) - (b.matchTierOrder ?? 99);
        return (b.score || 0) - (a.score || 0) || String(a.label || a.id || '').localeCompare(String(b.label || b.id || ''));
      });

      return results.slice(0, Math.max(1, limit));
    }

    async function searchPopularIconifyCollectionsLocal(queries, limit = 120) {
      const prefixes = POPULAR_ICONIFY_LOCAL_SEARCH_PREFIXES.slice();
      const perCollectionLimit = Math.max(20, Math.ceil(limit / Math.max(prefixes.length, 1)) * 2);
      const groups = await Promise.all(prefixes.map(prefix => searchIconifyCollectionLocal(prefix, queries, perCollectionLimit)));
      const unique = new Map();
      groups.flat().forEach(item => {
        if (item?.id && !unique.has(item.id)) unique.set(item.id, item);
      });
      return sortCreateIconMatches(Array.from(unique.values()), { iconApiSource: 'iconify' }).slice(0, Math.max(1, limit));
    }

    function attachCreateIconMatchMetadata(matches, queries) {
      return (Array.isArray(matches) ? matches : [])
        .map(match => {
          if (!match || !match.id) return null;
          if (match.id === '__generate__') {
            return {
              ...match,
              matchTier: 'generate',
              matchTierLabel: getCreateIconMatchTierLabel('generate'),
              matchTierOrder: getCreateIconMatchTierOrder('generate'),
              score: match.score || 0
            };
          }

          const iconName = parseIconNameFromId(match.id);
          const matchInfo = getBestCreateIconMatchInfo(iconName, queries);
          if (!matchInfo) return null;
          return {
            ...match,
            score: Math.max(match.score || 0, matchInfo.score),
            matchTier: matchInfo.tier,
            matchTierLabel: matchInfo.label,
            matchTierOrder: matchInfo.order,
            matchWords: matchInfo.wordsMatched
          };
        })
        .filter(Boolean);
    }

    function sortCreateIconMatches(matches, { iconApiSource } = {}) {
      const list = Array.isArray(matches) ? [...matches] : [];
      list.sort((a, b) => {
        if ((a.matchTierOrder ?? 99) !== (b.matchTierOrder ?? 99)) return (a.matchTierOrder ?? 99) - (b.matchTierOrder ?? 99);

        if (iconApiSource === 'iconfont') {
          const aFont = getIconFontConfig(a.fontFamily)?.sortOrder ?? 99;
          const bFont = getIconFontConfig(b.fontFamily)?.sortOrder ?? 99;
          if (aFont !== bFont) return aFont - bFont;
        }

        const aId = String(a.id || '').toLowerCase();
        const bId = String(b.id || '').toLowerCase();
        const aPrefix = aId.includes(':') ? aId.split(':')[0] : '';
        const bPrefix = bId.includes(':') ? bId.split(':')[0] : '';
        const aIsLogo = aPrefix === 'logos';
        const bIsLogo = bPrefix === 'logos';
        if (aIsLogo !== bIsLogo) return aIsLogo ? 1 : -1;

        return (b.score || 0) - (a.score || 0) || String(a.label || a.id || '').localeCompare(String(b.label || b.id || ''));
      });
      return list;
    }

    function mergeCreateIconMatches(baseMatches, extraMatches, searchQueries, { iconApiSource } = {}) {
      const uniqueMap = new Map();
      [...(Array.isArray(baseMatches) ? baseMatches : []), ...(Array.isArray(extraMatches) ? extraMatches : [])].forEach(match => {
        if (match?.id) uniqueMap.set(`${match.fontFamily || ''}:${match.id}`, match);
      });
      const merged = attachCreateIconMatchMetadata(Array.from(uniqueMap.values()), searchQueries);
      return sortCreateIconMatches(merged, { iconApiSource }).slice(0, 120);
    }

    function shouldLazyLoadCreateIconRelatedHits({ iconApiSource }) {
      return iconApiSource === 'iconify';
    }

    async function searchLazyCreateIconRelatedMatches({ iconApiSource, iconSet, description, slug, searchQueries }) {
      if (!shouldLazyLoadCreateIconRelatedHits({ iconApiSource })) return [];
      const broadenedQueries = buildCreateIconSearchQueries(description || slug || 'icon', ...searchQueries);
      if (iconSet) {
        return searchIconifyCollectionLocal(iconSet, broadenedQueries, 240);
      }
      return searchPopularIconifyCollectionsLocal(broadenedQueries, 240);
    }

    async function createIconFontFromId(iconId, { size, fallbackHint, actionMeta, fontFamily, suppressThinkingIndicator = false }) {
      const selectedFont = fontFamily || 'Font Awesome 6 Free';
      const fontStyle = getIconFontStyleForIconId(iconId, selectedFont);

      if (!suppressThinkingIndicator) {
        showThinkingIndicator('Inserting icon font glyph...');
      }
      try {
        const availabilityMap = await ensureIconFontAvailabilityMap();
        const figmaFromList = isIconFontFamilyAvailable(selectedFont, availabilityMap)
          ? resolveFigmaFontNameForIconFont(selectedFont, fontStyle, availabilityMap)
          : null;
        const orderedFamilies = buildOrderedIconFontFamilies(selectedFont, figmaFromList?.family);
        const primaryFamily = orderedFamilies[0] || selectedFont;
        const primaryStyle = figmaFromList?.style || fontStyle;
        const fontFamilyCandidates = orderedFamilies.slice(1);

        const resolvedInsert = await resolveIconFontInsertText(iconId, selectedFont);
        const textToInsert = resolvedInsert?.text || '?';

        const execResult = await executeCommands([{
          action: 'createText',
          text: textToInsert,
          name: `icon-font:${iconId}`,
          fontFamily: primaryFamily,
          fontStyle: primaryStyle,
          fontFamilyCandidates,
          iconFontStrictLoad: true,
          fontSize: size,
          x: 0,
          y: 0
        }]);

        if (execResult && execResult.failed > 0 && execResult.error && execResult.error.message === 'ICON_FONT_LOAD_FAILED') {
          if (!suppressThinkingIndicator) {
            removeThinkingIndicator();
          }
          showToast(`Could not load "${selectedFont}" in Figma (try activating the font in this file). Inserting ${iconId} as SVG.`, 'info');
          await createIconFromId(iconId, { size, useAiFallback: false, fallbackHint, actionMeta, suppressThinkingIndicator });
          return;
        }

        const successText = resolvedInsert?.mode === 'glyph'
          ? `Inserted icon font glyph "${iconId}" using ${selectedFont}.`
          : resolvedInsert?.mode === 'ligature'
            ? `Inserted icon font ligature "${textToInsert}" using ${selectedFont}.`
            : `Inserted icon font text "${textToInsert}" using ${selectedFont} (unicode mapping unavailable).`;
        addMessage('bot', successText);
        chatHistory.push({ role: 'model', parts: [{ text: successText }] });
        await autoSaveAfterResponse();
      } catch (err) {
        console.error('createIconFontFromId failed', err);
        const failText = `Failed to insert icon font glyph${fallbackHint?.description ? ` for "${fallbackHint.description}"` : ''}.`;
        showToast(failText, 'error');
        addMessage('bot', failText);
        chatHistory.push({ role: 'model', parts: [{ text: failText }] });
        await autoSaveAfterResponse();
      } finally {
        if (!suppressThinkingIndicator) {
          removeThinkingIndicator();
        }
      }
    }

    async function searchAntVIcon(query, limit = 10) {
      if (!query) return [];
      console.log('[AntV] Searching for:', query);
      try {
        const url = new URL('https://www.weavefox.cn/api/open/v1/icon');
        url.searchParams.set('text', query);
        url.searchParams.set('topK', String(limit));

        const res = await fetch(url.toString(), { cache: 'no-store' });
        if (!res.ok) {
          console.warn('[AntV] Search failed with status:', res.status);
          return [];
        }

        const result = await res.json();
        console.log('[AntV] Search result:', result);
        if (!result.status || !result.data || !Array.isArray(result.data.data)) {
          return [];
        }

        const toReadableAntVName = (value) => {
          if (typeof value !== 'string' || !value.trim()) return 'AntV Icon';
          const raw = value.split('/').pop()?.split('?')[0] || value;
          const withoutExt = raw.replace(/\.[a-z0-9]+$/i, '');
          return withoutExt
            .replace(/[-_]+/g, ' ')
            .replace(/\s+/g, ' ')
            .trim() || 'AntV Icon';
        };

        return result.data.data
          .map(item => {
            if (typeof item === 'string') {
              return {
                id: item,
                label: toReadableAntVName(item),
                source: 'antv'
              };
            }
            if (item && typeof item === 'object') {
              const id = item.url || item.icon || item.id || item.svgUrl || '';
              if (!id || typeof id !== 'string') return null;
              const label = item.name || item.title || toReadableAntVName(id);
              return { id, label, source: 'antv' };
            }
            return null;
          })
          .filter(Boolean);
      } catch (err) {
        console.warn('[AntV] Search error:', err);
        return [];
      }
    }

    async function fetchAntVIconSvg(url, size, color) {
      try {
        console.log('[AntV] Fetching SVG from:', url);
        const res = await fetch(url, { cache: 'no-store' });
        if (!res.ok) {
          console.warn('[AntV] Fetch failed with status:', res.status);
          return null;
        }
        const svg = await res.text();
        const prepared = prepareSvgForFigma(svg, size, color);
        if (!prepared) {
          console.warn('[AntV] Preparation failed for SVG');
          return null;
        }
        return prepared;
      } catch (err) {
        console.error('[AntV] Fetch error:', err);
        return null;
      }
    }

    function svgToDataUrl(svg) {
      if (!svg) return null;

      // Ensure xmlns is present for standalone rendering in <img>
      let updated = svg;
      if (!updated.includes('xmlns=')) {
        updated = updated.replace(/<svg\b/i, '<svg xmlns="http://www.w3.org/2000/svg"');
      }

      // Use Base64 encoding for better compatibility with attributes like rx/ry
      try {
        // Use btoa for encoding, but handle Unicode characters correctly
        const base64 = btoa(unescape(encodeURIComponent(updated)));
        return `data:image/svg+xml;base64,${base64}`;
      } catch (e) {
        // Fallback to URL encoding if Base64 fails
        return `data:image/svg+xml;utf8,${encodeURIComponent(updated)}`;
      }
    }

    async function generateSvgIconFallback(descriptionOrContext, size, color) {
      console.log('[generateSvgIconFallback] Called with:', {
        descriptionOrContext: typeof descriptionOrContext === 'string' ? descriptionOrContext : JSON.stringify(descriptionOrContext),
        size,
        color
      });

      const apiKey = getCurrentApiKey();
      if (!isAiProviderReady()) {
        console.error('[generateSvgIconFallback] No API key configured');
        showToast('Please configure your API key in Settings', 'error');
        return null;
      }

      const ctx = typeof descriptionOrContext === 'string'
        ? { description: descriptionOrContext }
        : descriptionOrContext;

      const desc = ctx.description || 'icon';
      const targetSize = clampNumber(size || ctx.size || 24, 16, 512);
      const strokeW = ctx.strokeWidth || 2;
      const isSolid = ctx.isSolid ?? /solid|filled|bold|heavy/i.test(desc);
      const safeColor = normalizeHexColor(color || ctx.color || '#111827');

      const systemPrompt = `You are an expert SVG icon designer specializing in minimalist UI icons for modern digital products.
Your goal is to generate high-quality, clean, and production-ready inline SVG icons.

STYLING RULES:
- Style: Minimalist UI icon design, modern digital product style.
- Abstraction: Icons must be symbolic and abstract. Do NOT illustrate scenes, characters, or realistic objects.
- Simplicity: Represent the concept using the simplest recognizable form. Remove any decorative or non-essential elements.
- Shapes: Use simple geometric shapes (circles, rectangles, paths).
- Composition: Centered composition with a clear silhouette and balanced proportions.
- Style Type: Flat design, monochrome, high contrast.
- Consistency: Do NOT mix stroke-based and filled styles in the same icon.
- Visual Constraints: NO gradients, NO shadows, NO textures, NO masks, NO filters.
- Background: Must be transparent (do not include a background rectangle).
- Stroke/Fill: Use consistent stroke width. Use currentColor for stroke (fill="none" for outlines) or fill (for solid icons). DO NOT use hex codes.

OPTIMIZATION RULES:
- Optimized for small-size display (24x24).
- Use viewBox="0 0 24 24".
- Ensure geometry fits within the frame with 1–2px internal padding to avoid clipping.
- Prefer compound paths over separate elements where logical for cleaner SVG output.

TECHNICAL RULES:
- Output ONLY a single <svg>...</svg> string. 
- ABSOLUTELY NO reasoning, NO explanations, NO commentary, NO conversational filler, NO code fences, NO markdown.
- START your response immediately with "<svg".
- COMPLETE the entire SVG structure. Do NOT stop mid-way or leave tags open.
- NO XML declarations (<?xml ... ?>), no DOCTYPE, no comments.
- Use stroke-linecap="round" and stroke-linejoin="round" for smooth, modern appearance.
- Default stroke-width="2" for main outlines, "1.5" for fine details.
- No external references, stylesheets, fonts, scripts, or event handlers.
- Use explicit attributes (fill, stroke, stroke-width) on each element.
- Avoid using <style> tags or CSS classes.
- Ensure the provided concept is recognizable as a single clear icon.
- If any rule is violated, regenerate a simpler version that fully complies.
- If rules conflict, prioritize minimalism, clarity, and technical correctness over visual flair.`;

      const userPrompt = `Create a high-quality, minimalist SVG icon for: "${desc}".
- Target: Modern digital product UI.
- Color: Use stroke="currentColor" or fill="currentColor" for all elements. DO NOT use specific hex codes.
- Style: ${isSolid ? 'Solid/Filled (fill="currentColor", no stroke)' : `Stroke-based outline (stroke="currentColor", stroke-width: ${strokeW}, fill="none")`}
- Scale: Optimized for ${targetSize}x${targetSize}
- Requirements: Clean geometric execution, consistent stroke weight, and a clear silhouette.
- Abstraction: Use the simplest symbolic representation possible. Avoid literal illustrations.
- Output Format: ONLY the raw <svg>...</svg> string. No text before or after.`;
      try {
        let responseText = '';
        let apiError = null;

        if (selectedProvider === 'gemini') {
          const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${geminiModel || DEFAULT_GEMINI_CHAT_MODEL}:generateContent?key=${apiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
              systemInstruction: { parts: [{ text: systemPrompt }] },
              generationConfig: { temperature: 0.1, maxOutputTokens: 2048 }
            })
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
          } else {
            const errData = await response.json().catch(() => ({}));
            apiError = errData?.error?.message || `API error: ${response.status}`;
          }
        } else if (selectedProvider === 'openai' || selectedProvider === 'ollama') {
          const response = await openAICompatFetch('chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', ...openAICompatAuthHeaders() },
            body: JSON.stringify(buildOpenAIRequestBody(getOpenAICompatChatModelId() || (selectedProvider === 'ollama' ? DEFAULT_OLLAMA_CHAT_MODEL : 'gpt-5-mini'), [
              { role: 'system', content: systemPrompt },
              { role: 'user', content: userPrompt }
            ], { max_tokens: 2048, temperature: 0.1 }))
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.choices?.[0]?.message?.content || '';
          } else {
            const errData = await response.json().catch(() => ({}));
            apiError = errData?.error?.message || `API error: ${response.status}`;
          }
        } else if (selectedProvider === 'anthropic') {
          const response = await fetch('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'x-api-key': apiKey,
              'anthropic-version': '2023-06-01'
            },
            body: JSON.stringify({
              model: anthropicModel || 'claude-sonnet-4-20250514',
              max_tokens: 2048,
              temperature: 0.1,
              system: systemPrompt,
              messages: [{ role: 'user', content: userPrompt }]
            })
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.content?.[0]?.text || '';
          } else {
            const errData = await response.json().catch(() => ({}));
            apiError = errData?.error?.message || `API error: ${response.status}`;
          }
        }

        if (apiError) {
          console.error('Icon generation API error:', apiError);
          showToast(`Icon generation failed: ${apiError}`, 'error');
          return null;
        }

        if (!responseText) {
          console.warn('Icon generation returned empty response');
          return null;
        }

        console.log('[Icon Gen] AI response:', responseText.substring(0, 500));

        const prepared = prepareSvgForFigma(responseText, targetSize, safeColor);
        if (!prepared) {
          console.warn('Failed to extract/prepare valid SVG from AI response. Raw response:', responseText);
          return null;
        }
        return prepared;
      } catch (error) {
        console.error('SVG fallback generation failed', error);
        return null;
      }
    }

    async function suggestIconSlug({ iconSet, description, styles = [], tags = [], strokeWidth, samples = [] }) {
      const apiKey = getCurrentApiKey();
      if (!isAiProviderReady()) return null;
      const styleLine = styles.length ? `Style preferences: ${styles.join(', ')}` : 'Style preferences: none specified';
      const tagLine = tags.length ? `Icon set tags: ${tags.join(', ')}` : 'Icon set tags: none provided';
      const sampleLine = samples.length ? `Sample icons: ${samples.slice(0, 5).join(', ')}` : '';
      const setContext = iconSet ? `from the "${iconSet}" set` : 'from any suitable Iconify set (prefer "mdi", "lucide", or "material-symbols")';
      const userPrompt = `Pick the most likely Iconify icon slug (no prefix) ${setContext}.
Description: ${description || 'icon'}
${styleLine}
${tagLine}
${sampleLine}
Stroke width: ${strokeWidth || 'default'}
Respond with ONLY the slug in lowercase hyphenated form (e.g., calendar-check). Do not include the prefix or extra text.`;
      const systemPrompt = 'You are a professional icon librarian for a modern design system. Your task is to find the most accurate and stylistically consistent Iconify slug (no prefix) for a given description. Prioritize minimalist, clean, and recognizable icons that work well in modern UI. Output ONLY the slug (e.g., calendar-check).';

      try {
        let responseText = '';
        if (selectedProvider === 'gemini') {
          const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${geminiModel || DEFAULT_GEMINI_CHAT_MODEL}:generateContent?key=${apiKey}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
              systemInstruction: { parts: [{ text: systemPrompt }] },
              generationConfig: { temperature: 0, maxOutputTokens: 60 }
            })
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
          }
        } else if (selectedProvider === 'openai' || selectedProvider === 'ollama') {
          const response = await openAICompatFetch('chat/completions', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', ...openAICompatAuthHeaders() },
            body: JSON.stringify(buildOpenAIRequestBody(getOpenAICompatChatModelId() || (selectedProvider === 'ollama' ? DEFAULT_OLLAMA_CHAT_MODEL : 'gpt-5-mini'), [
              { role: 'system', content: systemPrompt },
              { role: 'user', content: userPrompt }
            ], { max_tokens: 60, temperature: 0 }))
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.choices?.[0]?.message?.content || '';
          }
        } else if (selectedProvider === 'anthropic') {
          const response = await fetch('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'x-api-key': apiKey,
              'anthropic-version': '2023-06-01'
            },
            body: JSON.stringify({
              model: anthropicModel || 'claude-sonnet-4-20250514',
              max_tokens: 60,
              temperature: 0,
              system: systemPrompt,
              messages: [{ role: 'user', content: userPrompt }]
            })
          });
          if (response.ok) {
            const data = await response.json();
            responseText = data.content?.[0]?.text || '';
          }
        }

        const cleaned = (responseText || '').trim().split(/\s+/)[0]?.replace(/[`"'.,]/g, '');
        return normalizeIconSlug(cleaned);
      } catch (error) {
        console.error('Icon slug suggestion failed', error);
        return null;
      }
    }

    async function lazyLoadCreateIconDrawerRelatedMatches({
      runId,
      initialMatches,
      iconApiSource,
      iconSet,
      description,
      slug,
      searchQueries,
      renderOptions,
      historyTabId = null,
      historyKey = '',
      historyLabel = ''
    }) {
      try {
        const relatedMatches = await searchLazyCreateIconRelatedMatches({
          iconApiSource,
          iconSet,
          description,
          slug,
          searchQueries
        });
        if (runId !== createIconLazySearchRunId) return;
        if (!promptDrawer.classList.contains('open') || currentPromptAction?.directAction !== 'createIcon') return;

        const mergedMatches = mergeCreateIconMatches(initialMatches, relatedMatches, searchQueries, { iconApiSource });
        const initialIds = new Set((Array.isArray(initialMatches) ? initialMatches : []).map(match => `${match?.fontFamily || ''}:${match?.id || ''}`));
        const addedCount = mergedMatches.reduce((count, match) => {
          const key = `${match?.fontFamily || ''}:${match?.id || ''}`;
          return initialIds.has(key) ? count : count + 1;
        }, 0);

        renderCreateIconResultsInDrawer(mergedMatches, {
          ...renderOptions,
          historyTabId,
          historyKey,
          historyLabel,
          activateHistoryTab: false,
          showFeedback: false,
          lazyState: { loading: false, addedCount }
        });
      } catch (error) {
        if (runId !== createIconLazySearchRunId) return;
        console.warn('Lazy create-icon related search failed', error);
        renderCreateIconResultsInDrawer(initialMatches, {
          ...renderOptions,
          historyTabId,
          historyKey,
          historyLabel,
          activateHistoryTab: false,
          showFeedback: false,
          lazyState: { loading: false, addedCount: 0 }
        });
      }
    }

    async function runCreateIconAction(values, actionMeta) {
      const currentCreateIconRunId = ++createIconLazySearchRunId;
      const rawIconSet = (values.iconSet || '').trim();
      const iconSet = rawIconSet; // empty means global search
      const size = clampNumber(values.size || 24, 16, 512);
      const selectedIconSource = values.iconSource || 'iconify';
      const iconSourceMap = {
        iconify: { apiSource: 'iconify', fontFamily: null, label: 'Iconify' },
        antv: { apiSource: 'antv', fontFamily: null, label: 'AntV Infographic' },
        iconfont: { apiSource: 'iconfont', fontFamily: null, label: 'Icon Font' }
      };
      const resolvedIconSource = iconSourceMap[selectedIconSource] || iconSourceMap.iconify;
      const iconApiSource = resolvedIconSource.apiSource;
      const iconFontFamily = resolvedIconSource.fontFamily;
      const isNoAiMode = isAiOffModeEnabled();
      const useAiFallback = iconApiSource !== 'iconfont' && !isNoAiMode && values.useAiFallback !== false;
      const description = (values.iconDescription || '').trim();
      const strokeWidth = Number(values.strokeWidth || 0) || 2;
      const useDrawerPicker = values.showResultsInDrawer !== false
        && promptDrawer.classList.contains('open')
        && currentPromptAction?.directAction === 'createIcon';
      const setMeta = (iconSetOptionsCache || []).find(opt => opt.value === iconSet) || {};
      const sampleIcons = Array.isArray(setMeta.samples) ? setMeta.samples : (iconCollectionsCache?.[iconSet]?.samples || []);

      const slugSuggestion = (isNoAiMode || iconApiSource === 'iconfont') ? null : await suggestIconSlug({
        iconSet: iconSet || 'mdi',
        description,
        styles: [],
        tags: [],
        strokeWidth,
        samples: sampleIcons
      });
      const slug = normalizeIconSlug(slugSuggestion || description || 'icon');

      // Clean up description for search to avoid noise
      const cleanDesc = (description || '').replace(/["']/g, '').trim();
      const searchQueries = buildCreateIconSearchQueries(cleanDesc, slug);
      const iconFontSearchTerms = expandIconFontSynonymTerms(...searchQueries).slice(0, 12);

      let matches = [];
      if (iconApiSource === 'antv') {
        console.log('[AntV] Action started. Description:', description);
        const allResults = [];
        for (const q of searchQueries) {
          const res = await searchAntVIcon(q, 20);
          if (res && res.length) allResults.push(...res);
        }
        matches = allResults;
      } else if (iconApiSource === 'iconfont') {
        matches = await searchLocalIconFontNames(iconFontSearchTerms, 240);
      } else if (iconSet) {
        const allResults = [];
        const localCollectionMatches = await searchIconifyCollectionLocal(iconSet, searchQueries, 120);
        if (localCollectionMatches.length) {
          allResults.push(...localCollectionMatches);
        } else {
          for (const q of searchQueries) {
            const foundName = await searchIconifyIcon(iconSet, q);
            if (foundName) {
              allResults.push({
                id: `${iconSet}:${foundName}`,
                label: `${iconSet}:${foundName}`
              });
            }
          }
          if (!allResults.length) {
            allResults.push({
              id: `${iconSet}:${slug}`,
              label: `${iconSet}:${slug}`
            });
          }
        }
        matches = allResults;
      } else {
        const allResults = [];
        for (const q of searchQueries) {
          const res = await searchIconifyIconGlobal(q, 20);
          if (res && res.length) allResults.push(...res);
        }
        matches = allResults;
      }

      // Loosen search if not enough matches: try broader query and ensure AI option
      if (!matches.length || (iconApiSource !== 'antv' && iconApiSource !== 'iconfont' && matches.length < 3)) {
        if (iconApiSource === 'antv') {
          // Broader search for AntV if initial queries failed
          const loosened = await searchAntVIcon(description || slug || 'icon', 30);
          const existingIds = new Set(matches.map(m => m.id));
          const newMatches = (loosened || []).filter(m => !existingIds.has(m.id));
          matches = [...matches, ...newMatches];
        } else if (iconApiSource === 'iconfont') {
          const broadenedQuery = iconFontSearchTerms[0] || description || slug || 'icon';
          const broadenedTerms = expandIconFontSynonymTerms(broadenedQuery).slice(0, 6);
          const loosened = await searchLocalIconFontNames(broadenedTerms, 240);
          matches = [...matches, ...loosened];
        } else {
          const loosened = await searchIconifyIconGlobal(description || slug || 'icon', 30);
          matches = [...matches, ...(loosened || [])];
        }
      }

      // Deduplicate and rank by explicit match tiers.
      matches = matches || [];
      const uniqueMap = new Map();
      matches.forEach(m => {
        if (m?.id) uniqueMap.set(`${m.fontFamily || ''}:${m.id}`, m);
      });
      matches = attachCreateIconMatchMetadata(Array.from(uniqueMap.values()), searchQueries);
      matches = sortCreateIconMatches(matches, { iconApiSource });

      if (!isNoAiMode && iconApiSource !== 'iconfont' && !matches.find(m => m.id === '__generate__')) {
        matches.push({ id: '__generate__', label: 'Generate with AI' });
      }
      matches = attachCreateIconMatchMetadata(matches, searchQueries);
      matches = sortCreateIconMatches(matches, { iconApiSource });
      matches = matches.slice(0, 120); // keep a larger pool for paging

      const aiContext = {
        description: description || slug,
        strokeWidth,
        isSolid: false,
        size,
        color: null
      };

      const fallbackHint = [
        aiContext.description,
        `stroke ${aiContext.strokeWidth}px`,
        iconSet ? `set ${iconSet}` : ''
      ].filter(Boolean).join(' | ');

      const userText = `Create ${iconApiSource === 'antv'
        ? 'AntV'
        : iconApiSource === 'iconfont'
          ? 'Icon Font'
          : (iconSet || 'any')
        } icon${description ? `: "${description}"` : ''}`;
      addMessage('user', userText, null, { name: actionMeta?.name || 'Create icon', icon: actionMeta?.icon });
      chatHistory.push({ role: 'user', parts: [{ text: userText }] });
      await autoSaveAfterResponse();

      if (useDrawerPicker) {
        renderCreateIconDrawerLoadingState(description || slug || '');
      } else {
        showThinkingIndicator('Searching for icons...');
      }
      setSendButtonMode(true);
      try {
        if (!matches.length && iconApiSource === 'iconfont') {
          if (useDrawerPicker) {
            clearCreateIconDrawerLoadingState();
          }
          const noMatchText = `No icon font matches found for "${description || slug}". Try a broader keyword.`;
          addMessage('bot', noMatchText);
          chatHistory.push({ role: 'model', parts: [{ text: noMatchText }] });
          await autoSaveAfterResponse();
          showToast(noMatchText, 'error');
          return;
        }

        if (matches.length > 1) {
          if (useDrawerPicker) {
            const lazyEnabled = shouldLazyLoadCreateIconRelatedHits({ iconApiSource });
            const normalizedHistoryKey = normalizeCreateIconSearchRaw(cleanDesc || slug || '');
            const historyLabel = description || slug || 'Search';
            const historyKey = `${iconApiSource}:${iconSet || 'any'}:${normalizedHistoryKey || 'search'}`;
            const renderOptions = {
              fallbackHint: aiContext,
              size,
              useAiFallback,
              actionMeta,
              iconApiSource,
              iconFontFamily
            };
            const historyTabId = renderCreateIconResultsInDrawer(matches, {
              ...renderOptions,
              historyKey,
              historyLabel,
              activateHistoryTab: true,
              showFeedback: true,
              lazyState: lazyEnabled ? { loading: true, addedCount: 0 } : null
            });
            const resultText = `Showing ${matches.length} icon result${matches.length === 1 ? '' : 's'} in the drawer. Click any icon to insert it.`;
            addMessage('bot', resultText);
            chatHistory.push({ role: 'model', parts: [{ text: resultText }] });
            await autoSaveAfterResponse();
            if (lazyEnabled) {
              void lazyLoadCreateIconDrawerRelatedMatches({
                runId: currentCreateIconRunId,
                initialMatches: matches,
                iconApiSource,
                iconSet,
                description,
                slug,
                searchQueries,
                renderOptions,
                historyTabId,
                historyKey,
                historyLabel
              });
            }
            return;
          }

          const PAGE_SIZE = 24;
          const generateOpt = matches.find(m => m && m.id === '__generate__');
          const showChoices = (start = 0) => {
            const page = matches.slice(start, start + PAGE_SIZE);
            const hasMore = start + PAGE_SIZE < matches.length;
            const remaining = Math.max(matches.length - (start + PAGE_SIZE), 0);
            const options = [...page];
            if (hasMore) {
              options.push({
                id: '__load_more__',
                label: `Load more (${remaining} more)`,
                previewSvg: null,
              });
            }
            if (generateOpt && !options.some(o => o.id === '__generate__')) {
              options.push(generateOpt);
            }

            presentIconChoices(options, {
              fallbackHint,
              size,
              actionMeta,
              onChoose: async (chosenId) => {
                if (!chosenId) return;
                if (chosenId === '__load_more__') {
                  const nextStart = start + PAGE_SIZE;
                  showChoices(nextStart);
                  return;
                }
                const chosenMatch = options.find(o => o.id === chosenId);
                if (iconApiSource === 'iconfont') {
                  await createIconFontFromId(chosenId, { size, fallbackHint: aiContext, actionMeta, fontFamily: chosenMatch?.fontFamily || iconFontFamily });
                } else {
                  await createIconFromId(chosenId, { size, useAiFallback, fallbackHint: aiContext, actionMeta });
                }
                pendingAskBackContext = null;
                chatInput.dataset.askBackActive = 'false';
              }
            });
          };

          showChoices(0);
          return;
        }

        if (useDrawerPicker) {
          clearCreateIconDrawerLoadingState();
        }

        const target = matches[0];
        const iconId = target?.id || `${iconSet || 'mdi'}:${slug}`;
        if (iconApiSource === 'iconfont') {
          await createIconFontFromId(iconId, { size, fallbackHint: aiContext, actionMeta, fontFamily: target?.fontFamily || iconFontFamily });
        } else {
          await createIconFromId(iconId, { size, useAiFallback, fallbackHint: aiContext, actionMeta });
        }
      } catch (err) {
        console.error('Create icon action failed', err);
        if (useDrawerPicker) {
          clearCreateIconDrawerLoadingState();
        }
        showToast('Failed to create icon.', 'error');
        addMessage('bot', 'Failed to create icon.');
        chatHistory.push({ role: 'model', parts: [{ text: 'Failed to create icon.' }] });
        await autoSaveAfterResponse();
      } finally {
        removeThinkingIndicator();
        setSendButtonMode(false);
      }
    }

    function cleanupBrowseState() {
      const submitBtn = document.getElementById('promptDrawerSubmit');
      const cancelBtn = document.getElementById('promptDrawerCancel');

      // Clean up any existing browse event handlers
      if (window._currentIconBrowseHandler) {
        if (submitBtn) {
          submitBtn.removeEventListener('click', window._currentIconBrowseHandler);
        }
        window._currentIconBrowseHandler = null;
      }

      if (window._currentIconBrowseCancelHandler) {
        if (cancelBtn) {
          cancelBtn.removeEventListener('click', window._currentIconBrowseCancelHandler);
        }
        window._currentIconBrowseCancelHandler = null;
      }

      // Always restore default submit behavior in case drawer was closed
      // while a custom icon selection handler was active.
      if (submitBtn) {
        submitBtn.removeEventListener('click', submitPromptDrawer);
        submitBtn.addEventListener('click', submitPromptDrawer);
        submitBtn.textContent = submitBtn.dataset.originalText || 'Run Action';
        submitBtn.disabled = false;
      }

      // Clear any existing observers
      if (window._currentBrowseObserver) {
        window._currentBrowseObserver.disconnect();
        window._currentBrowseObserver = null;
      }
    }

    async function loadIconsForBrowse(prefix, values) {
      if (!prefix) return;

      // Clean up any existing browse state before loading new set
      cleanupBrowseState();

      showThinkingIndicator('Loading icon set...');
      try {
        const data = await fetchIconifyCollection(prefix);
        if (!data) {
          showToast(`Failed to load icon set: ${prefix}`, 'error');
          return;
        }

        // Show custom content area below fields
        promptDrawerCustomContent.classList.remove('hidden');

        renderIconBrowser(data, values, true); // true = inline mode
      } catch (err) {
        console.error('Browse icon set failed', err);
        showToast('Failed to browse icon set.', 'error');
      } finally {
        removeThinkingIndicator();
      }
    }

    async function runBrowseIconSetAction(values, config) {
      // If we're already showing icons, this button should trigger the import
      // But we already override the button in renderIconBrowser.
      // This function is now just a fallback or initial trigger.
      const prefix = values.iconSet;
      if (!prefix) {
        showToast('Please select an icon set first.', 'error');
        return;
      }
      await loadIconsForBrowse(prefix, values);
    }

    function renderIconBrowser(collectionData, config, isInline = false) {
      const container = document.createElement('div');
      container.className = 'icon-browse-container';


      // Iconify collection response can have 'icons' (map) or 'uncategorized' (array)
      // and sometimes 'categories' (map of arrays)
      let iconsList = [];
      if (collectionData.uncategorized) {
        iconsList = [...collectionData.uncategorized];
      }

      if (collectionData.icons) {
        const keys = Object.keys(collectionData.icons);
        keys.forEach(k => {
          if (!iconsList.includes(k)) iconsList.push(k);
        });
      }

      if (collectionData.categories) {
        Object.values(collectionData.categories).forEach(catList => {
          catList.forEach(iconId => {
            if (!iconsList.includes(iconId)) iconsList.push(iconId);
          });
        });
      }

      let categories = {};
      if (collectionData.categories && Object.keys(collectionData.categories).length > 0) {
        categories = collectionData.categories;
        // Also add uncategorized if they exist and aren't in categories
        const categorizedSet = new Set();
        Object.values(categories).forEach(list => list.forEach(id => categorizedSet.add(id)));
        const remaining = iconsList.filter(id => !categorizedSet.has(id));
        if (remaining.length > 0) {
          categories['Uncategorized'] = remaining;
        }
      } else {
        categories = categorizeIcons(iconsList);
      }

      let selectedIcons = new Set();
      const MAX_SELECTION = 5000;
      const isLargeSet = iconsList.length > 5000;
      // Grid previews must follow UI theme (import still uses Color field in doImport).
      const iconBrowsePreviewColor = getResolvedTextPrimaryColor();

      const statsEl = document.createElement('div');
      statsEl.className = 'icon-browse-stats';

      const selectionBar = document.createElement('div');
      selectionBar.className = 'icon-browse-selection-bar';
      selectionBar.appendChild(statsEl);

      const actions = document.createElement('div');
      actions.className = 'icon-browse-actions';

      if (!isLargeSet) {
        const importAllBtn = document.createElement('button');
        importAllBtn.className = 'setting-btn';
        importAllBtn.style.padding = '4px 12px';
        importAllBtn.textContent = 'Import All';
        importAllBtn.onclick = () => {
          selectedIcons = new Set(iconsList.slice(0, MAX_SELECTION));
          updateStats();
          doImport();
        };
        actions.appendChild(importAllBtn);
      }

      selectionBar.appendChild(actions);

      function updateStats() {
        statsEl.textContent = `${selectedIcons.size} selected / ${MAX_SELECTION} max`;
        const importBtn = document.getElementById('promptDrawerSubmit');
        if (importBtn) {
          importBtn.disabled = selectedIcons.size === 0;
          importBtn.textContent = `Import ${selectedIcons.size} Icons`;
        }
      }

      // Lazy load observer for images
      if (window._currentBrowseObserver) {
        window._currentBrowseObserver.disconnect();
      }
      window._currentBrowseObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const img = entry.target.querySelector('img');
            if (img && img.dataset.src) {
              img.src = img.dataset.src;
              delete img.dataset.src;
              if (window._currentBrowseObserver) {
                window._currentBrowseObserver.unobserve(entry.target);
              }
            }
          }
        });
      }, { root: document.getElementById('promptDrawer'), threshold: 0.1 });

      Object.entries(categories).forEach(([catName, catIcons]) => {
        const catSection = document.createElement('div');
        catSection.className = 'icon-browse-category';

        const header = document.createElement('div');
        header.className = 'icon-browse-category-header';

        const title = document.createElement('span');
        title.className = 'icon-browse-category-title';
        title.textContent = `${catName} (${catIcons.length})`;

        const collapseBtn = document.createElement('button');
        collapseBtn.className = 'cat-collapse-btn';
        collapseBtn.innerHTML = '▼'; // Down arrow for expanded
        collapseBtn.title = 'Collapse category';

        const selectBtn = document.createElement('button');
        selectBtn.className = 'cat-select-btn';
        selectBtn.textContent = 'Select Category';

        const grid = document.createElement('div');
        grid.className = 'icon-browse-grid';

        let isCollapsed = false;

        const updateCategorySelectBtn = () => {
          const selectedInCat = catIcons.filter(id => selectedIcons.has(id)).length;
          const allInCatSelected = selectedInCat === catIcons.length;
          const someInCatSelected = selectedInCat > 0;

          if (allInCatSelected) {
            selectBtn.textContent = 'Deselect Category';
            selectBtn.classList.add('all-selected');
          } else if (someInCatSelected) {
            selectBtn.textContent = 'Deselect Category';
            selectBtn.classList.remove('all-selected');
          } else {
            selectBtn.textContent = 'Select Category';
            selectBtn.classList.remove('all-selected');
          }
        };

        const toggleCollapse = () => {
          isCollapsed = !isCollapsed;
          grid.classList.toggle('collapsed', isCollapsed);
          collapseBtn.innerHTML = isCollapsed ? '▶' : '▼'; // Right arrow for collapsed, down arrow for expanded
          collapseBtn.title = isCollapsed ? 'Expand category' : 'Collapse category';
        };

        collapseBtn.onclick = (e) => {
          e.stopPropagation(); // Prevent triggering other click handlers
          toggleCollapse();
        };

        selectBtn.onclick = () => {
          const selectedInCat = catIcons.filter(id => selectedIcons.has(id)).length;
          const hasAnySelected = selectedInCat > 0;

          if (hasAnySelected) {
            // Deselect all from this category
            catIcons.forEach(id => selectedIcons.delete(id));
          } else {
            // Select as many as possible from this category
            for (const id of catIcons) {
              if (selectedIcons.size >= MAX_SELECTION) break;
              selectedIcons.add(id);
            }
          }

          // Refresh grid items
          grid.querySelectorAll('.icon-browse-item').forEach(item => {
            const iconName = item.dataset.name;
            item.classList.toggle('selected', selectedIcons.has(iconName));
          });

          updateCategorySelectBtn();
          updateStats();
        };

        header.appendChild(collapseBtn);
        header.appendChild(title);
        header.appendChild(selectBtn);
        catSection.appendChild(header);

        catIcons.forEach(iconName => {
          const item = document.createElement('div');
          item.className = `icon-browse-item${selectedIcons.has(iconName) ? ' selected' : ''}`;
          item.dataset.name = iconName;

          const img = document.createElement('img');
          // Get the text-primary color value from CSS variables
          img.dataset.src = `https://api.iconify.design/${collectionData.prefix}:${iconName}.svg?color=${encodeURIComponent(iconBrowsePreviewColor)}`;

          item.onclick = () => {
            if (selectedIcons.has(iconName)) {
              selectedIcons.delete(iconName);
            } else {
              if (selectedIcons.size >= MAX_SELECTION) {
                showToast(`Max selection limit of ${MAX_SELECTION} reached.`, 'warning');
                return;
              }
              selectedIcons.add(iconName);
            }
            item.classList.toggle('selected');
            updateCategorySelectBtn();
            updateStats();
          };

          item.appendChild(img);
          grid.appendChild(item);
          fetchAndApplyBrowseItemKindBadge(item, { id: `${collectionData.prefix}:${iconName}` }).catch(() => {});
          if (window._currentBrowseObserver) {
            window._currentBrowseObserver.observe(item);
          }
        });

        updateCategorySelectBtn();
        catSection.appendChild(grid);
        container.appendChild(catSection);
      });

      container.appendChild(selectionBar);
      promptDrawerCustomContent.innerHTML = '';
      promptDrawerCustomContent.appendChild(container);

      // Add drag-to-select functionality
      let isDragging = false;
      let dragStartX = 0;
      let dragStartY = 0;
      let selectionRect = null;
      let dragStartElement = null;

      // Remove selection rectangle
      const removeSelectionRect = () => {
        if (selectionRect) {
          selectionRect.remove();
          selectionRect = null;
        }
      };

      // Get icons within viewport rectangle
      const getIconsInViewportRect = (viewportRect) => {
        const icons = [];
        const allItems = container.querySelectorAll('.icon-browse-item');

        allItems.forEach(item => {
          const itemRect = item.getBoundingClientRect();

          // Both are viewport-relative
          if (itemRect.right > viewportRect.left && itemRect.left < viewportRect.right &&
            itemRect.bottom > viewportRect.top && itemRect.top < viewportRect.bottom) {
            icons.push(item);
          }
        });

        return icons;
      };

      // Create selection rectangle element
      const createSelectionRect = () => {
        if (selectionRect) return;
        selectionRect = document.createElement('div');
        selectionRect.className = 'icon-selection-rect';
        document.body.appendChild(selectionRect);
      };

      const refreshAllCategoryButtons = () => {
        container.querySelectorAll('.icon-browse-category').forEach(catSection => {
          const grid = catSection.querySelector('.icon-browse-grid');
          const selectBtn = catSection.querySelector('.cat-select-btn');
          if (!grid || !selectBtn) return;

          const catIconsCount = grid.querySelectorAll('.icon-browse-item').length;
          const selectedInCatCount = grid.querySelectorAll('.icon-browse-item.selected').length;

          const allInCatSelected = selectedInCatCount === catIconsCount && catIconsCount > 0;
          const someInCatSelected = selectedInCatCount > 0;

          if (allInCatSelected) {
            selectBtn.textContent = 'Deselect Category';
            selectBtn.classList.add('all-selected');
          } else if (someInCatSelected) {
            selectBtn.textContent = 'Deselect Category';
            selectBtn.classList.remove('all-selected');
          } else {
            selectBtn.textContent = 'Select Category';
            selectBtn.classList.remove('all-selected');
          }
        });
      };

      // Add event listeners to all icon-browse-grid elements and their expanded areas
      const grids = container.querySelectorAll('.icon-browse-grid');

      let startClientX = 0;
      let startClientY = 0;

      const onMouseMove = (e) => {
        if (!isDragging || !selectionRect || !dragStartElement) return;

        // Calculate selection rectangle coordinates using viewport-relative clientX/Y
        const left = Math.min(startClientX, e.clientX);
        const top = Math.min(startClientY, e.clientY);
        const width = Math.abs(e.clientX - startClientX);
        const height = Math.abs(e.clientY - startClientY);

        selectionRect.style.left = left + 'px';
        selectionRect.style.top = top + 'px';
        selectionRect.style.width = width + 'px';
        selectionRect.style.height = height + 'px';
      };

      const onMouseUp = (e) => {
        if (!isDragging) return;

        if (selectionRect && dragStartElement) {
          const rect = selectionRect.getBoundingClientRect();
          const iconsInSelection = getIconsInViewportRect(rect);

          // Toggle selection for all icons in the selection rectangle
          iconsInSelection.forEach(iconItem => {
            const iconName = iconItem.dataset.name;
            if (selectedIcons.has(iconName)) {
              selectedIcons.delete(iconName);
            } else {
              if (selectedIcons.size >= MAX_SELECTION) {
                showToast(`Max selection limit of ${MAX_SELECTION} reached.`, 'warning');
                return;
              }
              selectedIcons.add(iconName);
            }
            iconItem.classList.toggle('selected');
          });

          // Use the global refresh function
          refreshAllCategoryButtons();
          if (typeof updateStats === 'function') updateStats();
        }

        removeSelectionRect();
        isDragging = false;
        dragStartElement = null;

        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
      };

      // Function to check if a point is within 32px of any non-collapsed grid
      const isNearAnyGrid = (clientX, clientY) => {
        for (const grid of grids) {
          if (grid.classList.contains('collapsed')) continue;

          const rect = grid.getBoundingClientRect();
          // Expand the rectangle by 32px on all sides
          const expandedRect = {
            left: rect.left - 32,
            top: rect.top - 32,
            right: rect.right + 32,
            bottom: rect.bottom + 32
          };

          if (clientX >= expandedRect.left && clientX <= expandedRect.right &&
            clientY >= expandedRect.top && clientY <= expandedRect.bottom) {
            return grid;
          }
        }
        return null;
      };

      // Handle mouse down on container for expanded drag area
      container.addEventListener('mousedown', (e) => {
        // Only start drag if not clicking on an icon item
        if (!e.target.closest('.icon-browse-item')) {
          const nearGrid = isNearAnyGrid(e.clientX, e.clientY);
          if (nearGrid) {
            isDragging = true;
            dragStartElement = nearGrid;

            startClientX = e.clientX;
            startClientY = e.clientY;

            createSelectionRect();

            // Initial position (zero size)
            selectionRect.style.left = startClientX + 'px';
            selectionRect.style.top = startClientY + 'px';
            selectionRect.style.width = '0px';
            selectionRect.style.height = '0px';

            window.addEventListener('mousemove', onMouseMove);
            window.addEventListener('mouseup', onMouseUp);

            e.preventDefault();
            e.stopPropagation();
          }
        }
      });

      // Prevent text selection during drag
      container.addEventListener('selectstart', (e) => {
        if (isDragging) {
          e.preventDefault();
        }
      });

      // Update the existing submit button instead of cloning it repeatedly
      const submitBtn = document.getElementById('promptDrawerSubmit');
      const cancelBtn = document.getElementById('promptDrawerCancel');

      // Store original state if not already stored
      if (!submitBtn.dataset.originalText) {
        submitBtn.dataset.originalText = submitBtn.textContent;
      }

      const handleImportClick = (e) => {
        e.preventDefault();
        e.stopPropagation();
        doImport();
      };

      // Remove any previous custom listeners
      if (window._currentIconBrowseHandler) {
        submitBtn.removeEventListener('click', window._currentIconBrowseHandler);
      }
      window._currentIconBrowseHandler = handleImportClick;

      submitBtn.removeEventListener('click', submitPromptDrawer);
      submitBtn.addEventListener('click', handleImportClick);

      const restoreButtons = () => {
        if (window._currentIconBrowseHandler) {
          submitBtn.removeEventListener('click', window._currentIconBrowseHandler);
          window._currentIconBrowseHandler = null;
        }
        submitBtn.addEventListener('click', submitPromptDrawer);
        submitBtn.textContent = submitBtn.dataset.originalText || 'Run Action';

        promptDrawerFields.classList.remove('hidden');
        promptDrawerCustomContent.classList.add('hidden');
        promptDrawerCustomContent.innerHTML = '';
      };

      // Clean up previous cancel listener if any
      if (window._currentIconBrowseCancelHandler) {
        cancelBtn.removeEventListener('click', window._currentIconBrowseCancelHandler);
      }
      window._currentIconBrowseCancelHandler = (e) => {
        e.preventDefault();
        e.stopPropagation();
        restoreButtons();
      };
      cancelBtn.addEventListener('click', window._currentIconBrowseCancelHandler, { once: true });

      updateStats();

      async function doImport() {
        if (selectedIcons.size === 0) return;

        // Get fresh values from the form in case user changed settings after loading icons
        const currentValues = getPromptFieldValues();
        const currentConfig = {
          size: currentValues.size || config.size,
          color: currentValues.color || config.color,
          importMode: currentValues.importMode || config.importMode
        };

        // Group selected icons by category
        const iconsByCategory = {};
        const iconIds = Array.from(selectedIcons);
        const sortedKeywords = [...ICON_STYLE_KEYWORDS].sort((a, b) => b.length - a.length);

        iconIds.forEach(iconName => {
          let category = 'Regular';
          for (const keyword of sortedKeywords) {
            if (iconName.endsWith(`-${keyword}`)) {
              category = keyword.split('-').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
              break;
            }
          }
          if (!iconsByCategory[category]) iconsByCategory[category] = [];
          iconsByCategory[category].push(`${collectionData.prefix}:${iconName}`);
        });

        const BATCH_SIZE = 400;
        const totalIcons = iconIds.length;
        let processedIcons = 0;
        let batchIndex = 0;

        showThinkingIndicator('Processing icons...');
        if (submitBtn) {
          submitBtn.disabled = true;
          submitBtn.textContent = `Preparing ${totalIcons} icons...`;
        }

        try {
          // Process each category separately
          for (const [categoryName, categoryIcons] of Object.entries(iconsByCategory)) {
            const categoryIconCount = categoryIcons.length;

            // Split category into batches of 400
            for (let i = 0; i < categoryIconCount; i += BATCH_SIZE) {
              const batchIcons = categoryIcons.slice(i, i + BATCH_SIZE);
              const batchSize = batchIcons.length;

              if (submitBtn) {
                submitBtn.textContent = `Processing batch ${batchIndex + 1} (${batchSize} icons)...`;
              }

              const svgPayload = [];
              for (const iconId of batchIcons) {
                const svg = await fetchIconifySvg(iconId, currentConfig.size, currentConfig.color);
                if (svg) {
                  svgPayload.push({ id: iconId, svg });
                }
              }

              if (svgPayload.length > 0) {
                // Send batch with positioning info
                parent.postMessage({
                  pluginMessage: {
                    type: 'import-icons-batch',
                    icons: svgPayload,
                    config: {
                      size: currentConfig.size,
                      color: currentConfig.color,
                      importMode: currentConfig.importMode,
                      collectionName: collectionData.title,
                      categoryName,
                      batchIndex,
                      isFirstBatch: batchIndex === 0,
                      totalBatches: Math.ceil(totalIcons / BATCH_SIZE)
                    }
                  }
                }, '*');

                // Wait a bit between batches to avoid overwhelming Figma
                await new Promise(resolve => setTimeout(resolve, 100));
              }

              processedIcons += batchSize;
              batchIndex++;
            }
          }

          // Final cleanup after all batches are sent
          restoreButtons();
          closePromptDrawer();
          showToast(`Started importing ${totalIcons} icons in ${batchIndex} batches.`, 'success');

        } catch (err) {
          console.error('Batch import failed', err);
          showToast('Failed to prepare icons for import.', 'error');
          if (submitBtn) {
            submitBtn.disabled = false;
            updateStats();
          }
        } finally {
          removeThinkingIndicator();
        }
      }
    }

