    async function runCreateAdvancedGridAction(values, actionMeta) {
      const pattern = values.pattern || 'grid';
      const shape = values.shape || 'rectangle';
      const rows = clampNumber(values.rows || 4, 1, 50);
      const cols = clampNumber(values.cols || 3, 1, 50);
      const cellWidth = clampNumber(values.cellWidth || 100, 1, 500);
      const cellHeight = clampNumber(values.cellHeight || 80, 1, 500);
      const spacing = clampNumber(values.spacing || 16, 0, 100);
      const color = normalizeHexColor(values.color || '#E5E7EB');
      const strokeColor = normalizeHexColor(values.strokeColor || '#000000');
      const strokeWeight = clampNumber(values.strokeWeight || 0, 0, 20);
      const cornerRadius = clampNumber(values.cornerRadius || 0, 0, 50);
      const sides = clampNumber(values.sides || 6, 3, 20);
      const innerRadius = clampNumber(values.innerRadius || 0.4, 0, 1);
      const points = clampNumber(values.points || 5, 3, 20);
      const radialRadius = clampNumber(values.radialRadius || 200, 10, 1000);
      const radialInnerRadius = clampNumber(values.radialInnerRadius || 0, 0, 500);
      const radialAngle = clampNumber(values.radialAngle || 0, 0, 360);
      const radialRings = clampNumber(values.radialRings || 3, 1, 10);
      const radialItems = clampNumber(values.radialItems || 20, 1, 100);
      const spiralRadius = clampNumber(values.spiralRadius || 200, 10, 1000);
      const spiralAngle = clampNumber(values.spiralAngle || 0, 0, 360);
      const spiralTurns = clampNumber(values.spiralTurns || 3, 0.1, 10);
      const spiralItems = clampNumber(values.spiralItems || 20, 1, 100);
      const brickOffset = clampNumber(values.brickOffset || 0.5, 0, 1);

      // Prevent extremely large grids
      const totalCells = rows * cols;
      if (totalCells > 1000) {
        showToast(`Grid too large (${totalCells} cells). Maximum allowed is 1000 cells.`, 'warning');
        return;
      }

      showThinkingIndicator('Creating grid...');
      setSendButtonMode(true);

      try {
        // Send command to main plugin code
        const command = {
          action: 'createAdvancedGrid',
          pattern,
          shape,
          rows,
          cols,
          cellWidth,
          cellHeight,
          spacing,
          color,
          strokeColor,
          strokeWeight,
          cornerRadius,
          sides,
          innerRadius,
          points,
          radialRadius,
          radialInnerRadius,
          radialAngle,
          radialRings,
          radialItems,
          spiralRadius,
          spiralAngle,
          spiralTurns,
          spiralItems,
          brickOffset
        };

        await executeCommands([command]);

        const patternName = pattern.charAt(0).toUpperCase() + pattern.slice(1);
        const shapeName = shape.charAt(0).toUpperCase() + shape.slice(1);
        // Calculate actual number of items based on pattern
        let actualItemCount = totalCells;
        if (pattern === 'radial') {
          actualItemCount = radialItems;
        } else if (pattern === 'spiral') {
          actualItemCount = spiralItems;
        }

        const botText = `Created ${patternName} pattern with ${shapeName} shapes (${actualItemCount} total).`;
        addMessage('bot', botText);
        chatHistory.push({ role: 'model', parts: [{ text: botText }] });
        await autoSaveAfterResponse();
        showToast(`${patternName} grid created`, 'success');
      } catch (err) {
        console.error('Create advanced grid action failed', err);
        showToast('Failed to create grid.', 'error');
        addMessage('bot', 'Failed to create grid.');
        chatHistory.push({ role: 'model', parts: [{ text: 'Failed to create grid.' }] });
        await autoSaveAfterResponse();
      } finally {
        removeThinkingIndicator();
        setSendButtonMode(false);
      }
    }

