    function readSwapColorsIncludeFlag(fieldKey, values, defaultValue = true) {
      try {
        const checkbox = promptDrawerFields?.querySelector(`input[type="checkbox"][data-field-key="${fieldKey}"]`);
        if (checkbox) {
          return !!checkbox.checked;
        }
      } catch (_err) {
        // ignore selector issues
      }
      const raw = values[fieldKey];
      if (raw === false || raw === 'false' || raw === 0 || raw === '0') return false;
      if (raw === true || raw === 'true' || raw === 1 || raw === '1') return true;
      return defaultValue;
    }

    function getTopLevelSelectionEntries(selection) {
      if (!Array.isArray(selection) || selection.length === 0) return [];
      const descendantIds = new Set();
      selection.forEach((node) => {
        if (Array.isArray(node?.descendantIds)) {
          node.descendantIds.forEach((id) => descendantIds.add(id));
          return;
        }
        const cachedIds = selectionDescendantsById.get(node?.id);
        if (Array.isArray(cachedIds)) {
          cachedIds.forEach((id) => descendantIds.add(id));
        }
      });
      return selection.filter((node) => !descendantIds.has(node?.id));
    }

    async function runSwapColorsAction(values, actionMeta) {
      const fromRawList = Array.isArray(values.fromColor) ? values.fromColor : [values.fromColor];
      const fromTargets = [];
      const fromSeen = new Set();
      fromRawList.forEach((rawTarget) => {
        const normalized = normalizePromptColorSelection(rawTarget || '');
        if (!normalized?.hex) return;
        const dedupeKey = `${normalized.kind || 'custom'}::${normalized.id || ''}::${normalized.hex}`;
        if (fromSeen.has(dedupeKey)) return;
        fromSeen.add(dedupeKey);
        fromTargets.push(normalized);
      });
      const toTarget = normalizePromptColorSelection(values.toColor || '');
      const swapMode = values.swapMode || 'replace';

      if (!fromTargets.length || !toTarget?.hex) {
        showToast('Please provide both From Color and To Color.', 'error');
        return;
      }
      if (swapMode === 'swap' && fromTargets.length > 1) {
        showToast('Swap mode supports only one From Color. Use Replace mode for multiple source colors.', 'error');
        return;
      }

      const result = await requestSelectionData(false, false, ContextMode.STYLE_ONLY);
      const selection = Array.isArray(result?.data) ? result.data : [];
      if (selection.length === 0) {
        showToast('Please select at least one layer.', 'error');
        return;
      }

      const includeGradients = readSwapColorsIncludeFlag('includeGradients', values, true);
      const includeStrokes = readSwapColorsIncludeFlag('includeStrokes', values, true);
      const includeEffects = readSwapColorsIncludeFlag('includeEffects', values, true);

      const commands = selection.flatMap(node => fromTargets.map(fromTarget => ({
        action: 'swapColorTargets',
        nodeId: node.id,
        swapMode,
        fromTarget,
        toTarget,
        includeGradients,
        includeStrokes,
        includeEffects
      })));

      const execResult = await executeCommands(commands);
      const success = execResult?.success || 0;
      const failed = execResult?.failed || 0;
      if (success > 0) {
        const modeLabel = swapMode === 'swap' ? 'swapped' : 'replaced';
        showToast(`Colors ${modeLabel} on ${success} selection${success === 1 ? '' : 's'}${failed > 0 ? ` (${failed} skipped)` : ''}.`, failed > 0 ? 'warning' : 'success');
      }
    }

