    // Slash quick actions menu ("/" inside chat input)
    const SLASH_MENU_MAX_ITEMS = 8;
    let slashMenuItems = [];
    let slashMenuSelectedIndex = -1;
    let slashMenuVisible = false;
    let lastSlashQuery = '';

    function getSlashCommandContext() {
      if (!chatInput) return null;
      const cursorPos = chatInput.selectionStart ?? chatInput.value.length;
      const textBefore = chatInput.value.slice(0, cursorPos);
      const lastSlash = textBefore.lastIndexOf('/');
      if (lastSlash === -1) return null;

      // Require slash to be at start or after whitespace
      const charBefore = lastSlash === 0 ? ' ' : textBefore[lastSlash - 1];
      if (charBefore && !/\s/.test(charBefore)) return null;

      const query = textBefore.slice(lastSlash + 1);
      // Stop if user moved past the slash token with whitespace/newline
      if (/\s/.test(query)) return null;

      return { query, slashIndex: lastSlash };
    }

    function renderSlashActionsMenu() {
      if (!slashActionsMenu) return;
      if (!slashMenuVisible || slashMenuItems.length === 0) {
        slashActionsMenu.classList.remove('show');
        slashActionsMenu.innerHTML = '';
        return;
      }

	      const itemsHtml = slashMenuItems.map((action, idx) => {
	        const isActive = idx === slashMenuSelectedIndex;
	        const isDisabled = !isTaskAvailableInAiOff(action.task, action.name);
        const disabledClass = isDisabled ? ' ai-disabled' : '';
        const disabledAttrs = isDisabled ? ' aria-disabled="true" tabindex="-1"' : '';
	        const displayName = localizeActionString(action.name || '');
	        const displayDesc = localizeActionString(action.desc || '');
	        const title = isDisabled ? getAiOffBlockedMessage(displayName || 'Quick action') : (displayDesc || displayName || action.name);
          const slashBadges = buildQuickActionBadges(action.task, { compact: true });
	        return `
	          <button class="slash-action-item ${isActive ? 'active' : ''}${disabledClass}" data-index="${idx}" data-ai-disabled="${isDisabled ? 'true' : 'false'}" title="${title}"${disabledAttrs}>
	            <div class="slash-action-icon">${action.icon || defaultActionIcon}</div>
	            <div class="slash-action-name">${displayName || action.name}</div>
              <div class="slash-action-badges">${slashBadges}</div>
	          </button>
	        `;
	      }).join('');

      slashActionsMenu.innerHTML = `
        <div class="slash-actions-list">
          ${itemsHtml || `<div class="slash-actions-empty">${tu('actions.commands.none')}</div>`}
        </div>
      `;

      slashActionsMenu.classList.add('show');
    }

    function openSlashActionsMenu(actions, query) {
      slashMenuItems = actions || [];
      if (slashMenuItems.length === 0) {
        slashMenuSelectedIndex = -1;
      } else {
        const firstEnabled = slashMenuItems.findIndex(action => isTaskAvailableInAiOff(action.task, action.name));
        slashMenuSelectedIndex = firstEnabled >= 0 ? firstEnabled : 0;
      }
      slashMenuVisible = slashMenuItems.length > 0;
      lastSlashQuery = query || '';
      renderSlashActionsMenu();
    }

    function closeSlashActionsMenu() {
      slashMenuVisible = false;
      slashMenuItems = [];
      slashMenuSelectedIndex = -1;
      if (slashActionsMenu) {
        slashActionsMenu.classList.remove('show');
        slashActionsMenu.innerHTML = '';
      }
    }

    function moveSlashSelection(delta) {
      if (!slashMenuVisible || slashMenuItems.length === 0) return;
      const count = slashMenuItems.length;
      let nextIndex = slashMenuSelectedIndex;
      for (let i = 0; i < count; i++) {
        nextIndex = (nextIndex + delta + count) % count;
        const action = slashMenuItems[nextIndex];
        if (isTaskAvailableInAiOff(action?.task, action?.name || '')) {
          slashMenuSelectedIndex = nextIndex;
          renderSlashActionsMenu();
          return;
        }
      }
      slashMenuSelectedIndex = nextIndex;
      renderSlashActionsMenu();
    }

    function handleSlashInput() {
      const context = getSlashCommandContext();
      if (!context) {
        closeSlashActionsMenu();
        return;
      }
      const actions = context.query
        ? searchQuickActions(context.query, SLASH_MENU_MAX_ITEMS)
        : getMostUsedQuickActions(SLASH_MENU_MAX_ITEMS);
      openSlashActionsMenu(actions, context.query);
    }

    // Image reference context menu ("@" inside inputs)
    let imageRefItems = [];
    let imageRefSelectedIndex = -1;
    let imageRefVisible = false;
    let lastImageRefQuery = '';
    let imageRefActiveInput = null;

    function getImageRefContext() {
      // Lazy initialize imageRefMenu
      const imageRefMenu = document.getElementById('imageRefMenu');
      if (!imageRefMenu) return null;
      const target = document.activeElement;
      if (!target || (target !== chatInput && !target.closest('#promptDrawer'))) return null;
      if (target.tagName !== 'TEXTAREA' && target.tagName !== 'INPUT') return null;

      const cursorPos = target.selectionStart ?? target.value.length;
      const textBefore = target.value.slice(0, cursorPos);
      const lastAt = textBefore.lastIndexOf('@');
      if (lastAt === -1) return null;

      // Require @ to be at start or after whitespace
      const charBefore = lastAt === 0 ? ' ' : textBefore[lastAt - 1];
      if (charBefore && !/\s/.test(charBefore)) return null;

      const query = textBefore.slice(lastAt + 1);
      // Stop if user moved past the @ token with whitespace/newline
      if (/\s/.test(query)) return null;

      return { query, atIndex: lastAt, input: target };
    }

    function renderImageRefMenu() {
      const imageRefMenu = document.getElementById('imageRefMenu');
      if (!imageRefMenu) return;
      if (!imageRefVisible || imageRefItems.length === 0) {
        imageRefMenu.classList.remove('show');
        imageRefMenu.innerHTML = '';
        return;
      }

      const itemsHtml = imageRefItems.map((item, idx) => {
        const isActive = idx === imageRefSelectedIndex;
        return `
          <button class="image-ref-item ${isActive ? 'active' : ''}" data-index="${idx}">
            <img src="${item.thumbnail}" class="image-ref-thumbnail" />
            <div class="image-ref-info">
              <div class="image-ref-name">${escapeHtml(item.name)}</div>
              <div class="image-ref-index">@Image ${item.index}</div>
            </div>
          </button>
        `;
      }).join('');

      imageRefMenu.innerHTML = itemsHtml;
      imageRefMenu.classList.add('show');
      positionImageRefMenu();

      // Attach click listeners
      imageRefMenu.querySelectorAll('.image-ref-item').forEach(btn => {
        btn.onclick = (e) => {
          e.preventDefault();
          e.stopPropagation();
          imageRefSelectedIndex = parseInt(btn.dataset.index);
          selectImageRef();
        };
      });
    }

    function positionImageRefMenu() {
      const imageRefMenu = document.getElementById('imageRefMenu');
      if (!imageRefVisible || !imageRefActiveInput || !imageRefMenu) return;

      const rect = imageRefActiveInput.getBoundingClientRect();
      const menuWidth = 180;
      const menuHeight = imageRefMenu.offsetHeight || 200;

      // Position above the input
      let top = rect.top - menuHeight - 8;
      let left = rect.left;

      // Keep within viewport
      if (top < 0) {
        top = rect.bottom + 8;
      }
      if (left + menuWidth > window.innerWidth) {
        left = window.innerWidth - menuWidth - 8;
      }

      imageRefMenu.style.top = `${top}px`;
      imageRefMenu.style.left = `${left}px`;
      imageRefMenu.style.width = `${menuWidth}px`;
    }

    function openImageRefMenu(items, query, input) {
      imageRefItems = items || [];
      imageRefSelectedIndex = imageRefItems.length ? 0 : -1;
      imageRefVisible = imageRefItems.length > 0;
      lastImageRefQuery = query || '';
      imageRefActiveInput = input;
      renderImageRefMenu();
    }

    function closeImageRefMenu() {
      imageRefVisible = false;
      imageRefItems = [];
      imageRefSelectedIndex = -1;
      imageRefActiveInput = null;
      const imageRefMenu = document.getElementById('imageRefMenu');
      if (imageRefMenu) {
        imageRefMenu.classList.remove('show');
        imageRefMenu.innerHTML = '';
      }
    }

    function handleImageRefInput() {
      const context = getImageRefContext();
      if (!context) {
        closeImageRefMenu();
        return;
      }

      let images = [];
      if (context.input === chatInput) {
        images = getStagedImageAttachments().map((img, idx) => {
          const blob = new Blob([new Uint8Array(img.data)], { type: 'image/png' });
          return {
            name: img.name,
            thumbnail: URL.createObjectURL(blob),
            index: idx + 1
          };
        });
      } else {
        // Try to find images in the prompt drawer
        const container = promptDrawerFields.querySelector('.prompt-image-upload-container');
        if (container) {
          container.querySelectorAll('.prompt-image-upload-slot.has-image').forEach(slot => {
            images.push({
              name: `Image ${slot.dataset.slotNumber}`,
              thumbnail: slot.dataset.imageData,
              index: parseInt(slot.dataset.slotNumber)
            });
          });
        }
      }

      if (context.query) {
        const q = context.query.toLowerCase();
        images = images.filter(img =>
          img.name.toLowerCase().includes(q) ||
          String(img.index).includes(q) ||
          `image ${img.index}`.includes(q)
        );
      }

      openImageRefMenu(images, context.query, context.input);
    }

    function selectImageRef() {
      if (!imageRefVisible || imageRefSelectedIndex === -1 || !imageRefActiveInput) return;
      const item = imageRefItems[imageRefSelectedIndex];
      if (!item) return;

      const context = getImageRefContext();
      if (!context) return;

      const input = context.input;
      const atIndex = context.atIndex;
      const text = input.value;
      const cursorPos = input.selectionStart;

      const before = text.slice(0, atIndex);
      const after = text.slice(cursorPos);
      const insertion = `@Image ${item.index} `;

      setInputValueWithUndo(input, before + insertion + after, true);
      const newPos = atIndex + insertion.length;
      input.setSelectionRange(newPos, newPos);
      input.focus();

      closeImageRefMenu();
    }

    function moveImageRefSelection(delta) {
      if (!imageRefVisible || imageRefItems.length === 0) return;
      const count = imageRefItems.length;
      imageRefSelectedIndex = (imageRefSelectedIndex + delta + count) % count;
      renderImageRefMenu();
    }

    async function triggerSlashAction(action) {
      if (!action || !action.task) return;
      closeSlashActionsMenu();

      chatInput.value = '';
      chatInput.style.height = 'auto';

      const task = action.task;
      if (!isTaskAvailableInAiOff(task, task?.name || action?.name || '')) {
        showToast(getAiOffBlockedMessage(task.name || 'Quick action'), 'error');
        return;
      }
      const noSelection = task.noSelection === true;
      const includeTokens = task.includeTokens === true;
      const icon = action.icon || defaultActionIcon;

      // Auto-switch modes based on action type
      if (task.askMode && currentMode !== 'ask') {
        setMode('ask');
      } else if (!task.askMode && currentMode !== 'agent') {
        setMode('agent');
      }

      // Actions that need fields go to prompt drawer
      if ((task.fields && task.fields.length > 0) ||
        task.name === 'UI Section Outline' ||
        task.directAction === 'createIcon' ||
        task.directAction === 'browseIconSet' ||
        task.directAction === 'generatePalette' ||
        task.directAction === 'listAllComponents' ||
        task.directAction === 'browseStyles' ||
        task.directAction === 'googleFontPreview' ||
        task.directAction === 'hueShift' ||
        task.directAction === 'fontMapping') {
        let hydratedFields = task.fields || [];
        if (task.directAction === 'browseIconSet') {
          const excludeAnyIconifySet = true;
          hydratedFields = await hydrateCreateIconFields(task.fields, excludeAnyIconifySet);
        } else if (task.directAction === 'generatePalette') {
          // hydratedFields will be handled inside openPromptDrawer for palette generation
        }
        // Handle askMode actions - don't switch to agent mode
        if (task.askMode) {
          await openPromptDrawer({ ...task, fields: hydratedFields, icon });
        } else {
          setMode('agent');
          await openPromptDrawer({ ...task, fields: hydratedFields, icon });
        }
        return;
      }

      // Direct actions (no fields)
      recordQuickActionUsage(task.name);

      // Handle askMode direct actions
      if (task.askMode) {
        if (task.directAction === 'extractImagePrompt') {
          await handleExtractImagePrompt(task.name, icon);
        } else {
          const prompt = task.prompt || (typeof task.promptTemplate === 'string' ? task.promptTemplate : '');
          await sendAskModeQuickAction(prompt, { name: task.name, icon });
        }
        return;
      }

      if (task.directAction) {
        setMode('agent');
        await runDirectAction(task.directAction, {}, { ...task, icon });
        return;
      }

      setMode('agent');
      const prompt = task.prompt || (typeof task.promptTemplate === 'string' ? task.promptTemplate : '');
      const contextMode = task.requiredContext || ContextMode.SMART;
      await sendQuickActionMessage(prompt, noSelection, { name: task.name, icon }, includeTokens, contextMode);
    }

    if (slashActionsMenu) {
      slashActionsMenu.addEventListener('mousedown', (e) => {
        const item = e.target.closest('.slash-action-item');
        if (!item) return;
        e.preventDefault(); // keep focus in textarea
        if (item.dataset.aiDisabled === 'true') {
          showToast(item.title || getAiOffBlockedMessage('Quick action'), 'error');
          return;
        }
        const idx = parseInt(item.dataset.index);
        if (!Number.isNaN(idx) && slashMenuItems[idx]) {
          triggerSlashAction(slashMenuItems[idx]);
        }
      });
    }

    // AI improvement button functionality
    const chatInputAiBtn = document.getElementById('chatInputAiBtn');
    let chatInputEditTimer = null;

