    // Event delegation for message action buttons (edit, copy)
    chatMessages.addEventListener('click', async (e) => {
      // Handle code block copy button
      const codeBlockCopyBtn = e.target.closest('.code-block-copy-btn');
      if (codeBlockCopyBtn) {
        e.stopPropagation();
        const container = codeBlockCopyBtn.closest('.code-block-container');
        const codeEl = container?.querySelector('code');
        if (codeEl) {
          const textToCopy = codeEl.textContent;
          try {
            await navigator.clipboard.writeText(textToCopy);
          } catch (err) {
            const textArea = document.createElement('textarea');
            textArea.value = textToCopy;
            textArea.style.cssText = 'position:fixed;top:-9999px;left:-9999px;opacity:0';
            document.body.appendChild(textArea);
            textArea.select();
            document.execCommand('copy');
            document.body.removeChild(textArea);
          }
          const label = codeBlockCopyBtn.querySelector('span');
          if (label) label.textContent = 'Copied!';
          codeBlockCopyBtn.classList.add('copied');
          setTimeout(() => {
            if (label) label.textContent = 'Copy';
            codeBlockCopyBtn.classList.remove('copied');
          }, 2000);
        }
        return;
      }

      // Handle code block edit button
      const codeBlockEditBtn = e.target.closest('.code-block-edit-btn');
      if (codeBlockEditBtn) {
        e.stopPropagation();
        const container = codeBlockEditBtn.closest('.code-block-container');
        if (container) {
          openCodeEditor(container);
        }
        return;
      }

      const inlineCodeCopy = e.target.closest('code.inline-code-copyable');
      if (inlineCodeCopy) {
        e.stopPropagation();
        const textToCopy = inlineCodeCopy.textContent || '';
        if (!textToCopy) return;
        try {
          await navigator.clipboard.writeText(textToCopy);
        } catch (err) {
          const textArea = document.createElement('textarea');
          textArea.value = textToCopy;
          textArea.style.cssText = 'position:fixed;top:-9999px;left:-9999px;opacity:0';
          document.body.appendChild(textArea);
          textArea.select();
          try {
            document.execCommand('copy');
          } catch (copyErr) {
            showToast('Failed to copy', 'error');
            document.body.removeChild(textArea);
            return;
          }
          document.body.removeChild(textArea);
        }
        showToast(t('settings.messages.copied'), 'success');
        return;
      }

      // Handle placeholder click
      const placeholder = e.target.closest('.placeholder-inline');
      if (placeholder) {
        e.stopPropagation();
        const type = placeholder.dataset.type;
        const value = placeholder.dataset.value;
        const originalText = placeholder.textContent;

        // Only allow editing placeholders in user messages (not bot messages)
        if (!placeholder.closest('.message.user')) return;

        // For chat messages, we don't necessarily have "staged" images anymore as the message is already sent,
        // but we can show the images that were sent with this message if we want.
        // For now, openPlaceholderPopover will fallback to current staged image attachments which is fine for "editing before send" scenarios.
        openPlaceholderPopover(placeholder, type, value, (newValue) => {
          const newFull = type === 'brace' ? `{${newValue}}` : `[${newValue}]`;

          // Update the placeholder element directly
          placeholder.textContent = newFull;
          placeholder.dataset.value = newValue;

          // Find the parent message div and update its stored text
          const messageDiv = placeholder.closest('.message.user');
          if (messageDiv) {
            const userText = messageDiv.dataset.originalText || messageDiv.querySelector('.message-content').textContent;
            // Escape all regex special characters in the original text
            const escapedOriginal = originalText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            const regex = new RegExp(escapedOriginal, 'g');
            const updatedUserText = userText.replace(regex, newFull);

            // Update the stored text
            messageDiv.dataset.originalText = updatedUserText;

            // Also update the chat history
            const userMessageIndex = chatHistory.findIndex(msg => msg.role === 'user' && msg.parts[0].text === userText);
            if (userMessageIndex !== -1) {
              chatHistory[userMessageIndex].parts[0].text = updatedUserText;
            }
          }
        });
        return;
      }

      // Handle color preview click
      const colorPreview = e.target.closest('.color-preview-inline');
      if (colorPreview) {
        // Disable picker for bot messages as requested
        if (colorPreview.closest('.message.bot')) return;

        e.stopPropagation();
        const swatch = colorPreview.querySelector('.color-preview-swatch');
        if (!swatch) return;

        const color = swatch.dataset.color;

        // Create a hidden color input to trigger the picker
        const colorInput = document.createElement('input');
        colorInput.type = 'color';
        // Normalize 3-char hex to 6-char for input type="color"
        let normalizedColor = colorToHex(color);
        colorInput.value = normalizedColor.toUpperCase();

        colorInput.style.position = 'fixed';
        colorInput.style.top = '-9999px';
        colorInput.style.left = '-9999px';
        colorInput.style.opacity = '0';
        document.body.appendChild(colorInput);

        colorInput.addEventListener('change', () => {
          const newColor = colorInput.value.toUpperCase();
          swatch.style.backgroundColor = newColor;
          swatch.dataset.color = newColor;
          // Update the text node (it's the second child of colorPreview)
          const textNode = colorPreview.childNodes[1];
          if (textNode && textNode.nodeType === Node.TEXT_NODE) {
            textNode.textContent = newColor;
          }

          // Also update the parent message text if we're in a user message
          const messageDiv = colorPreview.closest('.message.user');
          if (messageDiv) {
            const userText = messageDiv.dataset.originalText || messageDiv.querySelector('.message-content').textContent;
            // Create a safe regex for the old color (could be name or hex)
            const isHex = color.startsWith('#');
            const escapedColor = color.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            const pattern = isHex ? escapedColor : `\\b${escapedColor}\\b`;
            const regex = new RegExp(pattern, 'gi');
            const updatedUserText = userText.replace(regex, newColor);

            // This is a bit tricky since disableEditMode is meant for the textarea,
            // but we can reuse the history update logic here if we wanted to sync.
            // For now, let's at least update the UI.
            messageDiv.dataset.originalText = updatedUserText;
          }

          if (colorInput.parentNode) document.body.removeChild(colorInput);
        });

        colorInput.addEventListener('blur', () => {
          setTimeout(() => {
            if (colorInput.parentNode) document.body.removeChild(colorInput);
          }, 100);
        });

        colorInput.click();
        return;
      }

      const actionBtn = e.target.closest('.message-action-btn');
      if (!actionBtn) return;

      const messageDiv = actionBtn.closest('.message');
      if (!messageDiv) return;

      // Handle edit button click
      if (actionBtn.classList.contains('edit-btn')) {
        e.stopPropagation();
        if (isAIThinking) {
          showToast('Please wait for the current response to finish', 'info');
          return;
        }
        enableEditMode(messageDiv);
        return;
      }

      // Handle resend button click
      if (actionBtn.classList.contains('resend-btn')) {
        e.stopPropagation();
        if (isAIThinking) {
          showToast('Please wait for the current response to finish', 'info');
          return;
        }
        resendMessage(messageDiv);
        return;
      }

      // Handle copy button click
      if (actionBtn.classList.contains('copy-btn')) {
        e.stopPropagation();

        // Get the text to copy
        let textToCopy = messageDiv.dataset.content || '';

        if (messageDiv.dataset.isQuickAction === 'true') {
          textToCopy = messageDiv.dataset.originalPrompt;
        } else if (messageDiv.classList.contains('bot')) {
          // For bot messages, we already have the raw content in dataset.content
          // which is better than textContent because it preserves markdown
        } else {
          // Fallback if needed, though we set dataset.content for all messages now
          const contentDiv = messageDiv.querySelector('.message-content');
          if (!textToCopy) textToCopy = contentDiv.textContent;
        }

        try {
          await navigator.clipboard.writeText(textToCopy);
          showToast('Message copied to clipboard', 'success');
        } catch (err) {
          // Fallback for older browsers
          const textArea = document.createElement('textarea');
          textArea.value = textToCopy;
          textArea.style.position = 'fixed';
          textArea.style.left = '-9999px';
          document.body.appendChild(textArea);
          textArea.select();
          try {
            document.execCommand('copy');
            showToast('Message copied to clipboard', 'success');
          } catch (e) {
            showToast('Failed to copy message', 'error');
          }
          document.body.removeChild(textArea);
        }
        return;
      }
    });

