    function updateCustomQuickActionPromptTextareaValue() {
      if (customQuickActionPrompt) {
        customQuickActionPrompt.value = serializeCustomQuickActionPromptEditor();
      }
    }

    function createCustomQuickActionPromptChip(input) {
      const chip = document.createElement('button');
      chip.type = 'button';
      chip.className = 'custom-quick-action-prompt-chip';
      chip.contentEditable = 'false';
      chip.dataset.tokenKey = input.key;
      chip.textContent = `{${input.key}}`;
      chip.addEventListener('click', (event) => {
        event.preventDefault();
        event.stopPropagation();
        openCustomQuickActionInsertMenu(chip, { type: 'replace-chip', chip, tokenKey: input.key });
      });
      return chip;
    }

    function appendPromptTemplateSegment(fragment, text, inputsByKey) {
      if (!text) return;
      const regex = /\{([a-zA-Z0-9_]+)\}/g;
      let lastIndex = 0;
      let match;
      while ((match = regex.exec(text)) !== null) {
        const before = text.slice(lastIndex, match.index);
        if (before) fragment.appendChild(document.createTextNode(before));
        const input = inputsByKey.get(match[1]);
        if (input) fragment.appendChild(createCustomQuickActionPromptChip(input));
        else fragment.appendChild(document.createTextNode(match[0]));
        lastIndex = regex.lastIndex;
      }
      const after = text.slice(lastIndex);
      if (after) fragment.appendChild(document.createTextNode(after));
    }

    function renderCustomQuickActionPromptEditor(template = '') {
      if (!customQuickActionPromptEditor) return;
      const fragment = document.createDocumentFragment();
      const inputsByKey = new Map(customQuickActionDraftInputs.map((input) => [input.key, input]));
      appendPromptTemplateSegment(fragment, template, inputsByKey);
      customQuickActionPromptEditor.innerHTML = '';
      customQuickActionPromptEditor.appendChild(fragment);
      updateCustomQuickActionPromptTextareaValue();
    }

    function serializeCustomQuickActionPromptEditor() {
      if (!customQuickActionPromptEditor) return '';
      const walk = (node) => {
        if (!node) return '';
        if (node.nodeType === Node.TEXT_NODE) return node.textContent || '';
        if (node.nodeType !== Node.ELEMENT_NODE) return '';
        if (node.dataset?.tokenKey) return `{${node.dataset.tokenKey}}`;
        if (node.tagName === 'DIV' || node.tagName === 'P') return `${Array.from(node.childNodes).map(walk).join('')}\n`;
        if (node.tagName === 'BR') return '\n';
        return Array.from(node.childNodes).map(walk).join('');
      };
      return Array.from(customQuickActionPromptEditor.childNodes).map(walk).join('').replace(/\u00a0/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
    }

    function saveCustomQuickActionSelectionRange() {
      if (!customQuickActionPromptEditor) return;
      const selection = window.getSelection();
      if (!selection || selection.rangeCount === 0) return;
      const range = selection.getRangeAt(0);
      if (!customQuickActionPromptEditor.contains(range.commonAncestorContainer)) return;
      customQuickActionPromptSelectionRange = range.cloneRange();
    }

    function placeCustomQuickActionCaretAtEnd() {
      if (!customQuickActionPromptEditor) return;
      const range = document.createRange();
      range.selectNodeContents(customQuickActionPromptEditor);
      range.collapse(false);
      const selection = window.getSelection();
      selection.removeAllRanges();
      selection.addRange(range);
      customQuickActionPromptSelectionRange = range.cloneRange();
    }

    function hideCustomQuickActionInsertMenu() {
      customQuickActionInsertMenu?.classList.add('hidden');
      customQuickActionInsertContext = null;
    }

    function renderCustomQuickActionInsertMenu() {
      if (!customQuickActionInsertMenu) return;
      const itemsHtml = customQuickActionDraftInputs.map((input) => `
        <button type="button" class="custom-quick-action-insert-menu-item" data-insert-input-id="${escapeHtml(input.id)}">
          <span class="custom-quick-action-insert-menu-item-title">{${escapeHtml(input.key)}}</span>
          <span class="custom-quick-action-insert-menu-item-meta">${escapeHtml(input.label)} • ${escapeHtml(tu(`actions.customQuickAction.input.type.${input.type}`))}</span>
        </button>
      `).join('');
      customQuickActionInsertMenu.innerHTML = `
        ${itemsHtml}
        <button type="button" class="custom-quick-action-insert-menu-item" data-insert-new-input="true">
          <span class="custom-quick-action-insert-menu-item-title">+ ${escapeHtml(tu('actions.customQuickAction.insertMenu.newInput'))}</span>
          <span class="custom-quick-action-insert-menu-item-meta">${escapeHtml(tu('actions.customQuickAction.insertMenu.newInputHint'))}</span>
        </button>
      `;
    }

    function openCustomQuickActionInsertMenu(anchorEl, context = { type: 'insert' }) {
      if (!customQuickActionInsertMenu) return;
      customQuickActionInsertContext = context;
      renderCustomQuickActionInsertMenu();
      customQuickActionInsertMenu.classList.remove('hidden');
      const rect = anchorEl?.getBoundingClientRect?.();
      const top = rect ? rect.bottom + 8 : 120;
      const left = rect ? Math.max(12, Math.min(rect.left, window.innerWidth - 320)) : 20;
      customQuickActionInsertMenu.style.top = `${top}px`;
      customQuickActionInsertMenu.style.left = `${left}px`;
    }

    function insertCustomQuickActionChip(input, context = customQuickActionInsertContext) {
      if (!customQuickActionPromptEditor || !input) return;
      const chip = createCustomQuickActionPromptChip(input);
      const insertContext = context || {};
      if (insertContext.type === 'replace-chip') {
        const targetChip = insertContext.chip?.parentNode
          ? insertContext.chip
          : (insertContext.tokenKey
            ? Array.from(customQuickActionPromptEditor.querySelectorAll('.custom-quick-action-prompt-chip')).find((node) => node.dataset.tokenKey === insertContext.tokenKey)
            : null);
        if (targetChip?.parentNode) {
          targetChip.replaceWith(chip);
        } else {
          customQuickActionPromptEditor.appendChild(chip);
          placeCustomQuickActionCaretAtEnd();
        }
      } else {
        const selection = window.getSelection();
        const range = customQuickActionPromptSelectionRange ? customQuickActionPromptSelectionRange.cloneRange() : null;
        if (range && customQuickActionPromptEditor.contains(range.commonAncestorContainer)) {
          range.deleteContents();
          range.insertNode(chip);
          range.setStartAfter(chip);
          range.collapse(true);
          selection.removeAllRanges();
          selection.addRange(range);
          customQuickActionPromptSelectionRange = range.cloneRange();
        } else {
          customQuickActionPromptEditor.appendChild(chip);
          placeCustomQuickActionCaretAtEnd();
        }
      }
      updateCustomQuickActionPromptTextareaValue();
      hideCustomQuickActionInsertMenu();
      customQuickActionPromptEditor.focus();
    }

    function renderCustomQuickActionInputsList() {
      if (!customQuickActionInputsList) return;
      if (!customQuickActionDraftInputs.length) {
        customQuickActionInputsList.innerHTML = `<div class="custom-quick-action-input-empty">${escapeHtml(tu('actions.customQuickAction.inputsEmpty'))}</div>`;
        return;
      }
      customQuickActionInputsList.innerHTML = customQuickActionDraftInputs.map((input) => {
        const optionCount = Array.isArray(input.options) ? input.options.length : 0;
        const meta = input.type === 'select'
          ? tu('actions.customQuickAction.input.card.selectMeta', {
            count: String(optionCount),
            suffix: optionCount === 1 ? '' : 's',
            customSuffix: input.allowCustomOption ? tu('actions.customQuickAction.input.card.customSuffix') : ''
          })
          : input.type === 'image'
            ? tu('actions.customQuickAction.input.card.imageMeta')
            : (input.placeholder || tu('actions.customQuickAction.input.card.textMeta'));
        const typeLabel = tu(`actions.customQuickAction.input.type.${input.type}`);
        const extraFlags = [
          input.multiple ? tu('actions.customQuickAction.input.card.multiple') : '',
          input.required ? tu('actions.customQuickAction.input.card.required') : ''
        ].filter(Boolean).join(' • ');
        const metaLine = [typeLabel, extraFlags, meta].filter(Boolean).join(' • ');
        return `
          <div class="custom-quick-action-input-card" data-custom-input-id="${escapeHtml(input.id)}">
            <div class="custom-quick-action-input-card-main">
              <div class="custom-quick-action-input-card-title">
                <span>${escapeHtml(input.label)}</span>
                <span class="custom-quick-action-input-card-key">{${escapeHtml(input.key)}}</span>
              </div>
              <div class="custom-quick-action-input-card-meta">${escapeHtml(metaLine)}</div>
            </div>
            <div class="custom-quick-action-input-card-actions">
              <button type="button" class="custom-quick-action-input-card-btn" data-custom-input-action="edit" data-custom-input-id="${escapeHtml(input.id)}" title="${escapeHtml(tu('actions.customQuickAction.input.editTitle'))}">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 1 1 3 3L7 19l-4 1 1-4 12.5-12.5Z"/></svg>
              </button>
              <button type="button" class="custom-quick-action-input-card-btn danger" data-custom-input-action="delete" data-custom-input-id="${escapeHtml(input.id)}" title="${escapeHtml(tu('actions.customQuickAction.input.deleteTitle'))}">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18"/><path d="M8 6V4a1 1 0 0 1 1-1h6a1 1 0 0 1 1 1v2"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/></svg>
              </button>
            </div>
          </div>
        `;
      }).join('');
    }

    function updateCustomQuickActionInputEditorVisibility() {
      const isSelect = customQuickActionInputType?.value === 'select';
      const isImage = customQuickActionInputType?.value === 'image';
      customQuickActionSelectOnlyFields?.classList.toggle('hidden', !isSelect);
      customQuickActionInputDefaultWrap?.classList.toggle('hidden', isImage);
      if (customQuickActionInputDefaultValue) {
        customQuickActionInputDefaultValue.placeholder = isSelect
          ? (customQuickActionInputMultiple?.checked
            ? tu('actions.customQuickAction.input.defaultValueMultiplePlaceholder')
            : tu('actions.customQuickAction.input.defaultValueSelectPlaceholder'))
          : tu('actions.customQuickAction.input.defaultValuePlaceholder');
      }
    }

    function closeCustomQuickActionInputEditor() {
      editingCustomQuickActionInputId = null;
      pendingInsertAfterInputSave = false;
      pendingInsertContextAfterInputSave = null;
      customQuickActionInputEditor?.classList.add('hidden');
    }

    function openCustomQuickActionInputEditor(input = null, options = {}) {
      editingCustomQuickActionInputId = input?.id || null;
      pendingInsertAfterInputSave = options.insertAfterSave === true;
      pendingInsertContextAfterInputSave = options.insertContext || null;
      if (customQuickActionInputEditorTitle) {
        customQuickActionInputEditorTitle.textContent = input
          ? tu('actions.customQuickAction.inputEditor.editTitle')
          : tu('actions.customQuickAction.inputEditor.addTitle');
      }
      if (customQuickActionInputLabel) customQuickActionInputLabel.value = input?.label || '';
      if (customQuickActionInputKey) {
        customQuickActionInputKey.value = input?.key || generateCustomQuickActionInputKey('', customQuickActionDraftInputs, customQuickActionDraftInputs.length + 1);
      }
      if (customQuickActionInputType) customQuickActionInputType.value = input?.type || 'text';
      if (customQuickActionInputPlaceholder) customQuickActionInputPlaceholder.value = input?.placeholder || '';
      if (customQuickActionInputRequired) customQuickActionInputRequired.checked = input?.required === true;
      if (customQuickActionInputMultiple) customQuickActionInputMultiple.checked = input?.multiple === true;
      if (customQuickActionInputAllowCustomOption) customQuickActionInputAllowCustomOption.checked = input?.allowCustomOption === true;
      if (customQuickActionInputOptions) {
        customQuickActionInputOptions.value = Array.isArray(input?.options)
          ? input.options.map((option) => option.label === option.value ? option.label : `${option.label}|${option.value}`).join('\n')
          : '';
      }
      if (customQuickActionInputDefaultValue) {
        customQuickActionInputDefaultValue.value = Array.isArray(input?.defaultValue)
          ? input.defaultValue.join('\n')
          : (input?.defaultValue || '');
      }
      customQuickActionInputEditor?.classList.remove('hidden');
      updateCustomQuickActionInputEditorVisibility();
      customQuickActionInputLabel?.focus();
    }

    function parseCustomQuickActionInputOptionsFromTextarea(text) {
      return String(text || '').split('\n').map((line) => line.trim()).filter(Boolean).map((line) => {
        const [labelPart, valuePart] = line.includes('|') ? line.split('|') : [line, line];
        const label = String(labelPart || '').trim();
        const value = String(valuePart || '').trim();
        if (!label || !value) return null;
        return { id: generateCustomQuickActionInputOptionId(), label, value };
      }).filter(Boolean);
    }

    function saveCustomQuickActionInputFromEditor() {
      const label = customQuickActionInputLabel?.value.trim() || '';
      const type = customQuickActionInputType?.value || 'text';
      const key = sanitizeCustomQuickActionInputKey(customQuickActionInputKey?.value || '')
        || generateCustomQuickActionInputKey(label, customQuickActionDraftInputs, customQuickActionDraftInputs.length + 1);
      const previousInput = editingCustomQuickActionInputId
        ? customQuickActionDraftInputs.find((input) => input.id === editingCustomQuickActionInputId)
        : null;
      if (!label) {
        showToast(tu('actions.customQuickAction.validation.inputLabelRequired'), 'error');
        return null;
      }
      const keyTaken = customQuickActionDraftInputs.some((input) => input.id !== editingCustomQuickActionInputId && input.key.toLowerCase() === key.toLowerCase());
      if (keyTaken) {
        showToast(tu('actions.customQuickAction.validation.inputKeyUnique'), 'error');
        return null;
      }
      const nextInput = {
        id: editingCustomQuickActionInputId || generateCustomQuickActionInputId(),
        key,
        label,
        type,
        required: customQuickActionInputRequired?.checked === true,
        multiple: type === 'select' ? customQuickActionInputMultiple?.checked === true : false,
        options: type === 'select' ? parseCustomQuickActionInputOptionsFromTextarea(customQuickActionInputOptions?.value || '') : [],
        allowCustomOption: type === 'select' ? customQuickActionInputAllowCustomOption?.checked === true : false,
        placeholder: customQuickActionInputPlaceholder?.value.trim() || '',
        defaultValue: null,
      };
      if (type === 'select' && nextInput.options.length === 0) {
        showToast(tu('actions.customQuickAction.validation.inputOptionsRequired'), 'error');
        return null;
      }
      if (type === 'select') {
        nextInput.defaultValue = nextInput.multiple
          ? String(customQuickActionInputDefaultValue?.value || '').split('\n').map((entry) => entry.trim()).filter(Boolean)
          : (customQuickActionInputDefaultValue?.value.trim() || '');
      } else if (type !== 'image') {
        nextInput.defaultValue = customQuickActionInputDefaultValue?.value || '';
      }
      const shouldInsertAfterSave = pendingInsertAfterInputSave === true;
      const insertContextAfterSave = pendingInsertContextAfterInputSave;
      let currentTemplate = serializeCustomQuickActionPromptEditor();
      if (previousInput?.key && previousInput.key !== nextInput.key) {
        const tokenRegex = new RegExp(`\\{${previousInput.key}\\}`, 'g');
        currentTemplate = currentTemplate.replace(tokenRegex, `{${nextInput.key}}`);
      }
      const existingIndex = customQuickActionDraftInputs.findIndex((input) => input.id === nextInput.id);
      if (existingIndex >= 0) customQuickActionDraftInputs[existingIndex] = nextInput;
      else customQuickActionDraftInputs.push(nextInput);
      customQuickActionDraftInputs = sanitizeCustomQuickActionInputs(customQuickActionDraftInputs);
      renderCustomQuickActionInputsList();
      renderCustomQuickActionPromptEditor(currentTemplate);
      closeCustomQuickActionInputEditor();
      return { input: nextInput, shouldInsertAfterSave, insertContextAfterSave };
    }

    function deleteCustomQuickActionInput(inputId) {
      customQuickActionDraftInputs = customQuickActionDraftInputs.filter((input) => input.id !== inputId);
      renderCustomQuickActionInputsList();
      renderCustomQuickActionPromptEditor(serializeCustomQuickActionPromptEditor());
      hideCustomQuickActionInsertMenu();
    }

    function normalizeCustomQuickActionFieldValues(action, rawValues = {}) {
      if (!action?.customQuickActionInputs?.length) return { values: rawValues, imageDataUrls: [] };
      const nextValues = { ...rawValues };
      const imageDataUrls = [];
      const initialImageOffset = Array.isArray(rawValues.imageInput) ? rawValues.imageInput.length : 0;
      action.customQuickActionInputs.forEach((input) => {
        if (!input?.key) return;
        if (input.type === 'select') {
          const customKey = `${input.key}__custom`;
          const customValue = String(nextValues[customKey] || '').trim();
          if (input.multiple) {
            const selectedValues = Array.isArray(nextValues[input.key]) ? nextValues[input.key].filter(Boolean) : [];
            const normalizedValues = selectedValues.filter((value) => value !== '__custom__');
            if (selectedValues.includes('__custom__') && customValue) normalizedValues.push(customValue);
            nextValues[input.key] = normalizedValues.join(', ');
          } else if (nextValues[input.key] === '__custom__') {
            nextValues[input.key] = customValue;
          }
        } else if (input.type === 'image') {
          const images = Array.isArray(nextValues[input.key]) ? nextValues[input.key] : [];
          const refs = [];
          images.forEach((image) => {
            if (!image?.data) return;
            imageDataUrls.push(image.data);
            refs.push(`@Image ${initialImageOffset + imageDataUrls.length}`);
          });
          nextValues[input.key] = refs.join(', ');
        }
      });
      return { values: nextValues, imageDataUrls };
    }

    function validateCustomQuickActionRequiredInputs(action, values = {}) {
      if (!action?.customQuickActionInputs?.length) return true;
      for (const input of action.customQuickActionInputs) {
        if (!input.required) continue;
        const value = values[input.key];
        const customValue = String(values[`${input.key}__custom`] || '').trim();
        if (input.type === 'image') {
          if (!Array.isArray(value) || value.length === 0) {
            showToast(`"${input.label}" is required.`, 'error');
            return false;
          }
        } else if (input.type === 'select' && input.multiple) {
          const selectedValues = Array.isArray(value) ? value.filter(Boolean) : [];
          const onlyCustomMarker = selectedValues.length === 1 && selectedValues[0] === '__custom__';
          if (selectedValues.length === 0 || (onlyCustomMarker && !customValue)) {
            showToast(`"${input.label}" is required.`, 'error');
            return false;
          }
        } else if (input.type === 'select') {
          if (!String(value || '').trim() || (value === '__custom__' && !customValue)) {
            showToast(`"${input.label}" is required.`, 'error');
            return false;
          }
        } else if (!String(value || '').trim()) {
          showToast(`"${input.label}" is required.`, 'error');
          return false;
        }
      }
      return true;
    }

    function generateCustomQuickActionId() {
      return `qa_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    }

    function persistCustomQuickActions() {
      parent.postMessage({
        pluginMessage: {
          type: 'save-custom-quick-actions',
          customQuickActions
        }
      }, '*');
    }

    function getUniqueCustomQuickActionName(baseName, excludeId = null) {
      const fallbackName = tu('actions.customQuickAction.defaultName');
      const candidateBase = (baseName || fallbackName).trim() || fallbackName;
      const isTaken = (candidate) => {
        if (builtInQuickActionNames.has(candidate)) return true;
        return customQuickActions.some((action) =>
          action.id !== excludeId && action.name.toLowerCase() === candidate.toLowerCase()
        );
      };

      if (!isTaken(candidateBase)) return candidateBase;

      let counter = 2;
      let nextCandidate = `${candidateBase} ${counter}`;
      while (isTaken(nextCandidate)) {
        counter += 1;
        nextCandidate = `${candidateBase} ${counter}`;
      }
      return nextCandidate;
    }

    function populateCustomQuickActionCategoryOptions(selectedValue) {
      if (!customQuickActionCategory) return;
      customQuickActionCategory.innerHTML = BUILT_IN_COMMAND_CATEGORIES.map((category) => `
        <option value="${escapeHtml(category)}"${category === selectedValue ? ' selected' : ''}>${escapeHtml(localizeActionString(category))}</option>
      `).join('');
    }

    function getCustomQuickActionContextValue() {
      return VALID_CUSTOM_QUICK_ACTION_CONTEXTS.has(customQuickActionContext?.dataset.value)
        ? customQuickActionContext.dataset.value
        : ContextMode.SMART;
    }

    function closeCustomQuickActionContextMenu() {
      customQuickActionContext?.classList.remove('open');
      customQuickActionContextTrigger?.setAttribute('aria-expanded', 'false');
    }

    function setCustomQuickActionContextValue(value) {
      const selected = customQuickActionContextOptions.find((option) => option.value === value)
        || customQuickActionContextOptions[0];
      if (!customQuickActionContext || !customQuickActionContextTrigger || !customQuickActionContextMenu) return;
      customQuickActionContext.dataset.value = selected.value;
      customQuickActionContextTrigger.setAttribute('aria-expanded', 'false');
      customQuickActionContextTrigger.querySelector('.custom-quick-action-context-trigger-label').textContent = tu(selected.labelKey);
      customQuickActionContextMenu.innerHTML = customQuickActionContextOptions.map((option) => `
        <button
          type="button"
          class="custom-quick-action-context-option${option.value === selected.value ? ' is-selected' : ''}"
          data-context-value="${escapeHtml(option.value)}"
          role="option"
          aria-selected="${option.value === selected.value ? 'true' : 'false'}"
        >
          <span class="custom-quick-action-context-option-title">${escapeHtml(tu(option.labelKey))}</span>
          <span class="custom-quick-action-context-option-desc">${escapeHtml(tu(option.descriptionKey))}</span>
        </button>
      `).join('');
    }

    function closeCommandItemPopover() {
      openCustomActionPopoverId = null;
      document.querySelectorAll('.command-item-custom-actions.is-open').forEach((node) => {
        node.classList.remove('is-open');
      });
      nodeActionsContent?.classList.remove('has-open-custom-menu');
      document.querySelectorAll('[data-custom-popover-trigger][aria-expanded="true"]').forEach((node) => {
        node.setAttribute('aria-expanded', 'false');
      });
    }

    function closeCustomQuickActionModal() {
      if (!customQuickActionModal) return;
      customQuickActionModal.classList.remove('show');
      closeCustomQuickActionContextMenu();
      closeCustomQuickActionInputEditor();
      hideCustomQuickActionInsertMenu();
      customQuickActionDraftInputs = [];
      customQuickActionPromptSelectionRange = null;
      editingCustomQuickActionId = null;
    }

    function openCustomQuickActionModal(action = null, options = {}) {
      const duplicate = options.duplicate === true;
      const isEdit = !!action && !duplicate;
      const title = duplicate
        ? tu('actions.customQuickAction.modal.duplicateTitle')
        : isEdit
          ? tu('actions.customQuickAction.modal.editTitle')
          : tu('actions.customQuickAction.modal.addTitle');
      const defaultCategory = BUILT_IN_COMMAND_CATEGORIES.includes(selectedCategory)
        ? selectedCategory
        : BUILT_IN_COMMAND_CATEGORIES[0];
      const nextName = action
        ? (duplicate ? getUniqueCustomQuickActionName(action.name) : action.name)
        : '';

      editingCustomQuickActionId = isEdit ? action.id : null;
      customQuickActionDraftInputs = sanitizeCustomQuickActionInputs(action?.inputs || []);
      if (customQuickActionModalTitle) customQuickActionModalTitle.textContent = title;
      if (saveCustomQuickActionBtn) saveCustomQuickActionBtn.textContent = isEdit
        ? tu('actions.customQuickAction.update')
        : tu('actions.customQuickAction.save');
      if (customQuickActionName) customQuickActionName.value = nextName;
      if (customQuickActionMode) customQuickActionMode.value = action?.mode === 'ask' ? 'ask' : 'agent';
      if (customQuickActionDescription) customQuickActionDescription.value = action?.desc || '';
      renderCustomQuickActionInputsList();
      renderCustomQuickActionPromptEditor(action?.promptTemplate || '');
      closeCustomQuickActionInputEditor();
      hideCustomQuickActionInsertMenu();
      setCustomQuickActionContextValue(
        VALID_CUSTOM_QUICK_ACTION_CONTEXTS.has(action?.requiredContext) ? action.requiredContext : ContextMode.SMART
      );
      if (customQuickActionNoSelection) customQuickActionNoSelection.checked = action?.noSelection === true;
      if (customQuickActionIncludeTokens) customQuickActionIncludeTokens.checked = action?.includeTokens === true;
      populateCustomQuickActionCategoryOptions(action?.category || defaultCategory);
      customQuickActionModal.classList.add('show');
      customQuickActionPromptSelectionRange = null;
      customQuickActionName?.focus();
      customQuickActionName?.select();
    }

    function updateQuickActionUsageName(oldName, newName) {
      if (!oldName || !newName || oldName === newName) return;

      const existingCount = quickActionUsage[oldName] || 0;
      if (existingCount > 0) {
        quickActionUsage[newName] = (quickActionUsage[newName] || 0) + existingCount;
        delete quickActionUsage[oldName];
      }

      const updatedLastUsed = [];
      const seen = new Set();
      lastUsedQuickActions.forEach((name) => {
        const nextName = name === oldName ? newName : name;
        if (nextName && !seen.has(nextName)) {
          updatedLastUsed.push(nextName);
          seen.add(nextName);
        }
      });
      lastUsedQuickActions = updatedLastUsed.slice(0, MAX_LAST_USED_ACTIONS);
      saveQuickActionUsage();
    }

    function removeQuickActionUsageName(name) {
      if (!name) return;
      delete quickActionUsage[name];
      lastUsedQuickActions = lastUsedQuickActions.filter((entry) => entry !== name);
      saveQuickActionUsage();
    }

    function handleSaveCustomQuickAction() {
      const name = customQuickActionName?.value.trim() || '';
      const category = customQuickActionCategory?.value || '';
      const mode = customQuickActionMode?.value === 'ask' ? 'ask' : 'agent';
      const desc = customQuickActionDescription?.value.trim() || '';
      const promptTemplate = serializeCustomQuickActionPromptEditor();
      const requiredContext = getCustomQuickActionContextValue();

      if (!name) {
        showToast(tu('actions.customQuickAction.validation.nameRequired'), 'error');
        return;
      }

      if (!promptTemplate) {
        showToast(tu('actions.customQuickAction.validation.promptRequired'), 'error');
        return;
      }

      if (!BUILT_IN_COMMAND_CATEGORIES.includes(category)) {
        showToast(tu('actions.customQuickAction.validation.categoryInvalid'), 'error');
        return;
      }

      const duplicateName = builtInQuickActionNames.has(name) || customQuickActions.some((action) =>
        action.id !== editingCustomQuickActionId && action.name.toLowerCase() === name.toLowerCase()
      );
      if (duplicateName) {
        showToast(tu('actions.customQuickAction.validation.nameExists'), 'error');
        return;
      }

      const existing = editingCustomQuickActionId
        ? customQuickActions.find((action) => action.id === editingCustomQuickActionId)
        : null;
      const nextAction = {
        id: existing?.id || generateCustomQuickActionId(),
        name,
        category,
        mode,
        promptTemplate,
        inputs: sanitizeCustomQuickActionInputs(customQuickActionDraftInputs),
        desc,
        noSelection: customQuickActionNoSelection?.checked === true,
        includeTokens: customQuickActionIncludeTokens?.checked === true,
        requiredContext,
        createdAt: existing?.createdAt || Date.now(),
        updatedAt: Date.now(),
      };

      if (existing) {
        const actionIndex = customQuickActions.findIndex((action) => action.id === existing.id);
        if (actionIndex !== -1) {
          customQuickActions[actionIndex] = nextAction;
        }
        updateQuickActionUsageName(existing.name, nextAction.name);
      } else {
        customQuickActions.unshift(nextAction);
      }

      customQuickActions = sanitizeCustomQuickActions(customQuickActions);
      persistCustomQuickActions();
      rebuildAgentTasks(true);
      closeCustomQuickActionModal();
    }

    function duplicateCustomQuickAction(actionId) {
      const action = customQuickActions.find((entry) => entry.id === actionId);
      if (!action) return;
      openCustomQuickActionModal(action, { duplicate: true });
    }

    function editCustomQuickAction(actionId) {
      const action = customQuickActions.find((entry) => entry.id === actionId);
      if (!action) return;
      openCustomQuickActionModal(action);
    }

    function deleteCustomQuickAction(actionId) {
      const action = customQuickActions.find((entry) => entry.id === actionId);
      if (!action) return;
      customQuickActions = customQuickActions.filter((entry) => entry.id !== actionId);
      removeQuickActionUsageName(action.name);
      customQuickActions = sanitizeCustomQuickActions(customQuickActions);
      persistCustomQuickActions();
      rebuildAgentTasks(true);
      showToast(`Deleted "${action.name}".`, 'success');
    }

    function getDrawerFieldTypedText(fieldKey) {
      if (!promptDrawerFields || !fieldKey) return '';
      const fieldEl = promptDrawerFields.querySelector(`[data-field-key="${fieldKey}"]`);
      if (!fieldEl) return '';

      if (fieldEl.matches('input, textarea')) {
        return (fieldEl.value || '').trim();
      }

      // Custom select: prefer actively typed search text, fallback to selected value.
      if (fieldEl.classList.contains('prompt-custom-select')) {
        const searchInput = fieldEl.querySelector('.prompt-select-search input[data-select-search="true"]');
        const typed = (searchInput?.value || '').trim();
        if (typed) return typed;
        return (fieldEl.dataset.selected || '').trim();
      }

      return '';
    }

    function prefillAddOptionModalFromPromptDrawer(fieldKey, isEdit) {
      if (isEdit || !promptDrawerFields) return;
      const values = typeof getPromptFieldValues === 'function' ? getPromptFieldValues() : {};

      if (fieldKey === 'tone') {
        const toneText = (values.customTone || '').toString().trim();
        if (customToneValue && toneText) customToneValue.value = toneText;
        if (customToneName && !customToneName.value) {
          customToneName.value = getDrawerFieldTypedText('tone') || toneText;
        }
        return;
      }

      if (fieldKey === 'imagePreset' || fieldKey === 'reStylePreset' || fieldKey === 'renamePreset') {
        const typedPresetName = getDrawerFieldTypedText(fieldKey);
        if (customPresetName && typedPresetName) customPresetName.value = typedPresetName;
        if (customPresetStyle) {
          customPresetStyle.value = fieldKey === 'renamePreset'
            ? (values.renamePrompt || '').toString()
            : (values.imageStyle || '').toString();
        }
        if (fieldKey === 'imagePreset' && customPresetSubject) {
          customPresetSubject.value = (values.imageSubject || '').toString();
        }
        return;
      }

      if (fieldKey === 'styleCategory') {
        const typedStyleName = getDrawerFieldTypedText('styleCategory');
        if (customStyleName && typedStyleName) customStyleName.value = typedStyleName;
      }
    }

    function openAddOptionModal(fieldKey, editData = null) {
      currentAddingFor = fieldKey;
      editingOptionOriginalId = editData ? editData.id : null;
      editingOptionOriginalValue = editData ? editData.value : null;

      const isEdit = !!editData;
      const titleKey = fieldKey === 'tone'
        ? (isEdit ? 'actions.modal.editCustomTone' : 'actions.modal.addCustomTone')
        : (fieldKey === 'styleCategory'
          ? (isEdit ? 'actions.modal.editDesignStyle' : 'actions.modal.addDesignStyle')
          : (fieldKey === 'imagePreset'
            ? (isEdit ? 'actions.modal.editStylePreset' : 'actions.modal.addStylePreset')
            : (fieldKey === 'renamePreset'
              ? (isEdit ? 'actions.modal.editRenamePromptPreset' : 'actions.modal.addRenamePromptPreset')
              : (isEdit ? 'actions.modal.editReStylePreset' : 'actions.modal.addReStylePreset'))));
      addOptionModalTitle.textContent = tu(titleKey);
      btnConfirmAddOption.textContent = tu(isEdit ? 'actions.modal.updateOptionButton' : 'actions.modal.addOptionButton');

      // Reset all fields
      if (customToneName) customToneName.value = editData && fieldKey === 'tone' ? editData.label : '';
      if (customToneValue) customToneValue.value = editData && fieldKey === 'tone' ? editData.value : '';
      if (customPresetName) customPresetName.value = editData && (fieldKey === 'imagePreset' || fieldKey === 'reStylePreset' || fieldKey === 'renamePreset') ? editData.label : '';
      if (customPresetSubject) customPresetSubject.value = editData && fieldKey === 'imagePreset' ? editData.subject : '';
      if (customPresetStyle) customPresetStyle.value = editData && (fieldKey === 'imagePreset' || fieldKey === 'reStylePreset' || fieldKey === 'renamePreset') ? editData.style : '';
      if (customPresetThumbnail) customPresetThumbnail.value = editData && (fieldKey === 'imagePreset' || fieldKey === 'reStylePreset') ? (editData.thumbnail || '') : '';
      if (customStyleName) customStyleName.value = editData && fieldKey === 'styleCategory' ? (editData.name || editData.label) : '';
      if (customStyleKeywords) customStyleKeywords.value = editData && fieldKey === 'styleCategory' ? (editData.keywords || '') : '';
      if (customStylePrimaryColors) customStylePrimaryColors.value = editData && fieldKey === 'styleCategory' ? (editData.primaryColors || '') : '';
      if (customStyleSecondaryColors) customStyleSecondaryColors.value = editData && fieldKey === 'styleCategory' ? (editData.secondaryColors || '') : '';
      if (customStyleEffects) customStyleEffects.value = editData && fieldKey === 'styleCategory' ? (editData.effects || '') : '';

      // Show/hide appropriate fields
      if (toneOnlyFields) toneOnlyFields.style.display = fieldKey === 'tone' ? 'block' : 'none';
      if (imagePresetOnlyFields) {
        imagePresetOnlyFields.style.display = (fieldKey === 'imagePreset' || fieldKey === 'reStylePreset' || fieldKey === 'renamePreset') ? 'block' : 'none';
        const subjectField = customPresetSubject.closest('.setting-item');
        const thumbnailField = customPresetThumbnail.closest('.setting-item');
        if (subjectField) subjectField.style.display = fieldKey === 'imagePreset' ? 'block' : 'none';
        if (thumbnailField) thumbnailField.style.display = fieldKey === 'renamePreset' ? 'none' : 'block';
      }
      if (styleCategoryOnlyFields) styleCategoryOnlyFields.style.display = fieldKey === 'styleCategory' ? 'block' : 'none';

      // Widen modal for style category (6 fields)
      const modalContent = addOptionModal.querySelector('.add-option-modal-content');
      if (modalContent) modalContent.style.maxWidth = fieldKey === 'styleCategory' ? '420px' : '360px';

      // For add flow, pre-fill with current prompt drawer text to reduce re-typing.
      prefillAddOptionModalFromPromptDrawer(fieldKey, isEdit);

      addOptionModal.classList.add('show');
    }

    function closeAddOptionModal() {
      addOptionModal.classList.remove('show');
      currentAddingFor = null;
      editingOptionOriginalValue = null;
    }

    async function handleAddOptionSubmit() {
      const fieldKeyForSelect = currentAddingFor;
      const isEdit = !!editingOptionOriginalValue;

      if (currentAddingFor === 'tone') {
        const name = customToneName.value.trim();
        const value = customToneValue.value.trim();

        if (!name || !value) {
          showToast(tu('actions.validation.toneRequired'), 'error');
          return;
        }

        // Check for duplicates (excluding the one we're editing)
        if (customTones.some(t => t.value === value && t.value !== editingOptionOriginalValue)) {
          showToast(tu('actions.validation.toneExists'), 'error');
          return;
        }

        const newTone = {
          id: `tone_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          label: name,
          value: value,
          isCustom: true
        };

        if (isEdit) {
          const index = customTones.findIndex(t => t.id === editingOptionOriginalId || t.value === editingOptionOriginalValue);
          if (index !== -1) {
            newTone.id = customTones[index].id || newTone.id; // Keep same ID if possible
            customTones[index] = newTone;
          }
        } else {
          customTones.unshift(newTone);
        }
        saveCustomOptions('tone', customTones);

        // Preserve current values and set the new tone as selected
        const currentValues = getPromptFieldValues();
        currentValues.tone = value;

        closeAddOptionModal();

        // Re-render drawer to show new option with it selected
        if (currentPromptAction) {
          renderPromptFields(currentPromptAction.fields, currentValues);
        }

      } else if (currentAddingFor === 'imagePreset' || currentAddingFor === 'reStylePreset' || currentAddingFor === 'renamePreset') {
        const name = customPresetName.value.trim();
        const subject = customPresetSubject.value.trim();
        const style = customPresetStyle.value.trim();
        const thumbnail = customPresetThumbnail.value.trim();

        if (!name) {
          showToast(tu('actions.validation.presetNameRequired'), 'error');
          return;
        }

        if (currentAddingFor === 'imagePreset' && !subject && !style) {
          showToast(tu('actions.validation.presetNeedsSubjectOrStyle'), 'error');
          return;
        }

        if ((currentAddingFor === 'reStylePreset' || currentAddingFor === 'renamePreset') && !style) {
          showToast(tu('actions.validation.presetStyleRequired'), 'error');
          return;
        }

        const targetList = currentAddingFor === 'imagePreset'
          ? customImagePresets
          : (currentAddingFor === 'reStylePreset' ? customReStylePresets : customSmartRenamePresets);

        // Check for duplicates (excluding the one we're editing)
        if (targetList.some(p => p.value === name && (editingOptionOriginalId ? p.id !== editingOptionOriginalId : p.value !== editingOptionOriginalValue))) {
          showToast(tu('actions.validation.presetExists'), 'error');
          return;
        }

        const newPreset = {
          id: `${currentAddingFor === 'imagePreset' ? 'img' : (currentAddingFor === 'reStylePreset' ? 'rst' : 'rnp')}_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          label: name,
          value: name,
          subject: currentAddingFor === 'imagePreset' ? subject : '',
          style: style,
          isCustom: true
        };

        if (thumbnail) {
          newPreset.thumbnail = thumbnail;
        }

        if (isEdit) {
          const index = targetList.findIndex(p => p.id === editingOptionOriginalId || p.value === editingOptionOriginalValue);
          if (index !== -1) {
            newPreset.id = targetList[index].id || newPreset.id; // Keep same ID if possible
            targetList[index] = newPreset;
          }
        } else {
          targetList.unshift(newPreset);
        }
        saveCustomOptions(currentAddingFor, targetList);

        // Preserve current values and set the new preset as selected
        const currentValues = getPromptFieldValues();
        currentValues[currentAddingFor] = name;
        // Also populate the linked prompt fields
        if (currentAddingFor === 'imagePreset') {
          currentValues.imageSubject = subject;
          currentValues.imageStyle = style;
        } else if (currentAddingFor === 'reStylePreset') {
          currentValues.imageStyle = style;
        } else if (currentAddingFor === 'renamePreset') {
          currentValues.renamePrompt = style;
        }

        closeAddOptionModal();

        // Re-render drawer to show new option with it selected
        if (currentPromptAction) {
          renderPromptFields(currentPromptAction.fields, currentValues);
          // Apply the preset to populate the textareas
          if (currentAddingFor === 'imagePreset') {
            setTimeout(() => {
              applyImageGenPreset(name);
            }, 50);
          } else if (currentAddingFor === 'reStylePreset') {
            setTimeout(() => {
              applyReStylePreset(name);
            }, 50);
          } else if (currentAddingFor === 'renamePreset') {
            setTimeout(() => {
              applySmartRenamePreset(name);
            }, 50);
          }
        }
      } else if (currentAddingFor === 'styleCategory') {
        const name = customStyleName.value.trim();
        const keywords = customStyleKeywords.value.trim();
        const primaryColors = customStylePrimaryColors.value.trim();
        const secondaryColors = customStyleSecondaryColors.value.trim();
        const effects = customStyleEffects.value.trim();

        if (!name) {
          showToast(tu('actions.validation.styleNameRequired'), 'error');
          return;
        }

        if (customStyleCategories.some(s => s.name === name && (editingOptionOriginalId ? s.id !== editingOptionOriginalId : s.name !== editingOptionOriginalValue))) {
          showToast(tu('actions.validation.styleExists'), 'error');
          return;
        }

        const newStyle = {
          id: `style_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          name: name,
          keywords: keywords,
          primaryColors: primaryColors,
          secondaryColors: secondaryColors,
          effects: effects,
          isCustom: true
        };

        if (isEdit) {
          const index = customStyleCategories.findIndex(s => s.id === editingOptionOriginalId || s.name === editingOptionOriginalValue);
          if (index !== -1) {
            newStyle.id = customStyleCategories[index].id || newStyle.id;
            customStyleCategories[index] = newStyle;
          }
        } else {
          customStyleCategories.unshift(newStyle);
        }
        saveCustomOptions('styleCategory', customStyleCategories);

        const currentValues = getPromptFieldValues();
        currentValues.styleCategory = name;

        closeAddOptionModal();

        if (currentPromptAction) {
          renderPromptFields(currentPromptAction.fields, currentValues);
        }
      }
    }

    // Context Menu Management
    const optionContextMenu = document.getElementById('optionContextMenu');
    const ctxEditOption = document.getElementById('ctxEditOption');
    const ctxDuplicateOption = document.getElementById('ctxDuplicateOption');
    const ctxRemoveOption = document.getElementById('ctxRemoveOption');

    let menuActiveFieldKey = null;
    let menuActiveOptionValue = null;
    let menuActiveOptionId = null;

    function showOptionContextMenu(e, fieldKey, optionValue, optionId) {
      e.preventDefault();
      e.stopPropagation();

      menuActiveFieldKey = fieldKey;
      menuActiveOptionValue = optionValue;
      menuActiveOptionId = optionId;

      const x = e.clientX;
      const y = e.clientY;

      optionContextMenu.style.left = `${x}px`;
      optionContextMenu.style.top = `${y}px`;
      optionContextMenu.classList.add('show');

      // Handle boundary
      const rect = optionContextMenu.getBoundingClientRect();
      if (rect.right > window.innerWidth) {
        optionContextMenu.style.left = `${window.innerWidth - rect.width - 10}px`;
      }
      if (rect.bottom > window.innerHeight) {
        optionContextMenu.style.top = `${window.innerHeight - rect.height - 10}px`;
      }
    }

    function hideOptionContextMenu() {
      optionContextMenu.classList.remove('show');
    }

    window.addEventListener('click', () => {
      hideOptionContextMenu();
      hideSplitPatternMenu();
    });
    window.addEventListener('resize', () => {
      hideOptionContextMenu();
      hideSplitPatternMenu();
    });

    ctxEditOption.onclick = (e) => {
      e.stopPropagation();
      hideOptionContextMenu();

      let optionData = null;
      if (menuActiveFieldKey === 'tone') {
        optionData = customTones.find(t => t.id === menuActiveOptionId || (menuActiveOptionValue && t.value === menuActiveOptionValue));
      } else if (menuActiveFieldKey === 'imagePreset') {
        optionData = customImagePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
      } else if (menuActiveFieldKey === 'reStylePreset') {
        optionData = customReStylePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
      } else if (menuActiveFieldKey === 'renamePreset') {
        optionData = customSmartRenamePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
      } else if (menuActiveFieldKey === 'styleCategory') {
        optionData = customStyleCategories.find(s => s.id === menuActiveOptionId || (menuActiveOptionValue && (s.name === menuActiveOptionValue || s.value === menuActiveOptionValue)));
        if (optionData && !optionData.value) optionData = { ...optionData, value: optionData.name };
      }

      if (optionData) {
        openAddOptionModal(menuActiveFieldKey, optionData);
      }
    };

    ctxDuplicateOption.onclick = (e) => {
      e.stopPropagation();
      hideOptionContextMenu();

      let optionData = null;
      if (menuActiveFieldKey === 'tone') {
        optionData = customTones.find(t => t.id === menuActiveOptionId || (menuActiveOptionValue && t.value === menuActiveOptionValue));
        if (optionData) {
          const newOption = {
            ...optionData,
            id: `tone_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            label: tu('actions.option.copyName', { name: optionData.label })
          };
          customTones.unshift(newOption);
          saveCustomOptions('tone', customTones);
        }
      } else if (menuActiveFieldKey === 'imagePreset') {
        optionData = customImagePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
        if (optionData) {
          const newOption = {
            ...optionData,
            id: `img_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            label: tu('actions.option.copyName', { name: optionData.label })
          };
          customImagePresets.unshift(newOption);
          saveCustomOptions('imagePreset', customImagePresets);
        }
      } else if (menuActiveFieldKey === 'reStylePreset') {
        optionData = customReStylePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
        if (optionData) {
          const newOption = {
            ...optionData,
            id: `rst_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            label: tu('actions.option.copyName', { name: optionData.label })
          };
          customReStylePresets.unshift(newOption);
          saveCustomOptions('reStylePreset', customReStylePresets);
        }
      } else if (menuActiveFieldKey === 'renamePreset') {
        optionData = customSmartRenamePresets.find(p => p.id === menuActiveOptionId || (menuActiveOptionValue && p.value === menuActiveOptionValue));
        if (optionData) {
          const newOption = {
            ...optionData,
            id: `rnp_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            label: tu('actions.option.copyName', { name: optionData.label })
          };
          customSmartRenamePresets.unshift(newOption);
          saveCustomOptions('renamePreset', customSmartRenamePresets);
        }
      } else if (menuActiveFieldKey === 'styleCategory') {
        optionData = customStyleCategories.find(s => s.id === menuActiveOptionId || (menuActiveOptionValue && (s.name === menuActiveOptionValue || s.value === menuActiveOptionValue)));
        if (optionData) {
          const newOption = {
            ...optionData,
            id: `style_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            name: tu('actions.option.copyName', { name: optionData.name })
          };
          customStyleCategories.unshift(newOption);
          saveCustomOptions('styleCategory', customStyleCategories);
        }
      }

      if (currentPromptAction) {
        renderPromptFields(currentPromptAction.fields, getPromptFieldValues());
      }
    };

    ctxRemoveOption.onclick = (e) => {
      e.stopPropagation();
      hideOptionContextMenu();
      removeCustomOption(menuActiveFieldKey, menuActiveOptionValue, menuActiveOptionId);
    };

    function removeCustomOption(fieldKey, value, id = null) {
      // Preserve current selection before re-render
      const currentValues = getPromptFieldValues();

      if (fieldKey === 'tone') {
        customTones = customTones.filter(t => id ? t.id !== id : t.value !== value);
        saveCustomOptions('tone', customTones);
        // If the removed option was selected, reset to default
        if (currentValues.tone === value) {
          currentValues.tone = 'Casual';
        }
      } else if (fieldKey === 'imagePreset') {
        customImagePresets = customImagePresets.filter(p => id ? p.id !== id : p.value !== value);
        saveCustomOptions('imagePreset', customImagePresets);
        if (currentValues.imagePreset === value) {
          currentValues.imagePreset = '';
        }
      } else if (fieldKey === 'reStylePreset') {
        customReStylePresets = customReStylePresets.filter(p => id ? p.id !== id : p.value !== value);
        saveCustomOptions('reStylePreset', customReStylePresets);
        if (currentValues.reStylePreset === value) {
          currentValues.reStylePreset = '';
        }
      } else if (fieldKey === 'renamePreset') {
        customSmartRenamePresets = customSmartRenamePresets.filter(p => id ? p.id !== id : p.value !== value);
        saveCustomOptions('renamePreset', customSmartRenamePresets);
        if (currentValues.renamePreset === value) {
          currentValues.renamePreset = '';
        }
      } else if (fieldKey === 'styleCategory') {
        customStyleCategories = customStyleCategories.filter(s => id ? s.id !== id : (s.name !== value && s.value !== value));
        saveCustomOptions('styleCategory', customStyleCategories);
        if (currentValues.styleCategory === value) {
          currentValues.styleCategory = 'Auto';
        }
      }

      // Re-render drawer with preserved selections
      if (currentPromptAction) {
        renderPromptFields(currentPromptAction.fields, currentValues);
      }
    }

    function saveCustomOptions(type, data) {
      let messageType, payloadKey;
      if (type === 'tone') {
        messageType = 'save-custom-tones';
        payloadKey = 'customTones';
      } else if (type === 'imagePreset') {
        messageType = 'save-custom-image-presets';
        payloadKey = 'presets';
      } else if (type === 'reStylePreset') {
        messageType = 'save-custom-re-style-presets';
        payloadKey = 'presets';
      } else if (type === 'renamePreset') {
        messageType = 'save-custom-smart-rename-presets';
        payloadKey = 'presets';
      } else if (type === 'styleCategory') {
        messageType = 'save-custom-style-categories';
        payloadKey = 'customStyleCategories';
      }

      const payload = {};
      payload[payloadKey] = data;

      parent.postMessage({
        pluginMessage: {
          type: messageType,
          ...payload
        }
      }, '*');
    }

    // Modal event listeners
    closeAddOptionBtn.onclick = closeAddOptionModal;
    btnConfirmAddOption.onclick = handleAddOptionSubmit;
    addOptionModal.onclick = (e) => {
      if (e.target === addOptionModal) closeAddOptionModal();
    };
    customQuickActionContextTrigger?.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      const nextOpen = !customQuickActionContext.classList.contains('open');
      closeCustomQuickActionContextMenu();
      if (nextOpen) {
        customQuickActionContext.classList.add('open');
        customQuickActionContextTrigger.setAttribute('aria-expanded', 'true');
      }
    });
    customQuickActionContextMenu?.addEventListener('click', (e) => {
      const option = e.target.closest('[data-context-value]');
      if (!option) return;
      e.preventDefault();
      e.stopPropagation();
      setCustomQuickActionContextValue(option.dataset.contextValue);
      closeCustomQuickActionContextMenu();
    });
    customQuickActionAddInputBtn?.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      openCustomQuickActionInputEditor(null);
    });
    customQuickActionCancelInputBtn?.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      closeCustomQuickActionInputEditor();
    });
    customQuickActionSaveInputBtn?.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      const savedResult = saveCustomQuickActionInputFromEditor();
      if (savedResult?.input && savedResult.shouldInsertAfterSave) {
        insertCustomQuickActionChip(savedResult.input, savedResult.insertContextAfterSave);
      }
    });
    customQuickActionInputEditor?.addEventListener('click', (e) => {
      if (e.target === customQuickActionInputEditor) {
        closeCustomQuickActionInputEditor();
      }
    });
    customQuickActionInputType?.addEventListener('change', updateCustomQuickActionInputEditorVisibility);
    customQuickActionInputMultiple?.addEventListener('change', updateCustomQuickActionInputEditorVisibility);
    customQuickActionInputLabel?.addEventListener('input', () => {
      if (!customQuickActionInputKey) return;
      const currentKey = sanitizeCustomQuickActionInputKey(customQuickActionInputKey.value || '');
      if (!currentKey || currentKey.startsWith('input')) {
        customQuickActionInputKey.value = generateCustomQuickActionInputKey(customQuickActionInputLabel.value, customQuickActionDraftInputs, customQuickActionDraftInputs.length + 1);
      }
    });
    customQuickActionInputsList?.addEventListener('click', (e) => {
      const button = e.target.closest('[data-custom-input-action]');
      if (!button) return;
      e.preventDefault();
      e.stopPropagation();
      const inputId = button.dataset.customInputId;
      if (!inputId) return;
      if (button.dataset.customInputAction === 'edit') {
        const input = customQuickActionDraftInputs.find((entry) => entry.id === inputId);
        if (input) openCustomQuickActionInputEditor(input);
      } else if (button.dataset.customInputAction === 'delete') {
        deleteCustomQuickActionInput(inputId);
      }
    });
    customQuickActionPromptEditor?.addEventListener('mouseup', saveCustomQuickActionSelectionRange);
    customQuickActionPromptEditor?.addEventListener('keyup', saveCustomQuickActionSelectionRange);
    customQuickActionPromptEditor?.addEventListener('focus', saveCustomQuickActionSelectionRange);
    customQuickActionPromptEditor?.addEventListener('input', () => {
      updateCustomQuickActionPromptTextareaValue();
      saveCustomQuickActionSelectionRange();
    });
    customQuickActionPromptEditor?.addEventListener('click', (e) => {
      if (e.target.closest('.custom-quick-action-prompt-chip')) return;
      saveCustomQuickActionSelectionRange();
    });
    customQuickActionPromptShell?.addEventListener('mousedown', (e) => {
      if (e.target.closest('.custom-quick-action-prompt-chip')) return;
      if (e.target === customQuickActionPromptEditor) return;
      e.preventDefault();
      customQuickActionPromptEditor?.focus();
      placeCustomQuickActionCaretAtEnd();
    });
    customQuickActionInsertBtn?.addEventListener('click', (e) => {
      e.preventDefault();
      e.stopPropagation();
      saveCustomQuickActionSelectionRange();
      openCustomQuickActionInsertMenu(customQuickActionInsertBtn, { type: 'insert' });
    });
    customQuickActionInsertMenu?.addEventListener('click', (e) => {
      const item = e.target.closest('[data-insert-input-id], [data-insert-new-input]');
      if (!item) return;
      e.preventDefault();
      e.stopPropagation();
      if (item.dataset.insertNewInput === 'true') {
        openCustomQuickActionInputEditor(null, {
          insertAfterSave: true,
          insertContext: customQuickActionInsertContext,
        });
        hideCustomQuickActionInsertMenu();
        return;
      }
      const input = customQuickActionDraftInputs.find((entry) => entry.id === item.dataset.insertInputId);
      if (input) insertCustomQuickActionChip(input);
    });
    closeCustomQuickActionBtn.onclick = closeCustomQuickActionModal;
    cancelCustomQuickActionBtn.onclick = closeCustomQuickActionModal;
    saveCustomQuickActionBtn.onclick = handleSaveCustomQuickAction;
    customQuickActionModal.onclick = (e) => {
      if (e.target === customQuickActionModal) closeCustomQuickActionModal();
    };
    document.addEventListener('click', (e) => {
      if (!e.target.closest('.command-item-custom-actions')) {
        closeCommandItemPopover();
      }
      if (!e.target.closest('.custom-quick-action-context-select')) {
        closeCustomQuickActionContextMenu();
      }
      if (!e.target.closest('.custom-quick-action-insert-menu') && !e.target.closest('.custom-quick-action-insert-btn') && !e.target.closest('.custom-quick-action-prompt-chip')) {
        hideCustomQuickActionInsertMenu();
      }
    });

    // Settings
    btnSaveSettings.addEventListener('click', saveSettings);

    // Figma API event listeners
    btnTestFigmaToken.addEventListener('click', testFigmaToken);
    btnDetectFileKey.addEventListener('click', detectFileKey);
    btnLoadComments.addEventListener('click', loadFigmaComments);
    btnRefreshComments.addEventListener('click', loadFigmaComments);

    // Make file key input editable when clicked
    figmaFileKeyInput.addEventListener('click', () => {
      figmaFileKeyInput.readOnly = false;
      figmaFileKeyInput.placeholder = t('settings.figma.fileKeyEditingPlaceholder');
    });

    // Parse file key from pasted URL
    figmaFileKeyInput.addEventListener('paste', (e) => {
      setTimeout(() => {
        const value = figmaFileKeyInput.value.trim();
        // Try to extract file key from URL
        const urlMatch = value.match(/figma\.com\/(?:file|design)\/([a-zA-Z0-9]+)/);
        if (urlMatch) {
          figmaFileKeyInput.value = urlMatch[1];
          figmaFileKey = urlMatch[1];
          showToast(t('settings.messages.fileKeyExtracted'), 'success');
        }
      }, 0);
    });

    function setTestButtonLoading(button, isLoading) {
      if (!button) return;
      if (isLoading) {
        button.classList.add('loading');
        button.textContent = t('settings.testing');
        button.disabled = true;
      } else {
        button.classList.remove('loading');
        button.textContent = t('settings.test');
        button.disabled = false;
      }
    }

    testConnectionButtons.forEach(button => {
      button.addEventListener('click', async () => {
        const provider = button.dataset.testProvider || providerSelect.value;
        let testApiKey, testModel;

        switch (provider) {
          case 'gemini':
            testApiKey = geminiApiKeyInput.value;
            testModel = geminiModelSelect.value;
            break;
          case 'openai':
            testApiKey = openaiApiKeyInput.value;
            testModel = openaiModelSelect.value;
            break;
          case 'ollama':
            testApiKey = ollamaApiKeyInput ? ollamaApiKeyInput.value : '';
            testModel = ollamaModelSelect ? ollamaModelSelect.value : ollamaModel;
            break;
          case 'anthropic':
            testApiKey = anthropicApiKeyInput.value;
            testModel = anthropicModelSelect.value;
            break;
        }

        if (provider === 'openai') {
          if (!String(testApiKey || '').trim()) {
            showToast(t('settings.messages.enterApiKey'), 'error');
            return;
          }
        } else if (provider !== 'ollama' && !testApiKey) {
          showToast(t('settings.messages.enterApiKey'), 'error');
          return;
        }

        setTestButtonLoading(button, true);

        try {
          let response;

          if (provider === 'gemini') {
            response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${testModel}:generateContent?key=${testApiKey}`, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                contents: [{ role: 'user', parts: [{ text: 'Hello' }] }],
                generationConfig: { temperature: 0.1, maxOutputTokens: 10 }
              })
            });
          } else if (provider === 'openai') {
            const hdr = { 'Content-Type': 'application/json', Authorization: `Bearer ${String(testApiKey || '').trim()}` };
            response = await fetch(`${DEFAULT_OPENAI_API_BASE}/chat/completions`, {
              method: 'POST',
              headers: hdr,
              body: JSON.stringify({
                model: testModel,
                messages: [{ role: 'user', content: 'Hello' }],
                max_tokens: 10
              })
            });
          } else if (provider === 'ollama') {
            const hdr = { 'Content-Type': 'application/json' };
            const tk = String(testApiKey || '').trim();
            if (tk) hdr.Authorization = `Bearer ${tk}`;
            response = await compatHttpFetch(`${getOllamaBaseUrl()}/chat/completions`, {
              method: 'POST',
              headers: hdr,
              body: JSON.stringify({
                model: testModel,
                messages: [{ role: 'user', content: 'Hello' }],
                max_tokens: 10
              })
            });
          } else if (provider === 'anthropic') {
            response = await fetch('https://api.anthropic.com/v1/messages', {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
                'x-api-key': testApiKey,
                'anthropic-version': '2023-06-01',
                'anthropic-dangerous-direct-browser-access': 'true'
              },
              body: JSON.stringify({
                model: testModel,
                max_tokens: 10,
                messages: [{ role: 'user', content: 'Hello' }]
              })
            });
          }

          if (response.ok) {
            // Update local variables
            selectedProvider = provider;
            if (provider === 'gemini') {
              geminiApiKey = testApiKey;
              geminiModel = testModel;
              // Also list models to confirm quota/model visibility
              let listedModels = [];
              try {
                listedModels = await listGeminiModels(testApiKey);
                console.log('Gemini models for this key:', listedModels);
                if (listedModels.length > 0) {
                  const modelNames = listedModels.slice(0, 5).map(m => m.displayName || m.id).join(', ');
                  showToast(t('settings.messages.modelsAvailable', {
                    count: listedModels.length,
                    models: modelNames,
                    suffix: listedModels.length > 5 ? '…' : ''
                  }));
                } else {
                  showToast(t('settings.messages.connectedNoModels'), 'info');
                }
              } catch (e) {
                console.warn('Model list failed:', e);
                showToast(t('settings.messages.connectedModelListFailed', { message: e.message }), 'info');
              }
              populateGeminiModelSelect(listedModels.length ? listedModels : DEFAULT_GEMINI_MODELS, testModel);
              // Update chat dropdown if Gemini is current provider
              if (selectedProvider === 'gemini') {
                populateChatModelDropdown();
              }
            } else if (provider === 'openai') {
              openaiApiKey = testApiKey;
              openaiModel = testModel;
            } else if (provider === 'ollama') {
              ollamaApiKey = testApiKey || '';
              ollamaModel = testModel;
            } else if (provider === 'anthropic') {
              anthropicApiKey = testApiKey;
              anthropicModel = testModel;
            }

            showToast(t('settings.messages.connectionSuccessful'));
            updateChatStatus();

            // Update chat dropdown
            populateChatModelDropdown();
          } else {
            const error = await response.json();
            throw new Error(error.error?.message || 'Connection failed');
          }
        } catch (error) {
          showToast(t('settings.messages.connectionFailed', { message: error.message }), 'error');
        } finally {
          setTestButtonLoading(button, false);
        }
      });
    });

    // Message handler from plugin
    window.onmessage = (event) => {
      const msg = event.data.pluginMessage;
      if (!msg) return;

      if (msg.type === 'ollama-proxy-fetch-result') {
        const pending = ollamaProxyPending.get(msg.requestId);
        if (pending) {
          clearTimeout(pending.timeoutId);
          ollamaProxyPending.delete(msg.requestId);
          try {
            pending.settle(msg);
          } catch (e) {
            pending.reject(e);
          }
        }
        return;
      }

      // Remove loading states from export menu items
      exportMenuItems.forEach(item => item.classList.remove('loading'));

      switch (msg.type) {
        case 'css-result':
          addExportToInput('CSS', msg.data);
          break;

        case 'svg-result':
          addExportToInput('SVG', msg.data);
          break;

        case 'png-result':
          addExportToInput('PNG', msg.data);
          break;

        case 'figma-images-result':
          if (pendingSelectionImageResolve) {
            pendingSelectionImageResolve(msg.images);
            pendingSelectionImageResolve = null;
            pendingSelectionImageReject = null;
          } else {
            handleFigmaImagesResult(msg.fieldKey, msg.images);
          }
          break;

        case 'text-result':
          addExportToInput('TEXT', msg.data);
          break;

        case 'vector-network':
          const vnJson = JSON.stringify(msg.vectorNetwork, null, 2);
          addMessage('bot', `Vector Network for node ${msg.nodeId}:\n\`\`\`json\n${vnJson}\n\`\`\``);
          // Also add to input at cursor position so the AI can "see" it in the next turn
          addExportToInput('VECTOR_NETWORK', vnJson);
          break;

        case 'gradient-info':
          const gradJson = JSON.stringify(msg.gradients, null, 2);
          addMessage('bot', `Gradient Info for node ${msg.nodeId}:\n\`\`\`json\n${gradJson}\n\`\`\``);
          addExportToInput('GRADIENT_INFO', gradJson);
          break;

        case 'design-system-extracted':
          handleDesignSystemExtracted(msg.data);
          break;

        case 'design-tokens-created':
          showToast(msg.message || 'Design tokens created successfully', 'success');
          break;

        case 'design-system-figma-created':
          showToast(msg.message || 'Design system document created in Figma', 'success');
          break;

        case 'selection-changed':
        case 'selection-info':
          handleSelectionChange(msg.data);
          requestSelectionDescendantsIfNeeded(false);
          // Refresh comments if in selection scope
          if (currentCommentsScope === 'selection') {
            const promptContainer = document.getElementById('promptCommentsContainer');
            if (promptContainer) renderCommentsInDrawer(promptContainer);
          }
          if (currentPromptAction?.directAction === 'listAllComponents' && currentComponentsScope === 'selection') {
            if (!componentsSelectionManualLoadPending) {
              componentsSelectionStale = true;
              updateComponentsSelectionReloadFab();
            }
          }
          if (currentPromptAction?.directAction === 'listAllStickies' && currentStickiesScope === 'selection') {
            const promptContainer = document.getElementById('promptStickiesContainer');
            if (promptContainer) renderStickiesInDrawer(promptContainer);
          }
          break;

        case 'selection-descendants':
          if (applySelectionDescendantsPayload(msg.data, msg.signature, {
            selectionTooLarge: msg.selectionTooLarge,
            descendantsTruncated: msg.descendantsTruncated,
          })) {
            if (currentCommentsScope === 'selection') {
              const promptContainer = document.getElementById('promptCommentsContainer');
              if (promptContainer) renderCommentsInDrawer(promptContainer);
            }
            if (currentPromptAction?.directAction === 'listAllStickies' && currentStickiesScope === 'selection') {
              const promptContainer = document.getElementById('promptStickiesContainer');
              if (promptContainer) renderStickiesInDrawer(promptContainer);
            }
          }
          break;

        case 'nodes-pages-result':
          if (msg.results) {
            Object.entries(msg.results).forEach(([nodeId, pageId]) => {
              commentNodePageMap.set(nodeId, pageId);
            });
            // Re-render if we are in 'page' scope
            if (currentCommentsScope === 'page') {
              const promptContainer = document.getElementById('promptCommentsContainer');
              if (promptContainer) renderCommentsInDrawer(promptContainer);
            }
          }
          break;

        case 'viewport-and-node-positions-result':
          if (msg.viewportCenter) {
            cachedViewportCenter = msg.viewportCenter;
          }
          if (msg.positions) {
            cachedNodePositions = { ...cachedNodePositions, ...msg.positions };
          }
          if (msg.names) {
            cachedNodeNames = { ...cachedNodeNames, ...msg.names };
          }
          // Re-render with viewport sort now that we have data
          if (commentsSortBy === 'viewport' || Object.keys(cachedNodeNames).length > 0) {
            const promptContainer = document.getElementById('promptCommentsContainer');
            if (promptContainer) renderCommentsInDrawer(promptContainer);
          }
          break;


        case 'settings-loaded':
          applySettings(msg.data);
          // Load custom tones and image presets if available
          if (msg.data.customTones) {
            customTones = msg.data.customTones;
          }
          if (msg.data.customImagePresets) {
            customImagePresets = msg.data.customImagePresets;
          }
          if (msg.data.customReStylePresets) {
            customReStylePresets = msg.data.customReStylePresets;
          }
          if (msg.data.customSmartRenamePresets) {
            customSmartRenamePresets = msg.data.customSmartRenamePresets;
          }
          if (msg.data.customStyleCategories) {
            customStyleCategories = msg.data.customStyleCategories;
          }
          refreshAllReplyTemplateContainers();

          // Update storage usage
          if (msg.archivesSize !== undefined) {
            updateStorageUsage(msg.archivesSize);
          } else {
            updateStorageUsage();
          }

          // Restore maximized prompt drawer if needed
          if (msg.data.maximizedPromptDrawerData) {
            openPromptDrawer(msg.data.maximizedPromptDrawerData).then(() => {
              maximizePromptDrawer();
            });
          }
          break;

        case 'quick-actions-usage-loaded':
          mergeQuickActionUsage(msg.data);
          if (msg.lastUsed) {
            mergeLastUsedQuickActions(msg.lastUsed);
          }
          quickActionUsageLoadedFromPlugin = true;
          // Refresh slash suggestions if menu is open or no query yet
          if (slashMenuVisible || !lastSlashQuery) {
            handleSlashInput();
          }
          // Refresh node actions content (always, even with empty selection for last-used buttons)
          updateNodeActionsContent(lastKnownSelectionItems || []);
          break;

        case 'settings-saved':
          showToast(t('settings.messages.settingsSaved'));
          break;

        case 'google-fonts-catalog-result':
          window.dispatchEvent(new CustomEvent('plugin-google-fonts-catalog', { detail: msg }));
          break;

        case 'current-context':
        case 'file-info':
          handleFileInfo(msg.data);
          // Refresh comments if in page scope
          if (currentCommentsScope === 'page') {
            const promptContainer = document.getElementById('promptCommentsContainer');
            if (promptContainer) renderCommentsInDrawer(promptContainer);
          }
          if (currentPromptAction?.directAction === 'listAllComponents' && currentComponentsScope === 'page') {
            refreshComponentsInDrawer(true).catch((error) => {
              console.warn('Failed to refresh components for page scope:', error);
            });
          }
          if (currentPromptAction?.directAction === 'listAllStickies' && currentStickiesScope === 'page') {
            const promptContainer = document.getElementById('promptStickiesContainer');
            if (promptContainer) renderStickiesInDrawer(promptContainer);
          }
          break;

        case 'select-nodes-result':
          if (msg.partial) {
            showToast(`Selected ${msg.selectedCount}/${msg.requestedCount} nodes on ${msg.pageName}`, 'info');
          } else {
            showToast(`Selected ${msg.selectedCount} nodes on ${msg.pageName}`, 'success');
          }
          break;

        case 'navigate-success':
          showToast(t('settings.messages.navigatedToComment'));
          break;

        case 'chat-archives-saved':
          if (msg.size !== undefined) {
            updateStorageUsage(msg.size);
          } else {
            updateStorageUsage();
          }
          break;

        case 'error':
          showToast(msg.message, 'error');
          // Also reject any pending selection request so it doesn't timeout
          if (pendingSelectionDataReject) {
            pendingSelectionDataReject(new Error(msg.message));
            pendingSelectionDataReject = null;
            pendingSelectionDataResolve = null;
          }
          // Also reject any pending image capture request
          if (pendingSelectionImageReject) {
            pendingSelectionImageReject(new Error(msg.message));
            pendingSelectionImageReject = null;
            pendingSelectionImageResolve = null;
          }
          // Clear any image upload loading states
          document.querySelectorAll('.prompt-add-figma-btn.loading, .prompt-add-figma-separate-btn.loading').forEach(btn => {
            btn.classList.remove('loading');
            btn.disabled = false;
          });
          break;

        case 'context-lock-result':
          // Handle context lock response for intent-based pipeline
          if (pendingContextLockResolve) {
            pendingContextLockResolve(msg.data);
            pendingContextLockResolve = null;
            pendingContextLockReject = null;
          }
          break;

        case 'selection-data':
          // Update current selection size for token counter
          currentSelectionDataSize = msg.dataSize || 0;
          updateTokenCount();

          if (pendingSelectionDataResolve) {
            pendingSelectionDataResolve({
              data: msg.data,
              dataSize: msg.dataSize,
              tokenContext: msg.tokenContext,
              flattened: msg.flattened,
              selectionImage: msg.selectionImage,
              // New fields for pre-flight optimization
              requiresFallback: msg.requiresFallback || false,
              nodeCount: msg.nodeCount,
              skippedLibraryVariables: msg.skippedLibraryVariables || false,
              fromLockedContext: msg.fromLockedContext || false
            });
            pendingSelectionDataResolve = null;
            pendingSelectionDataReject = null;
          }
          // Also use for auto-fill viewport if loading flag is set
          if (auditAutoFillViewport.classList.contains('loading') && msg.data && msg.data.length > 0) {
            const firstNode = msg.data[0];
            auditTargetWidth.value = firstNode.width || 390;
            auditTargetHeight.value = firstNode.height || 844;
            showToast('Viewport set from selection!');
            auditAutoFillViewport.classList.remove('loading');
          }

          // Auto-detect language if provided
          // The auditLanguageSelect will now default to 'Auto' and not be automatically changed by selection
          // if (msg.detectedLanguage && auditLanguageSelect) {
          //   auditLanguageSelect.value = msg.detectedLanguage;
          //   // showToast(`Detected language: ${msg.detectedLanguage === 'ja' ? 'Japanese' : msg.detectedLanguage === 'en' ? 'English' : msg.detectedLanguage === 'cn' ? 'Chinese' : 'Korean'}`);
          // }
          break;

        case 'selection-dimensions':
          if (msg.data) {
            auditTargetWidth.value = msg.data.width || 390;
            auditTargetHeight.value = msg.data.height || 844;
            showToast(tu('aux.audit.dimensionsSet'));
          }
          auditAutoFillViewport.classList.remove('loading');
          break;

        case 'selection-bounding-box':
          if (promptDrawer.classList.contains('open') && currentPromptAction && currentPromptAction.name === 'Create Graph') {
            const chartSizeSelect = promptDrawerFields.querySelector('.prompt-custom-select[data-field-key="chartSize"]');
            if (chartSizeSelect) {
              const autoOption = chartSizeSelect.querySelector('.prompt-custom-select-option[data-value="Auto"]');
              if (autoOption) {
                const label = (msg.width != null && msg.height != null)
                  ? tu('actions.chart.selectionSize', { size: `${msg.width}x${msg.height}` })
                  : tu('actions.chart.autoSelection');
                autoOption.textContent = label;
                autoOption.dataset.text = label;
              }
            }
          }
          break;

        case 'selection-colors':
          if (msg.data && msg.data.length > 0) {
            const colors = msg.data;
            if (colors[0]) { auditColorPrimary.value = colors[0]; auditColorPrimaryHex.value = colors[0]; }
            if (colors[1]) { auditColorSecondary.value = colors[1]; auditColorSecondaryHex.value = colors[1]; }
            if (colors[2]) { auditColorError.value = colors[2]; auditColorErrorHex.value = colors[2]; }
            if (colors[3]) { auditColorWarning.value = colors[3]; auditColorWarningHex.value = colors[3]; }
            if (colors[4]) { auditColorSuccess.value = colors[4]; auditColorSuccessHex.value = colors[4]; }
            showToast(`${colors.length} colors extracted from selection!`);
          } else {
            showToast('No colors found in selection', 'error');
          }
          auditAutoFillColors.classList.remove('loading');
          break;

        case 'local-styles':
          if (msg.source !== 'command') {
            ensureStylesPanelVisible();
          }
          renderLocalStyles({
            paintStyles: msg.paintStyles || [],
            textStyles: msg.textStyles || [],
            effectStyles: msg.effectStyles || [],
            gridStyles: msg.gridStyles || [],
            variables: msg.variables || [],
            collections: msg.collections || []
          });
          showToast(`Loaded ${msg.paintStyles?.length || 0} paint, ${msg.textStyles?.length || 0} text, ${msg.effectStyles?.length || 0} effect, ${msg.variables?.length || 0} variable styles`, 'info');
          break;

        case 'local-variables':
          showToast(`Received ${msg.variables?.length || 0} local variables (not displayed)`, 'info');
          break;

        case 'smart-rename-case-only-result': {
          const renamed = Number(msg.renamed) || 0;
          const skipped = Number(msg.skipped) || 0;
          const total = Number(msg.total) || (renamed + skipped);
          if (renamed > 0) {
            showToast(`Renamed ${renamed}/${total} layer${renamed === 1 ? '' : 's'} with case-only formatting.`, 'success');
          } else {
            showToast(`No layer names needed changes${total ? ` out of ${total}` : ''}.`, 'info');
          }
          break;
        }

        case 'local-sequential-naming-result':
        case 'local-prefix-suffix-naming-result':
        case 'local-clean-up-names-result': {
          const renamed = Number(msg.renamed) || 0;
          const skipped = Number(msg.skipped) || 0;
          const total = Number(msg.total) || (renamed + skipped);
          if (renamed > 0) {
            showToast(`Renamed ${renamed}/${total} layer${renamed === 1 ? '' : 's'}.`, 'success');
          } else {
            showToast(`No layer names needed changes${total ? ` out of ${total}` : ''}.`, 'info');
          }
          break;
        }

        case 'local-format-sequencer-result':
        case 'local-add-prefix-suffix-text-result': {
          const updated = Number(msg.updated) || 0;
          const skipped = Number(msg.skipped) || 0;
          const failed = Number(msg.failed) || 0;
          const total = Number(msg.total) || (updated + skipped + failed);
          if (updated > 0 && failed === 0) {
            showToast(`Updated ${updated}/${total} text layer${updated === 1 ? '' : 's'}.`, 'success');
          } else if (updated > 0 && failed > 0) {
            showToast(`Updated ${updated}/${total} text layers, ${failed} failed.`, 'warning');
          } else if (failed > 0) {
            showToast(`Failed to update ${failed}/${total} text layer${failed === 1 ? '' : 's'}.`, 'error');
          } else {
            showToast(`No text content needed changes${total ? ` out of ${total}` : ''}.`, 'info');
          }
          break;
        }

        case 'local-verticalize-text-result': {
          const updated = Number(msg.updated) || 0;
          const skipped = Number(msg.skipped) || 0;
          const failed = Number(msg.failed) || 0;
          const total = Number(msg.total) || (updated + skipped + failed);
          if (updated > 0 && failed === 0) {
            showToast(`Verticalized ${updated}/${total} text layer${updated === 1 ? '' : 's'}.`, 'success');
          } else if (updated > 0 && failed > 0) {
            showToast(`Verticalized ${updated}/${total} text layers, ${failed} failed.`, 'warning');
          } else if (failed > 0) {
            showToast(`Failed to verticalize ${failed}/${total} text layer${failed === 1 ? '' : 's'}.`, 'error');
          } else {
            showToast(`No text layers needed changes${total ? ` out of ${total}` : ''}.`, 'info');
          }
          break;
        }

        case 'local-google-translate-text-result': {
          const gtUpdated = Number(msg.updated) || 0;
          const gtSkipped = Number(msg.skipped) || 0;
          const gtFailed = Number(msg.failed) || 0;
          const gtTotal = Number(msg.total) || (gtUpdated + gtSkipped + gtFailed);
          if (gtUpdated > 0 && gtFailed === 0) {
            showToast(`Translated ${gtUpdated}/${gtTotal} text layer${gtUpdated === 1 ? '' : 's'}.`, 'success');
          } else if (gtUpdated > 0 && gtFailed > 0) {
            showToast(`Translated ${gtUpdated}/${gtTotal} text layers, ${gtFailed} failed.`, 'warning');
          } else if (gtFailed > 0) {
            showToast(`Failed to translate ${gtFailed}/${gtTotal} text layer${gtFailed === 1 ? '' : 's'}.`, 'error');
          } else {
            showToast(`No text content needed translation${gtTotal ? ` out of ${gtTotal}` : ''}.`, 'info');
          }
          break;
        }

        case 'local-google-translate-naming-result': {
          const gtnRenamed = Number(msg.renamed) || 0;
          const gtnSkipped = Number(msg.skipped) || 0;
          const gtnTotal = Number(msg.total) || (gtnRenamed + gtnSkipped);
          if (gtnRenamed > 0) {
            showToast(`Renamed ${gtnRenamed}/${gtnTotal} layer${gtnRenamed === 1 ? '' : 's'} (translated).`, 'success');
          } else {
            showToast(`No layer names needed translation${gtnTotal ? ` out of ${gtnTotal}` : ''}.`, 'info');
          }
          break;
        }

        case 'variable-collections-list':
          // Store collections for palette generation dropdown
          window.variableCollectionsCache = msg.collections || [];
          break;

        case 'library-styles':
          showToast(`Received ${Array.isArray(msg.data) ? msg.data.length : 0} library styles (not displayed)`, 'info');
          break;

        case 'library-variable-collections':
          showToast(`Received ${Array.isArray(msg.data) ? msg.data.length : 0} library variable collections (not displayed)`, 'info');
          break;

        case 'library-components':
          showToast(`Received ${Array.isArray(msg.data) ? msg.data.length : 0} library components (not displayed)`, 'info');
          break;

        case 'commands-executed':
          if (pendingCommandsResolve) {
            pendingCommandsResolve(msg);
            pendingCommandsResolve = null;
          }

          // Show toast feedback
          const errorDetail = msg.error
            ? t('settings.messages.commands.errorDetail', {
                action: msg.error.action || t('settings.messages.commands.errorActionFallback'),
                message: msg.error.message ?? ''
              })
            : '';
          let finalStatusText = '';
          if (msg.success > 0 && msg.failed === 0) {
            finalStatusText = t('settings.messages.commands.executedSuccess', { count: msg.success });
            showToast(finalStatusText, 'success');
          } else if (msg.success > 0 && msg.failed > 0) {
            finalStatusText = t('settings.messages.commands.executedPartial', {
              success: msg.success,
              failed: msg.failed,
              errorDetail
            });
            showToast(finalStatusText, 'warning');
          } else if (msg.failed > 0) {
            finalStatusText = t('settings.messages.commands.executedFailed', {
              count: msg.failed,
              errorDetail
            });
            showToast(finalStatusText, 'error');
          } else if (msg.success === 0 && msg.failed === 0) {
            finalStatusText = t('settings.messages.commands.done');
          }

          // Final update to progress tracking div
          if (lastExecutionMessageDiv) {
            const contentDiv = lastExecutionMessageDiv.querySelector('.message-content');
            // Always clean up progress indicator
            if (contentDiv) {
              const leftoverProgress = contentDiv.querySelector('.execution-progress-status');
              if (leftoverProgress) leftoverProgress.remove();
            }
            if (contentDiv && finalStatusText) {
              if (msg.commands && msg.commands.length > 0) {
                const details = document.createElement('details');
                details.className = 'execution-details';
                const summary = document.createElement('summary');
                summary.innerHTML = `<svg class="chevron" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 18 15 12 9 6"></polyline></svg><span>${finalStatusText}</span>`;
                details.appendChild(summary);

                const list = document.createElement('ul');

                // Add Intent-Based Context information
                if (lastUsedContextInfo) {
                  const contextLi = document.createElement('li');
                  contextLi.innerHTML = getIntentContextListItemInnerHtml(lastUsedContextInfo);
                  list.appendChild(contextLi);
                }

                // Add UI Section Outline plan
                if (lastUsedUIOutline) {
                  const outlineLi = document.createElement('li');
                  outlineLi.innerHTML = getUiOutlinePlanListItemInnerHtml(lastUsedUIOutline);
                  list.appendChild(outlineLi);
                }

                msg.commands.forEach(cmd => {
                  const li = document.createElement('li');
                  const cmdName = cmd.name ? `: ${cmd.name}` : '';
                  const statusClass = cmd.status || 'success';
                  const hasNode = !!cmd.nodeId;

                  if (hasNode) {
                    li.className = 'has-node';
                    li.title = t('settings.messages.commands.clickToFindInFigma');
                    li.onclick = (e) => {
                      e.stopPropagation();
                      // Remove clicked class from all other command items
                      document.querySelectorAll('.execution-details li.has-node').forEach(el => el.classList.remove('clicked'));
                      // Add clicked class to this item
                      li.classList.add('clicked');
                      parent.postMessage({ pluginMessage: { type: 'select-node', nodeId: cmd.nodeId } }, '*');
                    };
                  }

                  const duration = cmd.duration !== undefined ? cmd.duration : 0;
                  const durationText = duration > 0 ? `${duration}ms` : '<1ms';

                  if (duration >= 500) {
                    li.classList.add('v-slow-execution');
                  } else if (duration >= 100) {
                    li.classList.add('slow-execution');
                  }

                  let innerHTML = `<div class="cmd-main-row">
                    <div class="status-dot ${statusClass}"></div>
                    <div class="cmd-info">
                      <span class="cmd-action">${cmd.action}</span>
                      <span class="cmd-name">${cmdName}</span>
                    </div>
                    <span class="cmd-duration" title="${escapeHtml(t('settings.messages.commands.executionTimeTitle'))}">${durationText}</span>
                  </div>`;

                  if (cmd.before !== null && cmd.after !== null && cmd.before !== cmd.after) {
                    // Two-row layout for changes
                    const beforeText = String(cmd.before);
                    const afterText = String(cmd.after);

                    innerHTML += `</div><div class="cmd-change-row">
                      <span class="change-value before" title="${beforeText}">${beforeText}</span>
                      <span class="change-arrow">→</span>
                      <span class="change-value after" title="${afterText}">${afterText}</span>
                    </div>`;
                  } else {
                    // Inline preview for simple actions
                    if (cmd.preview) {
                      innerHTML += `<div class="cmd-preview-row"><span class="cmd-preview">${cmd.preview}</span></div>`;
                    }
                  }

                  li.innerHTML = innerHTML;
                  list.appendChild(li);
                });
                details.appendChild(list);

                // Remove any pre-existing execution details or progress markers
                const existingDetails = contentDiv.querySelector('.execution-details');
                if (existingDetails) existingDetails.remove();
                const progressEl = contentDiv.querySelector('.execution-progress-status');
                if (progressEl) progressEl.remove();

                contentDiv.appendChild(details);
              } else {
                // If no commands to display, just add a status message at the bottom
                let statusEl = contentDiv.querySelector('.execution-status-message');
                if (!statusEl) {
                  statusEl = document.createElement('div');
                  statusEl.className = 'execution-status-message';
                  statusEl.style.fontSize = 'var(--text-xs)';
                  statusEl.style.opacity = '0.7';
                  statusEl.style.marginTop = '8px';
                  contentDiv.appendChild(statusEl);
                }
                statusEl.textContent = finalStatusText;
              }
              // Update dataset content only if it's currently generic
              if (!lastExecutionMessageDiv.dataset.originalContent) {
                lastExecutionMessageDiv.dataset.originalContent = lastExecutionMessageDiv.dataset.content;
              }
            }
          }
          lastExecutionMessageDiv = null;
          break;

        case 'remove-unused-component-properties-result':
          if (msg.removed && msg.removed.length > 0) {
            showToast(`Removed ${msg.removed.length} unused properties: ${msg.removed.join(', ')}`, 'success');
          } else {
            showToast('No unused component properties found to remove.', 'info');
          }
          break;

        case 'execution-progress':
          if (lastExecutionMessageDiv) {
            const contentDiv = lastExecutionMessageDiv.querySelector('.message-content');
            if (contentDiv) {
              const statusText = t('settings.messages.commands.executingProgress', {
                current: msg.current,
                total: msg.total
              });
              let progressEl = contentDiv.querySelector('.execution-progress-status');
              if (!progressEl) {
                progressEl = document.createElement('div');
                progressEl.className = 'execution-progress-status';
                progressEl.style.fontSize = 'var(--text-xs)';
                progressEl.style.opacity = '0.7';
                progressEl.style.marginTop = '8px';
                progressEl.style.fontStyle = 'italic';
                contentDiv.appendChild(progressEl);
              }
              progressEl.textContent = statusText;
            }
          }
          break;

        case 'set-component-description-result': {
          const success = msg.success || 0;
          const failed = msg.failed || 0;
          if (success > 0 && failed === 0) {
            showToast(`Saved guidelines to ${success} component(s).`, 'success');
          } else if (success > 0 && failed > 0) {
            showToast(`Saved to ${success} component(s); ${failed} skipped.`, 'warning');
          } else {
            showToast(msg.message || 'No component description updated.', 'error');
          }
          break;
        }

        case 'apply-reality-data-to-selection': {
          // Apply reality data to selected duplicated nodes using AI
          const nodeIds = msg.nodeIds || [];
          if (nodeIds.length === 0) {
            break;
          }

          // Create AI prompt to modify selected nodes with realistic data
          const prompt = `The following nodes are selected in Figma. Analyze the CURRENT text content of each node to determine its data type (e.g., if a node says "John Doe", it's a Name; if it says "$10.00", it's a Price).

Then, for each node, generate new, realistic, and diverse data that matches that identified type.

Key requirements:
1. CRITICAL: Use the existing text characters of each node to infer the intended data category.
2. Generate unique, realistic variations for every node to avoid repetition.
3. Maintain the original formatting style where appropriate (e.g., currency symbols, date formats, capitalization).
4. Do NOT use generic placeholders; provide specific, high-quality realistic data.

Update the text content for all selected nodes accordingly.`;

          // Send to AI for processing
          sendQuickActionMessage(prompt, false, {
            name: 'Apply Reality Data',
            icon: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>'
          }, false, ContextMode.ALL).catch(error => {
            console.error('Failed to apply reality data:', error);
            showToast('Failed to apply realistic data', 'error');
          });

          break;
        }

      }
    };

