    // Resize dragging logic
    /** Helper to save outline history */
    function saveToOutlineHistory(source, sections, fieldValues = null) {
      if (!sections || sections.length === 0) return;

      const historyKey = 'UI_OUTLINE_HISTORY';
      const timestamp = new Date().toISOString();

      // Use screenType as title if available
      const screenType = fieldValues?.screenType || sections[0].title || 'Untitled Outline';

      // Create summary from first 3 titles
      const summary = sections.slice(0, 3).map(s => s.title).join(', ') + (sections.length > 3 ? '...' : '');

      let history = promptHistory[historyKey] || [];

      // Check for exact duplicate of the MOST RECENT entry to avoid spamming saves
      if (history.length > 0) {
        const last = history[0];
        // Compare both sections and major field values to decide if it's a duplicate
        const isDuplicate = JSON.stringify(last.sections) === JSON.stringify(sections) &&
          last.fieldValues?.screenType === fieldValues?.screenType &&
          last.fieldValues?.platform === fieldValues?.platform;

        if (isDuplicate) {
          last.timestamp = timestamp; // just update timestamp
          if (last.source !== source) last.source = source;
          // Update fieldValues just in case
          if (fieldValues) last.fieldValues = JSON.parse(JSON.stringify(fieldValues));
          promptHistory[historyKey] = history;
          parent.postMessage({ pluginMessage: { type: 'save-prompt-history', history: promptHistory } }, '*');
          return;
        }
      }

      history.unshift({
        id: 'hist_' + Date.now(),
        timestamp,
        source: source || 'Manual Edit',
        title: screenType,
        summary,
        sections: JSON.parse(JSON.stringify(sections)), // deep copy
        fieldValues: fieldValues ? JSON.parse(JSON.stringify(fieldValues)) : null
      });

      // Keep max 20
      if (history.length > 20) {
        history = history.slice(0, 20);
      }

      promptHistory[historyKey] = history;
      parent.postMessage({ pluginMessage: { type: 'save-prompt-history', history: promptHistory } }, '*');
    }

    function _extractNameTaglineFromText(text) {
      if (!text) return null;
      const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
      for (const line of lines) {
        const m = line.match(/^(?:\d+\.\s*)?(?:Header\s*[:：]\s*)?(.+?[,，]\s*\d+(?:\s*(?:歳|才|years?\s*old))?)\s*[—\-–]+\s*(.+)/i);
        if (m) return { name: m[1].trim(), tagline: m[2].trim() };
      }
      for (const line of lines) {
        const m2 = line.match(/^(?:Name\s*(?:&|and)\s*Age|Name)\s*[:：]\s*(.+)/i);
        if (m2) return { name: m2[1].trim(), tagline: '' };
      }
      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        if (/^(?:Name\s*(?:&|and)\s*Age|Name)$/i.test(line) && lines[i + 1]) {
          const nameVal = lines[i + 1].trim();
          if (nameVal && !/^(?:Tagline|Background|Goal|Section|Detail)$/i.test(nameVal)) {
            let tagline = '';
            for (let j = i + 2; j < lines.length; j++) {
              if (/^Tagline$/i.test(lines[j]) && lines[j + 1]) {
                tagline = lines[j + 1].trim();
                break;
              }
              if (/^(?:Background|Goal|Experience|Practical|Safety)/i.test(lines[j])) break;
            }
            return { name: nameVal, tagline };
          }
        }
      }
      return null;
    }

    function updatePersonaHistoryWithAiResponse(parsed) {
      if (!parsed) return;
      const historyKey = 'PERSONA_HISTORY';
      const history = promptHistory[historyKey];
      if (!history || history.length === 0) return;

      const entry = history[0];
      const message = typeof parsed === 'string' ? parsed : (parsed.message || '');
      const commands = (typeof parsed === 'object' && Array.isArray(parsed.commands)) ? parsed.commands : [];

      const allTexts = [];
      let extractedName = '';
      let extractedTagline = '';

      const textCmds = commands.filter(c =>
        (c.action === 'createText' || c.action === 'setText') && c.text
      );
      if (textCmds.length > 0) {
        textCmds.forEach(c => allTexts.push(c.text));
        const nameCmd = textCmds.find(c => c.refId && /name/i.test(c.refId) && !/tagline/i.test(c.refId));
        if (nameCmd) extractedName = nameCmd.text;
        const taglineCmd = textCmds.find(c => c.refId && /tagline/i.test(c.refId));
        if (taglineCmd) extractedTagline = taglineCmd.text;
      }

      const tableCmds = commands.filter(c => c.action === 'createTable' && Array.isArray(c.data));
      if (tableCmds.length > 0) {
        for (const table of tableCmds) {
          if (table.name && /^Persona[:：]\s*/i.test(table.name)) {
            const nameFromTableName = table.name.replace(/^Persona[:：]\s*/i, '').trim();
            if (nameFromTableName && !extractedName) extractedName = nameFromTableName;
          }
          for (const row of table.data) {
            if (Array.isArray(row)) {
              row.forEach(cell => { if (typeof cell === 'string' && cell.trim()) allTexts.push(cell); });
            }
          }
          if (!extractedName && table.data.length > 1) {
            const nameRow = table.data.find(r => Array.isArray(r) && /Name/i.test(r[0]));
            if (nameRow && nameRow[1]) extractedName = nameRow[1];
            const taglineRow = table.data.find(r => Array.isArray(r) && /Tagline/i.test(r[0]));
            if (taglineRow && taglineRow[1]) extractedTagline = taglineRow[1];
          } else if (extractedName && !extractedTagline && table.data.length > 1 && table.name && /^Persona[:：]/i.test(table.name)) {
            const taglineRow = table.data.find(r => Array.isArray(r) && /Tagline/i.test(r[0]));
            if (taglineRow && taglineRow[1]) extractedTagline = taglineRow[1];
          }
        }
      }

      const stickyCmds = commands.filter(c => c.action === 'createSticky' && c.text);
      if (stickyCmds.length > 0) {
        stickyCmds.forEach(c => allTexts.push(c.text));
      }

      if (!extractedName) {
        const personaSection = commands.find(c =>
          (c.action === 'createSection' || c.action === 'createFrame') &&
          c.name && /^Persona[:：]\s*/i.test(c.name)
        );
        if (personaSection) extractedName = personaSection.name.replace(/^Persona[:：]\s*/i, '').trim();
      }

      const fullText = allTexts.length > 0 ? allTexts.join('\n') : message;

      if (fullText) {
        entry.aiResponse = fullText;
        if (extractedName) entry.personaName = extractedName;
        if (extractedTagline) entry.tagline = extractedTagline;
        if (!extractedName || !extractedTagline) {
          const found = _extractNameTaglineFromText(fullText);
          if (found) {
            if (!extractedName && found.name) entry.personaName = found.name;
            if (!extractedTagline && found.tagline) entry.tagline = found.tagline;
          }
        }
      }

      const combos = entry.contextVarCombinations || _pendingContextVarsCombinations;
      entry.scenarios = _extractScenariosFromTableCommands(tableCmds, combos);
      if (entry.scenarios.length === 0) {
        entry.scenarios = _extractScenariosFromResponse(fullText || '', combos);
      }
      if (entry.scenarios.length === 0 && fullText) {
        const scenarioText = _extractSingleScenario(fullText);
        if (scenarioText) {
          entry.scenarios = [{ combination: null, title: scenarioText.title || 'Scenario', text: scenarioText.text }];
        }
      }

      _pendingContextVarsCombinations = null;
      promptHistory[historyKey] = history;
      parent.postMessage({ pluginMessage: { type: 'save-prompt-history', history: promptHistory } }, '*');
    }

    function _extractScenariosFromTableCommands(tableCmds, combos) {
      const scenarios = [];
      const scenarioTables = tableCmds.filter(t => t.name && /Scenario/i.test(t.name));
      scenarioTables.forEach((table, idx) => {
        const data = table.data || [];
        const titleRow = data.find(r => Array.isArray(r) && r[0] && /^Title$/i.test(String(r[0]).trim()));
        const narrativeRow = data.find(r => Array.isArray(r) && r[0] && /^Narrative$/i.test(String(r[0]).trim()));
        const title = titleRow && titleRow[1] ? String(titleRow[1]).trim() : (table.name || `Scenario ${idx + 1}`).replace(/^Scenario\s*[:：]\s*/i, '').trim();
        const narrative = narrativeRow && narrativeRow[1] ? String(narrativeRow[1]).trim() : '';
        const combo = combos && combos[idx] ? combos[idx] : null;
        scenarios.push({ combination: combo, title, text: narrative });
      });
      return scenarios;
    }

    function _extractScenariosFromResponse(text, combos) {
      if (!text) return [];
      const scenarios = [];

      const scenarioBlocks = text.split(/(?:^|\n)(?:---\s*)?Scenario\s+(\d+)\s*[:：]/im);
      if (scenarioBlocks.length > 2) {
        for (let i = 1; i < scenarioBlocks.length; i += 2) {
          const idx = parseInt(scenarioBlocks[i]) - 1;
          const content = (scenarioBlocks[i + 1] || '').trim();
          const titleMatch = content.match(/^(.+?)(?:\n|$)/);
          const title = titleMatch ? titleMatch[1].replace(/^[-—–\s]+/, '').trim() : `Scenario ${idx + 1}`;
          const bodyText = content.replace(/^.+?\n/, '').trim();
          const combo = combos && combos[idx] ? combos[idx] : null;
          scenarios.push({ combination: combo, title, text: bodyText || content });
        }
        return scenarios;
      }

      const eqBlocks = text.split(/(?:^|\n)==+\s*SCENARIO\s*(\d*)\s*==*/im);
      if (eqBlocks.length > 2) {
        for (let i = 1; i < eqBlocks.length; i += 2) {
          const idx = parseInt(eqBlocks[i] || (Math.floor(i / 2) + 1)) - 1;
          const content = (eqBlocks[i + 1] || '').trim();
          const titleMatch = content.match(/^(.+?)(?:\n|$)/);
          const title = titleMatch ? titleMatch[1].replace(/^[-—–\s]+/, '').trim() : `Scenario ${idx + 1}`;
          const combo = combos && combos[idx] ? combos[idx] : null;
          scenarios.push({ combination: combo, title, text: content });
        }
        return scenarios;
      }

      return scenarios;
    }

    function _extractSingleScenario(text) {
      const scenarioMatch = text.match(/(?:^|\n)(?:==\s*)?SCENARIO(?:\s*==)?\s*\n([\s\S]+)/im);
      if (scenarioMatch) {
        const content = scenarioMatch[1].trim();
        const titleMatch = content.match(/^(?:Title\s*[:：]\s*)?(.+?)(?:\n|$)/);
        return {
          title: titleMatch ? titleMatch[1].replace(/^[-—–""\s]+/, '').replace(/[""]$/, '').trim() : 'Scenario',
          text: content
        };
      }
      return null;
    }

    function saveToPersonaHistory(values, prompt) {
      if (!values || !values.target) return;

      const historyKey = 'PERSONA_HISTORY';
      const timestamp = new Date().toISOString();
      const title = values.target || 'Untitled Persona';
      const summary = [values.targetUser, values.productContext].filter(Boolean).join(' — ').slice(0, 100) || 'No context';

      let history = promptHistory[historyKey] || [];

      if (history.length > 0) {
        const last = history[0];
        const timeDiff = Date.now() - new Date(last.timestamp).getTime();
        const isSameInputs = last.title === title &&
          last.fieldValues?.targetUser === values.targetUser &&
          last.fieldValues?.productContext === values.productContext;

        if (isSameInputs && timeDiff < 10000) {
          last.timestamp = timestamp;
          last.prompt = prompt || last.prompt;
          promptHistory[historyKey] = history;
          parent.postMessage({ pluginMessage: { type: 'save-prompt-history', history: promptHistory } }, '*');
          return;
        }
      }

      const cleanValues = {};
      for (const key in values) {
        const val = values[key];
        if (val === null || val === undefined) continue;
        if (Array.isArray(val) && val.length > 0 && typeof val[0] === 'object' && val[0] !== null && 'data' in val[0]) continue;
        if (typeof val === 'string' && val.length > 5000) continue;
        cleanValues[key] = val;
      }

      const entry = {
        id: 'persona_' + Date.now(),
        timestamp,
        title,
        targetUser: values.targetUser || '',
        summary,
        prompt: prompt || '',
        fieldValues: JSON.parse(JSON.stringify(cleanValues)),
        scenarios: []
      };
      if (_pendingContextVarsCombinations && _pendingContextVarsCombinations.length > 0) {
        entry.contextVarCombinations = JSON.parse(JSON.stringify(_pendingContextVarsCombinations));
      }
      history.unshift(entry);

      if (history.length > 20) {
        history = history.slice(0, 20);
      }

      promptHistory[historyKey] = history;
      parent.postMessage({ pluginMessage: { type: 'save-prompt-history', history: promptHistory } }, '*');
    }

    const inlineHandlerNames = Array.from(new Set([
      ...chatInlineHandlerNames,
      ...commentsInlineHandlerNames,
      ...stickiesInlineHandlerNames,
      ...historyInlineHandlerNames,
      ...stylesInlineHandlerNames,
      'switchComponentsScope',
      'handleComponentsSearchInput',
      'toggleComponentsBrowserDropdown',
      'setComponentsSourceFilter',
      'setComponentsGroupingMode',
      'toggleComponentsIncludeNestedInstances',
      'toggleComponentsIncludeHiddenInstances',
      'navigateToComponentInventoryEntry',
      'selectComponentInventoryEntryNodes',
      'refreshComponentsInDrawer',
      'loadComponentsFromCurrentSelection',
      'reloadComponentsInventoryForNewSelection',
    ]));

    function exposeInlineHandlerBindings() {
      const bindings = {};

      // Module scripts do not automatically publish top-level functions on window.
      // These bindings preserve existing inline `onclick`/`oninput` behavior without
      // changing the current HTML contract.
      inlineHandlerNames.forEach((name) => {
        try {
          bindings[name] = eval(name);
        } catch (error) {
          console.warn(`Skipping inline handler binding for ${name}`, error);
        }
      });

      exposeGlobals(bindings);
    }

    exposeInlineHandlerBindings();

    const resizeHandle = byId('resizeHandle');
    let isResizing = false;

    resizeHandle.addEventListener('mousedown', (e) => {
      isResizing = true;
      e.preventDefault();

      const startX = e.clientX;
      const startY = e.clientY;
      const startWidth = window.innerWidth;
      const startHeight = window.innerHeight;

      const onMouseMove = (moveEvent) => {
        if (!isResizing) return;

        const newWidth = Math.max(360, startWidth + (moveEvent.clientX - startX));
        const newHeight = Math.max(400, startHeight + (moveEvent.clientY - startY));

        postPluginMessage({
          type: 'resize',
          width: newWidth,
          height: newHeight
        });
      };

      const onMouseUp = () => {
        isResizing = false;
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
        document.body.style.cursor = 'default';
      };

      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', onMouseUp);
      document.body.style.cursor = 'nwse-resize';
    });
    resizeHandle.addEventListener('dblclick', () => {
      postPluginMessage({
        type: 'reset-size'
      });
    });
